ALTER TABLE whiskeys
    DROP COLUMN etc_detail,
    DROP COLUMN region,
    ADD COLUMN brand VARCHAR(255) AFTER type,
    ADD COLUMN volume INT AFTER cask,
    ADD COLUMN name_eng VARCHAR(255) AFTER volume,
    ADD COLUMN price INT AFTER name_eng,
    ADD COLUMN cost_url VARCHAR(500) AFTER price,
    ADD COLUMN cost_url_source VARCHAR(255) AFTER cost_url,
    ADD COLUMN description JSON AFTER cost_url_source,
    ADD COLUMN note JSON AFTER description;

delete from review_likes;
delete from reviews;

delete from tasting_note_tags;
delete from tasting_notes;

delete from my_picks;

delete from wishlist_items;

delete from avg_whiskey_tags;
delete from whiskeys_note_cache;

delete from whiskey_view_logs;
delete from whiskey_requests;

delete from whiskeys;

-- whiskeys INSERT queries

INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (1, '하이랜드 파크 12년', 'single_malt', 'Highland Park Whisky', 'whiskey/136607.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Highland Park 12 Year Old 70cl', 68138, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-12-year-old-whisky/?sku=136607', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 12년(Highland Park 12 Year Old Viking Honour)은 스코틀랜드 최북단 오크니 제도의 거친 자연 속에서 탄생한 증류소의 정체성을 담은 핵심 라인업입니다. 바이킹의 후예들이 빚어낸 이 위스키는 특유의 향긋한 피트감과 달콤한 과일 풍미가 완벽한 조화를 이루는 것으로 유명하며, 위스키 평론가 마이클 잭슨이 가장 완벽한 올라운더 위스키라고 극찬한 바 있습니다. 40%의 도수로 병입되며 전 세계 싱글 몰트 애호가들에게 스탠다드의 기준을 제시합니다.", "제조 및 숙성": "오크니 제도에서만 채취되는 헤더 식물이 풍부하게 섞인 피트를 사용하여 보리를 건조함으로써, 일반적인 아일라 피트와는 다른 달콤하고 화사한 스모크 향을 입힙니다. 원액은 고품질의 최고급 유러피안 및 아메리칸 셰리 오크통에서 최소 12년 동안 숙성되어 깊은 풍미를 완성합니다."}, "feature": {"바이킹의 유산": "오크니 제도의 바이킹 역사와 전통적인 수작업 플로어 몰팅 공정을 고집스레 이어가고 있습니다.", "헤더 피트 스모크": "헤더 꽃이 녹아든 피트를 사용하여 차별화된 달콤하고 향긋한 스모키함을 선사합니다.", "완벽한 밸런스": "셰리 오크통의 달콤한 과일 맛과 은은한 피트 향이 어느 한쪽으로 치우치지 않고 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "잘 익은 시트러스 과일과 신선한 꿀의 달콤함이 피어오르고, 그 뒤를 이어 하이랜드 파크 특유의 은은하고 향긋한 헤더 피트 스모크 향이 부드럽게 감쌉니다.", "맛 (Palate)": "입안에 닿는 느낌이 부드럽고 둥글며, 달콤한 꿀과 녹아든 밀랍, 잘 말린 오렌지 껍질의 풍미가 중심을 잡고 따뜻한 겨울 향신료와 부드러운 맥아의 고소함이 층을 이룹니다.", "여운 (Finish)": "깔끔하면서도 묵직하게 지속됩니다. 은은한 나무의 풍미와 함께 향긋한 헤더 스모크의 잔향이 입안에 길게 남습니다."}}' WHERE id = 1;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (2, '하이랜드 파크 18년', 'single_malt', 'Highland Park Whisky', 'whiskey/136609.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Highland Park 18 Year Old 70cl', 220870, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-18-year-old-whisky-2024/?sku=136609', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 18년(Highland Park 18 Year Old Viking Pride)은 전 세계 위스키 어워드에서 수차례 세계 최고의 증류주로 선정되며 그 명성을 입증한 마스터피스입니다. 18년이라는 오랜 세월 동안 오크니 제도의 혹독한 해풍을 견디며 숙성되어, 젊은 연산의 거친 느낌은 사라지고 극상의 부드러움과 깊이감을 자랑합니다. 43%의 도수로 병입되며 풍부한 셰리 풍미와 정교한 피트 스모크가 완벽하게 결합된 위스키입니다.", "제조 및 숙성": "증류소의 엄격한 기준에 따라 선별된 퍼스트 필 유러피안 오크 셰리 캐스크의 비율을 대폭 높여 숙성했습니다. 오랜 숙성 과정을 통해 셰리 와인의 깊은 풍미가 원액에 완벽하게 스며들었으며, 한랭한 기후 덕분에 오크통의 떫은 맛 대신 정제된 달콤함만 극대화되었습니다."}, "feature": {"세계가 인정한 명작": "위스키 저널 및 전문가들로부터 완벽에 가까운 균형을 가진 위스키로 수년째 극찬받고 있습니다.", "높은 셰리 캐스크 비중": "고급 유러피안 셰리 오크통의 영향으로 깊고 어두운 골드 빛깔과 묵직한 과일 풍미를 냅니다.", "정교한 숙성의 미학": "18년의 세월 동안 만들어낸 부드러운 질감과 복합적인 레이어가 매 모금마다 다채롭게 변화합니다."}}', note = '{"note": {"향 (Nose)": "풍부한 잘 익은 체리, 흑설탕, 말린 무화과와 함께 다크 초콜릿의 향이 묵직하게 다가옵니다. 은은하게 깔리는 에스프레소와 부드러운 피트 스모크가 깊이를 더합니다.", "맛 (Palate)": "묵직하고 풀바디의 질감이 입안을 가득 채웁니다. 벌꿀 집의 달콤함과 구운 견과류의 고소함, 졸인 자두의 맛이 느껴지며 오크통에서 배어 나온 시나몬과 시트러스 스파이스가 기분 좋은 타격감을 줍니다.", "여운 (Finish)": "놀라울 정도로 길고 우아합니다. 달콤한 말린 과일의 잔향과 쌉싸름한 다크 카카오, 그리고 부드럽고 향기로운 헤더 스모크 향이 완벽한 조화로 이어집니다."}}' WHERE id = 2;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (3, '하이랜드 파크 15년', 'single_malt', 'Highland Park Whisky', 'whiskey/136608.jpg', 44.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park 15 Year Old 70cl', 147533, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-15-year-old-whisky/?sku=136608', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 15년(Highland Park 15 Year Old Viking Heart)은 도자기를 연상시키는 세련된 세라믹 보틀에 담겨 시각적, 미각적 만족을 동시에 선사하는 프리미엄 익스프레션입니다. 셰리 숙성의 달콤함과 아메리칸 오크 특유의 바닐라 풍미가 균형을 이루도록 정교하게 설계되었으며, 44%의 도수로 병입되어 12년 제품보다 더 짙은 복합성과 부드러움을 제공합니다.", "제조 및 숙성": "이 제품은 마스터 블렌더 고든 모션이 직접 엄선한 퍼스트 필 아메리칸 오크 셰리 캐스크를 중심으로 숙성하여 풍부한 바닐라와 시트러스 향을 이끌어내고, 여기에 리필 캐스크를 마리잉하여 하이랜드 파크 본연의 DNA인 헤더 피트 캐릭터를 고스란히 살려냈습니다."}, "feature": {"아메리칸 셰리의 재발견": "바닐라 풍미가 탁월한 아메리칸 오크 셰리 캐스크를 주력으로 사용하여 독창적인 부드러움을 완성했습니다.", "예술적인 도자기 보틀": "영국의 유명 세라믹 제조사인 Wade와 협업하여 바이킹의 전통 리본 문양을 새긴 도자기 병을 사용했습니다.", "화사하고 생기 넘치는 캐릭터": "풍부한 과일 풍미와 크리미한 텍스처가 어우러져 한층 더 화사한 느낌을 줍니다."}}', note = '{"note": {"향 (Nose)": "구운 오크와 향긋한 시나몬 크림, 갓 구운 바닐라 스펀지케이크의 향이 코를 자극합니다. 뒤이어 신선한 레몬 제스트와 파인애플 같은 열대 과일, 부드러운 피트 향이 피어오릅니다.", "맛 (Palate)": "크리미하고 부드러운 질감이 특징입니다. 따뜻한 꿀의 달콤함과 잘 익은 복숭아, 말린 살구의 맛이 부드럽게 퍼지며 구운 생강과 피트 스모크의 힌트가 반전의 재미를 선사합니다.", "여운 (Finish)": "온화하고 긴 여운을 남깁니다. 나무 스파이스의 따뜻함, 부드러운 바닐라의 달콤함, 그리고 은은한 헤더탄의 연기가 조화롭게 가라앉습니다."}}' WHERE id = 3;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (4, '하이랜드 파크 21년', 'single_malt', 'Highland Park Whisky', 'whiskey/136024.jpg', 46.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park 21 Year Old (2023 Release) 70cl', 404162, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-21-year-old-2023-release-whisky/?sku=136024', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 21년(Highland Park 21 Year Old)은 매년 한정된 수량만 배치 형태로 선보이는 하이엔드 정규 라인업입니다. 20년이 넘는 세월 동안 오크니 섬의 서늘한 기후 속에서 원액이 증발하고 응축되는 과정을 거쳐 완벽한 세련미를 획득했습니다. 46%의 높은 도수로 병입되어 정제된 고급스러움과 강력한 풍미의 힘을 동시에 느킬 수 있는 위스키입니다.", "제조 및 숙성": "유러피안 오크 셰리 캐스크와 아메리칸 오크 셰리 캐스크, 그리고 극소량의 리필 캐스크를 정밀하게 블렌딩했습니다. 세 종류의 서로 다른 캐스크에 담긴 원액들이 오랜 시간 숙성되며 서로의 장점을 흡수하여 독보적인 복합성을 자랑합니다."}, "feature": {"소량 한정 배치 생산": "각 배치마다 미세하게 다른 캐스크 조합을 사용하여 위스키 컬렉터들의 소장 욕구를 자극합니다.", "삼중 오크 숙성의 깊이": "유러피안 셰리, 아메리칸 셰리, 리필 캐스크의 조합이 선사하는 다층적인 레이어가 특징입니다.", "노블 캐릭터": "오랜 연산이 주는 묵직한 숙성 오크 향과 하이랜드 파크 고유의 화사함이 고귀한 자태를 이룹니다."}}', note = '{"note": {"향 (Nose)": "오래된 숙성 오크의 묵직한 향과 시나몬 가루를 뿌린 구운 사과, 잘 익은 블랙베리의 향이 피어납니다. 부드러운 가죽 향과 아주 정제된 스모키함이 깊은 인상을 줍니다.", "맛 (Palate)": "혀를 감싸는 오일감이 뛰어납니다. 진한 오렌지 마멀레이드와 육두구, 부드러운 바닐라 빈의 풍미가 터져 나오고, 뒤이어 짭조름한 바닷바람의 힌트와 잘 구운 진저브레드의 맛이 느껴집니다.", "여운 (Finish)": "귀족적인 우아함이 돋보이는 매우 긴 여운입니다. 달콤한 셰리의 흔적, 따뜻한 계피 스파이스, 그리고 아주 멀리서 느껴지는 듯한 잔잔한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 4;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (5, '하이랜드 파크 16년 윙스 오브 더 이글', 'single_malt', 'Highland Park Whisky', 'whiskey/81131.jpg', 44.5, 16, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park 16 Year Old Wings Of The Eagle 70cl', 163662, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-16-year-old-wings-of-the-eagle-whisky/?sku=81131', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 16년 윙스 오브 더 이글(Highland Park 16 Year Old Wings of the Eagle)은 원래 면세점 한정판으로 출시되어 큰 인기를 끌었던 스페셜 에디션입니다. 바이킹 신화 속 세계수 위그드라실의 꼭대기에 앉아 온 세상을 감시하는 거대한 독수리에서 영감을 받아 탄생했습니다. 독수리의 날개짓처럼 강렬하고 와일드하면서도 내면의 정교함을 놓치지 않은 44.5% 도수의 위스키입니다.", "제조 및 숙성": "유러피안 오크와 아메리칸 오크 셰리 캐스크에서 각각 숙성된 원액을 매링하여 만들었습니다. 16년이라는 독특한 숙성 연수는 12년의 대중성과 18년의 묵직함 사이에서 가장 역동적이고 화려한 과일 향을 뿜어내는 완벽한 지점입니다."}, "feature": {"바이킹 신화의 오마주": "신화 속 독수리의 지혜와 힘을 시각적 레이블과 풍미의 타격감으로 형상화했습니다.", "독특한 도수 설계": "44.5%라는 정교한 도수 조정을 통해 스파이시함과 과일의 단맛을 극대화했습니다.", "면세 시장의 강자": "여행자들을 위해 특별히 기획되어 하이랜드 파크 특유의 아로마를 더욱 직관적으로 뽐냅니다."}}', note = '{"note": {"향 (Nose)": "말린 무화과와 구운 아몬드의 고소한 향이 먼저 가득 퍼집니다. 이내 신선한 살구 구이, 파인애플 시럽, 그리고 부드럽고 쌉싸름한 카카오와 은은한 피트 연기가 조화를 이룹니다.", "맛 (Palate)": "입안에서 생기 넘치는 타격감을 줍니다. 달콤한 꿀을 바른 건포도와 넛멕의 스파이시함이 조화를 이루며, 말린 오렌지 껍질과 따뜻한 바닐라 크림이 혀를 부드럽게 감싸 안습니다.", "여운 (Finish)": "복합적이고 따뜻한 피날레를 보여줍니다. 우디한 스파이스와 달콤한 과일 아로마가 가라앉으며 향긋하고 건조한 피트 스모크가 긴 여운을 남깁니다."}}' WHERE id = 5;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (6, '하이랜드 파크 25년', 'single_malt', 'Highland Park Whisky', 'whiskey/134566.jpg', 46.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park 25 Year Old (2023 Release) 70cl', 989281, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-25-year-old-2023-release-whisky/?sku=134566', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 25년(Highland Park 25 Year Old)은 위스키의 거장들과 평론가들 사이에서 완벽의 경지에 도달한 위스키로 꼽히는 최고급 럭셔리 익스프레션입니다. 무려 한 세기의 4분의 1에 달하는 세월 동안 천천히 호흡하며 오크니 섬의 서늘한 기후 속에서 에스테르화 과정을 거쳤습니다. 자극적인 알코올은 완벽히 정제되었으며, 위스키가 가질 수 있는 가장 깊고 기품 있는 아우라를 46% 안팎의 도수로 보여줍니다.", "제조 및 숙성": "극도로 희귀한 최상급 퍼스트 필 유러피안 셰리 오크통에서 대부분의 시간을 보낸 원액들을 엄선했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 모아 병입했습니다."}, "feature": {"궁극의 연산 숙성": "25년의 정성이 빚어낸 묵직한 가죽, 오래된 오크, 정제된 오일의 정수를 보여줍니다.", "독보적인 복합미": "달콤함, 쌉싸름함, 고소함, 스모키함이 거대한 드라마처럼 유기적으로 이어집니다.", "수집가들의 타겟": "생산량이 극도로 제한되어 출시될 때마다 전 세계 위스키 컬렉터들의 표적이 되는 주류입니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스럽습니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 진한 달콤함이 피어오르고, 잘 정제된 밀랍과 서양란의 화사함, 아주 은은하고 세련된 피트의 향이 고급스럽게 얹어집니다.", "맛 (Palate)": "마치 실크나 밤꿀을 머금은 듯 진득하고 매끄럽습니다. 다크 초콜릿 파이, 구운 호두의 고소함과 함께 잘 익은 체리의 풍미가 느껴지며 토피 당과 시나몬 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 달콤한 셰리의 흔적 뒤로 가죽, 마호가니 나무의 향, 그리고 미풍처럼 부드럽게 불어오는 잔잔한 헤더 피트 향이 코끝에 계속 맴봅니다."}}' WHERE id = 6;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (7, '하이랜드 파크 30년', 'single_malt', 'Highland Park Whisky', 'whiskey/146098.jpg', 45.4, 30, 'active', NOW(), NOW(), 'Island 30 Whisky', '', 700.0, 'Highland Park 30 Year Old (2024 Release) 70cl', 2062073, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-30-year-old-2024-release-whisky/?sku=146098', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 30년(Highland Park 30 Year Old)은 증류소가 보유한 가장 진귀하고 오래된 오크통에서 추출한 원액으로 만든 마스터클래스 위스키입니다. 30년이라는 기나긴 시간 동안 오크니 섬의 축축한 창고에서 해풍을 맞으며 숙성되어 위스키의 신비로움을 온몸으로 증명합니다. 인위적인 타협 없이 오크통 고유의 자연스러운 풍미가 고도로 축적된 최상위 플래그십 제품입니다.", "제조 및 숙성": "선별된 소수의 퍼스트 필 유러피안 셰리 오크통과 아메리칸 셰리 오크통에서 30년 이상 숙성된 진귀한 원액만을 매링했습니다. 오랜 세월 동안 나무와 원액이 완벽한 화학적 결합을 이루어, 색상과 풍미 모두에서 독보적인 기품을 자랑합니다."}, "feature": {"최상위 플래그십": "하이랜드 파크 정규 라인업 중 가장 높은 연산에 속하는 고귀한 위스키입니다.", "시간이 빚은 예술": "30년의 세월 동안 나무의 타닌과 스피릿이 만나 거칠고 매운 맛은 완전히 사라지고 극상의 부드러움만 남았습니다.", "완벽한 구조감": "풍미의 레이어가 촘촘하고 단단하게 짜여 있어 매 모금마다 새로운 맛을 발견하게 합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 향입니다. 달콤한 마지팬, 오렌지 에센스, 오래된 서랍장에서 날 법한 고풍스러운 나무 향이 조화를 이룹니다. 육두구, 바닐라 빈, 그리고 매우 희미하게 정제된 가을 낙엽 타는 듯한 피트 향이 어우러집니다.", "맛 (Palate)": "벨벳처럼 부드럽고 가득 차오르는 텍스처입니다. 다크 초콜릿에 절인 블랙커런트, 쌉싸름한 에스프레소, 구운 피칸의 풍미가 느껴지며 은은한 바다 소금의 짠맛과 시트러스 오일이 입안을 정교하게 자극합니다.", "여운 (Finish)": "가슴 깊은 곳까지 따뜻해지는 극도로 길고 복합적인 여운입니다. 스파이시한 오크 향과 진한 단맛이 완벽한 대칭을 이룰며, 아주 연한 담배 연기 같은 최고급 피트의 미련이 오래도록 남습니다."}}' WHERE id = 7;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (8, '하이랜드 파크 14년 로얄티 오브 더 울프', 'single_malt', 'Highland Park Whisky', 'whiskey/81132.jpg', 42.3, 14, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Highland Park 14 Year Old Loyalty Of The Wolf 100cl', 125366, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-14-year-old-loyalty-of-the-wolf-whisky/?sku=81132', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 14년 로얄티 오브 더 울프(Highland Park 14 Year Old Loyalty of the Wolf)는 바이킹들의 상징적인 동물인 늑대의 충성심과 강인한 결속력에서 영감을 얻은 면세 한정 에디션입니다. 늑대의 예리한 본능처럼 복합적이고 섬세한 맛의 균형을 자랑하며, 12년 제품보다 더 깊은 숙성미와 42.3% 도수에서 오는 부드럽고 안정적인 밸런스를 선사합니다.", "제조 및 숙성": "셰리 시즌드 아메리칸 오크 캐스크를 중심으로, 유러피안 오크 및 리필 캐스크를 정교하게 혼합하여 숙성시켰습니다. 아메리칸 오크 특유의 바닐라 풍미와 리필 캐스크가 주는 가벼운 몰트 본연의 맛이 절묘하게 조화되었습니다."}, "feature": {"스토리텔링 마케팅": "바이킹 전사들과 늑대 사이의 자연적 유대감과 용맹함을 보틀 디자인과 풍미에 투영했습니다.", "아메리칸 오크의 매력": "바닐라와 달콤한 스파이스 풍미를 주축으로 삼아 대중적이면서도 화사한 풍미를 구현했습니다.", "부드러운 타격감": "42.3%의 도수로 세팅되어 위스키 입문자부터 애호가까지 누구나 편안하게 즐길 수 있습니다."}}', note = '{"note": {"향 (Nose)": "달콤한 구운 바닐라와 달콤한 스펀지케이크, 잘 익은 사과 향이 지배적입니다. 그 뒤로 가벼운 시나몬 스파이스와 하이랜드 파크 특유의 향긋한 피트 연기가 살포시 피어오릅니다.", "맛 (Palate)": "입안에서 가볍고 부드럽게 굴러갑니다. 꿀에 절인 구운 땅콩의 고소함과 신선한 시트러스, 스펀지케이크의 달콤한 풍미가 느껴지며 약간의 정제된 구운 소금 같은 짭조름함이 풍미를 더합니다.", "여운 (Finish)": "깔끔하고 온화하게 마무리됩니다. 가벼운 나무 스파이스와 바닐라 캐러멜의 달콤함, 그리고 연한 헤더 피트 향이 입안을 부드럽게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 8;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (9, '하이랜드 파크 드래곤 레전드', 'single_malt', 'Highland Park Whisky', 'whiskey/70969.jpg', 43.1, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park Dragon Legend 70cl', 120925, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-dragon-legend-whisky/?sku=70969', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 드래곤 레전드(Highland Park Dragon Legend)는 정규 연산 제품들보다 더욱 강렬하고 깊은 피트 스모크를 원하는 애호가들을 위해 출시된 NAS 스페셜 에디션입니다. 바이킹 신화 속 영웅 시구르드가 사악한 용 파프니르를 처단하고 그 피를 마셔 지혜를 얻었다는 전설을 모티브로 삼았습니다. 전설만큼이나 대담하고 직관적인 타격감을 선사하는 43.1% 도수의 위스키입니다.", "제조 및 숙성": "하이랜드 파크의 일반적인 배치보다 헤더 피트로 훈연한 보리의 비율을 훨씬 높여 증류했습니다. 이 강렬한 피트 원액을 유러피안 오크 셰리 시즌드 캐스크에서 숙성시켜, 스모키함 뒤에 숨겨진 묵직한 달콤함의 극적인 대비를 이끌어냈습니다."}, "feature": {"강렬한 스모키 프로파일": "기존 라인업보다 한층 더 짙고 대담한 피트 향을 전면에 내세운 반전 매력의 제품입니다.", "드래곤 전설의 형상화": "검은색 보틀과 용의 비늘을 형상화한 화려한 디자인으로 강렬한 시각적 인상을 줍니다.", "단맛 tobacco 연기의 대비": "유러피안 셰리의 진한 과일 맛과 스모크가 입안에서 화려하게 충돌합니다."}}', note = '{"note": {"향 (Nose)": "기존 제품보다 확연히 강한 스모키함이 코를 찌릅니다. 가을철 타오르는 모닥불, 신선한 헤더 꽃, 그리고 뒤이어 올라오는 짙은 레몬 껍질와 달콤한 흑설탕 시럽의 향이 매력적입니다.", "맛 (Palate)": "대담하고 스파이시합니다. 구운 맥아의 고소함과 진한 꿀, 건포도의 달콤함이 피트 스모크와 어우러지며, 블랙페퍼와 스파이시한 오크통의 풍미가 입안에서 파도처럼 강렬하게 요동칩니다.", "여운 (Finish)": "드라이하면서도 스모키한 여운이 매우 길게 딻습니다. 입안에 오랫동안 남는 캠프파이어의 재와 같은 스모크 향, 그리고 따뜻한 계피와 다크 초콜릿의 잔향이 묵직하게 남습니다."}}' WHERE id = 9;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (10, '하이랜드 파크 트리스켈리온', 'single_malt', 'Highland Park Whisky', 'whiskey/98794.jpg', 45.1, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park Triskelion 70cl', 238780, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-triskelion-whisky/?sku=98794', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 트리스켈리온(Highland Park Triskelion)은 증류소의 역사를 이끌어온 전·현직 마스터 블렌더 3인이 공동으로 참여하여 만든 기념비적인 최고급 헤리티지 에디션입니다. 바이킹의 삼각 문양인 트리스켈리온에서 이름을 땄으며, 세 명의 거장이 가진 지혜와 기술이 결합되어 완벽한 예술적 가치를 지닙니다. 45.1% 도수로 병입되어 정교하고 다층적인 완성도를 보여줍니다.", "제조 및 숙성": "세 명의 마스터 블렌더가 각각 강조하는 캐스크 스타일을 조화롭게 융합했습니다. 퍼스트 필 유러피안 오크 셰리 캐스크, 퍼스트 필 아메리칸 오크 셰리 캐스크, 그리고 퍼스트 필 버번 캐스크에서 숙성된 진귀한 원액들을 절묘한 비율로 매링하여 독창적인 복합성을 만들어냈습니다."}, "feature": {"거장 3인의 콜라보레이션": "하이랜드 파크의 전설적인 마스터 블렌더 3인의 철학과 노하우가 집약된 마스터피스입니다.", "트리플 퍼스트 필 캐스크": "리필 캐스크 없이 오직 최고급 퍼스트 필 캐스크 3종만을 사용하여 원액의 힘이 강력합니다.", "최상급 복합성과 우아함": "버번의 바닐라, 유러피안 셰리의 과일, 아메리칸 셰리의 스파이스가 완벽한 삼위일체를 이룹니다."}}', note = '{"note": {"향 (Nose)": "화려하고 화사합니다. 싱그러운 오렌지 블러썸과 잘 익은 살구, 잘 정제된 바닐라 빈의 달콤한 향이 피어납니다. 은은하게 감도는 달콤한 밤꿀과 가벼운 헤더 연기가 향의 격을 높입니다.", "맛 (Palate)": "입안에서 아주 매끄럽고 정교하게 전개됩니다. 달콤한 바닐라 크림, 밀크 초콜릿, 건포도의 풍미가 부드럽게 퍼지고, 신선한 레몬 제스트와 부드러운 화이트 페퍼의 캐치한 스파이스가 훌륭한 레이어를 만듭니다.", "여운 (Finish)": "풍부하고 우아함이 깊게 지속됩니다. 퍼스트 필 캐스크 특유의 풍부한 나무 향과 바닐라의 달콤함, 그리고 잔잔하고 향긋한 헤더 피트 스모크가 아름다운 여운을 선사합니다."}}' WHERE id = 10;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (11, '하이랜드 파크 CS', 'single_malt', 'Highland Park Whisky', 'whiskey/103802.jpg', 63.3, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park Cask Strength - Release No.1 70cl', 100457, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-cask-strength-whisky/?sku=103802', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 캐스크 스트렝스(Highland Park Cask Strength)는 물을 섞어 도수를 낮추지 않고 오크통에서 꺼낸 원액 그대로를 병입하여, 증류소 고유의 거칠고 강력한 에너지를 날것 그대로 느낄 수 있는 익스프레션입니다. 배치별로 대략 60% 안팎의 높은 도수를 자랑하며, 냉각 여과나 색소 첨가 없이 내추럴 컬러로 완성되어 위스키 매니아들에게 하이랜드 파크의 가장 순수하고 강렬한 정수를 선사합니다.", "제조 및 숙성": "마스터 블렌더 고든 모션이 엄선한 퍼스트 필 셰리 시즌드 유러피안 오크 캐스크와 아메리칸 오크 캐스크, 그리고 극소량의 리필 캐스크 원액을 정교하게 블렌딩했습니다. 강한 도수 속에서도 하이랜드 파크 고유의 아로마가 무너지지 않도록 캐스크 조합에 심혈을 기울였습니다."}, "feature": {"순수한 캐스크 스트렝스": "가수 공정 없이 오크통 속 원액 그대로의 파워풀한 타격감과 풍미를 전합니다.", "내추럴 인티그리티": "냉각 여과를 거치지 않고 인공 색소를 넣지 않아 원액 본연의 진하고 탁월한 마우스필을 유지합니다.", "배치별 희소성": "각 배치마다 도수와 캐스크 조합이 미세하게 달라 비교 시음하는 재미를 보장합니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 짜릿한 알코올 볼륨감 뒤로 갓 구운 피트 향과 흑설탕, 말린 오렌지 껍질의 진한 달콤함이 피어오릅니다. 잘 익은 살구와 꿀, 매콤한 후추의 향이 레이어를 이룹니다.", "맛 (Palate)": "입안을 폭발적으로 가득 채우는 풀바디의 오일리함이 돋보입니다. 진한 헤더 꿀의 단맛과 헤더 피트의 알싸한 스모크가 충돌하며, 구운 생강, 육두구, 카카오 닙스의 쌉싸름함과 짭조름한 해풍의 힌트가 강렬하게 이어집니다.", "여운 (Finish)": "도수에 걸맞게 가슴 속까지 따뜻해지는 극도로 긴 여운입니다. 구운 오크의 우디함, 에스프레소의 잔향, 그리고 입안을 계속 맴도는 묵직한 피트 재의 연기가 강렬한 피날레를 장식합니다."}}' WHERE id = 11;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (12, '하이랜드 파크 40년', 'single_malt', 'Highland Park Whisky', 'whiskey/2401.jpg', 48.3, 40, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Highland Park 40 Year Old 70cl', 5108475, 'https://www.masterofmalt.com/whiskies/highland-park-40-year-old-whisky/?sku=2401', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 40년(Highland Park 40 Year Old)은 증류소가 보유한 초고연산 원액 중에서도 극상의 품질을 지닌 오크통만을 엄선하여 소량 한정 생산하는 최상위 마스터피스입니다. 40년이라는 장구한 시간 동안 오크니 섬의 서늘한 창고에서 천천히 숙성되며 자연스럽게 정제된 고귀한 아우라를 지니고 있으며, 알코올 도수는 오랜 세월 동안 낮아져 대략 43% 안팎의 자연스러운 캐스크 스트렝스로 병입되는 진귀한 최고급 주류입니다.", "제조 및 숙성": "1970년대 이전에 증류되어 퍼스트 필 유러피안 셰리 오크통에서 고독하게 오랜 세월을 버텨온 희귀 원액들을 기반으로 합니다. 나무의 거친 타닌 성분은 수십 년의 세월 동안 부드럽게 녹아들었고, 원액의 밀도는 극도로 높아져 위스키가 도달할 수 있는 미학적 정점을 보여줍니다."}, "feature": {"반세기에 가까운 세월": "40년이 넘는 기나긴 숙성 기간을 거쳐 거친 알코올은 완벽히 사라지고 귀족적인 부드러움만 남았습니다.", "극도의 희소 가치": "전 세계적으로 매년 극소량만 출시되어 위스키 수집가와 자산가들 사이에서 꿈의 보틀로 통합니다.", "시간이 자아낸 깊이": "현대적인 기술로는 흉내 낼 수 없는 오래된 마호가니 나무와 고풍스러운 다크 셰리의 정수를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽과 다크 초콜릿, 졸인 무화과, 건포도의 깊은 향이 퍼지고, 뒤이어 정교하게 다듬어진 헤더 꽃의 아로마와 은은한 샌달우드 향이 겹겹이 고결하게 피어오릅니다.", "맛 (Palate)": "혀를 비단처럼 매끄럽게 감싸는 농밀한 질감입니다. 진한 밤꿀과 쌉싸름한 오렌지 마멀레이드, 구운 호두의 고소함이 조화를 이루며, 오래된 오크에서 배어 나온 시나몬과 기품 있는 시트러스 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 우아한 여운입니다. 농축된 셰리의 단맛이 서서히 잦아들면서 고급스러운 시가 박스 향, 정제된 바다 소금의 흔적, 그리고 미풍처럼 부드러운 헤더 피트의 잔향이 영원처럼 머뭅니다."}}' WHERE id = 12;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (13, '하이랜드 파크 스피릿 오브 더 베어', 'single_malt', 'Highland Park Whisky', 'whiskey/81130.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Highland Park Spirit Of The Bear 100cl', 98226, 'https://www.masterofmalt.com/whiskies/highland-park/highland-park-spirit-of-the-bear-whisky/?sku=81130', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "하이랜드 파크 스피릿 오브 더 베어(Highland Park Spirit of the Bear)는 바이킹들이 전장에 나설 때 곰의 강인한 영혼과 용맹함을 빌리고자 했던 전통에서 영감을 받아 기획된 글로벌 면세 한정판 에디션입니다. 숙성 연수를 표기하지 않은 NAS 제품으로, 40% 도수로 가볍게 세팅되어 부담 없이 즐길 수 있으면서도 하이랜드 파크 고유의 아로마와 스모키 캐릭터를 직관적이고 생동감 있게 표현한 대중적인 위스키입니다.", "제조 및 숙성": "아메리칸 오크 셰리 시즌드 캐스크에서 숙성된 원액을 주로 사용하여 화사함을 극대화했습니다. 하이랜드 파크 고유의 헤더 피트 훈연 과정을 통해 스모키한 레이어를 입혀 곰의 강인한 이미지를 부드럽게 풀어냈습니다."}, "feature": {"강인한 곰의 유산": "바이킹 전사들의 영적 동물인 곰을 모티브로 삼아 화려한 일러스트 레이블과 스토리텔링을 자랑합니다.", "아메리칸 오크의 화사함": "버번 스타일의 오크 캐스크 영향을 받아 바닐라와 밝은 시트러스 과일 풍미가 두드러집니다.", "편안한 데일리 위스키": "부담 없는 40%의 도수로 설계되어 피트 위스키를 처음 접하는 입문자들에게 훌륭한 나침반 역할을 합니다."}}', note = '{"note": {"향 (Nose)": "향긋한 바닐라 크림과 신선한 맥아의 고소함이 먼저 퍼집니다. 뒤이어 잘 익은 노란 사과, 부드러운 진저 스파이스, 그리고 은은하게 깔리는 모닥불 연기 같은 피트 향이 조화롭게 다가옵니다.", "맛 (Palate)": "입안에서 가볍고 부드러운 질감을 줍니다. 달콤한 벌꿀과 신선한 레몬 제스트, 토스트의 고소함이 조화를 이루며 알싸한 후추와 계피 스파이스가 부드러운 타격감을 줍니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 나무 스파이스의 따뜻함, 그리고 은은하게 흩어지는 헤더 피트 스모크의 흔적이 조화롭게 마무리됩니다."}}' WHERE id = 13;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (14, '스프링뱅크 10년 100 Proof', 'single_malt', 'Springbank Whisky', 'whiskey/138112.jpg', 57.0, 10, 'active', NOW(), NOW(), 'Scotland', 'Bourbon', 700.0, 'Springbank 10 Year Old 100 Proof - 2010s 70cl', 845883, 'https://www.masterofmalt.com/whiskies/springbank/springbank-10-year-old-100-proof-2010s-whisky/?sku=138112', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 10년 100 Proof(Springbank 10 Year Old 100 Proof)는 전 세계 위스키 애호가들 사이에서 전설적인 명성을 자랑하는 캠벨타운의 상징적인 고도수 익스프레션입니다. 전통 방식의 2.5회 증류를 거쳐 생산된 무겁고 오일리한 스피릿을 영국 전통 기준인 100 Proof(57% ABV)로 물 첨가를 최소화하여 병입했습니다. 냉각 여과와 색소 첨가를 철저히 배제하여 증류소 특유의 투박하면서도 화려한 풍미를 오롯이 간직하고 있습니다.", "제조 및 숙성": "100% 수작업 플로어 몰팅으로 생산된 보리를 사용하며, 버번 캐스크와 셰리 캐스크에서 최소 10년 동안 대서양 해풍을 맞으며 숙성되었습니다. 고도수로 병입된 덕분에 캐스크의 특징과 캠벨타운 특유의 짭조름한 오일 펑크가 극대화되어 나타납니다."}, "feature": {"전설적인 100 Proof": "57%의 높은 도수에서 뿜어져 나오는 폭발적인 타격감과 농축된 풍미 레이어가 압권입니다.", "캠벨타운 오일 펑크": "스프링뱅크만의 시그니처인 아일랜드풍의 인더스트리얼 오일 펑크와 미네랄리티를 직관적으로 보여줍니다.", "타합 없는 장인 정신": "보리 발아부터 병입까지 전 과정을 한 증류소 내부에서 수작업으로 처리하여 품질의 무결성을 보장합니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 강렬한 젖은 양모, 기계 오일, 부싯돌 같은 인더스트리얼 펑크가 직관적으로 다가옵니다. 뒤이어 시트러스 껍질, 신선한 청사과, 진한 바닐라 빈과 흙내음 섞인 은은한 피트 스모크가 입체적으로 피어납니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 강렬하고 오일리한 마우스필이 일품입니다. 맥아의 달콤함과 버터스카치, 말린 살구의 맛이 묵직하게 퍼지며, 매콤한 블랙페퍼와 짭조름한 바다 소금의 맛이 스파이시하게 입안을 자극합니다.", "여운 (Finish)": "놀라울 정도로 길고 가슴 깊숙이 따뜻해지는 피날레입니다. 해풍의 짠맛과 떫지 않은 오크 스파이스, 그리고 입안 전체에 가득 깔리는 쌉싸름한 카카오와 마른 피트 재의 스모키가 짙은 흔적을 남깁니다."}}' WHERE id = 14;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (15, '스프링뱅크 10년', 'single_malt', 'Springbank Whisky', 'whiskey/2593.jpg', 46.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Springbank 10 Year Old 70cl', 101628, 'https://www.masterofmalt.com/whiskies/springbank/springbank-10-year-old-whisky/?sku=2593', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 10년(Springbank 10 Year Old)은 캠벨타운 지역 위스키의 독보적인 정체성을 전 세계에 알린 증류소의 가장 핵심적이고 위대한 웰컴 보틀입니다. 2.5회 증류라는 독특한 공법과 라이트 피트 스타일을 고수하며, 위스키가 가질 수 있는 다채로운 스펙트럼을 10년이라는 연산 안에 완벽하게 응축해 냈습니다. 46% 도수로 병입되며 비냉각여과, 내추럴 컬러를 적용해 위스키 애호가들 사이에서 항상 오픈런을 유발하는 최고의 스탠다드 싱글 몰트입니다.", "제조 및 숙성": "버번 캐스크 약 60%와 셰리 캐스크 약 40%의 정교한 비율로 숙성된 원액을 매링하여 생산합니다. 아메리칸 오크의 부드러운 단맛과 유러피안 오크의 깊고 묵직한 과일 맛이 캠벨타운 특유의 짭조름한 해풍 속에서 절묘한 하모니를 이뤄냅니다."}, "feature": {"100% 온사이트 생산": "보리 제맥부터 병입까지 모든 공정이 단 하나의 증류소 안에서 이루어지는 진정한 크래프트 위스키입니다.", "복합적인 2.5회 증류": "2회 증류의 묵직한 바디감과 3회 증류의 부드러운 세련미를 동시에 획득한 독창적인 스피릿입니다.", "최고의 밸런스 위스키": "달콤함, 스파이시함, 해풍의 짠맛, 피트 스모크가 한 보틀 안에서 기적 같은 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "향긋한 수풀 내음과 은은한 피트 연기, 싱그러운 레몬과 배의 과일 향이 어우러집니다. 그 기저에는 스프링뱅크 고유의 왁시하고 짭조름한 미네랄과 달콤한 바닐라 향이 튼튼하게 받쳐줍니다.", "맛 (Palate)": "10년 연산이라고 믿기 힘들 정도로 오일리하고 입안을 부드럽게 감쌉니다. 꿀과 맥아의 단맛이 중심을 잡고 구운 견과류의 고소함, 육두구와 생강의 알싸한 스파이스 뒤로 은은한 바다 소금의 짠맛이 뉘앙스를 더합니다.", "여운 (Finish)": "깔끔하면서도 묵직한 여운이 길게 지속됩니다. 입안을 드라이하게 정돈해 주는 오크의 풍미와 달콤한 밀랍, 그리고 향긋한 흙내음 섞인 피트 스모크의 잔향이 고급스럽게 마무리됩니다."}}' WHERE id = 15;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (16, '롱로우 피티드', 'single_malt', 'Springbank Whisky', 'whiskey/16981.jpg', 46.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Longrow Peated 70cl', 89749, 'https://www.masterofmalt.com/whiskies/springbank/longrow-peated-whisky/?sku=16981', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "롱로우 피티드(Longrow Peated)는 스프링뱅크 증류소에서 생산되는 세 가지 스타일 중 가장 강렬한 피트 스모크를 뿜어내는 헤비 피티드 싱글 몰트 위스키입니다. 아일라 섬의 피트 위스키와 경쟁하기 위해 1973년에 처음 증류되었으며, 완전히 피트 연기로만 건조한 보리를 사용해 투박하고 와일드한 서부 스코틀랜드 해안의 정취를 담았습니다. 숙성 연수를 표기하지 않은 NAS 제품으로 46%의 도수로 병입되어 순수한 피트의 파워를 증명합니다.", "제조 및 숙성": "피트 훈연 농도가 대략 48ppm에 달하는 헤비 피티드 몰트를 사용하여 전통적인 2회 증류 방식을 통해 스피릿의 묵직한 유기 화합물을 고스란히 남겨둡니다. 주로 리필 버번 캐스크에서 숙성하여 오크통의 간섭을 최소화하고 보리 본연의 고소함과 강렬한 피트 스모크 캐릭터를 전면에 내세웠습니다."}, "feature": {"헤비 피티드 및 2회 증류": "스프링뱅크의 타 라인업과 달리 완전한 2회 증류와 강한 피팅을 거쳐 극도의 스모키함을 자랑합니다.", "순수한 피트의 정수": "오크통의 영향을 절제하여 피트 연기 고유의 메디컬하고 토속적인 매력을 직관적으로 뽐냅니다.", "캠벨타운의 거친 매력": "아일라 피트와는 또 다른 캠벨타운 특유의 유기적인 기름짐과 해안가의 짠맛이 피트와 결합되었습니다."}}', note = '{"note": {"향 (Nose)": "코에 대자마자 타오르는 장작불, 강렬한 그을음, 소독약 같은 메디컬한 피트 향이 압도합니다. 이내 구운 마시멜로의 단향과 가죽, 짭조름한 해안가의 바닷바람 향이 뒤섞여 들어옵니다.", "맛 (Palate)": "오일리하면서도 드라이하고 크리미한 모순적인 텍스처입니다. 입안 가득 피트 연기가 퍼지며 맥아의 직관적인 고소함과 바닐라 캐러멜의 단맛이 은은하게 나고, 청양고추 같은 알싸한 스파이스와 소금기가 조화를 이룹니다.", "여운 (Finish)": "기반한 강력하고 오래 지속되는 스모키 피날레입니다. 입안 전체에 캠프파이어의 재와 타버린 오크통의 우디함, 쌉싸름한 에스프레소 원두의 묵직한 여운이 길고 건조하게 남습니다."}}' WHERE id = 16;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (17, '롱로우 100 Proof', 'single_malt', 'Springbank Whisky', 'whiskey/145146.jpg', 57.1, 0, 'active', NOW(), NOW(), 'Scotland', 'Wine Cask', 700.0, 'Longrow 100 Proof - Batch 2 70cl', 110091, 'https://www.masterofmalt.com/whiskies/springbank/longrow-100-proof-batch-2-whisky/?sku=145146', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "롱로우 100 Proof(Longrow 100 Proof)는 강렬한 헤비 피티드 위스키인 롱로우의 스피릿을 물을 거의 섞지 않고 영국 전통 고도수인 57% ABV로 병입한 전설적인 단종 제품이자 컬렉터들의 드림 보틀입니다. 롱로우 고유의 투박하고 기름진 감각에 강력한 알코올 볼륨감이 더해져 위스키가 보여줄 수 있는 가장 마초적이고 파워풀한 헤비 스모키의 극치를 보여주는 작품입니다.", "제조 및 숙성": "48ppm 수준으로 강하게 피팅된 보리를 사용하여 정통 2회 증류 방식으로 무겁게 증류했습니다. 주로 버번 오크통에서 10년 안팎으로 숙성된 원액들을 엄선하여 결합했으며, 고도수로 병입된 덕분에 위스키 내부의 아로마 성분들이 엉겨 붙어 압도적인 밀도를 자랑합니다."}, "feature": {"전설적인 단종 라인": "현재는 구하기가 극도로 어려운 올드 보틀로, 매니아들 사이에서 독보적인 프리미엄이 붙은 진귀한 제품입니다.", "57%의 파괴력": "헤비 피트와 고도수가 만나 입안에서 폭발적인 화력을 내뿜는 타격감 위주의 몬스터 위스키입니다.", "순수한 내추럴 퀄리티": "비냉각여과 및 내추럴 컬러를 채택하여 원액의 묵직한 침전물과 짙은 풍미 레이어를 그대로 보존했습니다."}}', note = '{"note": {"향 (Nose)": "폭발적인 타르, 아스팔트, 기계 오일과 짙은 석탄 연기의 향이 전면에 나섭니다. 뒤이어 구운 베이컨의 기름진 향과 말린 레몬 제스트, 강한 바닐라 크림과 가죽의 향이 묵직하게 조화를 이룹니다.", "맛 (Palate)": "입안을 가득 채우다 못해 조여오는 듯한 농밀하고 기름진 질감입니다. 강렬한 피트 스모크 속에서 구운 보리의 단맛과 카카오 닙스, 토피 당의 풍미가 스치며 강렬한 바다 소금의 짠맛과 통후추의 스파이시함이 혀를 때립니다.", "여운 (Finish)": "지워지지 않을 것처럼 오래 지속되는 긴 여운입니다. 묵직한 담배 연기와 시가 박스의 우디함, 타버린 장작 더미의 스모키, 그리고 마지막에 남는 쌉싸름한 다크 초콜릿의 기품 있는 미렌이 계속됩니다."}}' WHERE id = 17;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (18, '스프링뱅크 12년 CS', 'single_malt', 'Springbank Whisky', 'whiskey/143578.jpg', 55.5, 0, 'active', NOW(), NOW(), 'Scotland', 'Bourbon', 700.0, 'Springbank 12 Year Old Cask Strength - Batch 28 (2025 Release) 70cl', 122052, 'https://www.masterofmalt.com/whiskies/springbank/springbank-12-year-old-cask-strength-batch-1-2025-release-whisky/?sku=143578', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 12년 캐스크 스트렝스(Springbank 12 Year Old Cask Strength)는 매년 혹은 매 배치마다 오크통의 조합을 다채롭게 변경하며 위스키 세계에 신선한 충격을 주는 증류소의 간판 스타급 한정 배치 제품입니다. 물을 타지 않은 54%~56% 안팎의 원액 그대로 병입되어 10년 정규 제품보다 한층 깊어진 숙성미와 캐스크 스트렝스 특유의 묵직하고 폭발적인 퍼포먼스를 뽐냅니다.", "제조 및 숙성": "100% 수작업 플로어 몰팅 보리와 2.5회 증류 방식을 통해 완성된 무거운 스피릿을 기반으로 합니다. 각 배치마다 셰리 캐스크 100% 혹은 버번과 셰리의 절묘한 블렌딩 등 다양한 실험을 감행하여 숙성시키며, 캠벨타운의 거친 바닷바람 속에서 12년을 보냈습니다."}, "feature": {"매년 기다려지는 배치": "출시되는 배치 넘버마다 캐스크 비율과 도수가 달라 전 세계 위스키 애호가들이 무조건 수집하는 필수 아이템입니다.", "농축된 펑크의 정수": "높은 도수 덕분에 스프링뱅크의 아이덴티티인 기름지고 왁시한 캐릭터가 훨씬 진하고 진득하게 표현됩니다.", "완벽한 크래프트 위스키": "냉각 여과 및 색소 첨가 없는 순수한 상태로 병입되어 탁월한 구조감과 질감을 보장합니다."}}', note = '{"note": {"향 (Nose)": "진한 버터스카치와 캐러멜, 졸인 자두의 묵직한 달콤함이 피어오르고, 이내 기계 오일, 부싯돌, 미네랄의 인더스트리얼 펑크가 중심을 잡습니다. 가벼운 흙내음의 피트 스모크와 시나몬 향이 입체감을 줍니다.", "맛 (Palate)": "혓바닥을 진득하게 코팅하는 농밀하고 오일리한 풀바디 텍스처입니다. 다크 초콜릿에 절인 건포도와 꿀의 진한 단맛이 밀려오고, 뒤이어 짭조름한 바다 소금의 풍미와 으깬 통후추, 정제된 구운 오크의 훌륭한 타격감이 이어집니다.", "여운 (Finish)": "온몸을 짜릿하게 데워주는 극도로 긴 여운입니다. 농축된 셰리의 단맛과 가죽 향이 가라앉으며, 입안 전체를 계속 감싸는 은은하고 향긋한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 18;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (19, '헤이즐번 10년', 'single_malt', 'Springbank Whisky', 'whiskey/35189.jpg', 46.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Hazelburn 10 Year Old 70cl', 101628, 'https://www.masterofmalt.com/whiskies/springbank/hazelburn-10-year-old-whisky/?sku=35189', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "헤이즐번 10년(Hazelburn 10 Year Old)은 스프링뱅크 증류소에서 생산되는 세 가지 스타일 중 가장 부드럽고 화사한 매력을 자랑하는 트리플 디스틸드(3회 증류) 논피티드(Non-peated) 싱글 몰트 위스키입니다. 피트를 전혀 사용하지 않고 오직 열풍으로만 건조한 보리를 사용하여 탄생했으며, 1925년에 폐업한 캠벨타운의 전설적인 헤이즐번 증류소를 오마주하여 명맥을 잇고 있습니다. 46% 도수로 병입되며 섬세하고 우아한 풍미의 정수를 보여줍니다.", "제조 및 숙성": "피트 연기가 닿지 않은 순수한 몰트를 사용하며, 로우랜드 스타일과 유사한 정밀한 3회 증류 공정을 거쳐 가볍고 화사한 스피릿을 뽑아냅니다. 이 맑고 깨끗한 원액을 100% 퍼스트 필 버번 오크통에서 10년 동안 숙성시켜 아메리칸 오크 본연의 이국적인 달콤함을 극대화했습니다."}, "feature": {"3회 증류와 논피트": "피트 스모크를 완전히 배제하고 3번 증류하여 스프링뱅크 라인업 중 가장 부드럽고 가벼운 텍스처를 지닙니다.", "100% 퍼스트 필 버번 캐스크": "최고급 버번 오크통의 영향으로 밝은 골드 빛깔과 함께 꿀, 바닐라 고유의 달콤함을 선사합니다.", "반전의 캠벨타운 DNA": "화사하고 가벼운 화이트 플라워 느낌 속에서도 캠벨타운 특유의 미세한 오일리함과 짭조름함이 숨어있어 깊이를 더합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 싱그럽습니다. 갓 구운 바닐라 포드, 부드러운 캐러멜 당, 그리고 신선한 배와 레몬의 시트러스 향이 향긋하게 피어납니다. 뒤이어 가벼운 구운 견과류의 고소함과 은은한 화이트 플라워의 아로마가 감돕니다.", "맛 (Palate)": "실크처럼 부드럽고 가벼운 크림 같은 마우스필이 돋보입니다. 달콤한 꿀을 바른 밀크 초콜릿, 달콤한 밤잼, 잘 익은 사과의 풍미가 느껴지며 은은한 우드 스파이스와 미세한 소금기가 훌륭한 레이어를 이룹니다.", "여운 (Finish)": "깔끔하면서도 우아한 여운이 지속됩니다. 오크통에서 배어 나온 부드러운 바닐라의 단맛과 가벼운 생강 스파이스의 흔적이 입안을 산뜻하고 따뜻하게 정돈해 줍니다."}}' WHERE id = 19;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (20, '스프링뱅크 15년', 'single_malt', 'Springbank Whisky', 'whiskey/2595.jpg', 46.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Springbank 15 Year Old 70cl', 135518, 'https://www.masterofmalt.com/whiskies/springbank-15-year-old-whisky/?sku=2595', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 15년(Springbank 15 Year Old)은 셰리 오크통 숙성의 진수를 보여주는 제품으로, 증류소 정규 라인업 중 가장 묵직하고 달콤하며 진득한 풍미를 자랑하는 클래식 명작입니다. 10년 제품의 화사한 밸런스에 기품 있는 숙성미를 더했으며, 셰리 와인의 깊은 풍미와 스프링뱅크 특유의 투박한 개성이 가장 완벽하게 도킹한 결과물입니다. 46% 도수로 병입되며 전 세계적으로 매년 조기 품절을 기록하는 소장 가치 높은 위스키입니다.", "제조 및 숙성": "100% 수작업 플로어 몰팅 보리를 사용하여 2.5회 증류한 스피릿을 최고급 100% 셰리 오크통에서 최소 15년 이상 장기 숙성시켰습니다. 캠벨타운의 축축한 해안 창고에서 오랜 세월 오크통과 원액이 숨을 쉬며 다크 초콜릿 빛의 내추럴 컬러를 획득했습니다."}, "feature": {"100% 셰리 오크 숙성": "리필 및 퍼스트 필 셰리 캐스크만을 사용하여 진하고 어두운 과일 풍미와 묵직한 바디감을 완성했습니다.", "기품 있는 다크 프로파일": "스프링뱅크의 인더스트리얼 오일 펑크가 셰리의 단맛과 결합하여 마치 건포도를 오일에 절인 듯한 깊은 맛을 냅니다.", "시간의 세련미": "15년의 세월 동안 스피릿의 튀는 스파이스가 둥글게 깎여 나가 극상의 묵직함과 부드러움을 동시에 제공합니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 가득 차오릅니다. 토피 당, 말린 무화과, 건포도의 깊은 셰리 향이 지배적이며, 그 뒤로 달콤한 캐러멜과 오래된 가죽, 그리고 스프링뱅크 고유의 짭조름한 해풍와 부드러운 흙내음의 피트 향이 레이어를 이룹니다.", "맛 (Palate)": "오일리하고 묵직하게 입안을 가득 채우는 풀바디의 강렬함이 느껴집니다. 다크 초콜릿, 구운 아몬드, 가득 졸인 설탕 시럽의 단맛이 파도처럼 밀려오고 오크통의 시나몬 스파이스와 정제된 소금기가 입안을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 아주 길게 이어집니다. 달콤한 말린 과일의 단맛과 쌉싸름한 에스프레소의 잔향 뒤로 구운 오크의 향, 그리고 잔잔한 캠프파이어의 연기 같은 피트 스모크가 오랜 흔적을 남깁니다."}}' WHERE id = 20;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (21, '헤이즐번 21년', 'single_malt', 'Springbank Whisky', 'whiskey/117711.jpg', 46.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Hazelburn 21 Year Old 70cl', 845883, 'https://www.masterofmalt.com/whiskies/springbank/hazelburn-21-year-old-whisky/?sku=117711', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "헤이즐번 21년(Hazelburn 21 Year Old)은 스프링뱅크 증류소에서 생산되는 트리플 디스틸드(3회 증류) 논피티드 라인업의 최고 정점에 위치한 고연산 익스프레션입니다. 피트를 완전히 배제하여 몰트 본연의 화사함과 우아함을 간직한 스피릿이 20년이 넘는 기나긴 숙성 기간을 거쳐 극상의 부드러움을 획득했습니다. 매년 한정 수량만 출시되어 위스키 애호가들 사이에서 독보적인 소장 가치를 인정받는 46% 도수의 플래그십 싱글 몰트 위스키입니다.", "제조 및 숙성": "피트를 사용하지 않고 오직 열풍으로만 건조한 보리를 사용하고, 로우랜드 스타일의 정밀한 3회 증류 공정을 통해 가볍고 화사한 스피릿을 뽑아냅니다. 이후 마스터 블렌더의 치밀한 설계 아래 선별된 버번 캐스크와 셰리 캐스크, 그리고 일부 포트 캐스크 원액을 정교하게 블렌딩하여 캠벨타운의 축축한 던지 창고에서 21년간 숙성시켰습니다."}, "feature": {"트리플 디스틸드의 정점": "피트 스모크를 배제하고 3번 증류하여 완성할 수 있는 가장 섬세하고 부드러운 고연산의 텍스처를 구현했습니다.", "다채로운 캐스크의 조화": "버번과 셰리, 포트 캐스크의 정수가 오랜 세월 동안 상호 작용하며 다층적인 복합미를 형성합니다.", "귀족적인 희소성": "증류소 내에서도 원액 재고가 극히 한정되어 전 세계 위스키 컬렉터들이 가장 갈망하는 제품 중 하나입니다."}}', note = '{"note": {"향 (Nose)": "잘 익은 열대 과일과 파인애플 시럽, 부드러운 가죽의 향이 고풍스럽게 피어오릅니다. 뒤이어 꿀에 절인 대추야자, 진한 바닐라 빈, 그리고 섬세한 진저브레드의 스파이스가 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크를 입에 머금은 듯 극도로 부드럽고 둥근 마우스필이 압권입니다. 크리미한 밀크 초콜릿, 졸인 맥아당의 단맛이 중심을 잡고 구운 피칸의 고소함과 육두구, 부드러운 오크통의 우디함이 우아하게 전개됩니다.", "여운 (Finish)": "우아하고 귀족적인 잔향이 아주 길게 지속됩니다. 은은한 오렌지 오일과 바닐라 캐러멜의 흔적 뒤로 계피의 따뜻함, 그리고 깔끔하게 정제된 미세한 소금기가 긴 여운을 선사합니다."}}' WHERE id = 21;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (22, '스프링뱅크 21년', 'single_malt', 'Springbank Whisky', 'whiskey/142259.jpg', 46.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Springbank 21 Year Old (2025 Release) 70cl', 474641, 'https://www.masterofmalt.com/whiskies/springbank/springbank-21-year-old-2025-release-whisky/?sku=142259', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 21년(Springbank 21 Year Old)은 전 세계 위스키 매니아들 사이에서 싱글 몰트의 마스터피스로 손꼽히는 전설적인 고연산 위스키입니다. 2.5회 증류와 라이트 피트라는 증류소 고유의 개성이 21년이라는 장구한 세월 속에서 어떻게 진화하는지 완벽하게 증명하는 제품입니다. 매년 출시되는 배치마다 캐스크 구성을 다채롭게 가져가며, 46% 도수에 내추럴 컬러, 비냉각여과로 병입되어 독보적인 레이어를 뽐냅니다.", "제조 및 숙성": "보리의 발아부터 병입까지 전 과정을 증류소 내부에서 100% 전통 수작업으로 진행합니다. 버번 캐스크와 셰리 캐스크를 기반으로 삼고, 포트 와인 캐스크나 럼 캐스크 등을 정교하게 혼합 및 매링하여 복합미를 극대화합니다. 캠벨타운 특유의 축축하고 짭조름한 해풍 속에서 오랜 세월 숙성되었습니다."}, "feature": {"장인의 마스터피스": "장기 숙성을 통해 스프링뱅크 고유의 인더스트리얼 오일 펑크가 극도로 부드럽고 정교하게 다듬어졌습니다.", "배치별 캐스크 실험": "출시되는 해마다 마스터 블렌더의 캐스크 비율 실험이 감행되어 위스키 평론가들에게 항상 최고의 화두가 됩니다.", "완벽한 구조감": "단 하나의 맛도 튀지 않으며, 단맛, 짠맛, 스모키함이 거대한 오케스트라처럼 정교한 조화를 이룹니다."}}', note = '{"note": {"향 (Nose)": "숙성된 오크의 묵직함과 다크 초콜릿, 오래된 시가 박스의 향이 깊게 퍼집니다. 뒤이어 잘 익은 청자두와 살구, 달콤한 밤꿀의 향과 함께 스프링뱅크 특유의 왁시하고 짭조름한 미네랄 향이 고급스럽게 얹어집니다.", "맛 (Palate)": "농밀하고 오일리하게 입안을 가득 채웁니다. 건포도와 무화과 잼의 진한 단맛이 밀려오고, 고소한 구운 호두의 풍미 뒤로 블랙페퍼와 생강 편강의 알싸한 스파이스, 그리고 짭조름한 해풍의 맛이 혀를 자극합니다.", "여운 (Finish)": "가슴 속까지 스며드는 극도로 길고 우아한 피날레입니다. 달콤한 셰리의 흔적과 함께 고급 시가 연기 같은 부드러운 피트 스모크, 그리고 입안에 맴도는 쌉싸름한 카카오의 여운이 길게 이어집니다."}}' WHERE id = 22;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (23, '롱로우 21년', 'single_malt', 'Springbank Whisky', 'whiskey/95976.jpg', 46.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Longrow 21 Year Old 70cl', 449213, 'https://www.masterofmalt.com/whiskies/springbank/longrow-21-year-old-whisky/?sku=95976', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "롱로우 21년(Longrow 21 Year Old)은 스프링뱅크 증류소의 헤비 피티드 라인업인 롱로우의 최상위 정규 고연산 위스키입니다. 거칠고 와일드한 2회 증류의 헤비 피트 스피릿이 21년이라는 세월을 만나면서 경이로울 정도로 부드럽고 세련되게 진화한 명작입니다. 46% 도수로 병입되며, 전 세계적으로 생산량이 극도로 적어 구하기가 매우 어려운 희귀 보틀입니다.", "제조 및 숙성": "피트 연기로만 100% 건조한 헤비 피티드 몰트(48ppm)를 사용하여 전통적인 2회 증류 방식을 거쳐 묵직한 바디감을 완성합니다. 유러피안 오크 셰리 캐스크와 아메리칸 오크 버번 캐스크의 정교한 비율로 21년 동안 장기 숙성시켜, 피트의 날카로운 발톱을 무디게 만들고 셰리의 녹진함을 입혔습니다."}, "feature": {"헤비 피트의 세련된 진화": "젊은 연산의 투박한 탄내와 장작 그을음이 21년의 세월을 거치며 귀족적인 스모키 아로마로 탈바꿈했습니다.", "셰리 캐스크의 묵직한 영향": "고급 유러피안 셰리 오크통 숙성을 통해 짙은 컬러감과 녹진한 다크 프루트 풍미를 깊숙이 확보했습니다.", "최상위 클래스의 희소성": "롱로우 정규 라인업 중 가장 긴 연산으로, 출시될 때마다 전 세계 위스키 매니아들의 핵심 타겟이 됩니다."}}', note = '{"note": {"향 (Nose)": "오래된 캠프파이어의 재, 타르, 고급 가죽의 묵직한 향이 코를 감쌉니다. 뒤이어 흑설탕에 졸인 무화과, 건포도, 베리류 잼의 단향과 함께 짭조름한 훈제 베이컨의 기름진 뉘앙스가 깊이를 더합니다.", "맛 (Palate)": "입안을 진득하게 코팅하는 농밀하고 풀바디한 질감입니다. 진한 다크 초콜릿과 구운 피칸, 캐러멜 시럽의 단맛이 파도처럼 밀려오고, 통후추의 알싸함과 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "경이로울 정도로 길고 드라이한 여운입니다. 입안 전체를 지배하는 짙은 시가 연기와 묵직한 오크의 우디함, 그리고 마지막에 남는 달콤한 말린 과일과 쌉싸름한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 23;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (24, '롱로우 18년', 'single_malt', 'Springbank Whisky', 'whiskey/9976.jpg', 46.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Longrow 18 Year Old 70cl', 194937, 'https://www.masterofmalt.com/whiskies/longrow-18-year-old-whisky/?sku=9976', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "롱로우 18년(Longrow 18 Year Old)은 대담하고 강력한 헤비 피트 캐릭터와 중후한 오크통 숙성미가 가장 역동적인 지점에서 만난 프리미엄 싱글 몰트 위스키입니다. 아일라 피트와 차별화되는 캠벨타운 피트 특유의 투박하고 기름진 개성이 18년의 세월 동안 캐스크 속에서 완벽하게 숙성되었습니다. 46% 도수로 병입되며 매년 한정 수량만 출시되는 고품격 위스키입니다.", "제조 및 숙성": "완전 피트 건조 보리를 전통적인 2회 증류를 통해 무거운 유기 화합물을 가득 담아 증류합니다. 이후 퍼스트 필 및 리필 유러피안 셰리 캐스크와 아메리칸 버번 캐스크를 매 배치마다 마스터 블렌더의 정교한 감각으로 조합하여 대서양 해풍을 맞으며 18년간 숙성시켰습니다."}, "feature": {"강렬함과 묵직함의 조화": "100% 피트 훈연 보리의 강한 스모키함이 18년 오크 숙성의 깊은 우디함 및 탄닌과 균형을 이룹니다.", "캠벨타운 해안의 개성": "숙성 창고에 스며든 해풍의 영향으로 특유의 짭조름하고 기름진 펑크가 피트 캐릭터와 고스란히 결합되었습니다.", "순수한 크래프트 정신": "냉각 여과 및 색소 첨가를 철저히 배제하여 위스키가 가진 본연의 묵직한 질감과 복합적인 레이어를 유지합니다."}}', note = '{"note": {"향 (Nose)": "기분 좋은 훈제 향과 젖은 장작, 가죽 향이 먼저 피어오릅니다. 그 뒤로 잘 익은 사과, 말린 오렌지 껍질, 달콤한 캐러멜 토피와 흑설탕의 묵직한 단 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "오일리하고 진득한 마우스필이 특징입니다. 쌉싸름한 에스프레소와 다크 초콜릿, 졸인 자두의 단맛이 중심을 잡고, 구운 생강과 육두구의 스파이스, 그리고 해안가 특유의 짭조름한 바다 소금 풍미가 입안을 가득 채웁니다.", "여운 (Finish)": "묵직하고 따뜻한 여운이 길게 이어집니다. 타버린 오크통의 우디한 향과 담배 연기 같은 진한 피트 스모크, 그리고 마지막에 남는 달콤한 마지팬의 흔적이 인상적인 피날레를 장식합니다."}}' WHERE id = 24;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (25, '스프링뱅크 18년', 'single_malt', 'Springbank Whisky', 'whiskey/143404.jpg', 46.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Springbank 18 Year Old - 2010s 70cl', 845883, 'https://www.masterofmalt.com/whiskies/springbank/springbank-18-year-old-2010s-whisky/?sku=143404', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 18년(Springbank 18 Year Old)은 증류소의 정규 코어 라인업 중 가장 세련되고 완벽한 균형미를 자랑하는 품격 있는 익스프레션입니다. 100% 수작업 플로어 몰팅과 2.5회 증류라는 독창적인 공법으로 완성된 원액이 약 20년에 가까운 세월 동안 천천히 호흡하며 캠벨타운의 거친 바닷바람 속에서 숙성되었습니다. 46% 도수로 병입되며, 셰리 캐스크의 묵직함과 스프링뱅크 특유의 개성이 가장 아름답게 결합된 정석적인 위스키입니다.", "제조 및 숙성": "매년 출시되는 배치에 따라 차이가 있지만, 주로 고품질의 유러피안 셰리 오크통 비율을 매우 높게 가져가며, 아메리칸 버번 캐스크 원액을 정교하게 결합합니다. 오랜 시간 동안 원액이 오크통의 성분을 흡수하여 깊고 고풍스러운 내추럴 골드 빛을 띱니다."}, "feature": {"셰리 중심의 우아함": "셰리 캐스크의 깊은 영향으로 진한 말린 과일의 단맛과 묵직한 바디감이 전면에 도드라집니다.", "시간이 공들인 밸런스": "젊은 연산의 거친 오일 펑크는 부드럽게 가라앉고, 세련되고 복합적인 아로마 레이어가 완성되었습니다.", "장인 정신의 결정체": "제맥부터 병입까지의 전 과정이 단 하나의 증류소에서 수작업으로 이루어진 진정한 크래프트의 정수입니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마입니다. 말린 무화과와 건포도, 달콤한 마지팬 향이 먼저 다가오고, 이내 오래된 가죽, 던지 창고 고유의 흙내음, 은은한 미네랄과 부드러운 피트 스모크가 기품 있게 어우러집니다.", "맛 (Palate)": "풀바디의 오일리하고 매끄러운 텍스처입니다. 다크 초콜릿, 졸인 살구, 스파이스 와인의 단맛이 입안을 코팅하고 구운 아몬드의 고소함과 블랙페퍼, 육두구의 알싸함, 바다 소금의 짠맛이 정교한 레이어를 만듭니다.", "여운 (Finish)": "놀라울 정도로 길고 드라이하면서도 우아합니다. 달콤한 셰리의 여운이 가라앉으며 기품 있는 오크의 향, 그리고 입안 전체를 계속 감싸는 은은하고 향긋한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 25;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (26, '스프링뱅크 25년', 'single_malt', 'Springbank Whisky', 'whiskey/133968.jpg', 46.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Springbank 25 Year Old (2024 Release) 70cl', 864537, 'https://www.masterofmalt.com/whiskies/springbank/springbank-25-year-old-2024-release-whisky/?sku=133968', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "스프링뱅크 25년(Springbank 25 Year Old)은 위스키 평론가들과 컬렉터들 사이에서 싱글 몰트 위스키가 도달할 수 있는 신비의 경지라고 일컬어지는 최고급 울트라 프리미엄 익스프레션입니다. 한 세기의 4분의 1에 달하는 세월 동안 천천히 증발하고 응축되는 과정을 거쳐 타협 없는 완성도를 획득했습니다. 매년 극소량만 한정 생산되어 전 세계적으로 추첨제로만 구할 수 있는 진귀한 주류입니다.", "제조 및 숙성": "최상급 셰리 캐스크와 버번 캐스크에서 20년 이상 숙성된 원액들을 블렌딩한 후, 마지막 단계에서 최고급 포트 와인 캐스크 등에서 추가 매링 과정을 거쳐 복합미를 극대화합니다. 46% 도수로 병입되며 위스키가 가질 수 있는 가장 귀족적인 아우라를 뿜어냅니다."}, "feature": {"울트라 프리미엄 라인": "스프링뱅크 정규 라인업 중 가장 높은 연산에 속하는 독보적인 마스터피스입니다.", "경이로운 복합미": "셰리의 단맛, 버번의 바닐라, 포트의 베리류 풍미와 캠벨타운 해풍의 짠맛이 완벽한 구도를 이룹니다.", "시간의 마술": "25년의 기나긴 숙성 기간을 거쳐 날카로운 알코올은 완벽히 정제되고, 극상의 깊이감과 부드러움만 남았습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 흑설탕에 졸인 자두, 무화과 잼의 진한 향이 퍼지고, 뒤이어 고급스러운 가죽 책, 정제된 밀랍, 그리고 미풍처럼 부드러운 흙내음 섞인 피트 향이 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 실크처럼 매끄러운 텍스처입니다. 다크 초콜릿 파이, 구운 호두의 고소함과 함께 잘 익은 체리의 풍미가 느껴지며, 토피 당과 시나몬, 육두구 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 포트 와인의 단맛 뒤로 시가 박스의 우디한 향, 정제된 바다 소금의 흔적, 그리고 은은하게 피어오르는 최고급 헤더 피트의 잔향이 끝없이 맴봅니다."}}' WHERE id = 26;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (27, '보모어 15년', 'single_malt', 'Bowmore Whisky', 'whiskey/1855.jpg', 43.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bowmore 15 Year Old 70cl', 125159, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-15-year-old-whisky/?sku=1855', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 15년(Bowmore 15 Year Old)은 아일라 섬에서 가장 오래된 증류소인 보모어의 아이덴티티인 우아한 피트와 셰리 캐스크의 단맛이 가장 완벽하게 결합된 베스트셀러 익스프레션입니다. 보모어 특유의 과일 향 가득한 미디엄 피트 스피릿이 셰리 오크통의 옷을 입어 한층 진하고 달콤한 매력을 뽐냅니다. 43% 도수로 병입되며 입문자부터 매니아까지 모두를 만족시키는 훌륭한 밸런스를 지니고 있습니다.", "제조 및 숙성": "아메리칸 버번 캐스크에서 최초 12년 동안 숙성된 원액을 엄선한 후, 최고급 오로로소 셰리 캐스크(Oloroso Sherry Casks)로 옮겨 담아 마지막 3년 동안 집중적인 피니시 숙성을 거쳤습니다. 이 과정을 통해 보모어 고유의 화사한 스모키함에 셰리의 짙은 다크 초콜릿 빛과 단맛이 깊게 배어듭니다."}, "feature": {"오로로소 셰리 피니시": "마지막 3년간의 집중 셰리 숙성을 통해 매혹적인 건포도와 다크 초콜릿 풍미를 확실하게 획득했습니다.", "우아한 미디엄 피트": "아일라 섬의 강렬하고 메디컬한 피트와 달리, 보모어 특유의 부드럽고 화사한 스모키 밸런스를 보여줍니다.", "다크 하모니": "버번 캐스크의 바닐라 기저 위에 셰리의 묵직한 과일 맛과 스모크가 완벽한 대칭을 이룹니다."}}', note = '{"note": {"향 (Nose)": "진한 캐러멜 토피와 건포도, 달콤한 대추야자의 향이 부드럽게 다가옵니다. 그 뒤로 보모어 특유의 화사하고 은은한 미디엄 피트 스모크와 시트러스 껍질의 싱그러움이 조화를 이룹니다.", "맛 (Palate)": "크리미하고 진득한 질감이 특징입니다. 입안 가득 퍼지는 다크 초콜릿과 무화과 잼의 달콤함 뒤로, 따뜻한 시나몬과 구운 생강의 오크 스파이스가 셰리의 단맛을 우아하게 받쳐줍니다.", "여운 (Finish)": "온화하고 묵직한 여운이 길게 이어집니다. 달콤한 셰리의 단맛과 시트러스 오일의 잔향이 가라앉으며, 향긋하고 드라이한 타오르는 장작 연기 같은 피트 스모크의 여운이 기분 좋게 남습니다."}}' WHERE id = 27;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (28, '보모어 18년', 'single_malt', 'Bowmore Whisky', 'whiskey/1857.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bowmore 18 Year Old 70cl', 218348, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-18-year-old-whisky/?sku=1857', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 18년(Bowmore 18 Year Old)은 아일라 싱글 몰트 중에서도 가장 귀족적이고 품격 있는 우아함을 자랑하는 고연산 정규 라인업입니다. 18년이라는 오랜 세월 동안 전설적인 보모어의 바다 창고(No.1 Vaults)에서 서서히 숙성되어 위스키의 자극적인 면은 완전히 정제되었습니다. 43% 도수로 병입되며, 아일라 피트의 정교함과 과일의 단맛이 완벽한 조화를 이룬 마스터피스입니다.", "제조 및 숙성": "마스터 블렌더가 엄선한 최고급 오로로소 셰리 캐스크와 버번 캐스크에서 거의 두 세대에 가까운 18년 동안 장기 숙성시켰습니다. 보모어 특유의 부드러운 미디엄 피트 원액이 오랜 세월을 거치며 오크통의 풍미와 완벽히 동화되어 깊고 풍부한 에스테르를 형성했습니다."}, "feature": {"귀족적인 아일라 피트": "강한 타격감 대신 입안을 부드럽게 감싸는 극상의 세련된 스모키 밸런스를 보여줍니다.", "No.1 Vaults의 유산": "해수면 아래 위치한 유서 깊은 숙성 창고에서 오랜 세월 숙성되어 해풍의 은은한 미네랄리티를 품고 있습니다.", "완벽에 가까운 하모니": "숙성된 과일의 단맛과 카카오의 쌉싸름함, 은은한 피트 연기가 독보적인 구조감을 만듭니다."}}', note = '{"note": {"향 (Nose)": "우아하고 복합적인 아로마입니다. 흑설탕에 졸인 자두와 잘 익은 체리, 풍부한 크리미 토피 향이 피어오르고, 그 밑바닥에 부드러운 가죽 향과 잔잔한 바다의 미네랄 해풍, 정제된 피트 스모크가 아름답게 깔립니다.", "맛 (Palate)": "벨벳처럼 부드럽고 매끄럽게 혀를 감쌉니다. 진한 꿀과 다크 초콜릿, 말린 무화과의 단맛이 기품 있게 전개되며, 은은한 오크통의 시나몬 스파이스와 구운 견과류의 고소함이 조화를 이룹니다.", "여운 (Finish)": "끝없이 길고 아름다운 여운를 선사합니다. 농축된 단맛 뒤로 부드러운 오크의 풍미, 에스프레소의 잔향, 그리고 마치 미풍처럼 불어오는 잔잔한 캠프파이어의 연기 같은 피트 스모크가 오래도록 남습니다."}}' WHERE id = 28;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (29, '보모어 12년', 'single_malt', 'Bowmore Whisky', 'whiskey/1854.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bowmore 12 Year Old 70cl', 61848, 'https://www.masterofmalt.com/whiskies/bowmore-12-year-old-whisky/?sku=1854', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 12년(Bowmore 12 Year Old)은 아일라 섬의 심장부에서 생산되는 보모어 증류소의 가장 대표적이자 정석적인 엔트리 싱글 몰트 위스키입니다. 아일라 피트 위스키의 강렬한 소독약 향에 거부감이 있는 입문자들에게 가장 완벽한 가이드라인을 제시하는 제품으로 유명합니다. 과일의 단맛과 해풍의 짭조름함, 그리고 은은한 스모키함이 40% 도수 안에서 훌륭한 육각형의 밸런스를 이루고 있습니다.", "제조 및 숙성": "보모어 증류소 특유의 전통 플로어 몰팅 보리를 일부 사용하며, 아메리칸 버번 캐스크와 유러피안 셰리 캐스크의 원액을 조화롭게 블렌딩하여 12년간 숙성했습니다. 이 과정을 통해 아일라 피트 특유의 본질을 잃지 않으면서도 대중적인 화사함을 획득했습니다."}, "feature": {"아일라 피트의 나침반": "피트 스모키와 과일 단맛의 밸런스가 매우 뛰어나 피트 입문자들에게 교과서로 통합니다.", "화사한 시트러스 밸런스": "강한 타르 향 대신 밝은 시트러스 과일 풍미와 부드러운 연기 향이 돋보입니다.", "뛰어난 접근성": "부담 없는 가격대에서 아일라 전통 증류소의 크래프트 DNA와 세련된 풍미를 고스란히 맛볼 수 있습니다."}}', note = '{"note": {"향 (Nose)": "상큼한 레몬 제스트와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 뒤이어 보모어 특유의 은은하고 화사한 미디엄 피트 스모크와 해안가의 짭조름한 바닷바람 향이 은은하게 조화를 이룹니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감쌉니다. 벌꿀 집의 달콤함과 잘 익은 다크 프루트의 뉘앙스가 퍼지고, 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 후추 스파이스가 기분 좋은 타격감을 줍니다.", "여운 (Finish)": "깔끔하면서도 긴 여운을 남깁니다. 은은한 오크의 풍미와 달콤한 과일 향이 가라앉으며, 입안에 향긋하게 머무는 드라이한 피트 재의 연기 잔향이 매력적으로 마무리됩니다."}}' WHERE id = 29;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (30, '보모어 15년 셰리 오크', 'single_malt', 'Bowmore Whisky', 'whiskey/138786.jpg', 43.0, 15, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Bowmore 15 Year Old Sherry Oak 70cl', 152255, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-15-year-old-sherry-oak-whisky/?sku=138786', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 15년 셰리 오크 캐스크(Bowmore 15 Year Old Sherry Oak Casks)는 셰리 오크통 숙성이 선사할 수 있는 가장 짙고 매혹적인 달콤함을 극대화한 보모어 라인업의 명작입니다. 보모어 특유의 화사한 미디엄 피트 스피릿이 퍼스트 필 오로로소 셰리 캐스크의 강력한 영향을 받아, 마치 건포도와 다크 초콜릿을 피트 연기로 훈연한 듯한 독창적인 결과물로 탄생한 43% 도수의 위스키입니다.", "제조 및 숙성": "아메리칸 버번 캐스크에서 숙성된 원액을 기반으로, 엄선된 최고급 퍼스트 필 오로로소 셰리 캐스크(First-fill Oloroso Sherry Casks)에서 마지막 3년 이상 집중적인 셰리 피니시 숙성 과정을 거쳤습니다. 이 정교한 과정을 통해 위스키 원액은 짙은 마호가니 빛 내추럴 컬러와 진득한 밀도를 획득했습니다."}, "feature": {"진하고 깊은 셰리의 영향": "퍼스트 필 오로로소 캐스크의 깊은 영향으로 건포도, 무화과, 캐러멜 토피의 단맛이 압권입니다.", "환상적인 다크 하모니": "보모어 고유의 우수한 피트 스모크가 진득한 셰리의 달콤함과 만나 완벽한 대조와 조화를 이룹니다.", "묵직한 바디감": "엔트리 라인업보다 훨씬 묵직하고 진득한 질감을 제공하여 만족도가 매우 높은 위스키입니다."}}', note = '{"note": {"향 (Nose)": "농밀한 캐러멜 토피와 진한 건포도, 졸인 자두 잼의 달콤함이 가득 피어오릅니다. 그 깊은 단 향 뒤로 보모어 고유의 화사하고 달콤한 피트 스모크와 오래된 시가 박스, 삼나무의 고풍스러운 향이 겹겹이 어우러집니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 훌륭한 풀바디 텍스처입니다. 다크 초콜릿과 무화과, 대추야자의 진한 단맛이 파도처럼 밀려오고, 시나몬 가루와 구운 생강, 그리고 바다 소금의 미세한 짭조름함이 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 아주 길게 지속되는 피날레입니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며, 입안 전체를 묵직하게 채우는 드라이하고 향긋한 캠프파이어의 연기 향이 긴 여운을 선사합니다."}}' WHERE id = 30;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (31, '보모어 18년 셰리 오크', 'single_malt', 'Bowmore Whisky', 'whiskey/138787.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Bowmore 18 Year Old Sherry Oak 70cl', 277495, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-18-year-old-sherry-oak-whisky/?sku=138787', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 18년 셰리 오크(Bowmore 18 Year Old Sherry Oak)는 아일라 싱글 몰트의 귀족이라 불리는 보모어 고연산 스피릿에 최고급 셰리 캐스크의 풍미를 더욱 진하게 입힌 럭셔리 익스프레션입니다. 보모어 특유의 부드럽고 화사한 미디엄 피트 원액이 18년이라는 오랜 세월 동안 깊이감을 획득했으며, 셰리 오크통과의 정교한 만남을 통해 한층 더 중후하고 깊은 풍미를 완성했습니다. 43% 도수로 병입되어 완벽에 가까운 세련미를 뽐냅니다.", "제조 및 숙성": "보모어의 유서 깊은 해수면 아래 창고인 \'No. 1 Vaults\'에서 18년 동안 장기 숙성되었습니다. 엄선된 올로로소 및 페드로 히메네스 셰리 캐스크에서 원액이 천천히 호흡하며 오크통의 달콤한 과일 향과 타닌을 완벽하게 흡수하여 짙은 마호가니 빛을 띱니다."}, "feature": {"더블 셰리 숙성의 미학": "올로로소와 페드로 히메네스 셰리 캐스크의 조합이 선사하는 진득한 건포도와 초콜릿의 단맛이 압권입니다.", "시간이 공들인 부드러움": "18년의 세월 동안 피트의 날카로움은 완벽히 정제되고, 극상의 실키한 마우스필만 남았습니다.", "기품 있는 바다의 정취": "No. 1 Vaults에서 스며든 은은한 해풍의 짭조름함이 셰리의 단맛과 조화롭게 공존합니다."}}', note = '{"note": {"향 (Nose)": "진한 흑설탕에 졸인 무화과, 건포도, 달콤한 토피 향이 지배적으로 피어오릅니다. 그 뒤로 기품 있는 오래된 가죽, 시가 박스의 우디함, 그리고 보모어 특유의 잔잔하고 화사한 미디엄 피트 스모크 향이 우아하게 감쌉니다.", "맛 (Palate)": "벨벳이나 실크처럼 부드럽고 묵직한 질감이 입안을 가득 채웁니다. 다크 초콜릿, 럼에 절인 과일 퓨레의 진한 단맛이 퍼지고, 뒤이어 시나몬, 육두구의 알싸한 오크 스파이스와 은은한 소금기가 정교한 하모니를 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 여운입니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며, 입안 전체를 묵직하게 채우는 드라이하고 향긋한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 31;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (32, '보모어 12년 셰리 오크', 'single_malt', 'Bowmore Whisky', 'whiskey/138785.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Bowmore 12 Year Old Sherry Oak 70cl', 94692, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-12-year-old-sherry-oak-whisky/?sku=138785', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 12년 셰리 오크(Bowmore 12 Year Old Sherry Oak)는 보모어의 베스트셀러인 12년 제품의 핵심 캐릭터에 셰리 캐스크의 달콤함을 더해 출시된 매력적인 라인업입니다. 아일라 피트를 처음 접하는 입문자들에게 친숙한 보모어 특유의 화사한 스모키함에 진득한 과일 풍미를 입혀 훌륭한 육각형의 밸런스를 보여주며, 40% 도수로 편안하게 즐기기 좋은 위스키입니다.", "제조 및 숙성": "아메리칸 버번 캐스크에서 숙성된 보모어의 전통적인 원액을 엄선한 후, 최고급 셰리 오크통에서 피니시 숙성을 거치거나 블렌딩 비율을 조율하여 생산합니다. 아일라 섬의 해풍을 맞으며 12년 동안 균형 잡힌 숙성 과정을 거쳤습니다."}, "feature": {"셰리의 달콤한 터치": "엔트리 라인업의 화사한 시트러스 풍미 위에 셰리 오크통 특유의 캐러멜과 베리류 단맛을 더했습니다.", "친근한 미디엄 피트": "타르나 소독약 같은 강한 피트 대신, 누구나 쉽게 접근할 수 있는 잔잔한 모닥불 연기 향을 선사합니다.", "탁월한 데일리 밸런스": "부담 없는 바디감 속에서 단맛, 짠맛, 스모키함이 부드러운 하모니를 이루어 데일리로 즐기기에 좋습니다."}}', note = '{"note": {"향 (Nose)": "상큼한 레몬 제스트와 오렌지 껍질의 향 뒤로, 진한 캐러멜 토피와 말린 과일의 단 향이 달콤하게 올라옵니다. 은은하게 깔리는 화사한 피트 스모크와 가벼운 바닷바람의 뉘앙스가 조화를 이룹니다.", "맛 (Palate)": "입안을 가볍고 부드럽게 감싸 안는 질감입니다. 신선한 꿀의 단맛과 잘 익은 자두, 밀크 초콜릿의 풍미가 느껴지며, 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 후추 스파이스가 기분 좋은 타격감을 줍니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며, 입안에 향긋하게 머무는 드라이한 피트 연기의 잔향이 산뜻하게 마무리됩니다."}}' WHERE id = 32;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (33, '보모어 25년', 'single_malt', 'Bowmore Whisky', 'whiskey/13200.jpg', 43.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bowmore 25 Year Old 70cl', 681288, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-25-year-old-whisky/?sku=13200', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 25년(Bowmore 25 Year Old)은 보모어 증류소가 자랑하는 초고연산 마스터피스이자 울트라 프리미엄 싱글 몰트 위스키입니다. 반세기의 절반에 달하는 25년이라는 세월 동안 전설적인 No. 1 Vaults 창고에서 대서양의 혹독한 해풍을 맞으며 숙성되었습니다. 이 기나긴 시간 속에서 젊은 날의 거친 알코올 부즈와 자극적인 스파이스는 완전히 사라졌으며, 43% 도수 안에서 위스키가 도달할 수 있는 가장 고귀하고 기품 있는 아우라를 보여줍니다.", "제조 및 숙성": "최상급 오로로소 셰리 캐스크와 아메리칸 버번 캐스크에서 각각 25년 이상 오랜 세월 고독하게 숙성된 원액들을 마스터 블렌더의 정교한 감각으로 결합했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 병입했습니다."}, "feature": {"초고연산의 기품": "25년의 정성이 빚어낸 묵직한 숙성 오크, 부드러운 가죽, 농축된 에스테르의 정수를 보여줍니다.", "No. 1 Vaults의 완벽한 유산": "해수면보다 낮은 창고에서 축축한 해풍을 맞으며 숙성되어 독보적인 미네랄리티와 깊이를 자랑합니다.", "궁극의 부드러움": "아일라 피트 위스키 중 가장 우아하고 실키하게 다듬어진 궁극의 밸런스를 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 졸인 자두, 무화과 잼의 진한 향이 퍼지고, 뒤이어 기품 있는 가죽 책, 말린 오렌지 껍질, 그리고 미풍처럼 부드러운 흙내음 섞인 피트 향이 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 텍스처입니다. 다크 초콜릿, 구운 피칸의 고소함과 함께 잘 익은 체리의 풍미가 느껴지며 토피 당과 시나몬 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛 뒤로 시가 박스의 우디한 향, 정제된 바다 소금의 흔적, 그리고 은은하게 피어오르는 최고급 헤더 피트의 잔향이 끝없이 맴봅니다."}}' WHERE id = 33;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (34, '보모어 21년 셰리 오크', 'single_malt', 'Bowmore Whisky', 'whiskey/138788.jpg', 46.8, 21, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Bowmore 21 Year Old Sherry Oak 70cl', 455221, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-21-year-old-sherry-oak-whisky/?sku=138788', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 21년 셰리 오크(Bowmore 21 Year Old Sherry Oak)는 장기 숙성된 보모어의 예술적인 유산과 프리미엄 셰리 오크통의 영향력이 가장 격조 높게 결합된 하이엔드 싱글 몰트 위스키입니다. 20년이 넘는 세월 동안 서서히 에스테르화된 화사한 스모키 스피릿이 셰리의 묵직한 단맛과 완벽한 구도를 이룹니다. 일반적으로 50% 안팎의 높은 도수 또는 43%로 출시되며 컬렉터들의 표적이 되는 주류입니다.", "제조 및 숙성": "마스터 블렌더가 직접 선별한 최고급 퍼스트 필 오로로소 및 페드로 히메네스 셰리 캐스크에서 21년 동안 장기 숙성시켰습니다. 오랜 세월 동안 나무와 원액이 완벽한 화학적 결합을 이루어 색상과 풍미 모두에서 독보적인 기품을 자랑합니다."}, "feature": {"퍼스트 필 셰리의 위엄": "가장 순수한 최고급 셰리 캐스크 숙성을 통해 짙은 컬러감과 녹진한 다크 프루트 풍미를 확보했습니다.", "완벽한 구조감": "오랜 연산이 주는 중후함 속에서도 보모어 특유의 화사함과 바다의 짠맛이 촘촘하게 짜여 있습니다.", "희소성과 소장 가치": "한정 배치 형태로 생산되어 출시될 때마다 전 세계 콜렉터들과 애호가들 사이에서 높은 인기를 구가합니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스럽습니다. 진한 대추야자, 건포도, 베리류 잼의 묵직한 달콤함이 피어오르고, 이내 오래된 가죽, 던지 창고 고유의 흙내음, 은은한 미네랄리와 부드러운 피트 스모크가 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 진득하게 코팅하는 농밀하고 매끄러운 풀바디 텍스처입니다. 다크 초콜릿에 절인 건포도와 캐러멜 시럽의 단맛이 파도처럼 밀려오고, 으깬 통후추의 알싸함과 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "놀라울 정도로 길고 우아한 피날레를 보여줍니다. 달콤한 셰리의 여운이 가라앉으며 기품 있는 시가 박스의 우디한 향, 그리고 입안 전체를 계속 감싸는 잔잔한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 34;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (35, '보모어 15년 골든 앤 엘리건트', 'single_malt', 'Bowmore Whisky', 'whiskey/62957.jpg', 43.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Bowmore 15 Year Old - Golden & Elegant 1L 100cl', 125951, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-15-year-old-golden-and-elegant-1l-whisky/?sku=62957', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 15년 골든 앤 엘리건트(Bowmore 15 Year Old Golden & Elegant)는 주로 글로벌 면세 시장을 겨냥해 출시된 보모어의 세련된 에디션입니다. 셰리 피니시 중심의 정규 15년 제품과 달리, 이 제품은 이름 그대로 황금빛의 우아함을 전면에 내세웠습니다. 보모어 특유의 미디엄 피트 스모크에 버번 캐스크 고유의 화사함과 풍부한 바닐라를 극대화하여 43% 도수 속에서 산뜻하고 품격 있는 스타일을 보여줍니다.", "제조 및 숙성": "최상급 1등품 아메리칸 오크 버번 캐스크에서 15년 동안 숙성된 원액을 주축으로 합니다. 셰리 캐스크의 묵직함 대신 버번 캐스크의 화사한 옷을 입어 밝은 황금빛 자태와 생기 넘치는 과일 아로마 레이어를 획득했습니다."}, "feature": {"버번 캐스크의 찬가": "퍼스트 필 버번 캐스크 중심의 숙성을 통해 탁월한 바닐라 크림과 이국적인 열대 과일 풍미를 전합니다.", "이름에 걸맞은 우아함": "보모어의 다른 제품들에 비해 한층 더 가볍고, 화사하며, 실크처럼 부드럽게 다듬어진 텍스처가 돋보입니다.", "면세점의 숨은 명작": "여행자들을 위해 특별히 기획되어 보모어가 가진 밝고 생동감 넘치는 또 다른 이면의 매력을 뽐냅니다."}}', note = '{"note": {"향 (Nose)": "향긋한 바닐라 포드와 부드러운 꿀, 구운 토스트의 고소함이 먼저 퍼집니다. 뒤이어 신선한 레몬, 파인애플 같은 열대 과일의 아로마와 부드러운 미디엄 피트의 연기 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "크리미하고 부드러운 질감이 입안을 매끄럽게 감쌉니다. 벌꿀 집의 단맛과 잘 익은 복숭아, 말린 살구의 풍미가 퍼지고 가벼운 시나몬, 구운 생강 스파이스가 부드러운 타격감을 선사합니다.", "여운 (Finish)": "온화하고 산뜻한 여운을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 나무 스파이스의 따뜻함, 그리고 은은하게 흩어지는 헤더 피트의 연기 잔향이 조화롭게 마무리됩니다."}}' WHERE id = 35;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (36, '보모어 10년', 'single_malt', 'Bowmore Whisky', 'whiskey/62958.jpg', 40.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Bowmore 10 Year Old - Dark & Intense 1L 100cl', 86059, 'https://www.masterofmalt.com/whiskies/bowmore/bowmore-10-year-old-dark-and-intense-1l-whisky/?sku=62958', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "보모어 10년(Bowmore 10 Year Old)은 젊은 연산 특유의 활력 넘치는 피트 스모크와 강렬한 캐스크 풍미의 대비를 보여주는 생동감 있는 위스키입니다. 12년 제품보다 한층 더 직관적이고 과감한 타격감을 선사하며, 보모어가 가진 우아한 피트의 본질에 짙은 풍미를 더해 40% 도수 속에서도 확실한 존재감을 뿜어냅니다.", "제조 및 숙성": "엄선된 스페니시 오크 셰리 캐스크와 버번 캐스크에서 10년 동안 숙성된 원액을 매링하여 완성했습니다. 짧은 연산이지만 셰리 캐스크의 영향력을 강하게 받아 젊고 역동적인 과일 풍미와 피트 스모크의 멋진 대비를 이끌어냈습니다."}, "feature": {"역동적인 영 스피릿": "장기 숙성 제품들보다 훨씬 직관적이고 생기 넘치는 피트 타격감을 선사합니다.", "셰리와 버번의 충돌": "스페니시 오크의 묵직한 단맛과 버번 캐스크의 바닐라 풍미 및 스파이시함이 대담하게 어우러집니다.", "확실한 캐릭터 형성": "엔트리 급 숙성 연수 안에서 피트의 훈연 특성과 달콤함의 대조를 뚜렷하게 보여줍니다."}}', note = '{"note": {"향 (Nose)": "타오르는 장작 연기와 그을음의 피트 향이 먼저 직관적으로 다가옵니다. 이내 말린 무화과, 캐러멜 토피, 흑설탕의 진한 단 향과 함께 오렌지 제스트의 상큼함이 레이어를 이룹니다.", "맛 (Palate)": "입안에서 생기 넘치는 타격감을 줍니다. 달콤한 건포도와 꿀의 단맛이 중심을 잡고, 뒤이어 구운 맥아의 고소함과 으깐 통후추, 계피의 알싸한 스파이스가 피트 스모크와 어우러지며 역동적인 풍미를 냅니다.", "여운 (Finish)": "드라이하면서도 스모키한 여운이 묵직하게 남습니다. 타버린 오크통의 우디함, 쌉싸름한 다크 카카오의 흔적, 그리고 입안에 오랫동안 남는 드라이한 피트 재의 연기 잔향이 인상적입니다."}}' WHERE id = 36;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (37, '아드벡 우거다일', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/2839.jpg', 54.2, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg Uigeadail 70cl', 105782, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-uigeadail-whisky/?sku=2839', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 우거다일(Ardbeg Uigeadail)은 전 세계 위스키 매니아들과 아드베기안들 사이에서 불멸의 명작으로 꼽히는 고도수 셰리 피트 위스키입니다. 증류소 근처의 신비롭고 어두운 우거다일 호수에서 이름을 땄으며, 아드벡 특유의 날카롭고 강렬한 타르 피트 스모크에 셰리 캐스크의 녹진한 단맛이 완벽하게 결합한 결과물입니다. 냉각 여과 없이 54.2%의 강력한 고도수로 병입되어 폭발적인 퍼포먼스를 자랑합니다.", "제조 및 숙성": "강하게 피팅된 아드벡 원액을 버번 캐스크와 함께 최고급 올로로소 셰리 캐스크에서 숙성시켜 절묘하게 블렌딩했습니다. 물을 거의 섞지 않고 내추럴 컬러로 완성하여 원액 본연의 묵직한 바디감과 짙은 풍미 레이어를 고스란히 보존했습니다."}, "feature": {"피트와 셰리의 바이블": "강렬한 아드벡의 헤비 피트와 진득한 오로로소 셰리의 단맛이 보여줄 수 있는 최고의 결합 조건으로 평가받습니다.", "54.2%의 강력한 화력": "높은 도수에서 뿜어져 나오는 폭발적인 타격감과 입안을 농밀하게 코팅하는 오일리한 마우스필이 일품입니다.", "내추럴 무여과 구성": "색소 첨가나 냉각 여과 공정 없이 가장 자연적이고 묵직한 질감을 액체 안에 그대로 보존했습니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 강렬한 타르, 아스팔트, 기계 오일의 헤비 피트 향이 압도합니다. 이내 흑설탕에 졸인 건포도, 달콤한 토피 당, 가죽 향과 함께 신선한 바닷바람의 짭조름함이 묵직하게 엉켜 듭니다.", "맛 (Palate)": "입안을 가득 채우다 못해 폭발하는 듯한 농밀하고 기름진 질감입니다. 진한 다크 초콜릿과 무화과 잼의 녹진한 단맛이 밀려오고, 뒤이어 통후추의 알싸함, 구운 생강 스파이스, 그리고 강렬한 바다 소금의 맛이 피트 스모크와 함께 혀를 타격합니다.", "여운 (Finish)": "지워지지 않을 것처럼 오래 지속되는 긴 여운입니다. 묵직한 시가 연기와 타버린 오크통의 우디함, 쌉싸름한 에스프레소 원두의 흔적 뒤로 셰리의 달콤한 잔향이 깊고 드라이하게 남습니다."}}' WHERE id = 37;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (38, '아드벡 코리브레칸', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/3160.jpg', 57.1, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg Corryvreckan 70cl', 133629, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-corryvreckan-whisky/?sku=3160', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 코리브레칸(Ardbeg Corryvreckan)은 아일라 섬 북쪽에 위치한 전설적인 세계 3대 소용돌이 코리브레칸의 이름과 파괴력을 고스란히 투영한 아드벡 라인업의 최고 정점 중 하나입니다. 아드벡 특유의 헤비 피트에 프렌치 오크의 이국적이고 강렬한 스파이시함을 더해 위스키 애호가들 사이에서 야수라는 별칭으로 통합니다. 냉각 여과 없이 57.1%라는 강력한 고도수로 병입되어 정제되지 않은 날것의 순수한 힘을 전합니다.", "제조 및 숙성": "전통적인 아메리칸 버번 캐스크 숙성 원액과 함께, 위스키 세계에서 흔치 않은 최고급 프랑스산 뉴 프렌치 오크 캐스크에서 숙성된 원액을 매링했습니다. 프렌치 오크 나무가 가진 거칠고 매운 타닌 성분이 아드벡의 강한 피트와 만나 독창적인 스파이시 레이어를 형성합니다."}, "feature": {"소용돌이 같은 파괴력": "57.1%의 압도적인 도수와 프렌치 오크의 만남이 입안에서 폭발적인 풍미의 소용돌이를 일으킵니다.", "이국적인 프렌치 오크 터치": "기존 버번 캐스크 중심의 아드벡에서 벗어나 강렬한 정향, 육두구 등의 이색적인 나무 스파이스를 뿜어냅니다.", "매니아들의 우상": "타합 없는 강렬함과 묵직한 바디감을 선사하여 피트 위스키 끝판왕 중 하나로 확고한 지위를 가집니다."}}', note = '{"note": {"향 (Nose)": "정신이 번쩍 드는 강렬함입니다. 짙은 타르, 아스팔트, 로프의 피트 향과 함께 으깬 통후추, 멘톨, 소독약 같은 메디컬한 아로마가 돌진합니다. 그 뒤로 다크 초콜릿, 체리, 바닐라 포드의 단 향이 숨어있습니다.", "맛 (Palate)": "혓바닥을 진득하고 자극적으로 조여오는 강력한 풀바디 텍스처입니다. 알싸한 고추와 육두구, 정향의 스파이시함이 몰아치고, 뒤이어 구운 보리의 고소한 단맛, 에스프레소, 그리고 강렬한 바다 소금의 짭조름함이 묵직하게 충돌합니다.", "여운 (Finish)": "가슴 깊은 곳까지 타오르는 듯한 극도로 길고 드라이한 여운입니다. 입안 전체를 지배하는 짙은 시가 박스의 우디함, 석탄 재와 가죽 향, 그리고 마지막까지 남는 알싸한 후추의 스파이시한 잔향이 끝없이 이어집니다."}}' WHERE id = 38;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (39, '아드벡 10년', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/1721.jpg', 46.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg 10 Year Old 70cl', 66337, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-10-year-old-whisky/?sku=1721', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 10년(Ardbeg 10 Year Old)은 전 세계 피트 위스키 애호가들에게 종교와도 같은 지위를 누리는 아일라 섬의 상징이자 피트의 정석입니다. 가장 강렬하고 투박한 헤비 피트를 자랑하면서도, 역설적으로 스피릿 자체의 정교한 과일 단맛이 살아있어 위스키 세계의 완벽한 이중성을 보여주는 교과서입니다. 46% 도수에 비냉각여과, 내추럴 컬러로 병입되어 전 세계 싱글 몰트 시장의 기준점을 제시하는 위대한 엔트리 위스키입니다.", "제조 및 숙성": "증류소 내부의 고유한 정류기를 통과하여 증류된 무거우면서도 화사한 스피릿을 최고급 아메리칸 버번 캐스크에서 최소 10년 동안 숙성시켰습니다. 오크통의 과한 간섭을 배제하여 보리 고유의 단맛과 아일라 피트 본연의 캐릭터를 가장 순수하게 보존해 냈습니다."}, "feature": {"피트의 절대 기준": "강렬한 헤비 피트 스모크를 전면에 내세워 피트 매니아들의 확고한 기준점이 되는 아이코닉 보틀입니다.", "정류기가 만든 마술": "증류기 상단의 정류기 덕분에 헤비 피트 속에서도 레몬, 라임 같은 화사한 시트러스 단맛이 공존합니다.", "순수한 내추럴 크래프트": "색소 첨가나 냉각 여과 없이 밝은 레몬 빛깔의 원액 그대로 병입되어 탁월한 마우스필을 제공합니다."}}', note = '{"note": {"향 (Nose)": "소독약, 타르, 훈제 베이컨의 강렬한 헤비 피트 향이 직관적으로 코를 찌릅니다. 이내 라임, 레몬 제스트의 싱그러운 시트러스와 달콤한 바닐라, 구운 맥아의 고소함이 피트 연기와 멋진 대조를 이뤄냅니다.", "맛 (Palate)": "입안에 닿는 순간 오일리하면서도 파워풀한 타격감을 줍니다. 달콤한 바닐라 캐러멜과 잘 익은 사과의 단맛이 중심을 잡고, 으깬 통후추의 알싸함과 짭조름한 해풍, 그리고 입안을 가득 채우는 석탄 연기의 풍미가 터져 나옵니다.", "여운 (Finish)": "깔끔하면서도 묵직한 훈연 향이 길게 지속됩니다. 입안을 드라이하게 정돈해 주는 오크의 우디함, 쌉싸름한 에스프레소, 그리고 향긋하고 건조한 캠프파이어의 재와 같은 피트 스모크의 여운이 길게 남습니다."}}' WHERE id = 39;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (40, '아드벡 언 오', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/66854.jpg', 46.6, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg An Oa 70cl', 82850, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-an-oa-whisky/?sku=66854', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 언 오(Ardbeg An Oa)는 아드벡의 상징적인 코어 라인업 중 가장 부드럽고 둥글둥글하게 다듬어진 반전 매력의 싱글 몰트 위스키입니다. 아일라 섬 남서쪽에 위치한 거친 오 곶의 이름에서 따왔으며, 곶이 거센 대서양 해풍을 막아주듯 강렬한 아드벡의 피트를 다채로운 오크통의 조합으로 감싸 안았습니다. 46.6% 도수로 병입되며 아드벡 중 가장 실키하고 대중적인 접근성을 자랑합니다.", "제조 및 숙성": "증류소 내부에 특별히 제작된 대형 오크 혼합조인 \'가더링 툰\'의 유산입니다. 달콤한 페드로 히메네스 셰리 캐스크, 스파이시한 뉴 버진 오크 캐스크, 그리고 퍼스트 필 버번 캐스크에서 각각 숙성된 원액들을 한곳에 모아 오랜 시간 마리잉하여 완벽한 라운드감을 형성했습니다."}, "feature": {"가더링 툰의 블렌딩": "세 가지 서로 다른 스타일의 오크통 원액이 만나 아드벡 특유의 날카로움을 둥글게 깎아냈습니다.", "스모키와 실키의 결합": "아드벡 특유의 석탄 피트 스모크는 유지하되, 입안에서 느껴지는 감각은 크리미하고 부드럽습니다.", "다채로운 오크 레이어": "버진 오크의 우디 스파이시함과 셰리 캐스크 특유의 진득한 단맛이 촘촘하고 유기적으로 얽혀 있습니다."}}', note = '{"note": {"향 (Nose)": "부드럽고 달콤한 캐러멜 토피와 바닐라, 구운 가죽의 향이 먼저 퍼집니다. 뒤이어 상큼한 꿀과 신선한 시트러스, 그리고 아드벡 고유의 타르와 소독약 향이 과하지 않고 향긋한 모닥불 연기처럼 부드럽게 어우러집니다.", "맛 (Palate)": "입안을 실크처럼 매끄럽고 크리미하게 감싸 안는 텍스처입니다. 달콤한 밀크 초콜릿, 시럽을 바른 건포도의 풍미가 중심을 잡고, 뒤이어 구운 생강, 육두구의 부드러운 스파이스와 알싸한 블랙페퍼, 바다 소금의 짠맛이 레이어를 만듭니다.", "여운 (Finish)": "온화하고 감미로운 여운이 부드럽게 지속됩니다. 오크통의 따뜻한 우디함과 셰리 캐스크 특유의 달콤한 흔적이 가라앉으며, 입안에 부드러운 잔향을 남기는 감미로운 피트 스모크의 흔적이 매력적입니다."}}' WHERE id = 40;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (41, '아드벡 25년', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/106601.jpg', 46.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg 25 Year Old 70cl', 1396416, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-25-year-old-whisky/?sku=106601', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 25년(Ardbeg 25 Year Old)은 증류소가 장기간 폐쇄되었던 암흑기 직전인 1990년대 초반에 증류된 원액으로 빚어낸 아드벡 라인업 최고 정점의 울트라 프리미엄 싱글 몰트 위스키입니다. 아드벡 특유의 날카롭고 강렬했던 헤비 피트 스모크가 한 세기의 4분의 1에 달하는 세월 동안 천천히 호흡하며 상상할 수 없을 정도로 정교하고 기품 있게 에스테르화되었습니다. 46% 도수로 냉각 여과 없이 병입되며, 아드벡의 역사와 장인 정신을 상징하는 전설적인 마스터피스입니다.", "제조 및 숙성": "증류소가 보유한 초고연산 최상급 버번 캐스크들을 엄선하여 25년 동안 장기 숙성시켰습니다. 오랜 세월을 거치며 오크통의 과한 나무 타닌 대신 스피릿 고유의 화사한 시트러스와 피트 연기가 기적적인 화학 결합을 이루어 내어, 세련된 실버 보틀 패키지에 걸맞은 독보적인 아우라를 뿜어냅니다."}, "feature": {"궁극의 아드벡 캐릭터": "25년의 숙성을 통해 젊은 날의 거친 타르는 우아한 타르와 고급 시가 연기 같은 아로마로 진화했습니다.", "역사적 희소 가치": "증류소 폐쇄 전 극소량만 생산된 원액을 기반으로 하여, 출시될 때마다 전 세계 위스키 컬렉터들의 표적이 됩니다.", "완벽한 이중성": "헤비 피트의 흔적을 기저에 품고 있으면서도, 입안에서 느껴지는 질감과 피날레는 지극히 귀족적이고 세련되었습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 훈제 생강, 달콤한 왁스, 오래된 가죽 가방의 향이 먼저 피어오르고, 이내 갓 구운 파인애플, 레몬 셔벗의 화사한 시트러스와 정제된 멘톨, 가벼운 타르 향이 복합적인 레이어를 이룹니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 텍스처가 혀를 감쌉니다. 크리미한 토피 당, 다크 초콜릿, 졸인 사과의 진한 단맛이 밀려오고, 뒤이어 알싸한 후추, 아니스의 정교한 스파이스와 은은한 바다 소금의 짠맛이 피트 스모크와 완벽한 구도를 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 달콤한 바닐라 크림의 단맛 뒤로 시가 박스의 우디한 향, 정제된 석탄 재의 연기 향, 그리고 안개처럼 잔잔하게 머무는 헤더 피트의 흔적이 끝없이 이어집니다."}}' WHERE id = 41;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (42, '아드벡 위 비스티 5년', 'single_malt', 'Ardbeg Whisky Distillery', 'whiskey/104467.jpg', 47.4, 5, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Ardbeg Wee Beastie 5 Year Old 70cl', 57461, 'https://www.masterofmalt.com/whiskies/ardbeg/ardbeg-wee-beastie-5-year-old-whisky/?sku=104467', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "아드벡 위 비스티 5년(Ardbeg Wee Beastie 5 Year Old)은 이름 그대로 입안에서 톡 쏘는 작은 야수 같은 역동적이고 파워풀한 에너지를 전면에 내세운 획기적인 영 앤 헤비 피트 위스키입니다. 위스키는 오래 숙성해야 맛이 좋다는 편견을 깨부수며, 5년이라는 짧은 숙성 연수에서만 만날 수 있는 길들여지지 않은 날것 그대로의 직관적인 피트 타격감을 선사합니다. 47.4%의 도수로 병입되어 아드벡 고유의 와일드한 크래프트 개성을 여과 없이 뿜어냅니다.", "제조 및 숙성": "마스터 블렌더 박사 빌 럼스던의 창의적인 캐스크 실험작으로, 퍼스트 필 버번 캐스크와 최고급 오로로소 셰리 캐스크에서 각각 5년 동안 숙성된 원액을 매링했습니다. 짧은 숙성 덕분에 보리 본연의 힘찬 생동감과 피트 연기의 화력이 고스란히 보존되었습니다."}, "feature": {"길들여지지 않은 야수": "아드벡 라인업 중 가장 젊고 역동적이며, 코와 혀를 짜릿하게 자극하는 강력한 피트 화력을 자랑합니다.", "버번과 셰리의 절묘한 동거": "퍼스트 필 버번의 달콤한 바닐라와 오로로소 셰리의 스파이시한 고기 향 뉘앙스가 대담하게 결합되었습니다.", "직관적인 피트의 매력": "오크통의 간섭이 적어 아일라 피트 특유의 짠맛, 타르, 그을음 캐릭터를 가장 가감 없이 느낄 수 있습니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 짜릿한 통후추와 메디컬한 소독약, 타르 향이 직관적으로 다가옵니다. 그 거친 스모키함 뒤로 상큼한 배, 신선한 소나무 바늘, 캐러멜 토피와 바닐라의 단 향이 생기 넘치게 어우러집니다.", "맛 (Palate)": "입안을 자극적으로 쪼아주는 강력하고 오일리한 마우스필입니다. 초콜릿 크림과 크래커의 단맛이 기저에 깔리고, 으깬 통후추, 타르, 훈제 베이컨의 기름진 풍미가 파도처럼 몰아치며 유칼립투스의 알싸함이 혀를 때립니다.", "여운 (Finish)": "드라이하면서도 스모키한 화력이 묵직하게 남는 긴 여운입니다. 입안 가득 오랫동안 남는 캠프파이어의 재와 타버린 오크통의 우디함, 쌉싸름한 카카오의 흔적과 바다 소금의 잔향이 인상적인 피날레를 장식합니다."}}' WHERE id = 42;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (43, '브룩라디 포트샬롯 10년', 'single_malt', 'Bruichladdich Whisky', 'whiskey/77699.jpg', 50.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Port Charlotte 10 Year Old 70cl', 92254, 'https://www.masterofmalt.com/whiskies/bruichladdich/port-charlotte-10-year-old-whisky/?sku=77699', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 포트샬롯 10년(Bruichladdich Port Charlotte 10 Year Old)은 아일라 섬의 혁신가 브룩라디 증류소에서 생산하는 헤비 피티드 싱글 몰트 위스키의 대표 주자입니다. 1929년에 폐업한 이웃 증류소 포트샬롯의 이름을 따서 명맥을 잇고 있으며, 전통적인 아일라 피트의 강력함에 브룩라디 특유의 세련되고 플로럴한 캐릭터를 결합했습니다. 50%의 높은 도수로 병입되며, 비냉각여과와 내추럴 컬러를 고집하여 순수한 크래프트 정신을 보여줍니다.", "제조 및 숙성": "100% 스코틀랜드산 보리만을 사용하여 증류했으며, 원액의 65%는 퍼스트 필 버번 캐스크, 10%는 세컨드 필 버번 캐스크, 그리고 나머지 25%는 프랑스산 최고급 와인 캐스크에서 최소 10년 동안 아일라 해안의 창고에서 100% 숙성되었습니다."}, "feature": {"헤비 피트와 우아함의 공존": "40ppm의 강렬한 피트 스모크를 지니고 있으면서도, 브룩라디의 정밀한 증류 기법 덕분에 화사한 과일 향이 살아있습니다.", "50% ABV의 든든한 바디": "높은 도수에서 뿜어져 나오는 강렬한 타격감과 혀를 촘촘하게 코팅하는 텍스처가 일품입니다.", "투명한 크래프트 정신": "원료의 원산지부터 숙성 창고의 위치까지 모든 정보를 투명하게 공개하는 진정한 떼루아 위스키입니다."}}', note = '{"note": {"향 (Nose)": "기분 좋은 타오르는 장작 연기, 그을음과 바비큐 훈제 향이 먼저 코를 감쌉니다. 뒤이어 신선한 레몬, 청사과의 시트러스와 따뜻한 캐러멜 토피, 바닐라 크림, 그리고 아일라 해풍의 짭조름함이 겹겹이 피어오릅니다.", "맛 (Palate)": "오일리하고 진득하게 입안을 가득 채우는 훌륭한 풀바디 텍스처입니다. 벌꿀 집의 단맛과 잘 익은 복숭아 풍미가 중심을 잡고, 으깬 통후추, 구운 생강의 알싸한 스파이스와 바다 소금의 짠맛이 피트 스모크와 멋진 대조를 이룹니다.", "여운 (Finish)": "묵직하고 온화한 따뜻함이 아주 길게 지속되는 피날레입니다. 타버린 오크통의 우디한 향과 담배 연기 같은 진한 피트 스모크, 그리고 마지막에 남는 부드러운 몰트의 고소한 단맛이 깊은 흔적을 남깁니다."}}' WHERE id = 43;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (44, '브룩라디 18년', 'single_malt', 'Bruichladdich Whisky', 'whiskey/133548.jpg', 50.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bruichladdich 18 Year Old - Re/Define 70cl', 253893, 'https://www.masterofmalt.com/whiskies/bruichladdich/bruichladdich-18-year-old-re-define-whisky/?sku=133548', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 18년(Bruichladdich 18 Year Old)은 증류소가 긴 잠에서 깨어난 부활의 시기 이후, 100% 아일라 섬에서 증류하고 숙성하여 완성한 고연산 논피티드 싱글 몰트 위스키입니다. 피트 연기를 전혀 묻히지 않은 순수한 스코틀랜드 보리 고유의 풍미가 약 20년에 가까운 세월 동안 오크통 속에서 어떻게 진화하는지 명징하게 보여줍니다. 50% 도수로 병입되며 위스키가 가질 수 있는 극상의 복합미와 부드러운 세련미를 뽐냅니다.", "제조 및 숙성": "마스터 블렌더의 치밀한 설계 아래, 주로 퍼스트 필 버번 캐스크를 주축으로 삼고, 프랑스 최고의 와인 생산지에서 공수한 프리미엄 와인 캐스크 원액을 정교하게 결합하여 18년 동안 장기 숙성시켰습니다. 냉각 여과와 색소 첨가를 배제한 내추럴 퀄리티를 자랑합니다."}, "feature": {"논피트 고연산의 위엄": "아일라 섬 위스키이지만 피트 스모크 없이 오직 보리 본연의 단맛과 오크통 숙성미로 승부하는 우아한 제품입니다.", "50% 도수의 완벽한 구조감": "높은 알코올 볼륨감 덕분에 고연산 특유의 복합적인 과일 아로마와 오일감이 무너지지 않고 단단하게 짜여 있습니다.", "아일라 떼루아의 정수": "아일라 섬의 서늘하고 축축한 바다 창고에서 18년간 온전히 호흡하며 숙성되어 은은한 미네랄리티를 머금고 있습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 싱그러운 오렌지 블러썸과 잘 익은 살구, 서양 배의 화사한 향이 피어나고, 그 뒤로 달콤한 꿀, 바닐라 포드, 그리고 와인 캐스크에서 기인한 은은한 레드 베리류의 아로마가 고급스럽게 얹어집니다.", "맛 (Palate)": "입안을 실크나 꿀처럼 매끄럽고 크리미하게 감싸 안는 마우스필이 돋보입니다. 달콤한 토피 당, 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 느껴지며, 신선한 레몬 제스트와 계피, 넛멕의 부드러운 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "귀족적인 우아함이 돋보이는 매우 긴 여운입니다. 오크통에서 배어 나온 부드러운 바닐라의 단맛과 따뜻한 나무 향, 그리고 마지막에 남는 쌉싸름한 다크 카카오와 정제된 바다 소금의 흔적이 감미롭게 마무리됩니다."}}' WHERE id = 44;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (45, '브룩라디 포트샬롯 18년', 'single_malt', 'Bruichladdich Whisky', 'whiskey/143637.jpg', 52.3, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Port Charlotte 18 Year Old 70cl', 297908, 'https://www.masterofmalt.com/whiskies/bruichladdich/port-charlotte-18-year-old-whisky/?sku=143637', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 포트샬롯 18년(Bruichladdich Port Charlotte 18 Year Old)은 헤비 피티드 라인업인 포트샬롯의 한정판 고연산 플래그십 익스프레션입니다. 40ppm에 달하는 강렬한 피트 원액이 18년이라는 오랜 세월을 거치면서 피트의 날카로운 발톱은 무뎌지고, 대신 극상의 깊이감과 농밀한 복합미로 진화한 마스터피스입니다. 54.3% 안팎의 강력한 캐스크 스트렝스로 냉각 여과 없이 병입되어 헤비 피트 컬렉터들의 심장을 뛰게 만듭니다.", "제조 및 숙성": "최상급 유러피안 오크 셰리 캐스크와 아메리칸 버번 캐스크, 그리고 프랑스산 프리미엄 와인 오크통에서 18년 동안 고독하게 장기 숙성된 진귀한 원액들을 마스터 블렌더가 황금 비율로 블렌딩했습니다. 오랜 세월 동안 나무의 성분과 헤비 피트 스피릿이 완벽한 화학적 결합을 완성했습니다."}, "feature": {"헤비 피트 숙성의 미학": "젊은 날의 투박한 탄 무취가 18년의 세월을 거치며 고귀하고 중후한 스모키 아로마로 완전히 탈바꿈했습니다.", "다양한 캐스크의 하모니": "셰리의 단맛, 버번의 바닐라, 와인 캐스크의 베리류 풍미와 아일라 바닷바람의 소금기가 거대한 조화를 이룹니다.", "울트라 프리미엄 라인": "포트샬롯 정규 및 한정 라인 중 가장 높은 연산에 속하여 소장 가치가 극도로 높은 진귀한 주류입니다."}}', note = '{"note": {"향 (Nose)": "오래된 캠프파이어의 재, 타르, 기품 있는 오래된 가죽 책의 묵직한 향이 코를 감쌉니다. 뒤이어 흑설탕에 졸인 무화과, 말린 오렌지 껍질, 달콤한 밤꿀의 향과 함께 짭조름한 훈제 베이컨의 뉘앙스가 깊이를 더합니다.", "맛 (Palate)": "입안을 진득하게 코팅하는 농밀하고 풀바디한 질감입니다. 진한 다크 초콜릿과 구운 피칸, 캐러멜 시럽의 단맛이 파도처럼 밀려오고, 으깬 통후추의 알싸함과 육두구, 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "지워지지 않을 것처럼 오래 지속되는 경이로운 여운입니다. 입안 전체를 지배하는 짙은 시가 박스의 우디함, 석탄 재와 담배 연기 같은 스모키, 그리고 마지막에 남는 달콤한 마지팬과 다크 카카오의 잔향이 끝없이 지속됩니다."}}' WHERE id = 45;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (46, '브룩라디 더 클래식 라디', 'single_malt', 'Bruichladdich Whisky', 'whiskey/26546.jpg', 50.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bruichladdich The Classic Laddie - Scottish Barley 70cl', 77021, 'https://www.masterofmalt.com/whiskies/bruichladdich/bruichladdich-scottish-barley-the-classic-laddie-whisky/?sku=26546', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 더 클래식 라디(Bruichladdich The Classic Laddie)는 민트색 보틀로 시선을 사로잡으며 전 세계 위스키 시장에 신선한 충격을 던진 증류소의 시그니처 웰컴 위스키입니다. 아일라 섬 위스키이지만 피트를 전혀 사용하지 않은 논피티드 스타일을 고수하며, 보리 본연의 향긋하고 화사한 풍미를 극대화했습니다. 숙성 연수를 표기하지 않은 NAS 제품이지만 50%의 높은 도수로 병입되어 훌륭한 바디감과 크래프트 정신을 증명합니다.", "제조 및 숙성": "100% 스코틀랜드산 보리만을 사용하여 목이 긴 증류기에서 정밀하게 증류하여 가볍고 플로럴한 스피릿을 뽑아냈습니다. 주로 최고급 아메리칸 오크 버번 캐스크에서 숙성된 여러 연산의 원액들을 매링하여 냉각 여과 없이 내추럴 컬러 그대로 병입했습니다."}, "feature": {"아일라의 반전 매력": "피트 스모크를 완벽히 배제하고 화사한 화이트 플라워와 과일 향으로 승부하는 반전의 아일라 위스키입니다.", "민트색 디자인 아이콘": "현대적이고 감각적인 보틀 디자인 덕분에 젊은 세대와 여성 애호가들 사이에서도 선풍적인 인기를 끕니다.", "50% ABV의 탄탄함": "화사하고 가벼운 아로마 프로파일을 지니고 있으면서도, 50% 도수 세팅 덕분에 마우스필이 진득하고 꽉 차 있습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 싱그럽습니다. 갓 피어난 화이트 플라워, 싱그러운 레몬과 청사과의 시트러스 아로마가 맑게 피어오르고, 그 기저에는 은은한 부드러운 꿀, 구운 맥아의 고소함과 바닐라 향이 튼튼하게 받쳐줍니다.", "맛 (Palate)": "입안에 닿는 느낌이 매끄럽고 크리미합니다. 부드러운 캐러멜 토피, 설탕 시럽을 바른 과일 타르트의 풍미가 퍼지고, 뒤이어 오크통에서 배어 나온 가벼운 계피, 시트러스 오일과 대서양 해풍의 미세한 짭조름함이 레이어를 이룹니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 산뜻하고 온화하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 46;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (47, '브룩라디 더 라디 8', 'single_malt', 'Bruichladdich Whisky', 'whiskey/59716.jpg', 50.0, 8, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bruichladdich 8 Year Old - The Laddie Eight 70cl', 104096, 'https://www.masterofmalt.com/whiskies/bruichladdich/bruichladdich-8-year-old-the-laddie-eight-whisky/?sku=59716', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 더 라디 8(Bruichladdich The Laddie Eight)은 주로 글로벌 면세 시장을 겨냥하여 8년이라는 명확한 연산을 달성하고 출시된 프리미엄 논피티드 싱글 몰트 위스키입니다. 마스터 블렌더 아담 한네트가 젊은 연산 특유의 활력 넘치는 생동감과 브룩라디 고유의 화사한 헤리티지를 조화롭게 엮어냈으며, 50%의 높은 도수로 병입되어 정규 라인 못지않은 강력한 존재감을 보여줍니다.", "제조 및 숙성": "스코틀랜드산 청정 보리를 사용하여 맑게 증류한 스피릿을 아메리칸 오크 버번 캐스크와 유러피안 오크 캐스크에서 8년 동안 아일라 해안의 창고에서 숙성시켰습니다. 냉각 여과를 거치지 않고 인공 색소를 넣지 않아 원액 본연의 탁월한 질감을 유지합니다."}, "feature": {"생기 넘치는 8년의 미학": "장기 숙성 제품들보다 훨씬 직관적이고 생기 넘치는 맥아의 고소함과 과일 향을 선사합니다.", "50% ABV의 단단한 구조": "높은 알코올 볼륨감 덕분에 젊은 위스키임에도 튀지 않고 입안을 꽉 채우는 타격감을 자랑합니다.", "면세 시장의 숨은 강자": "여행자들을 위해 특별히 기획되어 브룩라디의 정석적인 과일 단맛과 화사함을 가성비 좋게 경험할 수 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그러운 레몬 껍질, 청사과, 서양 배의 파릇파릇한 과일 아로마가 가득 퍼집니다. 이내 부드러운 바닐라 크림, 구운 캐슈넛의 고소함과 함께 가벼운 허브, 바닷바람의 짭조름한 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 생기 넘치는 볼륨감을 줍니다. 달콤한 벌꿀과 캐러멜, 잘 익은 살구의 단맛이 중심을 잡고, 뒤이어 부드러운 오크통의 우디함과 화이트 페퍼의 알싸한 스파이스가 혀를 부드럽게 코팅합니다.", "여운 (Finish)": "깔끔하고 온화하게 마무리됩니다. 가벼운 나무 스파이스의 따뜻함, 바닐라 캐러멜의 달콤함, 그리고 은은한 바다의 미네랄 잔향이 입안을 산뜻하게 정돈해 줍니다."}}' WHERE id = 47;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (48, '브룩라디 30년', 'single_malt', 'Bruichladdich Whisky', 'whiskey/133547.jpg', 43.0, 30, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bruichladdich 30 Year Old - Re/Define 70cl', 2454301, 'https://www.masterofmalt.com/whiskies/bruichladdich/bruichladdich-30-year-old-re-define-whisky/?sku=133547', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 30년(Bruichladdich 30 Year Old)은 증류소가 오랜 역사 속에서 보유한 가장 진귀하고 오래된 초고연산 오크통에서 추출한 원액으로 만든 마스터클래스 위스키입니다. 1990년대 증류소 폐쇄 전 암흑기 시절부터 축축한 바다 창고에서 장구한 세월을 버텨온 희귀 원액들을 기반으로 하며, 알코올 도수는 오랜 세월 동안 자연스럽게 정제되어 대략 43% 안팎의 고귀한 품격으로 병입되는 진귀한 최고급 주류입니다.", "제조 및 숙성": "최상급 아메리칸 오크 버번 캐스크에서 무려 30년 이상 오랜 세월 고독하게 숙성된 원액들을 마스터 블렌더의 정교한 감각으로 엄선했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 논피트 원액의 정수만을 모아 완성했습니다."}, "feature": {"최상위 플래그십": "브룩라디 정규 및 헤리티지 라인업 중 가장 높은 연산에 속하는 고귀한 마스터피스입니다.", "시간이 공들인 부드러움": "30년의 세월 동안 나무의 타닌과 스피릿이 만나 거칠고 매운 맛은 완전히 사라지고 극상의 실키함만 남았습니다.", "독보적인 복합미": "피트 스모크 없이 오직 숙성된 열대 과일의 단맛, 오래된 오크의 깊이, 가죽 향이 완벽한 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 구운 코코넛, 망고와 파인애플 같은 극도로 숙성된 열대 과일의 향이 가득 퍼집니다. 뒤이어 부드러운 바닐라 포드, 토피 당, 오래된 가죽 책의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "벨벳이나 실크처럼 부드럽고 가득 차오르는 극상의 텍스처입니다. 진한 밤꿀과 다크 초콜릿, 럼에 절인 건포도의 단맛이 기품 있게 전개되며, 은은한 오크통의 시나몬 스파이스와 구운 피칸의 고소함이 조화를 이룹니다.", "여운 (Finish)": "가슴 깊은 곳까지 따뜻해지는 극도로 길고 우아한 여운입니다. 농축된 단맛 뒤로 부드러운 오크의 풍미, 에스프레소의 잔향, 그리고 아일라 해풍이 남긴 미세한 바다 소금의 흔적이 영원처럼 머뭅니다."}}' WHERE id = 48;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (49, '브룩라디 21년', 'single_malt', 'Bruichladdich Whisky', 'whiskey/138631.jpg', 50.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Bruichladdich 21 Year Old - Re/Define 70cl', 378545, 'https://www.masterofmalt.com/whiskies/bruichladdich/bruichladdich-21-year-old-re-define-whisky/?sku=138631', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "브룩라디 21년(Bruichladdich 21 Year Old)은 전 세계 위스키 매니아들 사이에서 증류소 헤리티지의 위대한 깊이감을 증명하는 최고급 럭셔리 익스프레션입니다. 2회 증류와 논피티드 스타일이라는 브룩라디 고유의 DNA가 21년이라는 기나긴 세월 속에서 어떻게 진화하는지 명징하게 보여줍니다. 주로 46% 도수에 내추럴 컬러, 비냉각여과로 병입되어 단 하나의 맛도 튀지 않는 독보적인 밸런스를 뽐냅니다.", "제조 및 숙성": "마스터 블렌더의 정밀한 감각으로 선별된 최고급 아메리칸 오크 버번 캐스크와 유러피안 오크 셰리 캐스크 원액을 정교하게 블렌딩했습니다. 아일라 섬의 서늘하고 축축한 dunnage 창고에서 오랜 세월 장기 숙성되어 깊고 고풍스러운 내추럴 골드 빛을 띱니다."}, "feature": {"위스키 거장의 마스터피스": "장기 숙성을 통해 브룩라디 고유의 화사함과 맥아 단맛이 극도로 부드럽고 정교하게 다듬어졌습니다.", "셰리와 버번의 황금 비율": "버번 캐스크의 깊은 바닐라 풍미와 셰리 캐스크의 풍부한 과일 향이 어느 한쪽으로 치우치지 않고 완벽한 균형을 이룹니다.", "결점 없는 조화": "입안에 닿는 순간 실크처럼 매끄럽고 고급스러운 질감을 선사하여 만족도가 매우 높은 위스키입니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마입니다. 말린 무화과와 건포도, 달콤한 마지팬 향이 먼저 다가오고, 이내 오래된 가죽, 따뜻한 바닐라 빈, 그리고 아일라 해풍이 남긴 은은한 미네랄리티가 기품 있게 어우러집니다.", "맛 (Palate)": "풀바디의 오일리하고 매끄러운 텍스처가 특징입니다. 다크 초콜릿, 졸인 살구, 캐러멜 토피의 단맛이 입안을 코팅하고, 구운 아몬드의 고소함과 블랙페퍼, 육두구의 알싸한 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "놀라울 정도로 길고 dry하면서도 우아합니다. 달콤한 셰리와 바닐라의 여운이 가라앉으며 기품 있는 오크의 향, 그리고 입안 전체를 계속 감싸는 은은한 바다 소금의 잔향이 지속됩니다."}}' WHERE id = 49;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (50, '발베니 14년 캐리비안 캐스크', 'single_malt', 'Balvenie Whisky', 'whiskey/16226.jpg', 43.0, 14, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 14 Year Old Caribbean Cask 70cl', 111632, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-14-year-old-caribbean-cask-whisky/?sku=16226', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 14년 캐리비안 캐스크(The Balvenie 14 Year Old Caribbean Cask)는 전설적인 몰트 마스터 데이비드 C. 스튜어트가 개발한 독창적인 캐스크 피니시 공법의 진수를 보여주는 베스트셀러 싱글 몰트 위스키입니다. 발베니 특유의 부드럽고 달콤한 꿀맛 같은 하우스 스타일에 캐리비안 럼 오크통 고유의 이국적인 열대 과일 풍미와 토피 당의 달콤함을 더해, 위스키 애호가들 사이에서 독보적인 인기를 구가하는 제품입니다. 43% 도수로 병입되어 균형 잡힌 만족감을 선사합니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 최초 14년 동안 안정적으로 숙성시켜 깊은 바닐라 향을 확보한 후, 마스터 블렌더가 직접 서인도 제도 럼을 담아 특제 제작한 럼 캐스크로 원액을 옮겨 담아 수개월간 정교한 피니시 숙성 과정을 거쳤습니다."}, "feature": {"럼 캐스크 피니시의 바이블": "정통 위스키에 이국적인 캐리비안 럼의 달콤한 터치를 가미하여 독창적인 스펙트럼을 넓혔습니다.", "이국적인 단맛의 유혹": "일반적인 셰리나 버번 숙성과는 결이 다른, 구운 당밀과 패션프루트 같은 달콤한 향이 도드라집니다.", "실키한 질감과 대중성": "발베니 특유의 부드럽고 달콤한 터치 덕분에 입문자부터 부드러운 스타일을 선호하는 매니아까지 모두를 매료시킵니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 달콤한 아로마가 코를 자극합니다. 발베니 고유의 진한 꿀과 캐러멜 토피 향 뒤로, 잘 익은 패션프루트, 망고 같은 열대 과일의 화사함과 구운 당밀, 이국적인 럼의 향이 달콤하게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 순간 실크나 벨벳처럼 매끄럽고 크리미한 부드러움을 줍니다. 바닐라 크림과 구운 마시멜로, 오렌지 마멀레이드의 달콤함이 퍼지고, 뒤이어 럼 캐스크에서 배어 나온 따뜻한 생강, 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "온화하고 감미로운 여운이 길게 이어집니다. 꿀을 머금은 오크 향과 토피 당의 달콤한 흔적이 가라앉으며, 입안에 기분 좋은 따뜻함과 이국적인 과일의 잔향을 부드럽게 남깁니다."}}' WHERE id = 50;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (51, '발베니 12년 더블우드', 'single_malt', 'Balvenie Whisky', 'whiskey/1767.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie DoubleWood 12 Year Old 70cl', 85105, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-doublewood-12-year-old-whisky/?sku=1767', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 12년 더블우드(The Balvenie 12 Year Old DoubleWood)는 전설적인 몰트 마스터 데이비드 C. 스튜어트가 1993년에 완성하여 전 세계 위스키 역사에 캐스크 피니시(Cask Finishing)라는 혁신을 일으킨 싱글 몰트 위스키입니다. 부드러운 단맛과 풍부한 깊이감을 고루 갖춘 발베니의 가장 대표적인 클래식 엔트리 제품입니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 최소 12년 동안 원액을 안정적으로 숙성시킨 후, 최고급 스페니시 오크 오로로소 셰리 캐스크(Oloroso Sherry Casks)로 원액을 옮겨 담아 마지막 9개월 동안 피니시 숙성 및 마리잉 과정을 거쳤습니다."}, "feature": {"캐스크 피니시의 시초": "위스키 업계에서 캐스크 피니시 공법을 최초로 대중화하여 싱글 몰트의 스펙트럼을 넓힌 역사적인 제품입니다.", "버번과 셰리의 황금 비율": "버번 배럴의 화사한 부드러움과 셰리 캐스크의 묵직한 과일 풍미가 정교하게 조화를 이룹니다.", "독보적인 입문 교과서": "부드러운 질감과 달콤한 향 덕분에 위스키 입문자들과 애호가들 사이에서 오랜 기간 표준으로 통합니다."}}', note = '{"note": {"향 (Nose)": "감미로운 꿀의 단향과 바닐라 아로마가 풍부하게 피어오르고, 그 뒤를 이어 오렌지 껍질의 상큼함과 셰리 오크통 특유의 말린 자두, 은은한 서양 배의 향이 조화롭게 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 부드럽고 매끄러우며, 캐러멜 토피와 구운 견과류의 고소함, 벌꿀 집의 단맛이 중심을 잡고 시나몬과 알싸한 생강의 우드 스파이스가 층을 이룹니다.", "여운 (Finish)": "온화하고 드라이한 잔향이 기분 좋게 지속됩니다. 오크통에서 배어 나온 부드러운 바닐라의 흔적과 셰리 와인의 단맛, 그리고 따뜻한 계피 향이 산뜻하게 마무리됩니다."}}' WHERE id = 51;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (52, '발베니 21년 포트우드', 'single_malt', 'Balvenie Whisky', 'whiskey/1769.jpg', 40.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 21 Year Old PortWood Finish 70cl', 374909, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-21-year-old-port-wood-finish-whisky/?sku=1769', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 21년 포트우드(The Balvenie 21 Year Old PortWood)는 증류소의 고연산 정규 라인업 중 가장 귀족적이고 품격 있는 우아함을 자랑하는 마스터피스입니다. 20년이 넘는 기나긴 세월 동안 다듬어진 발베니의 부드러운 캐릭터에 최고급 주정강화 포트 와인 오크통의 화려한 풍미를 정교하게 입혔습니다.", "제조 및 숙성": "아메리칸 오크 버번 배럴에서 최소 21년이라는 기나긴 세월 동안 장기 숙성시켜 알코올의 날카로움을 정제한 후, 포르투갈의 유서 깊은 와이너리에서 공수한 최고급 포트 파이프(Port Pipes) 캐스크로 원액을 옮겨 담아 피니시 숙성을 거쳤습니다."}, "feature": {"포트 파이프의 화려함": "포트 와인 캐스크가 선사하는 이국적인 베리류의 단맛과 붉은 아우라가 발베니의 하우스 스타일과 완벽하게 동화되었습니다.", "시간이 공들인 부드러움": "21년의 장구한 숙성 기간을 거쳐 자극적인 스파이스는 완전히 사라지고, 벨벳처럼 부드럽고 농밀한 질감만 남았습니다.", "귀족적인 발란스": "과하게 무겁지 않으면서도 화사한 과일 향과 중후한 오크통 숙성미가 고결한 구조감을 형성합니다."}}', note = '{"note": {"향 (Nose)": "깊은 숙성 아로마가 가득 퍼집니다. 럼에 절인 건포도, 신선한 잘 익은 복숭아, 말린 무화과의 달콤한 향이 지배적으로 피어오르고, 그 뒤로 은은한 가죽과 부드러운 흰 꽃의 향이 레이어를 이룹니다.", "맛 (Palate)": "벨벳이나 실크를 혀에 얹은 듯 극도로 부드럽고 매끄러운 텍스처가 압권입니다. 진한 밤꿀과 다크 초콜릿, 졸인 크랜베리의 단맛이 기품 있게 전개되며 구운 피칸의 고소함이 조화를 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 감미로운 여운을 선사합니다. 농축된 와인의 단맛과 부드러운 나무의 풍미 뒤로 가슴 속까지 따뜻해지는 우아한 스파이스의 여운이 오래도록 머뭅니다."}}' WHERE id = 52;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (53, '발베니 12년 더 스위트 토스트 오브 아메리칸 오크', 'single_malt', 'Balvenie Whisky', 'whiskey/89867.jpg', 43.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 12 Year Old - The Sweet Toast of American Oak 70cl', 89614, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-12-year-old-the-sweet-toast-of-american-oak-whisky/?sku=89867', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 12년 더 스위트 토스트 오브 아메리칸 오크(The Balvenie 12 Year Old The Sweet Toast of American Oak)는 증류소의 장인 정신을 전달하는 스토리 익스프레션(Stories Collection)의 첫 번째 제품입니다. 오크통의 안쪽을 정교하고 강렬하게 태우는 실험을 감행하여 탄생했습니다.", "제조 및 숙성": "전통적인 버번 캐스크에서 숙성된 발베니 원액을 엄선한 후, 미국 켄터키주에서 공수한 뉴 아메리칸 버진 오크 캐스크(Virgin American Oak)로 옮겨 숙성했습니다. 이 오크통은 내부를 깊게 그을려 단맛을 극대화했습니다."}, "feature": {"버진 오크의 화려한 변주": "리필 캐스크가 아닌 뉴 버진 오크의 강렬한 터치를 가미하여 기존 하우스 스타일보다 훨씬 직관적인 풍미를 전합니다.", "스토리 컬렉션의 서막": "장인들의 실패를 두려워하지 않는 실험 정신과 협업의 역사를 한 보틀 안에 스토리텔링으로 고스란히 담아냈습니다.", "바닐라와 토피의 극대화": "오크통을 그을리는 과정에서 배어 나온 천연 나무 설탕 성분 덕분에 독보적인 크리미함과 단맛을 선사합니다."}}', note = '{"note": {"향 (Nose)": "강렬하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 구운 마시멜로, 신선한 맥아의 고소함과 시트러스 계열의 상큼한 시럽 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "크리미하고 농밀하게 입안을 코팅하는 텍스처가 일품입니다. 진한 오렌지 오일과 벌꿀 집의 단맛이 파도처럼 밀려오고, 버진 오크 캐스크 특유의 으깬 통후추와 흑설탕, 넛멕의 스파이시한 타격감이 대조를 이룹니다.", "여운 (Finish)": "따뜻하고 풍부한 잔향이 길게 이어집니다. 구운 오크의 우디한 향과 바닐라 캐러멜의 달콤한 흔적이 가라앉으며, 입안 전체를 묵직하게 감싸 안는 진득하고 스파이시한 단맛의 미련이 기분 좋게 남습니다."}}' WHERE id = 53;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (54, '발베니 16년 프렌치 오크', 'single_malt', 'Balvenie Whisky', 'whiskey/115396.jpg', 47.6, 16, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 16 Year Old French Oak 70cl', 225965, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-16-year-old-french-oak-whisky/?sku=115396', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 16년 프렌치 오크(The Balvenie 16 Year Old French Oak)는 프랑스 주정강화 와인 캐스크 피니시 제품입니다. 발베니 특유의 달콤한 꿀맛 하우스 스타일에 프랑스 와인 오크통이 가진 이국적이고 화사한 과수원의 싱그러움을 도킹시켰습니다.", "제조 및 숙성": "전통 아메리칸 오크 버번 배럴에서 16년 동안 안정적으로 장기 숙성되어 부드러운 깊이를 획득한 원액을 베이스로 합니다. 이 원액을 프랑스 샤랑트 지역의 명품 주정강화 와인(Pineau des Charentes)을 담았던 프렌치 오크 캐스크로 옮겨 최종 피니시 숙성을 거쳤습니다."}, "feature": {"샤랑트 피노 캐스크의 마술": "코냑과 포도즙을 섞어 만드는 진귀한 와인 오크통 숙성을 통해 독창적이고 상큼한 산미와 단맛을 확보했습니다.", "탄탄한 구조감": "엔트리 라인보다 한층 높은 도수 세팅 덕분에 화사하고 플로럴한 아로마가 뭉개지지 않고 단단하게 전해집니다.", "과수원의 싱그러운 아우라": "묵직한 셰리 숙성과는 결이 다른, 잘 익은 자두와 청포도 고유의 우아한 산뜻함을 자랑합니다."}}', note = '{"note": {"향 (Nose)": "우아하고 싱그럽습니다. 갓 피어난 자스민 같은 화이트 플라워 아로마와 신선한 청포도, 서양 배의 시트러스가 달콤하게 올라옵니다. 그 기저에는 꿀을 바른 구운 토스트의 향이 받쳐줍니다.", "맛 (Palate)": "입안을 매끄럽고 맑게 감싸 안는 실키한 질감이 돋보입니다. 졸인 황도 복숭아와 청자두 잼, 캐러멜 시럽의 단맛이 퍼지고, 뒤이어 프렌치 오크 특유의 쌉싸름한 오렌지 제스트 스파이스와 따뜻한 진저의 맛이 전개됩니다.", "여운 (Finish)": "깔끔하면서도 긴 여운을 남깁니다. 바닐라의 달콤함과 와인 캐스크 고유의 상큼한 과일 향이 가라앉으며, 입안에 기분 좋은 드라이함과 우디한 스파이스의 흔적을 산뜻하게 남깁니다."}}' WHERE id = 54;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (55, '발베니 14년 더 위크 오브 피트', 'single_malt', 'Balvenie Whisky', 'whiskey/89868.jpg', 48.3, 14, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 14 Year Old - The Week of Peat 70cl', 136249, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-14-year-old-the-week-of-peat-whisky/?sku=89868', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 14년 더 위크 오브 피트(The Balvenie 14 Year Old The Week of Peat)는 장인 정신을 기리는 스토리 익스프레션(Stories Collection)의 두 번째 명작입니다. 전통적으로 논피트 위스키를 만드는 발베니가 1년 중 단 일주일 동안만 피트 위스키를 증류한다는 전통을 담았습니다.", "제조 및 숙성": "1년 중 증류소 정비 직전 일주일 동안 하이랜드 지역의 헤더 피트 연기로 건조한 보리를 사용하여 증류했습니다. 이 향긋한 피트 원액을 최고급 퍼스트 필 및 리필 아메리칸 오크 버번 캐스크에서 14년 동안 숙성시켰습니다."}, "feature": {"발베니의 독창적인 피트": "타르나 소독약 향 중심의 아일라 피트와 달리, 벌꿀 향 가득한 향긋하고 화사한 연기 향을 선사합니다.", "탄탄한 타격감": "높은 알코올 볼륨감 덕분에 헤비 피트 스모크 속에서도 발베니 본연의 바닐라 단맛과 과일 단 향이 무너지지 않습니다.", "일주일의 희소성": "증류소의 특별한 시즌에만 한정 생산되는 원액을 기반으로 하여, 피트 애호가들과 발베니 매니아들 사이에서 반전의 보틀로 통합니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 부드러운 스모크 향이 코를 부드럽게 감쌉니다. 타오르는 헤더 장작의 연기 뒤로 잘 익은 서양 배, 싱그러운 레몬 시트러스와 따뜻한 꿀, 바닐라 포드 고유의 진한 단 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "오일리하고 매끄러운 텍스처가 혀를 감쌉니다. 달콤한 토피 당, 바닐라 크림, 감미로운 벌꿀 집의 풍미가 중심을 잡고, 뒤이어 알싸한 블랙페퍼, 구운 생강, 그리고 향긋한 피트 스모크의 풍미가 터져 나옵니다.", "여운 (Finish)": "온화하고 묵직한 여운이 매우 길게 지속됩니다. 오크통의 따뜻한 우디함과 바닐라 캐러멜의 단맛이 서서히 가라앉으며, 입안 가득 맴도는 건조하고 향긋한 캠프파이어의 연기 잔향이 인상적인 피날레를 장식합니다."}}' WHERE id = 55;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (56, '발베니 25년 레어 메리지', 'single_malt', 'Balvenie Whisky', 'whiskey/109330.jpg', 48.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 25 Year Old - Rare Marriages 70cl', 991039, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-25-year-old-rare-marriages-whisky/?sku=109330', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 25년 레어 메리지(The Balvenie 25 Year Old Rare Marriages)는 전설적인 몰트 마스터 데이비드 C. 스튜어트가 장인 정신을 담아 빚어낸 최고급 럭셔리 위스키입니다. 발베니 증류소 고유의 캐릭터를 가장 완벽하고 다채로운 풍미로 표현해 낸 마스터피스라 할 수 있습니다.", "제조 및 숙성": "아메리칸 버번 오크통(리필)을 중심으로, 유러피안 오로로소 셰리 오크통에서 숙성된 희귀 원액들을 아주 정밀한 비율로 선택해 만듭니다. 이 원액들은 발베니의 전통적인 오크 마리잉 툰(Marrying Tun, 혼합조)에서 함께 어우러집니다."}, "feature": {"블렌딩의 미학": "전통 오크 통에서 원액을 결합하여 타협 없는 완벽한 밸런스를 구현했습니다.", "버번 오크 중심의 깊이감": "아메리칸 오크 숙성의 정점을 보여주며, 섬세한 셰리 향이 이를 우아하게 받쳐줍니다.", "결점 없는 조화": "발베니 특유의 꿀맛 같은 부드러움을 극대화하여 실크처럼 부드럽고 고급스러운 질감을 선사합니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며, 코끝을 스치는 향이 매우 아름답습니다. 진한 꿀과 달콤한 밀랍, 따뜻한 바닐라 빈의 향이 직관적으로 피어오릅니다. 뒤이어 잘 익은 가을 과수원의 붉은 사과와 배의 향이 느껴지며 레이어를 이룹니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 실크나 벨벳처럼 매끄럽고 깊은 풍미가 느껴집니다. 풍부한 바닐라 크림하고 구운 마시멜로의 진한 달콤함이 먼저 입안을 채우고, 졸인 황도 복숭아와 배 타르트 같은 과일의 풍미로 이어집니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 달콤함이 서서히 잦아들면서 꿀을 머금은 오크 향, 베이킹 스파이스, 구운 견과류의 고소함이 남고, 마지막에는 다크 카카오의 세련되고 쌉싸름한 여운이 길게 이어집니다."}}' WHERE id = 56;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (57, '발베니 18년 페드로 히메네스 캐스크', 'single_malt', 'Balvenie Whisky', 'whiskey/124592.jpg', 48.7, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 18 Year Old Pedro Ximénez Cask 70cl', 482398, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-18-year-old-pedro-ximenez-cask-whisky/?sku=124592', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 18년 페드로 히메네스 캐스크(The Balvenie 18 Year Old Pedro Ximénez Cask)는 면세점 한정판 또는 특정 스페셜 에디션으로 출시되어 전 세계 셰리 위스키 매니아들을 열광시킨 진득하고 농밀한 싱글 몰트 위스키입니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 최초 18년이라는 오랜 세월 동안 장기 숙성되어 완벽한 부드러움과 깊이를 획득한 고연산 원액을 기반으로 합니다. 이 진귀한 원액을 스페인의 페드로 히메네스(Pedro Ximénez) 와인을 담았던 최고급 퍼스트 필 캐스크로 옮겨 피니시 숙성했습니다."}, "feature": {"PX 셰리의 진득한 유혹": "위스키 세계에서 가장 달콤한 PX 와인 오크통의 영향력 덕분에 말린 무화과와 토피의 깊은 맛이 압권입니다.", "중후한 화력": "매우 높은 알코올 볼륨감 덕분에 진득한 셰리의 단맛 속에서도 오크통 고유의 탄닌과 스파이스가 강력한 타격감을 유지합니다.", "고연산 셰리 피니시의 정석": "18년의 장기 숙성이 주는 부드러운 가죽 향과 묵직한 과일 단맛이 완벽한 드라마처럼 유기적으로 이어집니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 가득 차오르는 아로마입니다. 흑설탕에 졸인 자두, 건포도, 베리류 잼의 진한 단향이 먼저 코를 찌르고, 뒤이어 달콤한 밀랍, 캐러멜 토피, 오래된 가죽, 그리고 계피 가루를 뿌린 구운 사과의 향이 깊고 고풍스럽게 어우러집니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 오일리하게 입안 전체를 가득 코팅합니다. 다크 초콜릿 파이, 무화과 잼, 토피 당의 진한 단맛이 파도처럼 밀려오고, 뒤이어 블랙페퍼, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며, 입안 가득 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 흔적이 짙게 머뭅니다."}}' WHERE id = 57;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (58, '발베니 40년', 'single_malt', 'Balvenie Whisky', 'whiskey/27232.jpg', 42.2, 40, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Balvenie 40 Year Old 70cl', 12229217, 'https://www.masterofmalt.com/whiskies/balvenie/the-balvenie-40-year-old-whisky/?sku=27232', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 40년(The Balvenie 40 Year Old)은 증류소가 보유한 초고연산 원액 중에서도 극상의 품질을 지닌 오크통만을 엄선하여 소량 한정 생산하는 최상위 하이엔드 마스터피스입니다. 반세기에 가까운 세월 동안 자연스럽게 정제된 고귀한 아우라를 지니고 있습니다.", "제조 및 숙성": "증류소 창고 깊숙한 곳에서 무려 40년 이상 세월을 버텨온 희귀한 전통 아메리칸 오크 버번 배럴과 유러피안 오크 오로로소 셰리 캐스크 원액을 정밀하게 감별하여 전통 오크 마리잉 툰(Marrying Tun)에 모아 결합하는 장인 예술로 탄생했습니다."}, "feature": {"반세기에 가까운 세월": "40년의 기나긴 세월 동안 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 위스키의 정수입니다.", "극도의 희소 가치": "전 세계적으로 매년 극소량만 출시되어 위스키 수집가와 글로벌 자산가들 사이에서 평생의 드림 보틀로 통합니다.", "현대 기술의 초월": "오래된 마호가니 나무, 정제된 밀랍, 숙성된 가죽 향 등 수십 년의 세월만이 자아낼 수 있는 귀족적인 레이어를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고, 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 계속감싸는 감미로운 허니 오크의 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 58;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (59, '발베니 30년', 'single_malt', 'Balvenie Whisky', 'whiskey/27231.jpg', 44.2, 30, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 30 Year Old 70cl', 5404467, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-30-year-old-whisky/?sku=27231', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 30년(The Balvenie 30 Year Old)은 위스키의 거장들이 선사하는 블렌딩 미학의 정점이자 전 세계 위스키 컬렉터들의 표적이 되는 최고급 프리미엄 싱글 몰트 위스키입니다. 30년이라는 장구한 숙성 연수 속에서 자극적인 알코올은 완벽히 정제되고, 깊고 감미로운 단맛을 완성했습니다.", "제조 및 숙성": "30년 이상 오랜 세월 동안 전통 아메리칸 오크 버번 배럴에서 숙성되어 독보적인 바닐라와 달콤함을 획득한 원액과 최고급 유러피안 오크 오로로소 셰리 캐스크에서 묵직한 과일 풍미를 입힌 원액들을 엄선하여 결합했습니다."}, "feature": {"삼십 년의 숙성미": "한 세기의 3분의 1에 달하는 세월 동안 나무의 성분과 원액이 만나 극상의 실키함과 중후한 깊이감을 확보했습니다.", "버번과 셰리의 마스터피스": "두 캐스크 고유의 캐릭터가 어느 한쪽으로 치우치지 않고 완벽한 대칭과 조화를 이루는 블렌딩의 예술입니다.", "결점 없는 조화": "발베니 특유의 꿀맛 같은 부드러움을 극대화하여 입안에서 느껴지는 모든 레이어가 귀족적인 자태를 이룹니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며, 코끝을 스치는 향이 매우 아름답습니다. 진한 밤꿀과 달콤한 밀랍, 부드러운 바닐라 빈의 향이 직관적으로 피어오릅니다. 뒤이어 말린 무화과, 오렌지 마멀레이드, 오래된 가죽, 그리고 오래된 오크 고유의 부드러운 아로마가 겹겹이 층을 이룹니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳이나 실크처럼 매끄럽고 깊은 풍미가 가득 차오릅니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 달콤함이 먼저 입안을 채우고, 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 감미로운 여운이 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며, 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 따뜻함과 함께 머뭅니다."}}' WHERE id = 59;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (60, '발베니 19년 레벨레이션 오브 캐스크 앤 캐릭터', 'single_malt', 'Balvenie Whisky', 'whiskey/128863.jpg', 47.5, 19, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 19 Year Old - Revelation of Cask & Character 70cl', 507706, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-19-year-old-revelation-of-cask-character-whisky/?sku=128863', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 19년 레벨레이션 오브 캐스크 앤 캐릭터(The Balvenie 19 Year Old A Revelation of Cask and Character)는 증류소의 유서 깊은 수작업 장인 정신을 기리는 스토리 익스프레션(Stories Collection)의 프리미엄 에디션입니다. 셰리 오크통 숙성이 선사할 수 있는 가장 우아하고 다채로운 캐릭터를 담아냈습니다.", "제조 및 숙성": "마스터 블렌더 켈시 맥케치니가 직접 엄선한 최고 품질의 유러피안 오크 오로로소 셰리 캐스크(Oloroso Sherry Casks)에서 19년 동안 온전히 호흡하며 숙성시켰습니다. 장인들의 손길로 정밀하게 수리되고 다듬어진 오크통만을 사용하여 원액의 밀도를 높였습니다."}, "feature": {"오크통 장인들의 찬가": "오크통을 만들고 유지하는 증류소 내부 협동조합 장인들의 노고와 철학을 스토리텔링으로 승화시킨 보틀입니다.", "100% 오로로소 셰리 숙성": "유러피안 셰리 캐스크에서만 19년을 보낸 원액들을 기반으로 하여 짙은 컬러감과 독보적인 다크 크러스트 풍미를 자랑합니다.", "고연산 스토리의 위엄": "엔트리 라인보다 훨씬 높은 숙성 연수와 47.5% 도수 세팅 덕분에 풍미의 촘촘한 밀도와 구조감이 압권입니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마입니다. 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 무화과 잼의 단향이 먼저 가득 퍼집니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 시가 박스의 우디함, 그리고 상큼한 말린 오렌지 껍질과 바닐라 빈의 향이 조화를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고, 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 60;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (61, '발베니 12년 트리플 캐스크', 'single_malt', 'Balvenie Whisky', 'whiskey/38423.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Balvenie 12 Year Old Triple Cask 100cl', 336825, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-12-year-old-triple-cask-whisky/?sku=38423', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 12년 트리플 캐스크(The Balvenie 12 Year Old Triple Cask)는 면세점 시장을 겨냥하여 출시되었던 제품으로, 세 가지 다른 오크통의 조합을 통해 발베니 특유의 부드럽고 꿀맛 같은 하우스 캐릭터를 한층 더 다채롭고 화사하게 풀어낸 싱글 몰트 위스키입니다.", "제조 및 숙성": "퍼스트 필 버번 배럴, 리필 버번 배럴, 그리고 오로로소 셰리 캐스크까지 총 세 가지 종류의 오크통에서 각각 최소 12년 동안 숙성된 원액들을 마스터 블렌더의 정교한 비율로 결합하여 대형 오크통에서 마리잉 과정을 거쳤습니다."}, "feature": {"삼중 캐스크의 복합미": "버번과 셰리뿐만 아니라 리필 캐스크의 원액까지 조화롭게 융합하여 다층적인 레이어의 과일 향을 이끌어냈습니다.", "화사한 대중성": "기존의 정규 라인업보다 가볍고 화사한 터치를 지니고 있어 여행자들과 대중들이 편안하게 즐기기에 적합합니다.", "섬세한 꿀맛의 진화": "발베니 고유의 허니 노트 기저 위에 버번의 화사한 바닐라와 셰리의 스파이시함이 기분 좋게 얹어져 있습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 꿀과 풍부한 바닐라 아로마가 먼저 코를 반깁니다. 뒤이어 신선한 빨간 사과, 잘 익은 배의 시트러스와 함께 셰리 오크통에서 기인한 은은한 시나몬 향이 감미롭게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 느낌이 부드럽고 가볍습니다. 부드러운 토피 당, 밀크 초콜릿, 시럽을 바른 과일 타르트의 달콤함이 퍼지고 오크통에서 배어 나온 가벼운 나무 스파이스와 말린 오렌지 껍질의 풍미가 전개됩니다.", "여운 (Finish)": "온화하고 산뜻한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 가벼운 생강 스파이스의 흔적이 입안을 기분 좋고 묵직하게 채우며 마무리됩니다."}}' WHERE id = 61;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (62, '발베니 12년 싱글배럴 퍼스트 필', 'single_malt', 'Balvenie Whisky', 'whiskey/21515.jpg', 47.8, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 12 Year Old Single Barrel - First Fill 70cl', 135396, 'https://www.masterofmalt.com/whiskies/balvenie/balvenie-12-year-old-single-barrel-first-fill-whisky/?sku=21515', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 12년 싱글배럴 퍼스트 필(The Balvenie 12 Year Old Single Barrel First Fill)은 블렌딩이나 마리잉 과정 없이 단 하나의 오크통에서 나온 원액만을 병입하여 버번 배럴 숙성의 순수한 정수를 보여주는 프리미엄 싱글 몰트 위스키입니다.", "제조 및 숙성": "미국 켄터키주에서 공수한 최고급 퍼스트 필 아메리칸 오크 버번 배럴에서 최소 12년 동안 숙성되었습니다. 각 오크통마다 단 300병 미만의 수량만 수작업으로 병입되며, 보틀 레이블에 고유의 오크통 번호가 명시됩니다."}, "feature": {"단일 오크통의 순수함": "다른 캐스크와의 혼합이 전혀 없어 최고급 아메리칸 버번 오크통이 품고 있는 때 묻지 않은 순수한 아로마를 선사합니다.", "독보적인 희소 가치": "각 보틀마다 고유의 통 번호가 새겨져 있어 매 보틀마다 미세하게 다른 개성을 탐험하는 재미가 있습니다.", "내추럴 무여과 구성": "47.8%의 탄탄한 도수에 냉각 여과 없이 병입되어 원액 본연의 묵직한 오일감과 바닐라 단맛을 극대화했습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 진한 바닐라 포드와 달콤한 캐러멜 토피 향이 직관적으로 피어오릅니다. 뒤이어 상큼한 레몬 제스트, 신선한 구운 맥아의 고소함과 함께 향긋한 화이트 플라워의 아로마가 레이어를 이룹니다.", "맛 (Palate)": "크리미하고 묵직하게 입안을 코팅하는 마우스필이 일품입니다. 꿀을 가득 머금은 밀크 초콜릿과 구운 마시멜로, 졸인 황도 복숭아의 단맛이 퍼지고 알싸한 화이트 페퍼와 따뜻한 생강의 스파이스가 혀를 자극합니다.", "여운 (Finish)": "온화하고 풍부한 잔향이 길게 이어집니다. 퍼스트 필 버번 캐스크 특유의 진한 바닐라 단맛과 나무 스파이스의 따뜻함이 입안을 기분 좋고 묵직하게 채우며 마무리됩니다."}}' WHERE id = 62;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (63, '발베니 15년 싱글배럴 셰리 캐스크', 'single_malt', 'Balvenie Whisky', 'whiskey/33345.jpg', 47.8, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Balvenie 15 Year Old Single Barrel Sherry Cask 70cl', 252208, 'https://www.masterofmalt.com/whiskies/balvenie/the-balvenie-15-year-old-single-barrel-sherry-cask-whisky/?sku=33345', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "발베니 15년 싱글배럴 셰리 캐스크(The Balvenie 15 Year Old Single Barrel Sherry Cask)는 셰리 오크통 숙성이 선사할 수 있는 가장 중후하고 녹진한 캐릭터를 단 하나의 오크통 독립 원액으로만 뿜어내는 최고급 럭셔리 싱글 몰트 위스키입니다.", "제조 및 숙성": "유러피안 오크 오로로소 셰리 캐스크에서 최소 15년 이상 장기 숙성된 단 하나의 오크통 원액만을 선택하여 병입했습니다. 한 캐스크당 800병 미만으로 소량 수작업 병입되며, 47.8%의 높은 도수에 내추럴 컬러로 완성되었습니다."}, "feature": {"100% 단일 셰리 숙성": "블렌딩 과정이 전혀 없어 오로로소 셰리 오크통의 짙은 마호가니 빛 내추럴 컬러와 진득한 밀도를 고스란히 간직하고 있습니다.", "캐스크별 독립적 정체성": "보틀마다 캐스크 넘버와 병 번호가 수기 명시되어 셰리 위스키 매니아들 사이에서 수집 및 오픈런의 대상이 됩니다.", "중후한 구조감": "스피릿의 거친 스파이스가 오랜 세월 동안 둥글게 깎여 나가 셰리의 단맛과 완벽한 하모니를 구현합니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 가득 차오르는 아로마입니다. 흑설탕에 졸인 자두, 진한 건포도, 달콤한 대추야자의 깊은 단향이 코를 찌르고 오래된 가죽, 시가 박스의 우디함과 계피 가루의 향이 고풍스럽게 어우러집니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 오일리하게 입안 전체를 풀바디로 감쌉니다. 다크 초콜릿 파이, 무화과 잼, 토피 당의 진한 단맛이 밀려오고 블랙페퍼, 구운 생강의 알싸한 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 기품 있는 마호가니 나무의 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 63;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (64, '버팔로 트레이스', 'bourbon', 'Buffalo Trace', 'whiskey/10987.jpg', 40.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Buffalo Trace 70cl', 40602, 'https://www.masterofmalt.com/whiskies/buffalo-trace/buffalo-trace-whiskey/?sku=10987', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "버팔로 트레이스(Buffalo Trace)는 미국 켄터키주에 위치한 역사적인 버팔로 트레이스 증류소의 이름을 전면에 내세운 세계적인 벤치마크 버번 위스키입니다. 개척 시대의 거친 야생 버팔로들이 지나간 길에서 유래했으며, 버번 위스키가 가질 수 있는 정석적이고 대담한 캐릭터를 45%의 도수 속에서 가장 훌륭한 밸런스로 보여줍니다.", "제조 및 숙성": "옥수수를 주원료로 하고 호밀과 몰트를 섞은 전통적인 매시빌을 사용하여 증류합니다. 안쪽을 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크에서 수년간 숙성하여, 켄터키의 이른바 미들 창고에서 완벽한 호흡을 거쳐 탄생합니다."}, "feature": {"버번 위스키의 기준점": "달콤함, 우디함, 스파이시함의 삼박자가 가장 모범적으로 짜여 있어 전 세계 바텐더들과 매니아들의 교과서로 통합니다.", "역사적인 증류소의 정수": "미국에서 가장 오래되고 수많은 어워드를 수상한 증류소의 플래그십 보틀로서 신뢰도 높은 품질을 보장합니다.", "독보적인 가성비": "부담 없는 가격대에서 버번 고유의 진득한 타격감과 캐러멜, 바닐라 본연의 개성을 가장 온전하게 맛볼 수 있습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 달콤한 캐러멜 토피와 짙은 바닐라, 그리고 버진 오크 특유의 묵직한 가죽 향과 매콤한 밀트 스파이스가 코를 자극합니다. 뒤이어 잘 익은 오렌지 껍질과 말린 과일의 단 향이 어우러집니다.", "맛 (Palate)": "입안에 닿는 순간 버번 특유의 진득하고 타격감 있는 단맛이 들어옵니다. 브라운 슈가, 호두의 고소함과 옥수수의 단맛이 퍼지고, 으깬 통후추, 계피, 구운 생강의 스파이시함이 혀를 매끄럽게 코팅합니다.", "여운 (Finish)": "깔끔하면서도 온화한 나무 잔향이 지속됩니다. 오크통에서 배어 나온 부드러운 토피 당의 달콤함과 드라이한 오크 스파이스의 흔적이 가슴 깊은 곳까지 따뜻한 여운을 전해 줍니다."}}' WHERE id = 64;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (65, '트래블러 위스키', 'blended', 'Buffalo Trace', 'whiskey/136910.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Traveller Whiskey 70cl', 47386, 'https://www.masterofmalt.com/whiskies/buffalo-trace/traveller-whiskey/?sku=136910', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "트래블러 위스키(Traveller Whiskey Batch No. 40)는 버팔로 트레이스 증류소의 세계적인 마스터 디스틸러 하를란 휘틀리와 그래미 어워드 수상 음악가 크리스 스테이플턴의 독창적인 협업으로 탄생한 프리미엄 아메리칸 블렌디드 위스키입니다. 음악과 위스키의 예술적 결합을 모티브로 삼았으며, 45% 도수 안에서 누구나 쉽고 부드럽게 즐길 수 있는 이지드링킹 캐릭터를 지향합니다.", "제조 및 숙성": "버팔로 트레이스 증류소가 보유한 엄선된 다양한 아메리칸 위스키 원액들을 기반으로 합니다. 마스터 블렌더의 치밀한 블렌딩 실험을 통해 버번 위스키 특유의 묵직함을 다소 걷어내고 복합적이면서도 한층 세련된 텍스처를 구현하여 숙성시켰습니다."}, "feature": {"음악가와의 예술적 결합": "크리스 스테이플턴의 음악적 감성과 하를란 휘틀리의 양조 지식이 결합하여 위스키 컬렉터들의 이목을 사로잡았습니다.", "최적의 블렌딩 넘버 40": "수십 번의 샘플링 결합 테스트를 거쳐 마침내 도달한 40번째 배치의 완성도 높은 부드러움을 전면에 뽐냅니다.", "뛰어난 부드러움과 접근성": "강한 타격감 위주의 기존 버번 스타일과 달리, 실크처럼 부드럽게 넘어가 데일리 위스키나 칵테일 베이스로 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 밝은 단향이 퍼집니다. 부드러운 바닐라 크림, 메이플 시럽, 싱그러운 레몬과 서양 배의 과일 아로마가 가득 피어오르고 그 뒤로 가벼운 구운 견과류의 고소한 아로마가 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러갑니다. 벌꿀 집의 단맛과 은은한 캐러멜 토피, 잘 익은 살구의 풍미가 중심을 잡고 따뜻한 오크통의 은은한 우디함과 화이트 페퍼의 가벼운 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하고 산뜻하게 가라앉습니다. 아메리칸 오크 특유의 달콤한 바닐라 흔적และ 부드러운 보리의 고소한 잔향이 입안을 산뜻하게 정돈해 주며 온화하게 마무리됩니다."}}' WHERE id = 65;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (66, '라프로익 10년 셰리 오크 피니시', 'single_malt', 'Laphroaig Whisky', 'whiskey/108102.jpg', 48.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig 10 Year Old Sherry Oak Finish 70cl', 90407, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-10-year-old-sherry-oak-whisky/?sku=108102', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 10년 셰리 오크 피니시(Laphroaig 10 Year Old Sherry Oak Finish)는 아일라 피트의 제왕 라프로익 증류소의 전설적인 10년 원액에 최고급 셰리 캐스크의 달콤함을 정교하게 입힌 스페셜 익스프레션입니다. 라프로익 특유의 강력한 병원 소독약, 타르 피트 스모크에 스페니시 오크의 녹진함이 입혀져 48%의 높은 도수 속에서 독창적인 단짠과 스모키의 하모니를 뿜어냅니다.", "제조 및 숙성": "전통적인 아메리칸 오크 리필 버번 배럴에서 최소 10년 동안 장기 숙성되어 라프로익 본연의 헤비 피트 개성을 완성한 원액을 주축으로 합니다. 이 원액을 엄선된 최고급 퍼스트 필 오로로소 셰리 캐스크로 옮겨 담아 최종 피니시 숙성 공정을 거쳤습니다."}, "feature": {"오로로소 셰리의 마술": "강렬한 석탄 타르 피트 스모크가 셰리 오크통 특유의 말린 무화과와 다크 초콜릿 풍미를 만나 부드럽게 중화되었습니다.", "48% ABV의 단단한 구조": "일반 10년 제품보다 높은 도수 세팅 덕분에 헤비 피트와 과일의 단맛이 뭉개지지 않고 직관적으로 전해집니다.", "독창적인 단짠 밸런스": "라프로익 고유의 짭조름한 해풍의 소금기와 요오드 향이 셰리의 진득한 단맛과 충돌하며 폭발적인 퍼포먼스를 냅니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 강렬한 피트 스모크와 소독약 향이 먼저 다가오고, 그 뒤를 이어 오로로소 셰리 특유의 진한 건포도, 달콤한 흑설탕에 졸인 무화과 잼의 향이 묵직하게 올라옵니다. 오래된 가죽과 향긋한 바닷바람 향이 조화를 이룹니다.", "맛 (Palate)": "오일리하고 진득하게 입안을 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 토피 당의 진한 단맛과 잘 익은 자두 풍미가 퍼지고 으깬 통후추, 구운 생강의 알싸한 스파이스와 강렬한 바다 소금의 맛이 피트 스모크와 함께 충돌합니다.", "여운 (Finish)": "중후하고 깊은 우디한 여운이 아주 길게 지속됩니다. 입안 전체를 묵직하게 채우는 드라이하고 향긋한 캠프파이어의 재와 타르 잔향 뒤로 셰리의 달콤한 미련이 기분 좋게 맴봅니다."}}' WHERE id = 66;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (67, '라프로익 10년', 'single_malt', 'Laphroaig Whisky', 'whiskey/2455.jpg', 40.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig 10 Year Old 70cl', 63000, 'https://www.masterofmalt.com/whiskies/laphroaig-10-year-old-whisky/?sku=2455', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 10년(Laphroaig 10 Year Old)은 전 세계 피트 위스키 애호가들 사이에서 피트의 제왕이자 가장 호불호가 극명하게 갈리는 독보적인 아이콘으로 통하는 아일라 섬의 상징입니다. 취향에 맞는 이들에게는 최고의 찬사를, 처음 접하는 이들에게는 강렬한 충격을 선사하며 40%~43% 도수 속에서 아일라 전통 피트의 정석을 증명합니다.", "제조 및 숙성": "증류소 고유의 킬른 창고에서 대서양 해풍을 머금은 피트 연기로 보리를 강하게 건조시켜 무거운 스피릿을 증류합니다. 이후 최고급 아메리칸 오크 버번 캐스크에서 최소 10년 동안 아일라 해안의 던지 창고에서 온전히 숙성시켰습니다."}, "feature": {"아이코닉 헤비 피트": "병원 소독약, 크레오소트, 타르, 요오드로 대변되는 라프로익 특유의 강력한 메디컬 피트 캐릭터를 전면에 내세웁니다.", "버번 캐스크의 탄탄한 기저": "버번 배럴에서 배어 나온 바닐라와 달콤한 단맛이 강력한 피트 연기 밑바닥에 탄탄하게 깔려 밸런스를 잡아줍니다.", "왕실 인증 증류소": "위스키 증류소 중 최초로 영국 찰스 3세 국왕의 왕실 조달 허가증을 획득한 고귀한 유산입니다."}}', note = '{"note": {"향 (Nose)": "강렬한 소독약, 요오드, 타르와 그을린 장작의 헤비 피트 향이 직관적으로 코를 자극합니다. 그 거친 스모키함 뒤로 상큼한 레몬 제스트, 부드러운 캐러멜과 바닐라 고유의 단 향이 은은하게 조화를 이뤄냅니다.", "맛 (Palate)": "입안에 닿는 순간 오일리하면서도 드라이한 타격감을 줍니다. 구운 보리의 고소함과 바닐라 토피의 단맛이 중심을 잡고, 으깬 통후추의 알싸함과 짭조름한 해풍, 그리고 입안 전체를 지배하는 짙은 석탄 연기의 풍미가 전개됩니다.", "여운 (Finish)": "깔끔하면서도 묵직한 훈연 향이 길게 지속됩니다. 입안을 드라이하게 정돈해 주는 오크의 우디함, 쌉싸름한 에스프레소, 그리고 향긋하고 건조한 캠프파이어의 재와 같은 피트 스모크의 여운이 길고 짙게 남습니다."}}' WHERE id = 67;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (68, '라프로익 로어', 'single_malt', 'Laphroaig Whisky', 'whiskey/51609.jpg', 48.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig Lore 70cl', 108726, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-lore-whisky/?sku=51609', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 로어(Laphroaig Lore)는 증류소가 1815년부터 이어온 위대한 지식과 전통의 전승을 기리기 위해 마스터 디스틸러 존 캠벨이 완성한 최고급 하이엔드 익스프레션입니다. 다양한 연산과 스타일의 오크통 원액을 블렌딩하여 라프로익 역사상 가장 깊고 다채로운 텍스처를 48% 도수 속에서 뿜어냅니다.", "제조 및 숙성": "7년부터 21년 이상 숙성된 희귀 원액들을 기반으로 합니다. 퍼스트 필 버번 배럴, 뉴 아메리칸 버진 오크 캐스크, 쿼터 캐스크 원액과 최고급 오로로소 셰리 부트에서 오랜 세월 숙성된 진귀한 원액들을 마스터 블렌더의 황금 비율로 마리잉하여 완성했습니다."}, "feature": {"역사상 가장 복합적인 라프로익": "기존 10년의 직관적인 소독약 향을 넘어 셰리의 단맛, 버진 오크의 스파이스가 촘촘하고 단단하게 짜여 있습니다.", "48% ABV의 중후함": "높은 알코올 볼륨감 덕분에 오랜 연산 원액 고유의 묵직한 바디감과 에스테르가 무너지지 않고 단단하게 전해집니다.", "크래프트 퀄리티의 정수": "비냉각여과 및 내추럴 컬러를 채택하여 원액 본연의 진하고 탁월한 마우스필과 짙은 풍미 레이어를 그대로 보존했습니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스러운 아로마입니다. 짙은 석탄 타르, 소독약 향과 함께 흑설탕에 졸인 무화과, 말린 오렌지 껍질, 달콤한 밤꿀의 향이 피어오릅니다. 은은하게 감도는 부드러운 토피 당과 짭조름한 가죽 향이 깊이를 더합니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처가 특징입니다. 다크 초콜릿, 캐러멜 시럽, 럼에 절인 건포도의 진한 단맛이 밀려오고 으깬 통후추, 구운 생강, 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "놀라울 정도로 길고 드라이하면서도 우아합니다. 달콤한 셰리와 바닐라의 여운이 가라앉으며 기품 있는 시가 박스의 우디한 향, 그리고 입안 전체를 계속 감싸는 잔잔하고 드라이한 피트 재의 연기 향이 끝없이 지속됩니다."}}' WHERE id = 68;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (69, '라프로익 쿼터 캐스크', 'single_malt', 'Laphroaig Whisky', 'whiskey/2451.jpg', 48.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig Quarter Cask 70cl', 75895, 'https://www.masterofmalt.com/whiskies/laphroaig-quarter-cask-whisky/?sku=2451', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 쿼터 캐스크(Laphroaig Quarter Cask)는 19세기 위스키 운송 시 사용되던 작은 오크통의 전통을 현대적으로 부활시켜, 오크통과 원액의 접촉 면적을 극대화하여 한층 더 역동적이고 화사한 나무 스파이스를 전면에 내세운 인기 싱글 몰트 위스키입니다.", "제조 및 숙성": "전통적인 버번 캐스크에서 숙성된 라프로익 원액을 엄선한 후, 일반 캐스크 크기의 4분의 1 크기에 불과한 특제 쿼터 캐스크로 옮겨 담아 아일라 해안의 바다 창고에서 집중적인 추가 숙성 과정을 거쳤습니다. 48%의 높은 도수로 병입되어 강력한 퍼포먼스를 자랑합니다."}, "feature": {"작은 오크통의 마술": "원액과 나무의 물리적 접촉 면적이 약 60% 이상 증가하여, 짧은 시간 안에도 농밀한 오크 캐러멜과 단맛을 획득했습니다.", "역동적인 풍미 레이어": "장기 숙성 제품들보다 훨씬 생기 넘치고 활력 있는 바닐라의 단맛과 알싸한 후추 스파이스의 타격감을 선사합니다.", "48% ABV의 든든함": "높은 도수 세팅 덕분에 쿼터 캐스크 특유의 강력한 우디함 속에서도 라프로익 본연의 요오드 스모크가 무너지지 않습니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 자극하는 타오르는 장작 연기, 소독약 향 뒤로 향긋한 바닐라 크림과 구운 토스트의 고소함이 가득 퍼집니다. 이내 신선한 레몬, 청사과의 시트러스와 함께 달콤한 캐러멜 아로마가 산뜻하게 어우러집니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 농밀하고 오일리한 마우스필입니다. 진한 벌꿀과 토피 당, 졸인 살구의 달콤한 풍미가 중심을 잡고 뒤이어 통후추, 계피의 알싸한 스파이스와 바다 소금의 짭조름함이 피트 스모크와 함께 혀를 부드럽게 감싸 안습니다.", "여운 (Finish)": "드라이하면서도 스모키한 화력이 묵직하게 남는 긴 여운입니다. 쿼터 캐스크 고유의 풍부한 나무 향과 바닐라 캐러멜의 달콤함, 그리고 입안 전체를 산뜻하게 정돈해 주는 드라이한 캠프파이어의 재 연기 잔향이 지속됩니다."}}' WHERE id = 69;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (70, '라프로익 오크 셀렉트', 'single_malt', 'Laphroaig Whisky', 'whiskey/33405.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig Oak Select 70cl', 57965, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-oak-select-whisky/?sku=33405', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 오크 셀렉트(Laphroaig Oak Select)는 다양한 스타일의 오크통 원액을 정교하게 혼합하여, 라프로익 고유의 강렬한 피트 스모크를 둥글고 부드럽게 깎아내어 대중적인 접근성을 높인 싱글 몰트 위스키입니다.", "제조 및 숙성": "마스터 블렌더가 직접 감별한 다섯 가지 서로 다른 캐스크(올로로소 셰리, 페드로 히메네스 셰리, 트리플 캐스크, 쿼터 캐스크, 퍼스트 필 버번 배럴) 원액을 정밀하게 블렌딩했습니다. 이 원액들을 신선한 뉴 아메리칸 오크통에서 최종 마리잉하여 40% 도수로 완성했습니다."}, "feature": {"다채로운 오크의 변주": "다섯 종류의 서로 다른 캐스크 성향이 한곳에 모여 라프로익의 날카로운 메디컬 피트 캐릭터를 부드럽게 감싸 안았습니다.", "피트 입문자들의 길잡이": "라프로익 특유의 요오드와 타르 향은 유지하되, 입안에서 느껴지는 감각은 한층 실키하고 가벼워 입문자들에게 적합합니다.", "합리적인 밸런스": "버번의 바닐라, 셰리의 과일 맛, 쿼터 캐스크의 우디함이 잔잔한 스모크와 조화로운 육각형의 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 잔잔한 모닥불 연기 향이 코를 부드럽게 반깁니다. 그 뒤로 부드러운 바닐라 포드, 달콤한 캐러멜 토피 향이 피어오르고 상큼한 레몬 시트러스와 가벼운 허브, 부드러운 맥아의 고소함이 조화를 이룹니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 달콤한 벌꿀과 밀크 초콜릿, 잘 익은 사과의 단맛이 중심을 잡고 뒤이어 구운 생강, 육두구의 부드러운 우드 스파이스와 미세한 소금기가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 오크통 특유의 부드러운 바닐라 단맛과 나무 향이 서서히 가라앉으며, 입안에 산뜻하게 머무는 드라이하고 가벼운 피트스모크의 흔적이 매력적으로 마무리됩니다."}}' WHERE id = 70;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (71, '라프로익 포 오크', 'single_malt', 'Laphroaig Whisky', 'whiskey/62917.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Laphroaig Four Oak (1L) 100cl', 110015, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-four-oak-1l-whisky/?sku=62917', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 포 오크(Laphroaig Four Oak)는 주로 글로벌 면세 시장을 타겟으로 기획된 스페셜 에디션으로, 네 가지 서로 다른 오크통의 특성을 다채롭게 엮어낸 싱글 몰트 위스키입니다. 라프로익 특유의 강력하고 메디컬한 헤비 피트 캐릭터에 다채로운 오크 풍미가 더해져 복합적이면서도 한층 둥글게 다듬어진 40% 도수의 이지드링킹 스타일을 완성했습니다.", "제조 및 숙성": "증류소 마스터 블렌더의 정밀한 설계 아래 버번 배럴, 작은 쿼터 캐스크, 처녀 아메리칸 화이트 오크 캐스크, 그리고 최고급 유러피안 오크 셰리 버트까지 총 네 종류의 다른 캐스크에서 숙성된 원액들을 매링하여 완성했습니다."}, "feature": {"사중 캐스크의 변주": "버번, 셰리, 버진 오크, 쿼터 캐스크까지 각기 다른 오크의 영향력이 결합되어 다층적인 향의 깊이를 보여줍니다.", "둥글게 깎인 피트감": "라프로익 특유의 요오드와 타르 향이 복합적인 오크의 단맛과 우디함 속에 부드럽게 녹아들어 접근성을 높였습니다.", "면세 전용의 매력": "여행자들을 위해 기획된 대용량 및 차별화된 풍미 스펙트럼으로 전 세계 매니아들의 수집욕을 자극합니다."}}', note = '{"note": {"향 (Nose)": "강렬한 소독약 향과 피트 연기 기저 위로 화사한 바닐라, 캐러멜 토피 향이 부드럽게 피어오릅니다. 잘 익은 자두와 말린 과일, 그리고 미세한 해풍의 짭조름한 바다 내음이 조화롭게 다가옵니다.", "맛 (Palate)": "입안에서 크리미하고 부드럽게 감싸는 질감입니다. 달콤한 꿀과 파인애플, 토피 시럽의 풍미가 중심을 잡고 구운 생강, 육두구의 알싸한 우드 스파이스와 은은한 탄 냄새가 입안을 가득 채웁니다.", "여운 (Finish)": "드라이하면서도 온화한 잔향을 남깁니다. 오크통 고유의 감미로운 캐러멜 흔적과 따뜻한 후추의 스파이시함, 그리고 은은하게 흩어지는 드라이한 캠프파이어의 연기 여운이 기분 좋게 마무리됩니다."}}' WHERE id = 71;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (72, '라프로익 10년 CS', 'single_malt', 'Laphroaig Whisky', 'whiskey/129902.jpg', 57.2, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig 10 Year Old Cask Strength Batch 005', 510002, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-10-year-old-cask-strength-whisky/?sku=129902', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 10년 캐스크 스트렝스(Laphroaig 10 Year Old Cask Strength)는 물을 섞어 도수를 낮추지 않고 오크통 원액 그대로를 병입하여 아일라 피트 위스키의 강력한 파괴력을 날것 그대로 느낄 수 있는 궁극의 익스프레션입니다. 배치별로 보통 55%에서 58% 안팎의 폭발적인 도수를 자랑하며 비냉각여과, 내추럴 컬러로 완성되어 전 세계 피트 매니아들의 종교적인 지지를 받습니다.", "제조 및 숙성": "엄선된 퍼스트 필 아메리칸 오크 버번 캐스크에서 최소 10년 동안 대서양 혹독한 해풍을 맞으며 숙성시켰습니다. 오랜 숙성을 거친 헤비 피트 원액을 인위적인 가수 공정 없이 그대로 추출하여 병입했기 때문에 원액 내부의 에스테르와 풍미 화합물이 압도적인 밀도로 농축되어 있습니다."}, "feature": {"타합 없는 캐스크 스트렝스": "가수 공정 없는 강력한 도수에서 뿜어져 나오는 폭발적인 타격감과 농밀한 오일감이 압권입니다.", "피트 제왕의 순수한 정수": "라프로익 고유의 요오드, 타르, 석탄 스모크 캐릭터를 가장 원초적이고 진득한 상태로 경험할 수 있습니다.", "배치별 희소성": "매년 한정 수량 생산되는 배치 넘버마다 도수와 풍미의 미세한 변화가 존재하여 컬렉터들의 표적이 됩니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 강렬한 소독약, 크레오소트, 아스팔트 타르의 헤비 피트 향이 지배적입니다. 그 강력한 스모크 뒤로 진한 캐러멜 토피, 바닐라 포드의 단 향과 신선한 바닷바람의 짠맛이 묵직하게 레이어를 형성합니다.", "맛 (Palate)": "입안 전체를 폭발적으로 자극하는 묵직하고 오일리한 풀바디 마우스필입니다. 구운 보리의 단맛과 버터스카치의 풍미가 퍼지고, 블랙페퍼, 알싸한 생강의 매운 오크 스파이스와 강렬한 바다 소금의 단짠이 스모키와 결합해 소용돌이칩니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 데워주는 듯한 극도로 긴 여운입니다. 구운 오크의 우디한 잔향, 에스프레소의 쌉싸름함, 그리고 입안 전체를 끈질기게 지배하는 드라이한 석탄 연기와 피트 재의 흔적이 깊은 인상을 남깁니다."}}' WHERE id = 72;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (73, '라프로익 25년 CS', 'single_malt', 'Laphroaig Whisky', 'whiskey/133209.jpg', 47.3, 25, 'active', NOW(), NOW(), 'Scotland', 'Bourbon', 700.0, 'Laphroaig 25 Year Old Cask Strength (2023 Release) 70cl', 795028, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-25-year-old-cask-strength-2023-release-whisky/?sku=133209', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 25년 캐스크 스트렝스(Laphroaig 25 Year Old Cask Strength)는 증류소가 보유한 초고연산 원액들 중 극상의 품질을 지닌 통만을 엄선하여 출시하는 울트라 프리미엄 싱글 몰트 위스키입니다. 한 세기의 4분의 1에 달하는 세월 동안 장기 숙성되어 젊은 날의 날카롭고 거친 알코올 부즈는 완벽히 정제되었으며 위스키가 도달할 수 있는 가장 우아하고 기품 있는 아우라를 약 48%에서 52% 안팎의 자연스러운 캐스크 스트렝스로 보여줍니다.", "제조 및 숙성": "최상급 오로로소 셰리 부트와 아메리칸 오크 버번 캐스크에서 각각 25년 이상 오랜 시간 고독하게 숙성된 진귀한 원액들을 마스터 블렌더의 정교한 감각으로 결합했습니다. 냉각 여과 없이 내추럴 컬러 그대로 병입하여 원액 본연의 진하고 탁월한 밀도를 보존했습니다."}, "feature": {"초고연산 피트의 진화": "25년의 숙성을 통해 강렬했던 소독약 향은 기품 있는 시가 스모크와 오래된 마호가니 가구 같은 고급스러운 아로마로 탈바꿈했습니다.", "셰리와 버번의 정밀한 결합": "셰리 오크통의 묵직한 말린 과일 맛과 버번 캐스크의 화사한 바닐라 단맛이 피트 캐릭터와 경이로운 하모니를 이룹니다.", "귀족적인 희소성": "매년 극소량만 한정 배치 형태로 출시되어 전 세계 위스키 컬렉터 및 글로벌 자산가들 사이에서 꿈의 보틀로 통합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 은은하고 세련된 피트 스모크 뒤로 말린 무화과, 건포도, 진한 밤꿀의 단향이 퍼지고 오래된 가죽, 시가 박스의 우디함과 정제된 미네랄 해풍의 뉘앙스가 고결하게 피어오릅니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 농밀하고 벨벳처럼 매끄러운 텍스처가 혀를 감쌉니다. 다크 초콜릿, 졸인 프루트 잼의 진한 단맛이 기품 있게 전개되며 시나몬, 육두구의 알싸한 스파이스와 은은한 바다 소금의 맛이 조화를 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 피날레입니다. 농축된 단맛과 기품 있는 우디 향, 에스프레소의 흔적이 가라앉으며 입안 전체를 감싸 안는 감미롭고 드라이한 헤더 피트 연기의 잔향이 끝없이 지속됩니다."}}' WHERE id = 73;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (74, '라프로익 16년', 'single_malt', 'Laphroaig Whisky', 'whiskey/110857.jpg', 48.0, 16, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Laphroaig 16 Year Old 70cl', 169428, 'https://www.masterofmalt.com/whiskies/laphroaig/laphroaig-16-year-old-whisky/?sku=110857', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라프로익 16년(Laphroaig 16 Year Old)은 정규 라인업 중 10년의 직관적인 강렬함과 고연산 제품들의 중후함 사이에서 가장 이상적인 짐검다리 역할을 수행하는 프리미엄 싱글 몰트 위스키입니다. 숙성 연수가 늘어남에 따라 피트의 자극적인 면은 둥글게 깎이고 오크통 숙성 특유의 복합적이고 감미로운 레이어가 대폭 증가한 48% 도수의 품격 있는 제품입니다.", "제조 및 숙성": "증류소 마스터 블렌더가 엄선한 퍼스트 필 아메리칸 오크 버번 캐스크에서 온전히 16년 동안 장기 숙성시켰습니다. 리필 캐스크를 배제하고 퍼스트 필 버번 오크통의 영향력을 길게 가져갔기 때문에 바닐라와 캐러멜 특유의 단맛이 스피릿 깊숙이 배어들었습니다."}, "feature": {"풍부한 버번 캐스크의 맛": "퍼스트 필 버번 배럴 숙성을 통해 라프로익 특유의 스모키함 위에 탁월한 바닐라 크림과 부드러운 단맛을 입혔습니다.", "정제된 밸런스 지향": "16년의 세월 속에서 거친 요오드와 소독약 향은 온화하게 다듬어지고 피트의 깊이와 오크의 나무 풍미가 균형을 이룹니다.", "48% ABV의 단단함": "다소 높은 도수 설정을 채택하여 장기 숙성 원액 고유의 풍성한 마우스필과 아로마 레이어가 뭉개지지 않고 단단하게 전해집니다."}}', note = '{"note": {"향 (Nose)": "감미롭고 풍성한 아로마입니다. 은은하게 깔리는 모닥불 연기와 가죽 향 뒤로 구운 캐슈넛의 고소함, 진한 캐러멜 토피, 바닐라 포드와 달콤한 자두의 과일 향이 조화롭고 우아하게 피어오릅니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 오일리한 질감이 돋보입니다. 벌꿀 집의 진한 단맛과 잘 익은 사과의 풍미가 중심을 잡고, 뒤이어 화이트 페퍼, 구운 생강의 알싸한 우드 스파이스와 미세한 소금기가 정교한 레이어를 만듭니다.", "여운 (Finish)": "온화하고 감미로운 우디 피날레를 선사합니다. 오크통에서 배어 나온 부드러운 바닐라의 단맛และ 따뜻한 나무 향이 서서히 가라앉으며 입안에 향긋하게 잔향을 남기는 드라이한 피트 스모크의 흔적이 길게 이어집니다."}}' WHERE id = 74;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (75, '맥캘란 12년 더블 캐스크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/55069.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 12 Year Old Double Cask 70cl', 127117, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-12-year-old-double-cask-whisky/?sku=55069', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 12년 더블 캐스크(The Macallan 12 Year Old Double Cask)는 전 세계 싱글 몰트의 명가 맥캘란이 자랑하는 두 가지 다른 오크통의 조화를 전면에 내세운 글로벌 베스트셀러 위스키입니다. 맥캘란 특유의 풍부하고 클래식한 셰리 캐릭터에 아메리칸 오크 고유의 화사하고 화려한 바닐라 풍미를 정교하게 엮어내어 40% 도수 속에서 완벽한 밸런스를 자랑합니다.", "제조 및 숙성": "미국에서 자란 아메리칸 오크와 스페인에서 자란 유러피안 오크를 모두 스페인 제맥소로 가져가 셰리 와인을 담아 숙성시켰습니다. 이렇게 완성된 최고급 아메리칸 셰리 오크통과 유러피안 셰리 오크통에서 각각 12년 동안 숙성된 원액들을 정밀한 비율로 결합했습니다."}, "feature": {"더블 오크의 조화": "두 대륙의 오크통이 기인한 풍미가 한 보틀 안에 결합되어 셰리의 깊이감과 버번 스타일의 화사함을 동시에 제공합니다.", "바닐라와 셰리의 하모니": "유러피안 셰리의 묵직한 건포도 단맛에 아메리칸 오크 고유의 달콤한 캐러멜, 시트러스 아로마가 균형을 이룹니다.", "압도적인 브랜드 가치": "싱글 몰트 시장의 명품이라 불리는 맥캘란의 철저한 오크통 관리 시스템을 통해 한결같은 품질을 보장합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 감미로운 캐러멜 토피와 진한 바닐라 크림 향이 먼저 피어오릅니다. 뒤이어 상큼한 말린 오렌지 껍질, 신선한 꿀의 단 향과 함께 유러피안 오크 고유의 은은한 생강, 오크통 나무 향이 조화롭게 다가옵니다.", "맛 (Palate)": "입안에 닿는 느낌이 매끄럽고 크리미합니다. 벌꿀 집의 단맛과 졸인 건포도, 말린 살구의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 시나몬 가루, 육두구의 알싸한 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "온화하고 묵직한 나무 잔향이 기분 좋게 지속됩니다. 오크통 특유의 부드러운 바닐라 풍미와 캐러멜의 단맛, 그리고 따뜻한 계피 스파이스의 흔적익 입안을 산뜻하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 75;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (76, '맥캘란 12년 셰리 오크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/2536.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 12 Year Old Sherry Oak 70cl', 135681, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-12-year-old-sherry-oak-whisky/?sku=2536', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 12년 셰리 오크(The Macallan 12 Year Old Sherry Oak)는 싱글 몰트 위스키 세계에서 클래식 셰리 숙성의 절대적인 기준이자 전 세계 애호가들 사이에서 교과서로 통하는 영원한 베스트셀러입니다. 다른 캐스크의 간섭 없이 오직 순수한 셰리 오크통 숙성 고유의 진득한 과일 단맛과 중후한 깊이감을 40% 도수 안에서 가장 정석적으로 뿜어냅니다.", "제조 및 숙성": "스페인 헤레스 지역에서 엄격한 기준에 따라 특제 제작되어 오로로소 셰리 와인을 가득 담아 숙성시켰던 최고급 100% 유러피안 오크 셰리 캐스크에서 최소 12년 동안 장기 숙성시켰습니다. 인공 색소를 전혀 넣지 않은 진한 호박색의 내추럴 컬러를 자랑합니다."}, "feature": {"100% 유러피안 셰리": "버번 캐스크나 아메리칸 오크 원액을 일절 섞지 않아 순수한 전통 스페니시 셰리 고유의 묵직한 캐릭터를 자랑합니다.", "셰리 위스키의 표준": "진한 건포도, 다크 초콜릿, 시나몬 스파이스 풍미의 정석을 보여주어 수많은 셰리 위스키의 품질 기준점이 됩니다.", "내추럴 골드 퀄리티": "오크통 나무 내부에서 우러나온 자연스러운 진한 색상과 농밀하게 혀를 감싸 안는 독보적인 마우스필을 완성했습니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 깊은 셰리 아로마가 코를 자극합니다. 진한 건포도, 말린 무화과, 흑설탕에 졸인 자두 잼의 단향이 지배적으로 피어오르고 오래된 나무 향과 진한 캐러멜, 그리고 은은한 시나몬과 진저 스파이스가 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 진득하게 가득 채우는 훌륭한 미디엄 바디의 질감입니다. 달콤한 토피 당과 밀크 초콜릿, 말린 과일의 진한 풍미가 전개되고 뒤이어 유러피안 오크 특유의 쌉싸름한 오렌지 마멀레이드와 계피의 알싸한 스파이스가 훌륭한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 따뜻한 여운이 묵직하게 오래 지속됩니다. 말린 과일의 단맛과 에스프레소의 흔적이 서서히 가라앉으며, 입안 가득 기품 있는 구운 오크의 우디함과 따뜻한 베이킹 스파이스의 잔향이 긴 여운을 선사합니다."}}' WHERE id = 76;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (77, '맥캘란 15년 더블 캐스크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/101175.jpg', 43.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 15 Year Old Double Cask 70cl', 229621, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-15-year-old-double-cask-whisky/?sku=101175', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 15년 더블 캐스크(The Macallan 15 Year Old Double Cask)는 12년 제품의 성공적인 조화를 기반으로, 한층 오랜 장기 숙성을 통해 중후한 깊이감과 부드러운 우아함을 극대화한 프리미엄 싱글 몰트 위스키입니다. 두 대륙 오크통의 결합력이 15년이라는 시간 속에서 완전히 에스테르화되어 43%의 높은 도수 안에서 탄탄한 바디감과 화려한 아로마를 자랑합니다.", "제조 및 숙성": "엄선된 아메리칸 셰리 오크 캐스크와 유러피안 셰리 오크 캐스크에서 각각 최소 15년 동안 숙성된 원액들을 마스터 블렌더의 황금 비율로 혼합했습니다. 12년 제품에 비해 원액이 통 속에서 숨을 쉰 기간이 길어 알코올의 튀는 맛이 완벽히 가라앉아 있습니다."}, "feature": {"더 깊어진 황금 비율": "15년의 장기 숙성을 거쳐 아메리칸 오크의 단맛과 유러피안 오크의 스파이시함이 한층 유기적이고 긴밀하게 결합되었습니다.", "43% ABV의 탄탄함": "알코올 볼륨감을 높여 장기 숙성 셰리 원액 고유의 풍성한 마우스필과 촘촘하게 짜인 풍미 레이어를 직관적으로 전합니다.", "중후한 세련미": "엔트리 라인업보다 묵직함과 화사함의 균형이 세련되게 다듬어져 격식 있는 자리에 훌륭한 만족감을 선사합니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 달콤한 아로마가 가득 퍼집니다. 구운 오크와 향긋한 바닐라 크림, 메이플 시럽의 향 뒤로 말린 살구, 건포도, 그리고 상큼한 말린 오렌지 껍질의 시트러스 아로마가 우아하고 복합적으로 피어오릅니다.", "맛 (Palate)": "실크나 벨벳처럼 부드럽고 묵직한 질감이 입안을 매끄럽게 코팅합니다. 진한 밤꿀과 다크 초콜릿, 졸인 황도 복숭아의 단맛이 중심을 잡고 시나몬 가루, 구운 생강, 육두구의 부드러운 오크 스파이스가 기품 있는 타격감을 선사합니다.", "여운 (Finish)": "온화하고 긴 우디 피날레를 보여줍니다. 오크통에서 배어 나온 부드러운 캐러멜의 단맛과 따뜻한 나무 향이 서서히 가라앉으며 입안에 기분 좋은 드라이함과 스파이스의 잔향을 부드럽게 남기며 가라앉습니다."}}' WHERE id = 77;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (78, '맥캘란 18년 셰리 오크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/137716.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Macallan 18 Year Old Sherry Oak (2024 Release) 70cl', 576330, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-18-year-old-sherry-oak-2024-release-whisky/?sku=137716', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 18년 셰리 오크(The Macallan 18 Year Old Sherry Oak)는 전 세계 싱글 몰트 시장에서 명품 위스키의 대명사이자 컬렉터들과 애호가들 사이에서 정점에 위치한 전설적인 아이코닉 위스키입니다. 100% 유러피안 셰리 오크통 장기 숙성이 선사하는 궁극의 귀족적인 중후함과 농밀함을 43% 도수 안에서 가장 정교하고 완벽한 오케스트라로 펼쳐 보입니다.", "제조 및 숙성": "스페인 헤레스 지역에서 철저하게 엄선한 최고급 오로로소 셰리 와인을 담았던 유러피안 오크 캐스크에서 장장 18년이라는 세월 동안 숨을 쉬며 숙성시켰습니다. 나무의 타닌과 셰리 와인의 정수가 스피릿 깊숙이 화학 결합을 마쳐 짙은 마호가니 색상의 내추럴 컬러를 획득했습니다."}, "feature": {"명품 위스키의 대명사": "맥캘란의 철학이 집약된 제품으로 출시 연도에 따라 가치가 급상승하는 독보적인 프리미엄 주류입니다.", "궁극의 유러피안 셰리": "다른 캐스크의 영향이 완전히 배제되어 진한 다크 초콜릿, 건포도, 시가 박스의 기품 있는 숙성미를 최고 수준으로 자랑합니다.", "결점 없는 하모니": "18년의 세월이 만들어낸 중후함 속에서도 스피릿 고유의 화사함과 셰리의 단맛이 완벽한 드라마처럼 유기적으로 이어집니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 묵직한 아로마입니다. 말린 자두, 건포도, 졸인 무화과 잼의 진한 향이 퍼지고 뒤이어 고급스러운 가죽 책, 오래된 시가 박스의 우디함, 은은한 정향과 따뜻한 바닐라 빈의 향이 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿과 무화과, 토피 당의 진한 단맛이 파도처럼 밀려오고, 뒤이어 블랙페퍼, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 에스프레소의 쌉싸름함이 가라앉으며 입안 전체를 계속 감싸 안는 기품 있는 마호가니 나무의 향과 따뜻한 베이킹 스파이스의 잔향이 영원처럼 지속됩니다."}}' WHERE id = 78;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (79, '맥캘란 18년 더블 캐스크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/101176.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 18 Year Old Double Cask 70cl', 507534, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-18-year-old-double-cask-whisky/?sku=101176', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 18년 더블 캐스크(The Macallan 18 Year Old Double Cask)는 장기 숙성된 맥캘란의 고급 원액과 두 종류의 서로 다른 셰리 오크통의 영향력이 가장 완벽하고 기품 있게 완성된 프리미엄 싱글 몰트 위스키입니다. 유러피안 오크의 중후한 깊이감 위에 아메리칸 오크가 선사할 수 있는 최고의 화사한 바닐라 터치를 가미하여 43% 도수 속에서 독보적인 세련미를 뿜어냅니다.", "제조 및 숙성": "엄선된 아메리칸 셰리 오크 캐스크와 유러피안 셰리 오크 캐스크에서 무려 18년이라는 오랜 세월 동안 고독하게 숙성된 원액들을 마스터 블렌더의 황금 비율로 결합했습니다. 오랜 숙성을 통해 두 캐스크 고유의 성향이 완벽한 평형을 이뤄 부드러움의 극치를 달성했습니다."}, "feature": {"더블 오크 장기 숙성의 정점": "두 대륙 오크통의 영향력이 18년의 세월을 거치며 날카로운 스파이스를 둥글게 깎아내고 극상의 세련미를 획득했습니다.", "완벽한 대칭의 미학": "유러피안 셰리의 묵직한 과일 단맛과 아메리칸 오크의 화사하고 달콤한 토피, 바닐라 풍미가 완벽한 대칭과 균형을 이룹니다.", "독보적인 구조감": "풍미의 레이어가 단 하나도 가라앉지 않고 단단하게 짜여 있어 매 모금마다 새로운 복합미를 선사합니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며 코끝을 스치는 향이 아름답습니다. 달콤한 캐러멜 토피와 진한 바닐라 크림, 메이플 시럽의 향이 피어오릅니다. 뒤이어 말린 살구, 건포도와 상큼한 말린 오렌지 껍질, 오래된 오크의 고풍스러운 아로마가 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크나 꿀처럼 매끄럽고 깊은 풍미가 가득 차오르는 질감입니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 달콤함이 먼저 입안을 채우고 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 따뜻함과 함께 머눕니다."}}' WHERE id = 79;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (80, '맥캘란 레어 캐스크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/138179.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan Rare Cask (2024 Release) 70cl', 508469, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-rare-cask-whisky/?sku=138179', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 레어 캐스크(The Macallan Rare Cask)는 증류소가 보유한 수만 개의 오크통 중 마스터 블렌더의 정밀한 테이스팅을 거쳐 극소수 선별된 진귀한 오크통 원액들로만 블렌딩하여 출시하는 프리미엄 한정판 익스프레션입니다. 연산을 표기하지 않은 NAS 제품이지만 고연산 제품 못지않은 깊은 밀도와 43% 도수에서 나오는 확실한 존재감을 자랑합니다.", "제조 및 숙성": "증류소 창고 깊숙한 곳에서 수리되고 보존된 최상급 퍼스트 필 유러피안 셰리 오크 캐스크의 원액 비율을 대폭 높여블렌딩했습니다. 이 희귀한 오크통 원액들이 한곳에 모여 정교 한 매링 공정을 거쳤으며 나무 고유의 성분에서 우러나온 루비 빛깔의 진하고 진득한 내추럴 컬러를 자랑합니다."}, "feature": {"상위 1% 오크통의 정수": "증류소 내부의 엄격한 감별을 통과한 극소수의 희귀한 캐스크 원액만을 엄선하여 소량 한정 생산하는 주류입니다.", "퍼스트 필 셰리의 위엄": "퍼스트 필 유러피안 셰리 오크 캐스크 숙성을 주축으로 삼아 진하고 묵직한 건포도, 천연 목재의 깊은 맛이 도드라집니다.", "예술적인 소장 가치": "감각적이고 화려한 전용 바틀과 패키지 디자인으로 기획되어 선물용이나 컬렉션 목적으로 가치가 매우 높습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 가득 차오르는 아로마입니다. 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 코를 감쌉니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 시가 박스의 우디함과 상큼한 말린 오렌지 껍질, 바닐라 빈의 향이 훌륭한 하모니를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고, 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머뭅니다."}}' WHERE id = 80;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (81, '맥캘란 25년 셰리 오크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/129065.jpg', 43.0, 25, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Macallan 25 Year Old Sherry Oak (2023 Release) 70cl', 3347955, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-25-year-old-sherry-oak-2023-release-whisky/?sku=129065', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 25년 셰리 오크(The Macallan 25 Year Old Sherry Oak)는 최고급 위스키의 대명사이자 전 세계 위스키 컬렉터들의 궁극의 목표 중 하나인 울트라 프리미엄 싱글 몰트 위스키입니다. 반세기의 절반에 달하는 25년이라는 세월 동안 스페인 헤레스 지역의 최고급 오크통에서 고독하게 숙성되어 위스키가 도달할 수 있는 가장 귀족적이고 세련된 아우라를 43%의 최적 도수로 보여줍니다.", "제조 및 숙성": "맥캘란의 마스터 블렌더가 증류소 창고 깊숙한 곳에서 엄격한 기준에 따라 선별한 100% 퍼스트 필 및 리필 유러피안 오크 오로로소 셰리 캐스크(European Oak Sherry Casks)에서 25년 동안 장기 숙성시켰습니다. 나무 고유의 성분에서 우러나온 짙은 마호가니 빛깔의 내추럴 컬러를 자랑합니다."}, "feature": {"초고연산의 정수": "25년의 정성이 빚어낸 묵직한 숙성 오크, 오래된 가죽, 농축된 셰리의 깊은 향이 독보적인 기품을 자랑합니다.", "100% 유러피안 셰리": "버번 캐스크나 아메리칸 오크 원액의 간섭이 전혀 없어 순수한 전통 스페니시 셰리 고유의 중후한 캐릭터를 유지합니다.", "역사적 자산 가치": "생산량이 극도로 제한되어 출시 연도에 따라 가치가 급상승하는 수집 및 재테크 가치가 매우 높은 진귀한 주류입니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 말린 살구, 건포도, 졸인 무화과 잼의 진한 단향이 깊게 퍼지고, 뒤이어 기품 있는 가죽 책, 정제된 밀랍, 그리고 은은한 시나몬과 시가 박스의 우디함이 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 잘 익은 체리의 풍미가 느껴지며 토피 당과 계피, 육두구 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 에스프레소의 쌉싸름함이 가라앉으며 입안 전체를 계속 감싸 안는 기품 있는 마호가니 나무의 향과 따뜻한 베이킹 스파이스의 잔향이 끝없이 지속됩니다."}}' WHERE id = 81;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (82, '맥캘란 30년 셰리 오크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/128072.jpg', 43.0, 30, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Macallan 30 Year Old Sherry Oak (2023 Release) 70cl', 6609477, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-30-year-old-sherry-oak-2023-release-whisky/?sku=128072', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 30년 셰리 오크(The Macallan 30 Year Old Sherry Oak)는 맥캘란 증류소가 정규 셰리 라인업에서 선보이는 가장 높은 연산이자 궁극의 플래그십 제품입니다. 30년이라는 장구한 숙성 연수 속에서 자극적인 알코올은 완전히 정제되고, 위스키가 가질 수 있는 가장 깊고 기품 있는 아우라를 43% 도수 안에서 가장 완벽한 오케스트라로 펼쳐 보입니다.", "제조 및 숙성": "스페인 헤레스 지역에서 철저하게 엄선한 최고급 오로로소 셰리 와인을 담았던 유러피안 오크 캐스크에서 장장 30년이라는 세월 동안 축축한 dunnage 창고에서 오랜 숙성 과정을 거쳤습니다. 오랜 세월 동안 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 병입했습니다."}, "feature": {"최상위 플래그십": "맥캘란 정규 셰리 라인업 중 가장 높은 연산에 속하는 고귀한 마스터피스로서 전 세계적인 표적이 됩니다.", "시간이 빚은 완벽함": "30년의 세월 동안 나무의 타닌과 스피릿이 만나 거칠고 매운 맛은 완전히 사라지고 극상의 실키함과 중후함만 남았습니다.", "결점 없는 조화": "맥캘란 고유의 화사함과 셰리의 진득한 단맛이 완벽한 대칭을 이루어 입안에서 느껴지는 모든 레이어가 귀족적인 자태를 이룹니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 묵직한 아로마입니다. 오래된 마호가니 가구, 졸인 무화과, 말린 자두의 농축된 향이 퍼지고 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 오래된 가죽 책의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 잘 익은 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 계속 감싸는 감미로운 허니 오크의 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 82;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (83, '맥캘란 30년 더블 캐스크', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/138407.jpg', 43.0, 30, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 30 Year Old Double Cask (2023 Release) 70cl', 5955053, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-30-year-old-double-cask-2023-release-whisky/?sku=138407', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 30년 더블 캐스크(The Macallan 30 Year Old Double Cask)는 장기 숙성된 맥캘란의 최고급 원액과 두 종류의 서로 다른 셰리 오크통의 영향력이 가장 완벽하고 기품 있게 완성된 프리미엄 싱글 몰트 위스키입니다. 유러피안 오크의 중후한 깊이감 위에 아메리칸 오크가 선사할 수 있는 최고의 화사한 바닐라 터치를 가미하여 43% 도수 속에서 독보적인 세련미를 뿜어냅니다.", "제조 및 숙성": "엄선된 아메리칸 셰리 오크 캐스크와 유러피안 셰리 오크 캐스크에서 무려 30년이라는 오랜 세월 동안 고독하게 숙성된 원액들을 마스터 블렌더의 황금 비율로 결합했습니다. 오랜 숙성을 통해 두 캐스크 고유의 성향이 완벽한 평형을 이뤄 부드러움의 극치를 달성했습니다."}, "feature": {"더블 오크 장기 숙성의 정점": "두 대륙 오크통의 영향력이 30년의 세월을 거치며 날카로운 스파이스를 둥글게 깎아내고 극상의 세련미를 획득했습니다.", "완벽한 대칭의 미학": "유러피안 셰리의 묵직한 과일 단맛과 아메리칸 오크의 화사하고 달콤한 토피, 바닐라 풍미가 완벽한 대칭과 균형을 이룹니다.", "독보적인 구조감": "풍미의 레이어가 단 하나도 가라앉지 않고 단단하게 짜여 있어 매 모금마다 새로운 복합미를 선사합니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며 코끝을 스치는 향이 아름답습니다. 달콤한 캐러멜 토피와 진한 바닐라 크림, 메이플 시럽의 향이 피어오릅니다. 뒤이어 말린 살구, 건포도와 상큼한 말린 오렌지 껍질, 오래된 오크의 고풍스러운 아로마가 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크나 꿀처럼 매끄럽고 깊은 풍미가 가득 차오르는 질감입니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 단맛이 먼저 입안을 채우고 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 따뜻함과 함께 머눕니다."}}' WHERE id = 83;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (84, '맥캘란 50년 레드 컬렉션', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/105407.jpg', 45.1, 50, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 50 Year Old - The Red Collection 2020 Release 70cl', 85606120, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-50-year-old-the-red-collection-whisky/?sku=105407', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 50년 레드 컬렉션(The Macallan 50 Year Old The Red Collection)은 증류소의 깊은 역사와 전통적인 붉은 색상에 대한 집착을 기리는 하이엔드 초고연산 스페셜 컬렉션입니다. 반세기가 넘는 장구한 시간 동안 숙성된 진귀한 원액으로 만든 마스터클래스 위스키이며, 위스키가 도달할 수 있는 신비로움을 온몸으로 증명하는 진귀한 최고급 주류입니다.", "제조 및 숙성": "맥캘란의 마스터 디스틸러가 증류소 창고 깊숙한 곳에서 무려 50년 이상 고독하게 세월을 버텨온 희귀한 오크통들을 엄선했습니다. 이 진귀한 정수들을 전통 오크 통에서 결합하는 고도의 장인 예술로 탄생했으며, 45.1%의 내추럴 캐스크 스트렝스(배치별 다름)로 병입되었습니다."}, "feature": {"반세기가 넘는 세월": "50년의 기나긴 세월 동안 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 위스키의 정수입니다.", "레드 컬렉션의 유산": "맥캘란 역사상 가장 중요한 순간들을 상징하는 붉은 색상을 모티브로 기획된 최상위 럭셔리 라인업입니다.", "현대 기술의 초월": "오래된 마호가니 나무, 정제된 밀랍, 숙성된 가죽 향 등 수십 년의 세월만이 자아낼 수 있는 귀족적인 레이어를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고, 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 84;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (85, '맥캘란 M 코퍼', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/132198.jpg', 42.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan M Copper (2023 Release) 70cl', 12883291, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-m-copper-2023-release-whisky/?sku=132198', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 M 코퍼(The Macallan M Copper)는 맥캘란의 상징적인 6가지 핵심 기둥(Six Pillars) 중 증류소 특유의 소형 구리 증류기(Curiously Small Copper Stills)를 오마주하여 탄생한 하이엔드 럭셔리 익스프레션입니다. 프랑스의 유명 유리 장인 라리크(Lalique)가 제작한 화려한 플래토 크리스탈 디켄터에 담겨 시각적, 미각적 만족을 동시에 선사하는 프리미엄 제품입니다.", "제조 및 숙성": "소형 구리 증류기에서 정밀하게 증류하여 뽑아낸 무겁고 오일리한 스피릿을 엄선된 최고급 유러피안 셰리 오크통에서 숙성시켰습니다. 연산을 표기하지 않은 NAS 제품이지만 고연산 원액이 대거 포함되어 42% 도수 속에서 극상의 농밀함을 자랑합니다."}, "feature": {"구리 증류기의 오마주": "맥캘란 고유의 무겁고 풍부한 풍미를 만들어내는 소형 구리 증류기의 가치를 풍미 레이어로 형상화했습니다.", "라리크 크리스탈 디켄터": "세계적인 크리스탈 명가 라리크가 디자인한 예술적인 보틀에 담겨 있어 소장 가치가 극도로 높습니다.", "독보적인 복합미": "유러피안 셰리의 묵직한 건포도 단맛과 구리 증류기 특유의 오일리하고 리치한 질감이 완벽한 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "화려하고 가득 차오르는 아로마입니다. 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 코를 감쌉니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 시가 박스의 우디함과 바닐라 빈의 향이 기품 있게 피어오릅니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고, 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 85;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (86, '맥캘란 M 블랙', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/137691.jpg', 46.0, 0, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Macallan M Black (2023 release) 70cl', 11527168, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-m-black-2023-release-whisky/?sku=137691', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 M 블랙(The Macallan M Black)은 맥캘란의 장인 정신과 최고급 오크통에 대한 집착을 기리는 최상위 럭셔리 라인업인 M 시리즈 중에서도 이례적인 피트 스모크 캐릭터를 전면에 내세운 독창적인 하이엔드 제품입니다. 라리크의 장인들이 빚어낸 칠흑 같은 블랙 크리스탈 디켄터에 담겨 독보적인 카리스마를 뿜어내며, 46% 도수로 병입되어 탄탄한 힘을 자랑합니다.", "제조 및 숙성": "맥캘란이 보유한 진귀한 원액들 중 극소수의 헤비 피티드(Peated) 셰리 오크통 원액과 장기 숙성된 유러피안 셰리 캐스크 원액들을 마스터 블렌더의 황금 비율로 결합했습니다. 오랜 세월 동안 나무의 성분과 피트 스피릿이 완벽한 화학적 결합을 완성했습니다."}, "feature": {"반전의 셰리 피트": "전형적인 맥캘란의 논피트 스타일에서 벗어나, 은은하고 세련된 피트 스모크가 셰리의 단맛과 만나는 극적인 대비를 보여줍니다.", "블랙 크리스탈 디켄터": "라리크와의 협업을 통해 탄생한 기하학적인 기품의 블랙 크리스탈 보틀로 시각적 압도감을 선사합니다.", "최상위 클래스의 희소성": "생산량이 극도로 제한되어 전 세계 위스키 컬렉터 및 자산가들 사이에서 독보적인 프리미엄이 붙은 진귀한 제품입니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스러운 아로마입니다. 은은하게 깔리는 모닥불 연기와 가죽 향 뒤로 말린 무화과, 건포도, 달콤한 밤꿀의 향이 피어오릅니다. 뒤이어 상큼한 말린 오렌지 껍질과 정제된 미네랄 해풍의 뉘앙스가 깊이를 더합니다.", "맛 (Palate)": "혓바닥을 진득하게 코팅하는 농밀하고 풀바디한 질감입니다. 진한 다크 초콜릿과 구운 피칸, 캐러멜 시럽의 단맛이 파도처럼 밀려오고, 시나몬 가루와 구운 생강, 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "놀라울 정도로 길고 우아한 피날레를 보여줍니다. 달콤한 셰리의 여운이 가라앉으며 기품 있는 시가 박스의 우디한 향, 그리고 입안 전체를 계속 감싸는 잔잔하고 향긋한 캠프파이어의 연기 향이 지속됩니다."}}' WHERE id = 86;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (87, '맥캘란 레어 캐스크 블랙', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/57241.jpg', 48.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan Rare Cask Black 70cl', 1101867, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-rare-cask-black-whisky/?sku=57241', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 레어 캐스크 블랙(The Macallan Rare Cask Black)은 주로 글로벌 면세 시장을 겨냥하여 출시되었던 스페셜 에디션으로, 맥캘란 고유의 풍부한 셰리 캐릭터에 아주 은은하고 화사한 스모키함을 더해 차별화된 매력을 선사하는 프리미엄 싱글 몰트 위스키입니다. 48%의 다소 높은 도수로 병입되어 탄탄한 바디감과 확실한 존재감을 자랑합니다.", "제조 및 숙성": "증류소가 보유한 수만 개의 오크통 중 마스터 블렌더가 직접 선별한 극소수의 희귀한 피티드 셰리 캐스크(Peated Sherry Casks) 원액들을 주축으로 합니다. 퍼스트 필 유러피안 오크 셰리 캐스크 숙성을 거쳐 짙은 루비 빛깔의 내추럴 컬러를 획득했습니다."}, "feature": {"스모키 맥캘란의 변주": "전통적인 논피트 맥캘란 스타일에서 벗어나 향긋한 피트 연기 향을 가미하여 이색적인 스펙트럼을 넓혔습니다.", "48% ABV의 중후함": "높은 알코올 볼륨감 덕분에 진득한 셰리의 단맛 속에서도 피트 스모크와 오크통의 우디함이 단단한 구조감을 유지합니다.", "면세 전용의 매력": "여행자들을 위해 특별히 기획되어 블랙 테마의 세련된 패키지 디자인과 함께 희소 가치가 매우 높은 제품입니다."}}', note = '{"note": {"향 (Nose)": "진한 캐러멜 토피와 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향 뒤로 향긋하고 부드러운 모닥불 연기 향이 감미롭게 피어오릅니다. 오래된 가죽과 시트러스 껍질의 상큼함이 레이어를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 무화과 잼의 녹진한 단맛이 밀려오고, 뒤이어 시나몬 가루, 구운 생강의 알싸한 오크 스파이스와 은은한 피트 스모크의 풍미가 혀를 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 피트 재의 연기 여운이 오래도록 머눕니다."}}' WHERE id = 87;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (88, '맥캘란 리플렉션', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/45885.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan Reflexion 70cl', 2880088, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-reflexion-whisky/?sku=45885', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 리플렉션(The Macallan Reflexion)은 맥캘란의 6가지 핵심 기둥 중 자연주의 색상(Natural Colour)의 미학을 극대화하여 표현한 하이엔드 럭셔리 싱글 몰트 위스키입니다. 정교하게 세공된 특제 라리크 스타일 디켄터 보틀에 담겨 위스키 원액이 내뿜는 화려한 루비 빛깔을 아름답게 반사(Reflection)합니다. 43% 도수로 병입되어 우아한 만족감을 선사합니다.", "제조 및 숙성": "스페인 헤레스 지역에서 특제 제작된 최고급 퍼스트 필 유러피안 및 아메리칸 셰리 시즌드 캐스크에서 숙성되었습니다. 특히 일반 캐스크보다 크기가 작은 호그스헤드(Hogshead) 캐스크 원액을 대거 사용하여 나무와 원액의 접촉 면적을 넓히고 풍미의 밀도를 극대화했습니다."}, "feature": {"자연주의 색상의 찬가": "색소 첨가 없이 오직 퍼스트 필 셰리 오크통 내부에서 우러나온 진하고 매혹적인 루비 색상의 자태를 뽐냅니다.", "호그스헤드 캐스크의 터치": "작은 오크통 숙성을 통해 원액의 농밀한 오크 캐러멜과 깊은 과일 풍미를 한층 생동감 있게 이끌어냈습니다.", "예술적인 디켄터 보틀": "빛의 반사를 극대화하도록 기하학적으로 디자인된 전용 프리미엄 디켄터에 담겨 소장 가치가 매우 높습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 달콤한 아로마가 가득 퍼집니다. 구운 오크와 향긋한 바닐라 크림, 메이플 시럽의 향 뒤로 말린 살구, 건포도, 그리고 상큼한 말린 오렌지 껍질의 시트러스 아로마가 우아하고 복합적으로 피어오릅니다.", "맛 (Palate)": "실크나 벨벳처럼 부드럽고 묵직한 질감이 입안을 매끄럽게 코팅합니다. 진한 밤꿀과 다크 초콜릿, 졸인 황도 복숭아의 단맛이 중심을 잡고 시나몬 가루, 구운 생강, 육두구의 부드러운 오크 스파이스가 기품 있는 타격감을 선사합니다.", "여운 (Finish)": "온화하고 긴 우디 피날레를 보여줍니다. 오크통에서 배어 나온 부드러운 캐러멜의 단맛과 따뜻한 나무 향이 서서히 가라앉으며 입안에 기분 좋은 드라이함과 스파이스의 잔향을 부드럽게 남기며 가라앉습니다."}}' WHERE id = 88;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (89, '맥캘란 71년 레드 컬렉션', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/105408.jpg', 41.6, 71, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 71 Year Old - The Red Collection 70cl', 127137812, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-71-year-old-the-red-collection-whisky/?sku=105408', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 71년 레드 컬렉션(The Macallan 71 Year Old The Red Collection)은 전 세계 위스키 역사상 가장 오래 숙성된 초고연산 라인업 중 하나로, 맥캘란 증류소의 깊은 역사와 전통적인 붉은 색상에 대한 집착을 기리는 울트라 하이엔드 주류입니다. 무려 70년이 넘는 기나긴 세월 동안 천천히 호흡하며 자연스럽게 정제된 고귀한 아우라를 지니고 있으며, 대략 41.1% 안팎의 자연스러운 캐스크 스트렝스 도수로 병입되는 인류의 진귀한 유산입니다.", "제조 및 숙성": "제2차 세계 대전이 한창이던 1940년대에 증류되어 증류소 창고 깊숙한 곳에서 무려 71년이라는 긴 세월 동안 고독하게 세월을 버텨온 희귀한 오크통들을 엄선했습니다. 오랜 숙성으로 인해 원액의 대부분이 증발하고 남은 극소량의 진귀한 정수만을 모아 병입했습니다."}, "feature": {"인류 위스키의 유산": "71년이라는 장구한 숙성 기간을 거쳐 날카로운 알코올은 완벽히 사라지고 귀족적인 부드러움과 깊은 밀도만 남았습니다.", "극도의 희소 가치": "전 세계적으로 단 몇 병만 한정 생산되는 수준의 극도로 진귀한 마스터피스로서, 글로벌 자산가들과 박물관의 소장품으로 통합니다.", "현대 기술의 초월": "오래된 마호가니 나무, 정제된 밀랍, 숙성된 가죽 향 등 수십 년의 세월만이 자아낼 수 있는 귀족적인 레이어를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고, 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 89;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (90, '맥캘란 78년 레드 컬렉션', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/105409.jpg', 42.2, 78, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 78 Year Old - The Red Collection 70cl', 152563686, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-78-year-old-the-red-collection-whisky/?sku=105409', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 78년 레드 컬렉션(The Macallan 78 Year Old The Red Collection)은 전 세계 싱글 몰트 위스키 역사상 가장 오래 숙성된 초고연산 위스키 중 하나이자 맥캘란 증류소의 정체성과 장인 정신이 도달한 궁극의 정점입니다. 무려 80년에 가까운 장구한 시간 동안 축축한 던지 창고에서 해풍을 맞으며 숙성되어 위스키의 신비로움을 온몸으로 증명하는 인류 역사상 가장 희귀한 마스터피스입니다.", "제조 및 숙성": "1940년대 초반에 증류되어 증류소가 보유한 가장 진귀하고 오래된 오크통에서 무려 78년 동안 고독하게 세월을 버텨온 정수만을 모았습니다. 기나긴 세월 동안 나무의 성분과 스피릿이 만날 수 있는 가장 완벽한 화학적 결합을 이루었으며, 대략 42.2% 안팎의 자연스러운 캐스크 스트렝스 도수로 병입되었습니다."}, "feature": {"인류 역사의 마스터피스": "78년의 세월이 만들어낸 중후함 속에서도 거칠고 매운 맛은 완전히 사라지고 극상의 깊이감과 부드러움만 남았습니다.", "레드 컬렉션의 최고 정점": "맥캘란의 붉은 헤리티지를 기념하는 컬렉션 중 가장 높은 숙성 연수를 자랑하는 독보적인 플래그십 제품입니다.", "박물관급 희소성": "생산량이 전 세계적으로 극도로 제한되어 출시될 때마다 글로벌 경매 시장의 역사적인 기록을 갈아치우는 신화적인 주류입니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 오렌지 에센스, 오래된 서랍장에서 날 법한 고풍스러운 나무 향이 조화를 이룹니다. 육두구, 파푸아뉴기니 바닐라 빈, 그리고 정제된 가을 낙엽 타는 듯한 아로마가 어우러집니다.", "맛 (Palate)": "벨벳처럼 부드럽고 가득 차오르는 극상의 텍스처입니다. 다크 초콜릿에 절인 블랙커런트, 쌉싸름한 에스프레소, 구운 피칸의 풍미가 느껴지며 은은한 미네랄리티와 시트러스 오일이 입안을 정교하게 자극합니다.", "여운 (Finish)": "가슴 깊은 곳까지 따뜻해지는 극도로 길고 복합적인 여운입니다. 스파이시한 오크 향과 진한 단맛이 완벽한 대칭을 이루며, 아주 연한 담배 연기 같은 최고급 피트의 미련과 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 90;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (91, '맥캘란 M', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/120930.jpg', 45.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan M (2022 Release) 70cl', 7204482, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-m-2022-release-whisky/?sku=120930', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 M(The Macallan M)은 맥캘란이 자랑하는 6가지 핵심 기둥인 자연주의 색상과 장인 정신의 미학을 극대화하여 표현한 하이엔드 울트라 프리미엄 싱글 몰트 위스키입니다. 프랑스의 유명 디자인 거장 파비엔 바론과 전설적인 크리스탈 명가 라리크가 협업하여 제작한 기하학적인 기품의 디켄터에 담겨 시각과 미각을 동시에 압도합니다.", "제조 및 숙성": "증류소 창고 깊숙한 곳에서 선별된 최고급 유러피안 셰리 오크 캐스크에서 장기 숙성된 원액들을 마스터 블렌더의 정교한 감각으로 결합했습니다. 연산을 표기하지 않은 NAS 제품이지만 수십 년의 세월을 버텨온 희귀 고연산 원액들이 대거 포함되어 45% 도수 속에서 독보적인 농밀함을 자랑합니다."}, "feature": {"라리크 크리스탈 디켄터": "라리크의 장인들이 수작업으로 빚어낸 독창적인 6면체 크리스탈 보틀에 담겨 위스키 컬렉터들 사이에서 최고의 소장 가치를 가집니다.", "자연주의 색상의 정점": "인공 색소를 전혀 넣지 않고 오직 최상급 셰리 오크통 내부에서 배어 나온 짙은 로즈우드 빛깔의 내추럴 컬러를 뽐냅니다.", "중후한 셰리의 유산": "유러피안 셰리 오크통 고유의 묵직한 건포도 풍미와 천연 목재의 깊은 풍미가 완벽한 레이어를 만듭니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스러운 아로마가 가득 퍼집니다. 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 코를 감쌉니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 가죽, 시가 박스의 우디함과 바닐라 빈의 향이 기품 있게 피어오릅니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 91;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (92, '맥캘란 40년 레드 컬렉션', 'single_malt', 'The Macallan Whisky Distillery', 'whiskey/132196.jpg', 47.5, 40, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Macallan 40 Year Old - The Red Collection 2023 Release 70cl', 50005844, 'https://www.masterofmalt.com/whiskies/the-macallan/the-macallan-40-year-old-the-red-collection-2023-whisky/?sku=132196', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "맥캘란 40년 레드 컬렉션(The Macallan 40 Year Old The Red Collection)은 증류소의 깊은 역사와 전통적인 붉은 색상에 대한 헤리티지를 기리는 하이엔드 초고연산 스페셜 컬렉션입니다. 40년이라는 장구한 시간 동안 천천히 호흡하며 자연스럽게 정제된 고귀한 아우라를 지니고 있으며 48.1%의 내추럴 캐스크 스트렝스 도수로 병입되는 진귀한 최고급 주류입니다.", "제조 및 숙성": "몰트 마스터기가 증류소 창고 깊숙한 곳에서 무려 40년 이상 고독하게 세월을 버텨온 희귀한 전통 아메리칸 오크 버번 배럴과 유러피안 오크 오로로소 셰리 캐스크 원액을 정밀하게 감별했습니다. 이 진귀한 정수들을 전통 오크 마리잉 툰에 모아 결합하는 고도의 장인 예술로 탄생했습니다."}, "feature": {"시간이 빚은 완벽함": "40년의 기나긴 세월 동안 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 위스키의 정수입니다.", "레드 컬렉션의 유산": "맥캘란 역사상 가장 중요한 순간들을 상징하는 붉은 색상을 모티브로 기획된 최상위 럭셔리 라인업입니다.", "현대 기술의 초월": "오래된 마호가니 나무, 정제된 밀랍, 숙성된 가죽 향 등 수십 년의 세월만이 자아낼 수 있는 귀족적인 레이어를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 92;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (93, '더 글렌리벳 18년', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/2527.jpg', 40.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet 18 Year Old 70cl', 161048, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-18-year-old-whisky/?sku=2527', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 18년(The Glenlivet 18 Year Old)은 스페이사이드 싱글 몰트의 기준이라 불리는 더 글렌리벳 증류소의 정규 라인업 중 부드러운 숙성미와 세련된 밸런스를 가장 완벽하게 보여주는 프리미엄 위스키입니다. 전 세계 위스키 어워드에서 수차례 메달을 수상하며 품질을 인정받았으며 40% 도수 속에서 극상의 온화함을 선사합니다.", "제조 및 숙성": "마스터 디스틸러가 엄선한 퍼스트 필 및 세컨드 필 아메리칸 오크 캐스크와 유러피안 오크 셰리 캐스크 원액을 정교하게 결합하여 18년 동안 장기 숙성시켰습니다. 오랜 숙성을 통해 버번의 화사한 바닐라와 셰리의 중후한 과일 풍미가 빈틈없는 균형을 이룹니다."}, "feature": {"명작의 균형미": "글렌리벳 특유의 과일 향과 오랜 숙성이 주는 우디한 스파이스가 부드럽게 동화된 정석적인 밸런스를 보여줍니다.", "어워드가 입증한 품질": "수많은 국제 주류 품평회에서 연속으로 금메달을 수상하며 전 세계 전문가들에게 품질을 검증받은 마스터피스입니다.", "다채로운 캐스크의 만남": "아메리칸 오크와 유러피안 셰리 캐스크의 장점만을 정밀하게 혼합하여 복합적인 풍미 레이어를 완성했습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 우아한 아로마가 피어오릅니다. 향긋한 수풀 내음과 달콤한 꿀, 바닐라 포드의 향 뒤로 잘 익은 서양 배, 청사과의 시트러스와 은은한 오크통의 세련된 나무 향이 기품 있게 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 벨벳처럼 매끄럽고 부드럽습니다. 감미로운 토피 당과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 퍼지고 뒤이어 은은한 오크통의 시나몬, 생강 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "따뜻하고 온화한 잔향이 길게 이어집니다. 오크통에서 배어 나온 부드러운 바닐라의 흔적과 건조한 오크의 우디함, 그리고 마지막에 남는 가벼운 향신료의 여운이 기분 좋게 마무리됩니다."}}' WHERE id = 93;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (94, '더 글렌리벳 15년 프렌치 오크 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/2525.jpg', 40.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet 15 Year Old French Oak Reserve 70cl', 93146, 'https://www.masterofmalt.com/whiskies/the-glenlivet-15-year-old-french-oak-reserve-whisky/?sku=2525', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 15년 프렌치 오크 리저브(The Glenlivet 15 Year Old French Oak Reserve)는 스코틀랜드 싱글 몰트 위스키 업계에서 최초로 프랑스산 고급 와인 오크통을 숙성에 도입하여 독창적인 캐릭터를 정립한 프리미엄 위스키입니다. 40% 도수로 병입되며 특유의 이국적이고 알싸한 우드 스파이스가 인상적입니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 원액을 안정적으로 숙성시킨 후, 프랑스 도르도뉴 지역에서 공수한 최고급 림구장 오크 캐스크로 원액을 옮겨 담아 최종 피니시 숙성을 거쳤습니다. 이 프렌치 오크통은 주로 최고급 코냑 숙성에 사용되는 진귀한 목재입니다."}, "feature": {"프렌치 오크의 선구자": "림구장 오크 캐스크 숙성을 과감하게 시도하여 기존 스페이사이드 스타일에 이국적인 스파이시 레이어를 더했습니다.", "림구장 오크의 타격감": "밀도가 높은 프렌치 오크 고유의 성분 덕분에 일반 버번 숙성보다 훨씬 직관적이고 알싸한 나무 풍미를 자랑합니다.", "달콤함과 알싸함의 대조": "글렌리벳 고유의 화사한 사과 꿀맛 위에 시나몬, 정향 같은 독특한 향신료 캐릭터가 멋진 대비를 이룹니다."}}', note = '{"note": {"향 (Nose)": "상큼하면서도 묵직한 아로마가 코를 자극합니다. 진한 캐러멜 토피와 바닐라 향 뒤로, 잘 익은 서양 배와 이국적인 망고의 단 향, 그리고 프렌치 오크 특유의 쌉싸름한 삼나무와 견과류의 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 질감입니다. 벌꿀 집의 단맛과 시럽을 바른 과일 타르트의 풍미가 퍼지고 뒤이어 림구장 캐스크에서 배어 나온 따뜻한 생강, 정향, 시나몬의 알싸한 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "온화하고 묵직한 잔향을 남깁니다. 바닐라의 달콤한 흔적지 가라앉으며, 입안에 기분 좋은 드라이함과 감미로운 나무 향, 알싸한 후추의 스파이시 스파크를 산뜻하게 남기며 우아하게 마무리됩니다."}}' WHERE id = 94;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (95, '더 글렌리벳 파운더스 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/41224.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet Founder\'s Reserve 70cl', 59236, 'https://www.masterofmalt.com/whiskies/the-glenlivet/glenlivet-founders-reserve-whisky/?sku=41224', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 파운더스 리저브(The Glenlivet Founder\'s Reserve)는 1824년 증류소를 설립한 전설적인 창립자 조지 스미스의 오리지널 레시피와 개척 정신을 오마주하여 탄생한 대중적인 논에이징 싱글 몰트 위스키입니다. 40% 도수로 병입되며 증류소 특유의 밝고 싱그러운 과일 본연의 매력을 가장 정직하게 보여줍니다.", "제조 및 숙성": "숙성 연수를 표기하지 않는 대신 마스터 블렌더가 증류소 고유의 화사함이 극대화된 여러 연산의 원액들을 엄선했습니다. 전통적인 랜턴 모양 구리 증류기에서 뽑아낸 맑은 스피릿을 퍼스트 필 아메리칸 오크 버번 캐스크와 전통 리필 캐스크를 블렌딩하여 숙성했습니다."}, "feature": {"창립자를 위한 찬가": "조지 스미스가 처음 완성했던 1800년대 초반의 화사하고 순수한 스페이사이드 위스키 스타일을 현대적으로 재해석했습니다.", "퍼스트 필 아메리칸 오크": "새 오크통의 강력한 바닐라 단맛을 부드럽게 주입하여 짧은 숙성 연수 특유의 거친 알코올 감을 우아하게 덮어냈습니다.", "독보적인 접근성": "가볍고 산뜻한 아로마 프로파일 덕분에 입문자부터 데일리 위스키를 선호하는 애호가들까지 모두에게 훌륭한 만족감을 선사합니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 과일 향이 가득 퍼집니다. 갓 피어난 화이트 플라워, 싱그러운 레몬과 레몬 제스트, 파릇파릇한 청사과의 시트러스 아로마가 맑게 피어오르고 그 기저에는 은은한 부드러운 꿀과 바닐라 향이 튼튼하게 받쳐줍니다.", "맛 (Palate)": "입안에 닿는 느낌이 가볍고 크리미합니다. 부드러운 캐러멜 토피, 설탕 시럽을 바른 건포도의 풍미가 느껴지며 뒤이어 오크통에서 배어 나온 가벼운 우디함과 화이트 페퍼의 알싸한 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 산뜻하고 온화하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 95;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (96, '더 글렌리벳 12년', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/100200.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet 12 Year Old 70cl', 72051, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-12-year-old-whisky/?sku=100200', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 12년(The Glenlivet 12 Year Old)은 전 세계 싱글 몰트 위스키 시장에서 스페이사이드 스타일의 정석이자 교과서로 통하는 영원한 베스트셀러 싱글 몰트 위스키입니다. 모든 싱글 몰트의 시작이라는 슬로건에 걸맞게 40% 도수 속에서 가장 이상적이고 정석적인 싱글 몰트 고유의 과일 밸런스를 자랑합니다.", "제조 및 숙성": "증류소 고유의 높은 랜턴 모양 구리 증류기에서 불순물을 완전히 걸러내어 맑고 플로럴한 스피릿을 뽑아냅니다. 이 맑은 원액을 전통적인 유러피안 오크 캐스크와 아메리칸 오크 버번 캐스크에서 최소 12년 동안 조화롭게 숙성시켜 블렌딩했습니다."}, "feature": {"싱글 몰트의 기준점": "화사한 꽃향기와 시트러스, 부드러운 단맛의 삼박자가 가장 모범적으로 짜여 있어 전 세계 위스키 시장의 표준으로 통합니다.", "랜턴 증류기의 미학": "독특한 높은 증류기 덕분에 원액 고유의 가볍고 싱그러운 과수원 과일 풍미를 가장 순수하게 확보해 냈습니다.", "합리적인 밸런스": "버번의 바닐라와 전통 오크통의 은은한 우디함이 잔잔한 꿀맛과 만나 완벽한 육각형의 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 그 뒤를 이어 은은하게 깔리는 바닐라 크림 고유의 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감싸 안는 질감입니다. 벌꿀 집의 달콤함과 잘 익은 노란 사과의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 생강 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며 입안에 향긋하게 머무는 감미로운 보리의 흔적이 산뜻하게 마무리됩니다."}}' WHERE id = 96;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (97, '더 글렌리벳 트리플 캐스크 머추어드 화이트 오크 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/121845.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'The Glenlivet Triple Cask Matured - White Oak Reserve 1L 100cl', 135518, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-triple-cask-matured-white-oak-reserve-1l-whisky/?sku=121845', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 트리플 캐스크 머추어드 화이트 오크 리저브(The Glenlivet Triple Cask Matured White Oak Reserve)는 주로 면세점 시장을 타겟으로 기획된 트리플 캐스크 시리즈 중 하나로, 아메리칸 화이트 오크의 영향력을 극대화하여 화사함을 끌어올린 논에이징 싱글 몰트 위스키입니다. 40% 도수로 병입되어 가볍고 경쾌한 이지드링킹 캐릭터를 뽐냅니다.", "제조 및 숙성": "전통적인 리필 캐스크 원액, 아메리칸 오크 ex-버번 캐스크 원액, 그리고 안쪽을 깊게 태우지 않은 최고급 퍼스트 필 아메리칸 화이트 오크 캐스크까지 총 세 종류의 다른 오크통에서 숙성된 원액들을 마스터 블렌더의 정교한 비율로 결합했습니다."}, "feature": {"화이트 오크의 찬가": "퍼스트 필 화이트 오크통 숙성을 주축으로 삼아 기존 정규 라인보다 훨씬 풍부한 바닐라 크림과 코코넛 고유의 단맛을 전합니다.", "삼중 캐스크의 복합미": "세 종류의 서로 다른 캐스크 성향이 한곳에 모여 스피릿 고유의 화사한 사과 아로마를 다채로운 레이어로 받쳐줍니다.", "면세 전용의 매력": "여행자들을 위해 기획된 차별화된 아로마 프로파일로 부담 없이 가볍고 산뜻한 스타일을 선호하는 이들에게 적합합니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 밝은 바닐라 포드와 부드러운 꿀, 구운 토스트의 고소함이 먼저 퍼집니다. 뒤이어 신선한 레몬, 청사과 같은 과수원 과일의 아로마가 화이트 오크 특유의 은은한 코코넛 향과 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 달콤한 벌꿀과 캐러멜, 잘 익은 살구의 단맛이 중심을 잡고 뒤이어 구운 생강, 화이트 페퍼의 부드러운 오크 스파이스가 혀를 부드럽게 감싸 안으며 전개됩니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 따뜻한 나무 향이 서서히 가라앉으며 입안을 산뜻하고 온화하게 정돈해 주며 마무리됩니다."}}' WHERE id = 97;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (98, '더 글렌리벳 캐리비안 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/105646.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet Caribbean Reserve 70cl', 63568, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-caribbean-reserve-whisky/?sku=105646', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 캐리비안 리저브(The Glenlivet Caribbean Reserve)는 스페이사이드 싱글 몰트 위스키 본연의 부드룸에 이국적인 캐리비안 럼 캐스크의 터치를 과감하게 시도하여 트렌디하고 화사한 매력을 선보이는 논에이징 위스키입니다. 40% 도수로 병입되어 부담 없이 칵테일 베이스나 데일리로 즐기기에 최적화되어 있습니다.", "제조 및 숙성": "전통적인 버번 캐스크에서 숙성되어 풍부한 바닐라와 달콤함을 획득한 원액을 주축으로 삼고 이 원액을 서인도 제도에서 공수한 최고급 캐리비안 럼을 담았던 럼 캐스크로 옮겨 담아 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"럼 캐스크 피니시의 조화": "정통 위스키에 이국적인 캐리비안 럼의 달콤한 단 향을 가미하여 독창적인 풍미 스펙트럼을 넓혔습니다.", "이국적인 달콤함": "일반적인 셰리나 버번 숙성과는 결이 다른, 구운 당밀과 패션프루트 같은 화사한 열대 과일 향이 도드라집니다.", "실키한 질감과 대중성": "글렌리벳 특유의 부드러운 터치 덕분에 위스키 입문자부터 가볍고 달콤한 캐주얼 위스키를 선호하는 젊은 세대까지 모두를 매료시켰습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 이국적인 단향이 코를 자극합니다. 진한 꿀과 캐러멜 토피 향 뒤로, 잘 익은 패션프루트, 바나나, 망고 같은 열대 과일의 화사함과 구운 당밀 고유의 향이 달콤하게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 순간 실크처럼 매끄럽고 크리미한 부드러움을 줍니다. 바닐라 크림과 구운 마시멜로, 오렌지 마멀레이드의 달콤함이 퍼지고 뒤이어 럼 캐스크에서 배어 나온 따뜻한 생강, 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "온화하고 감미로운 여운이 길게 이어집니다. 꿀을 머금은 오크 향과 토피 당의 달콤한 흔적이 가라앉으며 입안에 기분 좋은 따뜻함과 이국적인 과일의 잔향을 부드럽게 남기며 가라앉습니다."}}' WHERE id = 98;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (99, '더 글렌리벳 21년', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/127340.jpg', 43.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet 21 Year Old - The Sample Room Collection 70cl', 389712, 'https://www.masterofmalt.com/whiskies/the-glenlivet/-the-glenlivet-21-year-old-the-sample-room-collection-whisky/?sku=127340', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 21년(The Glenlivet 21 Year Old Sample Room Collection)은 증류소의 고급 숙성 철학을 대변하는 대표적인 고연산 프리미엄 라인업으로, 긴 시간 동안 정제된 완벽한 부드러움과 기품을 자랑하는 마스터피스입니다. 20년이 넘는 세월 속에서 완성된 원액을 기품 있는 아카이브 스타일 패키지에 담아 43% 도수 속에서 극상의 다층적인 매력을 전합니다.", "제조 및 숙성": "증류소 내부의 실험실이자 심장부인 샘플 룸에서 마스터 블렌더가 직접 엄선했습니다. 퍼스트 필 오로로소 셰리 캐스크, 트론세 코냑 캐스크, 그리고 주정강화 와인 캐스크까지 총 세 종류의 귀한 오크통 원액을 정교하게 블렌딩하여 21년의 장기 숙성을 완성했습니다."}, "feature": {"샘플 룸 컬렉션의 깊이": "세 종류의 프리미엄 캐스크 조합이 선사하는 다층적인 에스테르와 진득한 단맛이 오랜 세월을 거치며 완벽하게 동화되었습니다.", "코냑과 포트의 마술": "코냑 캐스크의 기품 있는 과일 산미와 포트 캐스크의 진한 베리류 풍미가 조화롭게 녹아들어 고급스러운 자태를 형성합니다.", "시간이 공들인 정제미": "21년의 기나긴 숙성 과정을 거쳐 자극적인 알코올은 완전히 정제되고 극상의 실키한 질감과 복합적인 우디함만 남았습니다."}}', note = '{"note": {"향 (Nose)": "깊고 진한 숙성 아로마가 가득 퍼집니다. 럼에 절인 건포도, 말린 자두, 무화과 잼의 깊은 단향이 지배적으로 피어오르고 그 뒤로 은은하게 깔리는 고급 가죽, 시가 박스의 우디함과 구운 피칸의 아로마가 고급스럽게 얹어집니다.", "맛 (Palate)": "벨벳이나 실크처럼 부드럽고 묵직한 질감이 입안을 매끄럽게 코팅합니다. 진한 밤꿀과 다크 초콜릿, 졸인 블랙커런트의 단맛이 기품 있게 전개되며 시나몬 가루, 육두구의 알싸한 오크 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 감미로운 여운을 선사합니다. 농축된 와인과 코냑의 잔향 뒤로 부드러운 마호가니 나무의 풍미, 에스프레소의 흔적과 따뜻한 베이킹 스파이스의 흔적이 영원처럼 머눕니다."}}' WHERE id = 99;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (100, '더 글렌리벳 25년', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/127341.jpg', 43.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet 25 Year Old - The Sample Room Collection 70cl', 737399, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-25-year-old-the-sample-room-collection-whisky/?sku=127341', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 25년(The Glenlivet 25 Year Old Sample Room Collection)은 증류소가 정규 코어 라인업에서 선보이는 가장 최고의 연산이자 울트라 프리미엄 플래그십 마스터피스입니다. 4분의 1세기가 넘는 기나긴 세월 동안 숨을 쉬며 오크통과 원액이 완벽한 결합을 이루었으며 43% 도수 안에서 위스키가 도달할 수 있는 가장 우아하고 고귀한 아우라를 보여줍니다.", "제조 및 숙성": "증류소 샘플 룸에서 철저하게 엄선된 희귀 원액들을 기반으로 합니다. 아메리칸 오크 버번 배럴에서 장기 숙성된 최상급 원액을 최종 단계에서 최고급 퍼스트 필 페드로 히메네스 셰리 캐스크와 트론세 코냑 캐스크에 옮겨 담아 정교하게 피니시 숙성 및 결합했습니다."}, "feature": {"궁극의 플래그십": "더 글렌리벳 라인업 중 가장 높은 숙성 연수를 자랑하는 고귀한 마스터피스로서 전 세계 위스키 콜렉터들의 표적이 됩니다.", "PX 셰리와 코냑의 피날레": "가장 달콤한 PX 와인 오크통의 영향력과 코냑 캐스크의 화려함이 더해져 이색적이고 풍부한 다크 크러스트 풍미를 확보했습니다.", "결점 없는 조화": "25년의 정성이 빚어낸 묵직한 숙성 오크, 오래된 가죽, 농축된 에스테르의 정수가 완벽한 대칭과 조화를 이룹니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 흑설탕에 졸인 무화과, 말린 무화과 잼의 진한 향이 퍼지고 뒤이어 고급스러운 시가 박스의 우디함, 정제된 밀랍과 은은한 계피 가루의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 호두의 고소함과 함께 잘 익은 체리의 풍미가 느껴지며 토피 당과 시나몬, 육두구 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 코냑의 단맛 뒤로 시가 박스의 우디한 향, 에스프레소의 잔향과 마지막까지 남는 따뜻한 베이킹 스파이스의 잔향이 끝없이 지속됩니다."}}' WHERE id = 100;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (101, '더 글렌리벳 트리플 캐스크 머추어드 레어 캐스크', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/97169.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'The Glenlivet Triple Cask Matured Rare Cask 100cl', 138915, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-triple-cask-matured-rare-cask-whisky/?sku=97169', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 트리플 캐스크 머추어드 레어 캐스크(The Glenlivet Triple Cask Matured Rare Cask)는 주로 글로벌 면세 시장을 겨냥해 높은 희소 가치를 지니도록 기획된 프리미엄 논에이징 싱글 몰트 위스키입니다. 증류소 특유의 부드럽고 화사한 스타일 위에 세 가지 오크통의 풍미 레이어를 촘촘히 엮어내어 40% 도수 속에서 격조 높은 복합미를 선사합니다.", "제조 및 숙성": "마스터 블렌더의 정밀한 선별을 거친 최고급 퍼스트 필 아메리칸 오크 ex-버번 캐스크, 리필 캐스크, 그리고 프리미엄 유러피안 오크 셰리 캐스크 원액을 정교한 비율로 결합했습니다. 서로 다른 캐릭터를 지닌 세 오크통이 오랜 시간 상호 작용하며 원액의 풍미를 입체적으로 확장시켰습니다."}, "feature": {"트리플 캐스크의 조화": "세 가지 오크통의 개성이 어느 한쪽으로 치우치지 않고 맥아의 화사함을 중심으로 완벽한 평형을 이룹니다.", "면세 한정의 희소성": "글로벌 여행자들을 위해 특별한 조합으로 소량 생산되어 스페이사이드 위스키 매니아들의 수집 욕구를 자극합니다.", "부드러운 다층 레이어": "부담 없는 질감 속에서도 유러피안 셰리 고유의 묵직한 과일 단맛과 아메리칸 오크의 바닐라 풍미가 촘촘하게 짜여 있습니다."}}', note = '{"note": {"향 (Nose)": "화사한 꿀와 신선한 바닐라 빈, 잘 익은 서양 배의 향이 먼저 코를 부드럽게 감쌉니다. 뒤이어 상큼한 말린 오렌지 껍질과 진한 건포도, 은은한 삼나무의 우디 아로마가 다채롭게 레이어를 이룹니다.", "맛 (Palate)": "입안에서 크리미하고 실크처럼 매끄럽게 굴러갑니다. 감미로운 캐러멜 토피와 밀크 초콜릿, 졸인 자두의 단맛이 중심을 잡고 가벼운 시나몬 파우더와 구운 생강의 알싸한 우드 스파이스가 뉘앙스를 더합니다.", "여운 (Finish)": "산뜻하면서도 온화한 여운이 기분 좋게 남습니다. 오크통에서 배어 나온 감미로운 바닐라의 잔향과 드라이한 나무 스파이스의 따뜻함이 입안을 정돈해 주며 깔끔하게 마무리됩니다."}}' WHERE id = 101;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (102, '더 글렌리벳 14년 셰리 캐스크 머추어드', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/145782.jpg', 40.0, 14, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Glenlivet 14 Year Old - Sherry Cask Matured 70cl', 254275, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-14-year-old-sherry-cask-matured-whisky/?sku=145782', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 14년 셰리 캐스크 머추어드(The Glenlivet 14 Year Old Sherry Cask Matured)는 대중적인 엔트리 라인업을 넘어 묵직하고 녹진한 셰리 위스키를 선호하는 한국을 비롯한 특정 아시아 시장을 타겟으로 출시되어 뜨거운 사랑을 받는 프리미엄 싱글 몰트 위스키입니다. 14년이라는 명확한 숙성 연수와 40% 도수 안에서 기품 있는 다크 프루트 캐릭터를 뿜어냅니다.", "제조 및 숙성": "발아된 보리를 랜턴 모양 구리 증류기에서 맑게 증류한 원액을 처음부터 끝까지 100% 최고급 유러피안 오크 오로로소 셰리 캐스크(European Oak Oloroso Sherry Casks)에 담아 14년 동안 온전히 숙성시켰습니다. 색소 첨가 없이 오크통 내부의 타닌과 와인 성분이 자연스럽게 스며든 짙은 호박색을 띱니다."}, "feature": {"100% 오로로소 셰리": "피니시 숙성이 아닌 전 기간 셰리 캐스크 숙성을 적용하여 글렌리벳 특유의 화사함 위에 깊고 진득한 단맛을 결합했습니다.", "특화 시장의 베스트셀러": "진한 과일 풍미와 다크 초콜릿 캐릭터를 선사하도록 설계되어 아시아 위스키 매니아들 사이에서 독보적인 인기를 구가합니다.", "내추럴 골드 텍스처": "인공 색소를 배제하고 오크통 나무 본연의 자연스러운 색상과 농밀하게 감싸 안는 탁월한 마우스필을 완성했습니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 깊은 셰리 아로마가 피어오릅니다. 흑설탕에 졸인 무화과, 럼에 절인 건포도, 말린 자두의 진한 단향이 중심을 이루고 은은한 시나몬과 감미로운 캐러멜 토피 향이 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 묵직하게 가득 채우는 풀바디 질감입니다. 진한 다크 초콜릿과 무화과 잼, 토피 당의 진한 달콤함이 파도처럼 밀려오고 유러피안 오크 특유의 쌉싸름한 오렌지 제스트 스파이스와 계피의 알싸함이 훌륭한 하모니를 이룹니다.", "여운 (Finish)": "중후하고 깊은 우아한 피날레가 아주 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 기품 있는 구운 오크의 우디함과 따뜻한 베이킹 스파이스의 잔향이 짙게 머눕니다."}}' WHERE id = 102;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (103, '더 글렌리벳 13년 셰리 캐스크 머추어드', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/143560.jpg', 40.0, 13, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'The Glenlivet 13 Year Old - Sherry Cask Matured 70cl', 254275, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-13-year-old-sherry-cask-matured-whisky/?sku=143560', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 13년 셰리 캐스크 머추어드(The Glenlivet 13 Year Old Sherry Cask Matured)는 정규 라인업에 존재하지 않는 13년이라는 독특한 숙성 연수를 채택하여 대만과 한국 등 셰리 캐릭터에 열광하는 특정 시장을 위해 한정 배정된 고품격 싱글 몰트 위스키입니다. 40% 도수 속에서 글렌리벳 하우스 스타일에 셰리의 녹진함을 가장 역동적으로 입혀낸 제품입니다.", "제조 및 숙성": "증류소의 상징인 높은 구리 증류기에서 맑게 뽑아낸 스피릿을 엄선된 최고 품질의 스페니시 오크 올로로소 셰리 캐스크(Oloroso Sherry Casks)에서 13년 동안 전 기간 숙성시켰습니다. 짧지도 길지도 않은 13년의 시간은 셰리의 녹진함이 글렌리벳 고유의 화사함을 가리지 않는 최적의 지점입니다."}, "feature": {"희소성 높은 13년 연산": "일반적인 정규 코어 라인업에서는 찾아볼 수 없는 희귀 연산 배치 제품으로 소장 가치가 매우 높습니다.", "전 기간 스페니시 셰리 숙성": "최고급 오로로소 셰리통에서 13년을 온전히 보내어 설탕 시럽을 졸인 듯한 녹진한 다크 크러스트 풍미를 자랑합니다.", "화사함과 묵직함의 대비": "글렌리벳 고유의 싱그러운 배, 사과 캐릭터 기저 위에 셰리 특유의 베리류 단맛이 멋진 스파링을 펼칩니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 진득한 말린 과일 향이 전면에 나섭니다. 건포도와 대추야자, 캐러멜 토피의 묵직한 단향이 피어오르고 상큼한 레드 베리와 신선한 꿀, 그리고 가벼운 생강 스파이스가 복합적인 레이어를 이룹니다.", "맛 (Palate)": "혀끝을 달콤하고 부드럽게 감싸 안는 오일리한 마우스필입니다. 진한 밀크 초콜릿, 무화과 잼의 달콤함이 입안을 가득 채우고 뒤이어 오크통에서 배어 나온 시나몬 파우더와 육두구의 알싸한 스파이시함이 혀를 정교하게 타격합니다.", "여운 (Finish)": "온화하고 감미로운 여운이 길게 이어집니다. 오크통 특유의 풍부한 나무 향과 말린 과일의 달콤한 흔적이 가라앉으며 입안에 따뜻함과 에스프레소의 잔향을 기분 좋게 남깁니다."}}' WHERE id = 103;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (104, '더 글렌리벳 캡틴스 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/76285.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The Glenlivet Captain\'s Reserve 70cl', 101954, 'https://www.masterofmalt.com/whiskies/glenlivet/the-glenlivet-captains-reserve-whisky/?sku=76285', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 캡틴스 리저브(The Glenlivet Captain\'s Reserve)는 증류소의 역사적인 영웅이자 1차 세계 대전 당시 프랑스 전선에서 활약하며 증류소를 지켜낸 조지 스미스의 후손 대위 윌리엄 스미스 그랜트를 기리기 위해 탄생한 독창적인 캐스크 피니시 싱글 몰트 위스키입니다. 40% 도수로 병입되며 프렌치 코냑 캐스크의 화려함을 전면에 뽐냅니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 캐스크와 유러피안 오크 셰리 캐스크에서 원액을 조화롭게 숙성시킨 후, 프랑스 명품 와인 생산지 및 코냑 생산지에서 공수한 최고급 프랑스산 코냑 캐스크(Cognac Casks)로 원액을 옮겨 담아 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"코냑 캐스크 피니시의 미학": "스페이사이드 싱글 몰트에 프랑스 코냑 와인의 화려하고 달콤한 포도 풍미와 세련된 산미 레이어를 이색적으로 더했습니다.", "캡틴을 위한 스토리텔링": "증류소의 암흑기를 극복하고 합법적 면허의 유산을 수호한 대위 그랜트의 개척 정신을 한 보틀 안에 오마주했습니다.", "생기 넘치는 달콤함": "일반 버번이나 셰리 숙성과 결이 다른, 꿀에 절인 건포도와 시트러스 계열의 산뜻하고 화사한 단맛이 압권입니다."}}', note = '{"note": {"향 (Nose)": "화사하고 이국적인 아로마가 가득 퍼집니다. 부드러운 밤꿀과 바닐라 폼 향 뒤로, 상큼한 청포도, 신선한 복숭아의 화려한 과일 향과 코냑 캐스크 고유의 리치하고 우아한 오크 향이 기품 있게 어우러집니다.", "맛 (Palate)": "실크처럼 부드럽고 가볍게 입안을 감싸 안는 크리미한 질감입니다. 시럽을 듬뿍 바른 건포도, 달콤한 만다린 오렌지 마멀레이드의 풍미가 중심을 잡고 뒤이어 계피, 구운 생강 스파이스가 부드러운 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 잔향이 길게 이어집니다. 코냑 캐스크 특유의 상큼하고 달콤한 흔적이 가라앉으며 입안을 산뜻하게 정돈해 주는 감미로운 오크 스파이스의 여운이 매력적으로 마무리됩니다."}}' WHERE id = 104;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (105, '더 글렌리벳 트리플 캐스크 머추어드 디스틸러스 리저브', 'single_malt', 'Glenlivet Scotch Whisky', 'whiskey/101178.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'The Glenlivet Triple Cask Matured Distiller\'s Reserve 100cl', 127056, 'https://www.masterofmalt.com/whiskies/the-glenlivet/the-glenlivet-triple-cask-matured-distillers-reserve-whisky/?sku=101178', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "더 글렌리벳 트리플 캐스크 머추어드 디스틸러스 리저브(The Glenlivet Triple Cask Matured Distiller\'s Reserve)는 주로 글로벌 면세 시장을 겨냥하여 조지 스미스의 장인 정신과 정밀한 증류 기법을 기리기 위해 출시된 컬렉션입니다. 세 종류의 다른 캐스크 원액을 블렌딩하여 40% 도수 안에서 누구나 부담 없이 데일리로 즐기기 좋은 육각형의 완벽한 밸런스를 구현했습니다.", "제조 및 숙성": "마스터 디스틸러의 엄격한 감별 아래 전통적인 리필 캐스크 원액, 아메리칸 오크 ex-버번 캐스크 원액, 그리고 스페니시 오크 셰리 캐스크 원액까지 총 세 종류의 상이한 오크통에서 숙성된 원액들을 정교한 비율로 결합하여 완성했습니다."}, "feature": {"디스틸러의 밸런스 지향": "증류소 하우스 스타일에 충실하여 화사한 꽃향기와 단맛, 우디함의 삼박자가 가장 모범적으로 조화를 이루도록 설계되었습니다.", "삼중 캐스크의 복합 레이어": "버번의 바닐라, 셰리의 과일 맛, 리필 오크통의 은은한 맥아 고소함이 촘촘하게 얽혀 입체적인 풍미를 선사합니다.", "훌륭한 데일리 가성비": "부담 없는 질감 속에서 스페이사이드 전통 싱글 몰트 고유의 세련된 과수원 과일 아로마를 가성비 좋게 경험할 수 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 그 뒤를 이어 은은하게 깔리는 바닐라 크림 고유의 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감싸 안는 질감입니다. 벌꿀 집의 달콤함과 잘 익은 노란 사과의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 생강 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며 입안에 향긋하게 머무는 감미로운 보리의 흔적이 산뜻하게 마무리됩니다."}}' WHERE id = 105;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (106, '라가불린 16년', 'single_malt', 'Lagavulin Whisky', 'whiskey/2444.jpg', 43.0, 16, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Lagavulin 16 Year Old 70cl', 122705, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-16-year-old-whisky/?sku=2444', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 16년(Lagavulin 16 Year Old)은 전 세계 위스키 평론가들과 헤비 피트 매니아들 사이에서 아일라 피트의 제왕이자 싱글 몰트 위스키가 도달할 수 있는 가장 고결하고 중후한 왕좌로 일컬어지는 전설적인 아이코닉 명작입니다. 피트의 강력한 타격감과 오랜 장기 숙성이 주는 궁극의 우아함이 43% 도수 안에서 거대한 오케스트라처럼 조화를 이룹니다.", "제조 및 숙성": "증류소 특유의 배 모양 구리 증류기에서 극도로 천천히 저속 증류하여 무겁고 유기 화합물이 가득 찬 스피릿을 뽑아냅니다. 이 묵직한 원액을 엄선된 아메리칸 오크 ex-버번 캐스크와 유러피안 셰리 오크통에서 무려 16년이라는 기나긴 세월 동안 장기 숙성시켜 내추럴 컬러에 가까운 중후함을 완성했습니다."}, "feature": {"아일라 피트의 절대 왕좌": "요오드, 석탄 타르, 해풍의 짠맛과 스모키함이 오랜 숙성을 통해 극상의 부드러움으로 세련되게 에스테르화되었습니다.", "슬로우 디스틸레이션": "아일라 섬에서 가장 느린 증류공정을 고수하여 스피릿 내부에 묵직한 바디감과 독보적인 기름진 오일 펑크를 남겨둡니다.", "결점 없는 삼위일체": "강렬한 헤비 피트, 버번 배럴의 바닐라, 셰리 캐스크의 묵직한 과일 단맛이 완벽한 드라마처럼 유기적으로 이어집니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 묵직한 아로마입니다. 코끝을 찌르는 짙은 타르, 아스팔트 로프, 병원 소독약의 헤비 피트 향 뒤로 흑설탕에 졸인 무화과, 건포도, 달콤한 밤꿀의 단향이 퍼지고 오래된 가죽과 은은한 미네랄 해풍의 뉘앙스가 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 졸인 프루트 잼, 토피 당의 진한 단맛이 파도처럼 밀려오고 cracked 블랙페퍼, 구운 생강, 바다 소금의 짠맛이 피트 스모크와 어우러지며 폭발적인 복합미를 냅니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 피날레를 보여줍니다. 달콤한 셰리의 여운과 가죽 향이 가라앉으며 기품 있는 시가 박스의 우디한 향, 그리고 입안 전체를 끈질기게 감싸 안는 잔잔하고 드라이한 피트 재의 연기 향이 끝없이 지속됩니다."}}' WHERE id = 106;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (107, '라가불린 8년', 'single_malt', 'Lagavulin Whisky', 'whiskey/71920.jpg', 48.0, 8, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Lagavulin 8 Year Old 70cl', 96363, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-8-year-old-whisky/?sku=71920', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 8년(Lagavulin 8 Year Old)은 2016년 증류소 창립 200주년을 기념하기 위해 한정판으로 출시되었다가, 전 세계 애호가들의 폭발적인 성원에 힘입어 정규 라인업으로 당당히 합류한 역동적이고 파워풀한 영 앤 헤비 피트 위스키입니다. 16년 제품의 중후함과 완벽히 대비되는 길들여지지 않은 날것 그대로의 직관적인 피트 화력을 48%의 높은 도수로 뿜어냅니다.", "제조 및 숙성": "1880년대 전설적인 위스키 평론가 알프레드 바틀렛이 증류소를 방문했을 때 극찬했던 젊은 연산의 맛을 그대로 재현했습니다. 엄선된 리필 아메리칸 및 유러피안 오크 캐스크에서 8년 동안 짧고 강렬하게 숙성시켜, 오크통의 간섭을 최소화하고 보리 본연의 단맛과 피트 고유의 파괴력을 전면에 내세웠습니다."}, "feature": {"길들여지지 않은 야수": "짧은 숙성 연수에서만 만날 수 있는 직관적이고 강력한 장작 그을음과 타르, 소독약 캐릭터를 전면에 내세웁니다.", "48% ABV의 단단한 구조": "높은 알코올 볼륨감 세팅 덕분에 젊은 위스키임에도 튀지 않고 입안을 꽉 채우는 묵직한 마우스필과 타격감을 자랑합니다.", "순수한 맥아와 피트의 조화": "나무의 타닌 성분이 절제되어 청정 보리 본연의 고소함과 짭조름한 바다 소금기가 피트 스모크와 가장 순수하게 충돌합니다."}}', note = '{"note": {"향 (Nose)": "정신이 번쩍 드는 강렬함입니다. 갓 그을린 타르, 요오드, 메디컬한 소독약 향이 직관적으로 코를 찌릅니다. 그 거친 스모키함 뒤로 상큼한 레몬, 청사과의 시트러스와 달콤한 캐러멜, 신선한 소나무 바늘의 향이 생기 넘치게 어우러집니다.", "맛 (Palate)": "입안을 자극적으로 쪼아주는 강력하고 오일리한 질감입니다. 구운 보리의 고소한 단맛과 밀크 초콜릿의 풍미가 기저에 깔리고 으깬 통후추, 알싸한 후추 스파이스와 바다 소금의 짭조름한 단짠이 피트 스모크와 함께 파도처럼 몰아칩니다.", "여운 (Finish)": "드라이하면서도 스모키한 화력이 묵직하게 남는 긴 여운입니다. 입안 전체를 드라이하게 정돈해 주는 오크의 우디함, 쌉싸름한 에스프레소, 그리고 마지막까지 맴도는 건조하고 향긋한 캠프파이어의 재와 같은 연기 잔향이 인상적입니다."}}' WHERE id = 107;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (108, '라가불린 12년', 'single_malt', 'Lagavulin Whisky', 'whiskey/142195.jpg', 56.5, 12, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Lagavulin 12 Year Old (Special Release 2025) 70cl', 224288, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-12-year-old-special-release-2025-whisky/?sku=142195', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 12년 캐스크 스트렝스(Lagavulin 12 Year Old Cask Strength)는 디아지오 스페셜 릴리즈의 매년 빼놓을 수 없는 핵심 스타이자 전 세계 헤비 피트 컬렉터들이 무조건 수집하는 한정판 프리미엄 위스키입니다. 물을 타지 않은 56%에서 58% 안팎의 강력한 고도수 그대로 병입되어 16년 제품보다 한층 직관적이고 폭발적인 피트의 화력을 뿜어냅니다.", "제조 및 숙성": "증류소의 마스터 블렌더가 가장 활력 넘치고 순수한 피트 캐릭터를 품은 오크통만을 엄선하여 12년 동안 숙성시켰습니다. 주로 리필 아메리칸 오크 버번 배럴에서 숙성되어 나무의 성분을 절제하고, 가수 공정 없이 냉각 여과나 색소 첨가를 철저히 배제한 크래프트 상태 그대로 병입했습니다."}, "feature": {"매년 기다려지는 스페셜 릴리즈": "출시되는 해마다 독창적인 아티스트 일러스트 테마 레이블과 도수 세팅으로 출시되어 희소 가치가 극도로 높습니다.", "폭발적인 캐스크 스트렝스": "가수 공정 없는 강력한 도수에서 뿜어져 나오는 파워풀한 타격감과 농밀하게 혀를 코팅하는 오일 펑크가 압권입니다.", "순수한 아일라의 본질": "오크통의 과한 타닌 간섭을 배제하여 라가불린 스피릿 고유의 날카로운 요오드, 석탄 타르, 해풍의 소금기를 전면에 내세웁니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 짜릿한 소독약, 크레오소트, 아스팔트 타르의 헤비 피트 향이 직관적입니다. 그 강력한 스모크 뒤로 신선한 레몬 제스트, 청사과의 상큼함과 부드러운 캐러멜, 바닐라 포드의 단 향이 입체적으로 피어납니다.", "맛 (Palate)": "혓바닥을 진득하고 자극적으로 조여오는 강력한 풀바디 텍스처입니다. 알싸한 통후추와 구운 생강, 육두구의 스파이시함이 몰아치고 뒤이어 구운 맥아의 고소한 단맛과 강렬한 바다 소금의 짭조름한 단짠이 피트 스모크와 묵직하게 충돌합니다.", "여운 (Finish)": "온몸을 짜릿하게 데워주는 극도로 길고 드라이한 피날레입니다. 입안 전체를 지배하는 짙은 시가 박스의 우디함, 석탄 재와 담배 연기 같은 스모키, 그리고 마지막에 남는 쌉싸름한 카카오의 여운이 끝없이 지속됩니다."}}' WHERE id = 108;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (109, '라가불린 10년', 'single_malt', 'Lagavulin Whisky', 'whiskey/102381.jpg', 43.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Lagavulin 10 Year Old 70cl', 129542, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-10-year-old-whisky/?sku=102381', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 10년(Lagavulin 10 Year Old)은 주로 글로벌 면세 시장을 겨냥하여 8년 제품의 역동적인 영 스피릿 캐릭터와 16년 제품의 중후한 벨런스 사이에서 가장 이상적인 절충점을 찾기 위해 기획된 프리미엄 싱글 몰트 위스키입니다. 43% 도수로 병입되며 라가불린 특유의 묵직한 스모키함을 가성비 좋고 깔끔한 스타일로 전합니다.", "제조 및 숙성": "엄선된 퍼스트 필 버번 배럴과 리필 캐스크 원액, 그리고 안쪽을 그을린 재생 캐스크 원액을 마스터 블렌더의 정교한 비율로 결합하여 10년 동안 숙성했습니다. 다양한 캐스크의 조합 덕분에 짧은 연산임에도 훌륭한 라운드감을 형성합니다."}, "feature": {"면세 시장의 숨은 강자": "여행자들을 위해 특별히 기획되어 라가불린 특유의 묵직한 피트 스모크와 소금기 밸런스를 부담 없는 바디감으로 맛볼 수 있습니다.", "다양한 캐스크의 터치": "퍼스트 필 버번의 달콤함과 리벤 캐스크 고유의 스파이시함이 결합되어 다층적인 풍미 레이어를 형성합니다.", "편안한 피트 밸런스": "날카로운 요오드 향을 오크통의 캐러멜 풍미가 부드럽게 감싸 안아 라가불린 스타일을 한층 대중적으로 풀어냈습니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 묵직한 모닥불 연기와 타르 향이 코를 부드럽게 감쌉니다. 뒤이어 상큼한 레몬 제스트와 부드러운 바닐라 크림, 구운 토스트의 고소함과 함께 아일라 해풍 고유의 짭조름한 내음이 조화롭게 다가옵니다.", "맛 (Palate)": "입안에서 크리미하고 부드럽게 감싸 안는 질감입니다. 벌꿀 집의 단맛과 밀크 초콜릿, 졸인 과일의 단맛이 중심을 잡고 뒤이어 구운 생강, 육두구의 알싸한 우드 스파이스와 알싸한 블랙페퍼, 바다 소금의 짠맛이 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 묵직한 훈연 향이 길게 지속됩니다. 오크통의 따뜻한 우디함과 바닐라 캐러멜의 달콤한 흔적이 가라앉으며 입안 가득 맴도는 건조하고 향긋한 캠프파이어의 연기 잔향이 매력적으로 마무리됩니다."}}' WHERE id = 109;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (110, '라가불린 디스틸러스 에디션', 'single_malt', 'Lagavulin Whisky', 'whiskey/124883.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Lagavulin Distillers Edition 70cl', 153428, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-distillers-edition-whisky/?sku=124883', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 디스틸러스 에디션(Lagavulin Distillers Edition)은 증류소가 매년 단 한 번 출시하는 연간 한정판 시리즈로, 전설적인 16년 원액 고유의 캐릭터에 최고급 셰리 와인의 달콤함을 집중적으로 주입한 마스터클래스 익스프레션입니다. 43% 도수로 병입되며 피트 위스키가 도달할 수 있는 가장 화려하고 농밀한 단짠의 극치를 뽐냅니다.", "제조 및 숙성": "전통적인 라가불린 공정에 따라 버번과 셰리 캐스크에서 약 14년 이상 숙성되어 깊은 숙성미를 획득한 원액을 주축으로 삼습니다. 이 원액을 최고급 페드로 히메네스 셰리 캐스크로 옮겨 담아 수개월간 정교한 더블 머추어드 피니시 과정을 거쳐 완성됩니다."}, "feature": {"페드로 히메네스 캐스크의 마술": "위스키 세계에서 가장 달콤하고 점성이 높은 PX 와인 오크통의 영향력 덕분에 말린 무화과와 흑설탕의 녹진한 단맛이 압권입니다.", "연간 한정판의 희소성": "매년 병입 연도와 고유 넘버를 새겨 한정 수량만 발매하므로 위스키 수집가들 사이에서 프리미엄이 보장되는 보틀입니다.", "하모니의 극치": "라가불린 특유의 묵직하고 거친 석탄 타르, 소독약 스모크가 PX 셰리의 진득한 단맛과 충돌하며 경이로운 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 가득 차오르는 아로마입니다. 코를 감싸는 짙은 피트 연기와 요오드 향 뒤로 흑설탕에 졸인 자두, 진한 건포도, 말린 무화과의 녹진한 단향이 파도처럼 밀려오고 오래된 가죽과 시나몬의 아로마가 고풍스럽게 어우러집니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 오일리하게 입안 전체를 풀바디 텍스처로 코팅합니다. 다크 초콜릿 파이, 무화과 잼, 토피 당의 진한 단맛이 전면에 나서고 뒤이어 블랙페퍼, 구운 생강, 그리고 강렬한 바다 소금의 짭조름함이 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 지속됩니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 기품 있는 시가 박스의 우디한 향과 입안 전체를 묵직하게 채우는 드라이한 캠프파이어의 잔향이 긴 흔적을 남깁니다."}}' WHERE id = 110;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (111, '라가불린 11년 오퍼맨 에디션', 'single_malt', 'Lagavulin Whisky', 'whiskey/122212.jpg', 46.0, 11, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Lagavulin 11 Year Old Offerman Edition 70cl', 339421, 'https://www.masterofmalt.com/whiskies/lagavulin/lagavulin-11-year-old-offerman-edition-whisky/?sku=122212', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "라가불린 11년 오퍼맨 에디션(Lagavulin 11 Year Old Offerman Edition)은 유명 배우 닉 오퍼맨과 라가불린 증류소의 독창적인 콜라보레이션으로 탄생한 프리미엄 아일라 싱글 몰트 위스키입니다. 라가불린 특유의 묵직하고 강렬한 스모키함 위에 배치별로 다채로운 캐스크 피니시 실험을 적용하여 46% 도수 안에서 색다른 단짠의 조화를 선사합니다.", "제조 및 숙성": "증류소의 전통적인 ex-버번 및 셰리 캐스크에서 11년 동안 기본 숙성된 원액을 주축으로 삼습니다. 공식 배치에 따라 최고급 기네스 맥주 캐스크 또는 카리브해 럼 캐스크 등에서 수개월간 정교한 추가 피니시 숙성 과정을 거쳐 완성됩니다."}, "feature": {"닉 오퍼맨의 오마주": "위스키 매니아이자 브랜드 홍보대사인 배우 닉 오퍼맨의 취향과 유머러스한 스토리를 한 보틀 안에 위트 있게 담아냈습니다.", "독창적인 캐스크 피니시": "정형화된 정규 라인업에서 벗어나 라가불린의 헤비 피트가 이색적인 오크통과 만났을 때 뿜어내는 반전 매력을 보여줍니다.", "46% ABV의 타격감": "엔트리 라인보다 한층 높은 도수 설정을 채택하여 피트 스모크 속에서도 원액 본연의 묵직한 질감과 단맛을 든든하게 받쳐줍니다."}}', note = '{"note": {"향 (Nose)": "강렬한 소독약 향과 피트 연기 기저 위로 화사한 바닐라, 캐러멜 토피 향이 부드럽게 피어오릅니다. 잘 익은 자두와 말린 과일, 그리고 미세한 해풍의 짭조름한 바다 내음이 조화롭게 다가옵니다.", "맛 (Palate)": "입안을 오일리하고 묵직하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿과 구운 마시멜로, 흑설탕의 단맛이 파도처럼 밀려오고 으깬 통후추, 알싸한 생강의 오크 스파이스와 바다 소금의 짠맛이 피트 스모크와 함께 충돌합니다.", "여운 (Finish)": "온몸을 짜릿하게 데워주는 듯한 긴 여운을 남깁니다. 타버린 오크통의 우디한 잔향과 에스프레소의 쌉싸름함이 가라앉으며 입안 가득 맴도는 건조하고 향긋한 캠프파이어의 재 연기가 짙은 흔적을 남깁니다."}}' WHERE id = 111;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (112, '글렌피딕 익스페리멘탈 시리즈 프로젝트 XX', 'single_malt', 'Glenfiddich Whisky', 'whiskey/57046.jpg', 47.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich Experimental Series - Project XX 70cl', 88503, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-experimental-series-project-xx-whisky/?sku=57046', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 익스페리멘탈 시리즈 프로젝트 XX(Glenfiddich Experimental Series Project XX)는 전 세계 위스키 거장 20인의 지혜를 모아 탄생시킨 대담하고 독창적인 논에이징 싱글 몰트 위스키입니다. 증류소 특유의 부드럽고 화사한 스타일에 수많은 캐스크의 개성을 촘촘하게 엮어내어 47%의 높은 도수 안에서 폭발적인 복합미를 자랑합니다.", "제조 및 숙성": "전 세계에서 초청된 20명의 글렌피딕 브랜드 앰배서더들이 증류소 창고에서 각자 가장 마음에 드는 최고의 오크통을 단 하나씩 엄선했습니다. 이 포트 와인 캐스크, 버번 배럴, 셰리 부트 원액들을 몰트 마스터 브라이언 킨스만이 정교하게 결합하여 완성했습니다."}, "feature": {"20인의 공동 마스터피스": "위스키 거장 20인의 고유한 안목과 취향이 집약되어 글렌피딕 역사상 가장 다채로운 프로파일을 보여줍니다.", "다채로운 트리플 캐스크": "버번의 바닐라, 셰리의 묵직함, 포트 와인 캐스크 고유의 베리류 단맛이 한곳에 모여 화려한 시너지를 냅니다.", "47% 무여과 퀄리티": "높은 알코올 볼륨감 덕분에 수많은 오크통이 자아내는 복합적인 아로마와 풍성한 마우스필이 뭉개지지 않고 단단하게 전해집니다."}}', note = '{"note": {"향 (Nose)": "화사하고 가득 차오르는 아로마입니다. 갓 피어난 화이트 플라워, 싱그러운 서양 배, 레몬의 시트러스 향 뒤로 진한 토피 당, 바닐라 빈, 그리고 포트 캐스크 고유의 달콤한 살구 잼 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 질감입니다. 신선한 벌꿀과 밀크 초콜릿, 럼에 절인 건포도의 단맛이 중심을 잡고구운 아몬드의 고소함과 블랙페퍼, 정향의 알싸한 오크 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며 입안 가득 따뜻한 계피 풍미와 부드러운 오크 나무의 풍미가 오랜 흔적을 남깁니다."}}' WHERE id = 112;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (113, '글렌피딕 21년 그랑 리제르바', 'single_malt', 'Glenfiddich Whisky', 'whiskey/2078.jpg', 40.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 21 Year Old Gran Reserva 70cl', 289786, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-21-year-old-gran-reserva-whisky/?sku=2078', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 21년 그랑 리제르바(Glenfiddich 21 Year Old Gran Reserva)는 증류소의 프리미엄 라인업 중 가장 이국적이고 화려한 세련미를 뽐내는 고연산 싱글 몰트 위스키입니다. 20년이 넘는 기나긴 세월 동안 다듬어진 스페이사이드 고유의 화사함에 카리브해 럼 캐스크의 정열적인 달콤함을 입혀 40% 도수 속에서 환상적인 럭셔리 스타일을 완성했습니다.", "제조 및 숙성": "엄선된 아메리칸 오크 버번 캐스크에서 최소 21년이라는 기나긴 세월 동안 장기 숙성시켜 알코올의 날카로움을 완벽히 정제한 후, 마스터 블렌더가 직접 카리브해에서 공수한 최고급 럼 캐스크로 원액을 옮겨 담아 최종 수개월간 피니시 숙성을 거쳤습니다."}, "feature": {"럼 캐스크 피니시의 정점": "정통 스페이사이드 위스키에 이국적인 캐리비안 럼의 달콤한 터치를 가미하여 독창적인 풍미 스펙트럼을 넓혔습니다.", "시간이 공들인 부드러움": "21년의 장구한 숙성 기간을 거쳐 거친 알코올은 완벽히 가라앉고 실크처럼 매끄러운 마우스필과 단맛만 남았습니다.", "화려한 패키징 가치": "고급스러운 오렌지 테마 장식 전용 패키지와 위엄 있는 보틀 디자인으로 기획되어 선물용으로 인기가 매우 높은 주류입니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 달콤한 아로마가 코를 자극합니다. 진한 꿀과 캐러멜 토피 향 뒤로, 잘 익은 패션프루트, 무화과, 망고 같은 열대 과일의 화사함과 구운 당밀 고유의 향이 달콤하고 기품 있게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 순간 벨벳이나 실크처럼 매끄럽고 크리미한 부드러움을 줍니다. 바닐라 크림과 구운 마시멜로, 오렌지 마멀레이드의 달콤함이 퍼지고 뒤이어 럼 캐스크에서 배어 나온 따뜻한 생강, 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "온화하고 감미로운 여운이 길게 이어집니다. 꿀을 머금은 오크 향과 토피 당의 달콤한 흔적이 가라앉으며 입안에 기분 좋은 따뜻함과 이국적인 과일의 잔향을 부드럽게 남기며 가라앉습니다."}}' WHERE id = 113;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (114, '글렌피딕 18년', 'single_malt', 'Glenfiddich Whisky', 'whiskey/2079.jpg', 40.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 18 Year Old 70cl', 167571, 'https://www.masterofmalt.com/whiskies/glenfiddich-18-year-old-whisky/?sku=2079', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 18년(Glenfiddich 18 Year Old)은 전 세계 위스키 시장에서 고연산 위스키의 대중적인 표준이자 세련된 밸런스를 가장 완벽하게 보여주는 프리미엄 싱글 몰트 위스키입니다. 맥아 고유의 화사함과 오크통 숙성미의 정석으로 수많은 전문가들에게 찬사를 받는 명작입니다.", "제조 및 숙성": "최상급 스페니시 오로로소 셰리 오크 캐스크와 전통적인 아메리칸 오크 버번 배럴에서 각각 최소 18년 이상 장기 숙성된 원액들을 엄선했습니다. 이 진귀한 원액들을 대형 전통 오크 혼합조에서 최소 3달 이상 함께 호흡하게 하는 정교한 매링 공정을 거쳤습니다."}, "feature": {"정밀한 매링의 예술": "소량의 배치 형태로 엄격히 관리되며, 혼합조에서 최소 3개월간 원액들을 결합하여 완벽한 균형미를 구현했습니다.", "셰리와 버번의 정석": "오로로소 셰리의 묵직한 건포도 단맛과 버번 배럴의 화사한 바닐라, 사과 풍미가 완벽한 평형과 대칭을 이룹니다.", "한결같은 품질 보장": "맥캘란 등 하이엔드 브랜드와 견주어도 손색없는 글렌피딕 고유의 철저한 나무 관리 시스템을 통해 일관된 럭셔리 품질을 전합니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 졸인 청사과의 시트러스와 달콤한 캐러멜 토피 향이 먼저 코를 반깁니다. 뒤이어 상큼한 말린 오렌지 껍질과 은은한 계피, 삼나무의 부드러운 나무 향이 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 훌륭한 질감이 돋보입니다. 벌꿀 집의 단맛과 다크 초콜릿, 말린 살구의 풍미가 중심을 잡고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 나무 잔향이 길게 이어집니다. 오크통에서 배어 나온 부드러운 바닐라의 흔적과 건조한 오크의 우디함, 그리고 마지막에 남는 가벼운 향신료의 여운이 기분 좋고 묵직하게 정돈해 주며 마무리됩니다."}}' WHERE id = 114;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (115, '글렌피딕 12년', 'single_malt', 'Glenfiddich Whisky', 'whiskey/2082.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 12 Year Old 70cl', 61567, 'https://www.masterofmalt.com/whiskies/glenfiddich-12-year-old-whisky/?sku=2082', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 12년(Glenfiddich 12 Year Old)은 전 세계 싱글 몰트 위스키 시장에서 전 세계 판매량 1위를 달성하며 스페이사이드 스타일의 정석이자 살아있는 신화로 통하는 영원한 베스트셀러 싱글 몰트 위스키입니다. 전형적인 삼각 보틀 디자인으로 시산을 사로잡으며 40% 도수 속에서 누구나 쉽고 부드럽게 접근할 수 있는 표준 가이드라인을 전합니다.", "제조 및 숙성": "증류소 고유의 구리 증류기에서 불순물을 완전히 걸러내어 맑고 플로럴한 스피릿을 뽑아냈습니다. 이 맑은 원액을 전통적인 유러피안 오크 캐스크와 아메리칸 오크 버번 캐스크에서 최소 12년 동안 조화롭게 숙성시켜 마스터 블렌더의 비율로 혼합했습니다."}, "feature": {"싱글 몰트의 개척자": "1963년 혼합 위스키 중심의 시장에서 최초로 싱글 몰트 위스키를 브랜드화하여 전 세계 시장의 문을 연 역사적인 보틀입니다.", "화사한 청사과 밸런스": "글렌피딕의 시그니처인 싱그러운 사과, 배 캐릭터와 부드러운 단맛의 삼박자가 가장 모범적인 균형을 이룹니다.", "독보적인 가성비": "부담 없는 가격대에서 스페이사이드 전통 싱글 몰트 고유의 화사함과 크래프트 헤리티지를 가장 온전하게 맛볼 수 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 그 뒤를 이어 은은하게 깔리는 바닐라 크림 고유의 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감싸 안는 질감입니다. 벌꿀 집의 달콤함과 잘 익은 노란 사과의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 생강 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며 입안에 향긋하게 머무는 감미로운 보리의 흔적이 산뜻하게 마무리됩니다."}}' WHERE id = 115;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (116, '글렌피딕 15년 솔레라', 'single_malt', 'Glenfiddich Whisky', 'whiskey/2077.jpg', 40.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 15 Year Old Solera 70cl', 98082, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-15-year-old-solera-whisky/?sku=2077', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 15년 솔레라(Glenfiddich 15 Year Old Solera Reserve)는 스코틀랜드 위스키 업계 최초로 스페인 전통 와인 제조 기법인 솔레라 시스템을 도입하여 독창적인 부드러움과 깊은 밀도를 완성한 증류소의 메인 베스트셀러 싱글 몰트 위스키입니다. 40% 도수로 병입되며 꿀과 같은 농밀한 질감을 전합니다.", "제조 및 숙성": "아메리칸 버번 오크통, 스페니시 셰리 오크통, 그리고 버진 아메리칸 오크 캐스크까지 세 종류의 서로 다른 통에서 15년간 숙성된 원액들을 거대한 전용 솔레라 툰에 모아 섞습니다. 이 혼합조의 원액은 항상 절반 이상을 남겨두고 새 원액을 채우는 방식으로 영속적인 결합을 이어갑니다."}, "feature": {"솔레라 공법의 마술": "원액들이 거대한 혼합조에서 영속적으로 섞이고 에스테르화되어, 연산 대비 독보적인 부드러움과 일관된 품질을 확보했습니다.", "버진 오크의 화려한 변주": "셰리와 버번 외에도 뉴 버진 오크의 강력한 단맛을 결합하여 기존 하우스 스타일보다 훨씬 진득한 풍미를 전합니다.", "단맛과 실키함의 정점": "벌꿀 향 가득한 향긋하고 화사한 텍스처 덕분에 입문자부터 부드러운 스타일을 선호하는 매니아까지 모두를 매료시킵니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 상큼한 말린 오렌지 껍질, 신선한 꿀의 단 향과 함께 셰리 오크통에서 기인한 말린 무화과, 베이킹 스파이스 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "크리미하고 농밀하게 입안을 코팅하는 질감이 돋보입니다. 진한 밤꿀과 다크 초콜릿, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "따뜻하고 풍부한 잔향이 길게 이어집니다. 구운 오크의 우디한 향과 바닐라 캐러멜의 달콤한 흔적이 가라앉으며 입안 전체를 묵직하게 감싸 안는 감미롭고 스파이시한 단맛의 미련이 기분 좋게 남습니다."}}' WHERE id = 116;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (117, '글렌피딕 14년 버번 배럴 리저브', 'single_malt', 'Glenfiddich Whisky', 'whiskey/110830.jpg', 43.0, 14, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 14 Year Old - Bourbon Barrel Reserve 70cl', 86907, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-14-year-old-bourbon-barrel-reserve-whisky/?sku=110830', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 14년 버번 배럴 리저브(Glenfiddich 14 Year Old Bourbon Barrel Reserve)는 미국 버번 위스키 특유의 강렬하고 진득한 달콤함을 스페이사이드 전통 싱글 몰트 위스키 스타일에 가장 화려하게 이식해 낸 스페셜 익스프레션입니다. 43% 도수로 병입되며 풍부한 바닐라와 캐러멜의 타격감을 자랑합니다.", "제조 및 숙성": "증류소 고유의 방식으로 맑게 증류한 원액을 미국 켄터키주에서 공수한 최고급 ex-버번 아메리칸 오크 배럴에서 14년 동안 안정적으로 장기 숙성시켰습니다. 이후 안쪽을 강렬하게 태운 헤비 차드 뉴 아메리칸 오크 캐스크로 옮겨 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"버번 캐스크의 찬가": "처음부터 끝까지 버번 스타일에 집중된 오크통 설계를 통해 탁월한 바닐라 크림과 이국적인 우디 스파이스 풍미를 전합니다.", "헤비 차드 캐스크의 매력": "안쪽을 깊게 그을린 새 오크통의 영향력 덕분에 짧은 피니시 숙성 안에서도 농밀한 나무 설탕 성분하고 토피 향을 확보했습니다.", "43% ABV의 탄탄함": "엔트리 라인보다 한층 높은 도수 세팅 덕분에 버번 스타일 고유의 묵직한 볼륨감과 풍성한 마우스필이 단단하게 전해집니다."}}', note = '{"note": {"향 (Nose)": "강렬하고 달콤한 캐러멜 토피와 진한 바닐라, 메이플 시럽의 향이 코를 가득 채웁니다. 뒤이어 구운 마시멜로, 신선한 노란 사과 고유의 과일 아로마와 버진 오크 특유의 묵직한 가죽 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 실크처럼 매끄럽고 크리미하게 감싸 안는 풀바디 텍스처입니다. 벌꿀 집의 단맛과 브라운 슈가, 잘 익은 살구의 풍미가 느껴지며 오크통에서 배어 나온 으깬 통후추, 시나몬, 구운 생강의 알싸한 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "온화하고 풍부한 잔향이 길게 이어집니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 드라이한 나무 향, 따뜻한 계피 스파이스의 흔적이 입안을 산뜻하고 온화하게 정돈해 주며 마무리됩니다."}}' WHERE id = 117;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (118, '글렌피딕 23년 그랑 크루', 'single_malt', 'Glenfiddich Whisky', 'whiskey/93618.jpg', 40.0, 23, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 23 Year Old - Grand Cru 70cl', 414396, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-grand-cru-23-year-old-whisky/?sku=93618', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 23년 그랑 크루(Glenfiddich 23 Year Old Grand Cru)는 증류소의 최상위 하이엔드 럭셔리 라인업인 그랑 시리즈의 포문을 연 플래그십 마스터피스입니다. 스코틀랜드 전통 위스키 장인 정신과 프랑스 최고의 명품 스파클링 와인 오크통의 영향력이 가장 격조 높게 결합되었습니다. 세련된 블랙 앤 골드 보틀 패키지에 담겨 40% 도수 속에서 영광스러운 아우라를 뿜어냅니다.", "제조 및 숙성": "마스터 블렌더가 직접 선별한 최고 품질의 아메리칸 오크 버번 배럴과 유러피안 오크 셰리 캐스크에서 무려 23년이라는 오랜 세월 동안 고독하게 숙성된 원액들을 기반으로 합니다. 이 귀한 원액들을 프랑스 상파뉴 지역에서 최고의 와인을 담았던 진귀한 최고급 프렌치 퀴베 캐스크로 옮겨 담아 최종 수개월간 피니시 숙성을 거쳤습니다."}, "feature": {"프렌치 퀴베 캐스크의 위엄": "싱글 몰트 세계에서 극히 이례적인 최고급 샴페인 오크통 숙성을 통해 독창적이고 상큼한 화이트 와인의 산미와 달콤함을 확보했습니다.", "축제를 위한 럭셔리 라인": "그랑 크루라는 이름에 걸맞게 축하와 영광의 순간을 빛내기 위해 기획된 최고급 프리미엄 컬렉션입니다.", "결점 없는 조화": "23년의 장기 숙성이 주는 부드러운 가죽 향과 프렌치 오크 고유의 화사한 플로럴 텍스처가 경이로운 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "우아하고 싱그러운 아로마가 가득 퍼집니다. 갓 피어난 자스민, 백합 같은 화이트 플라워 향과 싱그러운 애플 블러썸 뒤로 잘 익은 레몬 껍질, 신선한 배의 시트러스가 퍼지고 달콤한 브리오슈 빵과 바닐라 포드의 향이 고급스럽게 얹어집니다.", "맛 (Palate)": "입안을 실크나 비단처럼 매끄럽고 크리미하게 감싸 안는 마우스필이 압권입니다. 진한 벌꿀 집의 단맛과 졸인 청포도, 오렌지 마멀레이드의 달콤함이 느껴지며 오크통에서 배어 나온 따뜻한 생강, 부드러운 넛멕 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "귀족적인 우아함이 돋보이는 매우 긴 여운입니다. 프랑스 와인 캐스크 고유의 상큼한 과일 산미와 바닐라의 달콤함이 가라앉으며 입안에 기분 좋은 드라이함과 감미로운 나무 향의 흔적을 산뜻하게 남깁니다."}}' WHERE id = 118;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (119, '글렌피딕 그랑 코룬 26년', 'single_malt', 'Glenfiddich Whisky', 'whiskey/107200.jpg', 43.8, 26, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich Grande Couronne 26 Year Old 70cl', 799870, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-grand-couronne-26-year-old-whisky/?sku=107200', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 그랑 코룬 26년(Glenfiddich 26 Year Old Grande Couronne)은 증류소의 럭셔리 라인업인 그랑 시리즈의 최고 정점 중 하나이자 영광의 왕관이라는 이름에 걸맞은 초고연산 마스터피스입니다. 프랑스 궁정의 화려한 예술을 모티브로 삼아 정교한 황금빛 레이스 장식 바틀 패키지로 완성되었으며 43.8%의 독창적인 도수 세팅 안에서 가장 격조 높은 품격을 자랑합니다.", "제조 및 숙성": "아메리칸 및 유러피안 오크 캐스크에서 무려 26년이라는 장구한 세월 동안 스페이사이드 바닷바람이 아닌 내륙 창고에서 온전히 숙성시킨 원액을 베이스로 삼습니다. 이 진귀한 원액을 프랑스 최고의 명품 코냑을 담았던 최고급 코냑 캐스크로 옮겨 담아 최종 2년 동안 장기 피니시 숙성 과정을 거쳤습니다."}, "feature": {"2년간의 코냑 캐스크 피니시": "단순한 터치 수준을 넘어 무려 2년 동안 프랑스 코냑 오크통에서 장기 피니시를 단행하여 독보적인 프랑스산 과일 산미와 단맛을 입혔습니다.", "황금 왕관의 예술적 가치": "프랑스 베르사유 궁전의 화려한 금박 예술을 형상화한 보틀과 우드 패키지 디자인으로 기획되어 하이엔드 컬렉터들의 심장을 뛰게 만듭니다.", "43.8%의 탄탄함과 구조감": "장기 숙성 코냑 원액 고유의 풍성한 마우스필과 촘촘하게 짜인 풍미 레이어가 흐트러지지 않도록 정교하게 도수를 세팅했습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 고풍스러운 아로마가 가득 피어오릅니다. 갓 구운 바닐라 포드, 달콤한 밤잼, 메이플 시럽 향 뒤로 말린 무화과, 건포도와 코냑 캐스크 특유의 리치하고 상큼한 다크 프루트, 오래된 오크의 고귀한 향이 겹겹이 레이어를 형성합니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳이나 실크처럼 매끄럽고 깊은 풍미가 가득 차오릅니다. 진한 벌꿀과 카페라떼, 졸인 황도 복숭아의 진한 달콤함이 먼저 입안을 채우고 뒤이어 구운 견과류의 고소함과 시나몬 가루, 정향, 구운 생강의 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "놀라울 정도로 우아하고 깊은 피날레가 영원처럼 지속됩니다. 코냑 와인의 상큼한 단맛과 고급 시가 박스의 우디한 향이 가라앉으며 입안 전체를 계속 감싸 안는 감미로운 허니 오크의 흔적과 잔잔한 에스프레소의 잔향이 긴 따뜻함과 함께 머눕니다."}}' WHERE id = 119;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (120, '글렌피딕 30년 서스펜드 타임', 'single_malt', 'Glenfiddich Whisky', 'whiskey/118134.jpg', 43.0, 30, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 30 Year Old Suspended Time - Time Reimagined 70cl', 1505997, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-30-year-old-suspended-time-time-reimagined-whisky/?sku=118134', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 30년 서스펜드 타임(Glenfiddich 30 Year Old Suspended Time)은 증류소가 자랑하는 초고연산 라인업이자 시간의 흐름을 잠시 멈춘 채 축적된 수십 년의 유산을 명징하게 증명하는 프리미엄 럭셔리 싱글 몰트 위스키입니다. 반세기에 가까운 세월 동안 오크통 내부에서 천천히 에스테르화된 고귀한 아우라를 43% 도수 속에서 가장 격조 높은 품격으로 전합니다.", "제조 및 숙성": "최상급 전통 아메리칸 오크 버번 배럴과 유러피안 오크 오로로소 셰리 캐스크에서 무려 30년 이상 오랜 세월 고독하게 숙성된 원액들을 몰트 마스터의 감각으로 엄선했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 병입했습니다."}, "feature": {"시간이 멈춘 방의 마술": "30년이라는 장구한 숙성 연수 속에서 자극적인 알코올은 완전히 정제되고 위스키가 가질 수 있는 가장 깊고 부드러운 단맛을 완성했습니다.", "더블 오크 장기 숙성의 정점": "두 캐스크 고유의 캐릭터가 어느 한쪽으로 치우치지 않고 완벽한 대칭과 조화를 이루도록 블렌딩조에서 오랜 기간 매링했습니다.", "예술적인 디스플레이 가치": "움직이는 리본 궤적 형태의 혁신적이고 감각적인 전용 프리미엄 패키지에 패킹되어 시각적인 컬렉션 가치도 극도로 높습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 진한 밤꿀과 달콤한 밀랍, 부드러운 바닐라 빈의 향이 직관적으로 피어오릅니다. 뒤이어 말린 무화과, 오렌지 마멀레이드, 오래된 가죽, 그리고 오래된 오크 고유의 부드러운 아로마가 겹겹이 층을 이룹니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳이나 실크처럼 매끄럽고 깊은 풍미가 가득 차오릅니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 달콤함이 먼저 입안을 채우고 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 감미로운 여운이 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 따뜻함과 함께 머뭅니다."}}' WHERE id = 120;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (121, '글렌피딕 퍼페추얼 컬렉션 VAT 02', 'single_malt', 'Glenfiddich Whisky', 'whiskey/121771.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenfiddich Perpetual Collection - Vat 02 Rich & Dark (1L) 100cl', 196124, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-perpetual-collection-vat-02-rich-and-dark-1l-whisky/?sku=121771', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 퍼페추얼 컬렉션 VAT 02(Glenfiddich Perpetual Collection VAT 02)는 멈추지 않는 여정을 상징하는 면세점 전용 라인업으로, 스페인의 전통적인 솔레라 툰 공법을 현대적으로 해석한 위스키입니다. 부드러운 스페이사이드 몰트 캐릭터에 다채로운 셰리 풍미를 정교하게 더해 43% 도수 속에서 묵직하고 녹진한 만족감을 자랑합니다.", "제조 및 숙성": "스페니시 오크 셰리 캐스크에서 장기간 숙성된 원액들을 엄선하여 증류소의 거대한 \'VAT 02\' 솔레라 혼합조에 결합했습니다. 이 혼합조는 1998년 이후 단 한 번도 완전히 비우지 않고 항상 절반의 원액을 남겨두는 방식으로 끊임없는 복합미를 유지합니다."}, "feature": {"멈추지 않는 솔레라 VAT": "1998년부터 비워지지 않은 VAT 02 혼합조에서 탄생하여 배치마다 역사적인 연속성과 깊이를 선사합니다.", "셰리 오크의 녹진함": "최고급 스페니시 오크의 영향력을 극대화하여 엔트리 라인보다 훨씬 깊고 중후한 다크 프루트 캐릭터를 뿜어냅니다.", "면세점 한정의 희소성": "글로벌 여행자들을 위해 특별한 패키지와 전용 프로파일로 기획되어 애호가들의 수집 욕구를 자극합니다."}}', note = '{"note": {"향 (Nose)": "농밀한 캐러멜 토피와 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 가득 퍼집니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 시가 박스의 우디함과 상큼한 말린 오렌지 껍질의 향이 조화를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 시럽, 토스트한 보리의 단맛이 파도처럼 밀려오고 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 121;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (122, '글렌피딕 익스페리멘탈 시리즈 오차드', 'single_malt', 'Glenfiddich Whisky', 'whiskey/117107.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich Experimental Series - Orchard 70cl', 75895, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-experimental-series-orchard-whisky/?sku=117107', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 익스페리멘탈 시리즈 오차드(Glenfiddich Experimental Series Orchard Experiment)는 증류소의 혁신적인 실험 정신을 대변하는 다섯 번째 익스페리멘탈 컬렉션으로, 과수원의 싱그러움을 한 병에 응축해 낸 싱글 몰트 위스키입니다. 글렌피딕 시그니처인 서양 배 캐릭터에 이국적인 달콤함을 입혀 43% 도수 속에서 경쾌한 활력을 전합니다.", "제조 및 숙성": "증류소 고유의 구리 증류기에서 맑게 뽑아낸 스피릿을 전통적인 아메리칸 오크 배럴에서 숙성시킨 후, 스코틀랜드 서머셋 지역의 명품 사과 브랜디인 포모나 와인을 담았던 최고급 소형 오크통에서 피니시 숙성 과정을 거쳤습니다."}, "feature": {"포모나 캐스크의 변주": "전통 사과 브랜디 리큐르 캐스크 숙성을 과감하게 시도하여 독창적이고 상큼한 사과 산미와 과수원의 풍미를 확보했습니다.", "싱그러운 과수원의 정수": "묵직한 셰리 숙성과는 결이 다른, 가을철 햇살 아래 잘 익은 자두와 상큼한 배 고유의 우아한 산뜻함을 자랑합니다.", "실험 시리즈의 진화": "몰트 마스터의 치밀한 캐스크 조합 실험을 통해 기존 스페이사이드 스타일에 생기 넘치는 과일 레이어를 더했습니다."}}', note = '{"note": {"향 (Nose)": "우아하고 싱그럽습니다. 갓 피어난 자스민 같은 화이트 플라워 아로마와 신선한 청포도, 서양 배, 잘 익은 사과의 시트러스가 달콤하게 올라옵니다. 그 기저에는 꿀을 바른 구운 토스트와 바닐라 포드의 향이 받쳐줍니다.", "맛 (Palate)": "입안을 매끄럽고 맑게 감싸 안는 실키한 질감이 돋보입니다. 졸인 황도 복숭아와 청자두 잼, 캐러멜 시럽의 단맛이 퍼지고 뒤이어 프렌치 오크 특유의 쌉싸름한 오렌지 제스트 스파이스와 따뜻한 진저의 맛이 정교한 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 긴 여운을 남깁니다. 바닐라의 달콤함과 캐스크 고유의 상큼한 과일 향이 가라앉으며 입안에 기분 좋은 드라이함과 우디한 스파이스의 흔적을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 122;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (123, '글렌피딕 퍼페추얼 컬렉션 VAT 04', 'single_malt', 'Glenfiddich Whisky', 'whiskey/128864.jpg', 47.8, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 18 Year Old Perpetual Collection - Vat 04 70cl', 192645, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-18-year-old-perpetual-collection-vat-04-whisky/?sku=128864', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 퍼페추얼 컬렉션 VAT 04(Glenfiddich Perpetual Collection VAT 04)는 면세 시장의 하이엔드 고객을 타겟으로 출시된 초고연산 스페셜 에디션으로, 장기 숙성된 원액의 깊이와 끊임없는 솔레라 공법의 결합을 보여주는 위스키입니다. 18년 연산급 원액들을 기반으로 하여 47.8%의 탄탄한 도수 속에서 명품의 품격을 뿜어냅니다.", "제조 및 숙성": "올로로소 셰리 캐스크와 아메리칸 오크 버번 배럴에서 최소 18년 이상 고독하게 세월을 버텨온 희귀 원액들을 마스터 블렌더가 직접 엄선했습니다. 이 진귀한 정수들을 대형 \'VAT 04\' 솔레라 혼합조에 결합하여 장기 피니시 및 마리잉 과정을 거쳤습니다."}, "feature": {"18년 숙성과 솔레라의 결합": "장기 숙성이 주는 부드러운 가죽 향과 솔레라 시스템의 끊임없는 복합미가 경이로운 하모니를 이룹니다.", "47.8% ABV의 단단함": "다소 높은 도수 설정을 채택하여 장기 숙성 원액 고유의 풍성한 마우스필과 아로마 레이어가 단단하게 전해집니다.", "럭셔리 레드 테마": "레드 컬렉션의 유산과 일맥상통하는 강렬한 패키징 디자인으로 면세점 위스키 수집가들의 표적이 됩니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스러운 아로마가 가득 피어오릅니다. 갓 구운 바닐라 포드, 달콤한 밤잼, 메이플 시럽 향 뒤로 말린 무화과, 건포도와 셰리 캐스크 특유의 리치하고 상큼한 다크 프루트, 오래된 오크의 고귀한 향이 겹겹이 레이어를 형성합니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳이나 실크처럼 매끄럽고 깊은 풍미가 가득 차오릅니다. 진한 벌꿀과 졸인 황도 복숭아의 진한 달콤함이 먼저 입안을 채우고 뒤이어 구운 견과류의 고소함과 시나몬 가루, 정향, 구운 생강의 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "놀라울 정도로 우아하고 깊은 피날레가 영원처럼 지속됩니다. 셰리 와인의 상큼한 단맛과 고급 시가 박스의 우디한 향이 가라앉으며 입안 전체를 계속 감싸 안는 감미로운 허니 오크의 흔적과 잔잔한 에스프레소의 잔향이 긴 따뜻함과 함께 머눕니다."}}' WHERE id = 123;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (124, '글렌피딕 퍼페추얼 컬렉션 VAT 03', 'single_malt', 'Glenfiddich Whisky', 'whiskey/121772.jpg', 50.2, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 15 Year Old - Perpetual Collection Vat 03 70cl', 179074, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-15-year-old-perpetual-collection-vat-03-whisky/?sku=121772', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 퍼페추얼 컬렉션 VAT 03(Glenfiddich Perpetual Collection VAT 03)은 프리미엄 면세 라인업의 핵심 주자로, 15년 숙성 연산급 원액 고유의 리치함에 끊임없이 결합하는 솔레라 툰의 미학을 담아낸 싱글 몰트 위스키입니다. 50.2%라는 강력한 도수로 병입되어 원액 본연의 진하고 탁월한 파워를 자랑합니다.", "제조 및 숙성": "유러피안 셰리 캐스크와 아메리칸 버번 배럴에서 최소 15년 동안 숙성된 원액들을 엄선했습니다. 이 원액들을 대형 \'VAT 03\' 솔레라 혼합조에 채워 넣어 마리잉 과정을 거쳤으며, 물을 최소한으로 섞어 고도수의 볼륨감을 고스란히 살렸습니다."}, "feature": {"50.2%의 폭발적인 화력": "높은 알코올 볼륨감 덕분에 15년 숙성 원액 고유의 풍성한 마우스필과 촘촘하게 짜인 풍미 레이어가 흐트러지지 않습니다.", "솔레라 툰의 라운드감": "거대한 혼합조에서 영속적으로 섞이고 에스테르화되어, 높은 도수임에도 거칠지 않고 극상의 부드러움을 전합니다.", "단맛과 실키함의 정점": "벌꿀 향 가득한 향긋하고 화사한 텍스처 덕분에 부드러우면서도 강력한 타격감을 선사하는 위스키입니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 상큼한 말린 오렌지 껍질, 신선한 꿀의 단 향과 함께 셰리 오크통에서 기인한 말린 무화과, 베이킹 스파이스 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "크리미하고 농밀하게 입안을 코팅하는 질감이 돋보입니다. 진한 밤꿀과 다크 초콜릿, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "따뜻하고 풍부한 잔향이 길게 이어집니다. 구운 오크의 우디한 향과 바닐라 캐러멜의 달콤한 흔적이 가라앉으며 입안 전체를 묵직하게 감싸 안는 감미롭고 스파이시한 단맛의 미련이 기분 좋게 남습니다."}}' WHERE id = 124;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (125, '글렌피딕 22년 그랑 코르테스', 'single_malt', 'Glenfiddich Whisky', 'whiskey/122210.jpg', 44.3, 22, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Glenfiddich 22 Year Old - Gran Cortes 70cl', 680562, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-22-year-old-gran-cortes-whisky/?sku=122210', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 22년 그랑 코르테스(Glenfiddich 22 Year Old Gran Cortes)는 증류소의 최상위 하이엔드 럭셔리 라인업인 \'그랑 시리즈\'의 대표적인 스페셜 에디션으로, 한국을 포함한 아시아 시장의 하이엔드 매니아들을 위해 한정 배정된 프리미엄 싱글 몰트 위스키입니다. 스코틀랜드 장인 정신과 스페인 궁정의 고결함을 오마주하여 44.3% 도수 속에서 압도적인 풍미를 자랑합니다.", "제조 및 숙성": "전통적인 아메리칸 오크 캐스크에서 무려 22년이라는 장구한 세월 동안 숙성시켜 부드러운 깊이를 획득한 원액을 주축으로 삼습니다. 이 진귀한 원액을 스페인 헤레스 지역의 전설적인 팔로 코르타도 셰리 와인을 담았던 최고급 캐스크로 옮겨 담아 최종 피니시 숙성을 거쳤습니다."}, "feature": {"팔로 코르타도 캐스크의 마술": "위스키 세계에서 극히 이례적인 희귀 셰리 와인 오크통 숙성을 통해 독창적이고 녹진한 단맛과 세련된 우디함을 확보했습니다.", "아시아 하이엔드 한정판": "아시아 위스키 애호가들의 입맛을 정밀 타겟팅하여 진한 무화과, 다크 초콜릿 캐릭터를 전면에 뽐냅니다.", "44.3%의 정교한 밸런스": "알코올 볼륨감을 높여 장기 숙성 셰리 원액 고유의 풍성한 마우스필과 촘촘하게 짜인 풍미 레이어가 기품 있게 전해집니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 깊은 셰리 아로마가 코를 자극합니다. 진한 건포도, 말린 무화과, 흑설탕에 졸인 자두 잼의 단향이 지배적으로 피어오르고 오래된 나무 향과 진한 캐러멜, 그리고 은은한 시나몬과 진저 스파이스가 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 진득하게 가득 채우는 훌륭한 바디의 질감입니다. 달콤한 토피 당과 밀크 초콜릿, 말린 과일의 진한 풍미가 전개되고 뒤이어 유러피안 오크 특유의 쌉싸름한 오렌지 마멀레이드와 계피의 알싸한 스파이스가 훌륭한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 따뜻한 여운이 묵직하게 오래 지속됩니다. 말린 과일의 단맛과 에스프레소의 흔적이 서서히 가라앉으며, 입안 가득 기품 있는 구운 오크의 우디함과 따뜻한 베이킹 스파이스의 잔향이 긴 여운을 선사합니다."}}' WHERE id = 125;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (126, '글렌피딕 퍼페추얼 컬렉션 VAT 01', 'single_malt', 'Glenfiddich Whisky', 'whiskey/121770.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenfiddich Perpetual Collection - Vat 01 Smooth & Mellow 100cl', 159896, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-perpetual-collection-vat-01-smooth-and-mellow-whisky/?sku=121770', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 퍼페추얼 컬렉션 VAT 01(Glenfiddich Perpetual Collection VAT 01)은 끊임없이 흐르는 시간의 아름다움을 시각적, 미각적으로 표현한 면세점 전용 라인업의 엔트리 스타터입니다. 글렌피딕 본연의 밝고 싱그러운 과일 맛을 가장 산뜻하게 전개하며 40% 도수 안에서 완벽한 육각형의 대중적인 밸런스를 자랑합니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴과 유러피안 오크 리필 캐스크에서 숙성된 원액들을 엄선했습니다. 이 원액들을 증류소 내부의 거대한 \'VAT 01\' 솔레라 혼합조에 채워 넣어 오랜 시간 유기적으로 엮어냈으며, 인위적인 타협 없이 일관된 균형미를 유지합니다."}, "feature": {"모든 싱글 몰트의 시작": "화사한 꽃향기와 시트러스, 부드러운 단맛의 삼박자가 가장 모범적으로 짜여 있어 위스키 입문자들에게 적합합니다.", "솔레라 VAT 01의 하모니": "1998년부터 계속 축적된 혼합조 원액의 연속성 덕분에 연산 대비 깊고 기품 있는 아로마 레이어를 확보해 냈습니다.", "합리적인 데일리 밸런스": "부담 없는 질감 속에서 스페이사이드 전통 싱글 몰트 고유의 세련된 과수원 과일 아로마를 데일리로 즐기기에 좋습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 그 뒤를 이어 은은하게 깔리는 바닐라 크림 고유의 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감싸 안는 질감입니다. 벌꿀 집의 달콤함과 잘 익은 노란 사과의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 생강 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며 입안에 향긋하게 머무는 감미로운 보리의 흔적이 산뜻하게 마무리됩니다."}}' WHERE id = 126;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (127, '글렌피딕 몰트 마스터즈 에디션 셰리 캐스크 피니시', 'single_malt', 'Glenfiddich Whisky', 'whiskey/17574.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich Malt Master\'s Edition - Sherry Cask Finish 70cl', 91942, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-malt-masters-edition-sherry-cask-finish-whisky/?sku=17574', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 몰트 마스터즈 에디션 셰리 캐스크 피니시(Glenfiddich Malt Master\'s Edition Sherry Cask Finish)는 몰트 마스터 브라이언 킨스만의 장인 정신과 수작업 헤리티지를 기리기 위해 기획된 프리미엄 스페셜 에디션 위스키입니다. 글렌피딕의 화사한 스타일에 셰리의 녹진함을 우아하게 엮어내어 43% 도수 속에서 풍성한 볼륨감을 전합니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 오랜 세월 숙성되어 완벽한 부드러움과 깊이를 획득한 고품질 원액을 기반으로 합니다. 이 원액을 마스터 블렌더가 직접 엄선한 최고급 셰리 오크통으로 옮겨 담아 최종 수개월간 정교한 피니시 숙성 과정을 거쳤습니다."}, "feature": {"마스터 블렌더의 서명": "브라이언 킨스만이 자신의 이름을 걸고 캐스크 선별부터 피니시 시점까지 전 과정을 직접 통제한 마스터피스입니다.", "버번과 셰리의 이중주": "버번 캐스크의 화사한 바닐라, 사과 캐릭터 기저 위에 셰리 특유의 베리류 단맛이 절묘하게 하모니를 이룹니다.", "43% ABV의 탄탄한 구조": "엔트리 라인보다 한층 높은 도수 설정을 채택하여 풍미의 촘촘한 밀도와 오일감이 무너지지 않고 단단하게 전해집니다."}}', note = '{"note": {"향 (Nose)": "화사하면서도 묵직한 아로마가 코를 자극합니다. 진한 꿀과 바닐라 향 뒤로, 잘 익은 서양 배와 셰리 캐스크 특유의 건포도, 캐러멜 토피 향이 복합적이고 감미롭게 피어오릅니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 질감이 돋보입니다. 벌꿀 집의 단맛과 졸인 황도 복숭아의 풍미가 퍼지고 뒤이어 오크통에서 배어 나온 따뜻한 생강, 시나몬의 알싸한 우드 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "온화하고 드라이한 잔향을 남깁니다. 바닐라의 달콤함과 셰리 와인의 단맛이 가라앉으며 입안에 기분 좋은 따뜻함과 감미로운 나무 향의 흔적을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 127;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (128, '글렌피딕 12년 트리플 오크', 'single_malt', 'Glenfiddich Whisky', 'whiskey/110794.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 12 Year Old Triple Oak 70cl', 91840, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-12-year-old-triple-oak-whisky/?sku=110794', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 12년 트리플 오크(Glenfiddich 12 Year Old Triple Oak)는 기존의 클래식 12년 제품을 혁신적으로 업그레이드하여 세 종류의 다른 오크통 풍미를 극대화해 출시한 프리미엄 스탠다드 싱글 몰트 위스키입니다. 40% 도수 안에서 한층 더 진하고 다채로운 나무 스파이스와 단맛의 스펙트럼을 보여줍니다.", "제조 및 숙성": "아메리칸 오크 버번 배럴과 유러피안 오크 셰리 캐스크, 그리고 안쪽을 정교하게 태운 뉴 버진 아메리칸 오크 캐스크까지 총 세 종류의 다른 오크통에서 각각 최소 12년 동안 숙성된 원액들을 마스터 블렌더의 비율로 혼합했습니다."}, "feature": {"삼중 오크 숙성의 매력": "버번의 바닐라, 셰리의 과일 맛, 버진 오크의 강력한 탄닌과 스파이스가 완벽한 삼위일체의 균형을 이룹니다.", "진화한 엔트리 표준": "기존 12년 제품보다 오크통의 영향력이 대폭 증가하여 한층 더 묵직하고 직관적인 단맛의 타격감을 선사합니다.", "독보적인 가성비": "부담 없는 연산과 가격대에서 최고급 세 종류 캐스크 원액의 촘촘한 레이어를 가성비 좋게 경험할 수 있습니다."}}', note = '{"note": {"향 (Nose)": "강렬하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 구운 마시멜로, 신선한 노란 사과의 과일 아로마와 오크통 특유의 묵직한 가죽 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 실크처럼 매끄럽고 크리미하게 감싸 안는 텍스처입니다. 벌꿀 집의 단맛과 브라운 슈가, 잘 익은 살구의 풍미가 느껴지며 오크통에서 배어 나온 으깬 통후추, 시나몬, 구운 생강의 알싸한 스파이스가 타격감을 선사합니다.", "여운 (Finish)": "온화하고 풍부한 잔향이 길게 이어집니다. 오크통 고유의 달콤한 바닐라 풍미와 드라이한 나무 향, 따뜻한 계피 스파이스의 흔적이 입안을 기분 좋고 온화하게 정돈해 주며 마무리됩니다."}}' WHERE id = 128;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (129, '글렌피딕 40년 큐뮬레이티브 타임', 'single_malt', 'Glenfiddich Whisky', 'whiskey/118136.jpg', 44.6, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich 40 Year Old Cumulative Time - Time Reimagined 70cl', 6481533, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-40-year-old-time-reimagined-whisky/?sku=118136', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 40년 큐뮬레이티브 타임(Glenfiddich 40 Year Old Cumulative Time)은 증류소가 보유한 초고연산 원액들 중 극상의 품질을 지닌 통만을 엄선하여 소량 한정 생산하는 최상위 하이엔드 마스터피스입니다. 거의 반세기에 달하는 40년이라는 장구한 시간 동안 누적된 세월의 신비로움을 온몸으로 증명하며 대략 44.6% 안팎의 자연스러운 캐스크 스트렝스 도수로 병입되는 진귀한 최고급 명품 위스키입니다.", "제조 및 숙성": "증류소 창고 깊숙한 곳에서 무려 40년 이상 고독하게 세월을 버텨온 희귀한 전통 아메리칸 오크 버번 배럴과 유러피안 오크 오로로소 셰리 캐스크 원액을 정밀하게 감별했습니다. 이 진귀한 정수들을 대형 전통 오크 통에서 결합하는 고도의 장인 예술로 탄생했습니다."}, "feature": {"반세기에 가까운 세월": "40년의 기나긴 세월 동안 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 위스키의 정수입니다.", "큐뮬레이티브 타임의 가치": "수십 년의 세월 동안 오크통과 원액이 나눈 교감이 액체 안에 고스란히 누적되어 독보적인 레이어를 형성합니다.", "박물관급 디스플레이 디자인": "기하학적이고 파격적인 커팅 레이어 디자인의 최고급 프리미엄 전용 패키지에 소장되어 글로벌 자산가들의 드림 보틀로 통합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고, 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 129;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (130, '글렌피딕 익스페리멘탈 시리즈 IPA 캐스크 피니시', 'single_malt', 'Glenfiddich Whisky', 'whiskey/57047.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenfiddich Experimental Series - IPA Cask Finish 70cl', 81012, 'https://www.masterofmalt.com/whiskies/glenfiddich/glenfiddich-experimental-series-ipa-cask-finish-whisky/?sku=57047', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌피딕 익스페리멘탈 시리즈 IPA 캐스크 피니시(Glenfiddich Experimental Series IPA Cask Experiment)는 증류소의 파격적인 실험 정신을 전 세계에 알린 최초의 익스페리멘탈 컬렉션으로, 싱글 몰트 위스키와 수제 맥주의 결합을 시도한 획기적인 위스키입니다. 43% 도수로 병입되며 홉 특유의 상큼한 시트러스 쌉싸름함을 자랑합니다.", "제조 및 숙성": "스페이사이드 지역의 수제 맥주 양조장 마스터와 협업하여, 글렌피딕 오크통에 특제 인디아 페일 에일 맥주를 담아 홉의 향을 입혔습니다. 이후 맥주를 비워내고 글렌피딕 전통 숙성 원액을 다시 채워 넣어 최종 수개월간 피니시 숙성을 거쳤습니다."}, "feature": {"위스키와 IPA의 도킹": "위스키 역사상최초로 수제 맥주 IPA 캐스크 숙성을 도입하여 위스키 애호가들과 맥주 매니아들 사이에서 선풍적인 인기를 끌었습니다.", "홉 고유의 시트러스 터치": "일반 버번 숙성과 결이 다른, 홉에서 배어 나온 신선한 레몬그라스와 허브 고유의 싱그러운 아로마를 선사합니다.", "산뜻하고 경쾌한 마우스필": "가벼우면서도 상큼한 과일 단맛 기저 위에 은은한 홉의 쌉싸름함이 숨어있어 한층 더 경쾌한 느낌을 줍니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 아로마가 가득 퍼집니다. 갓 피어난 화이트 플라워, 신선한 서양 배 향 뒤로 IPA 맥주 특유의 상큼한 레몬그라스, 자몽 제스트, 그리고 향긋한 허브와 부드러운 맥아의 고소함이 조화롭게 피어오릅니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 부드러운 바닐라 크림과 벌꿀 집의 단맛, 졸인 청사과의 풍미가 느껴지며 오크통에서 배어 나온 은은한 우디함과 화이트 페퍼, 그리고 홉 고유의 산뜻하고 알싸한 쌉싸름함이 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 특유의 바닐라 단맛과 과일 향이 가라앉으며, 입안에 기분 좋은 드라이함과 홉의 싱그러운 잔향을 산뜻하게 남기며 우아하게 마무리됩니다."}}' WHERE id = 130;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (131, '글렌모렌지 시그넷', 'single_malt', 'Glenmorangie Whisky', 'whiskey/2118.jpg', 46.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie Signet 70cl', 322289, 'https://www.masterofmalt.com/whiskies/glenmorangie-signet-whisky/?sku=2118', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 시그넷(Glenmorangie Signet)은 증류소의 장인 정신과 혁신적인 실험 정신이 집약된 울트라 프리미엄 싱글 몰트 위스키입니다. 위스키 세계 최초로 강하게 볶은 에스프레소용 초콜릿 몰트를 사용하여 독창적이고 농밀한 풍미를 완성했으며, 46% 도수로 냉각 여과 없이 병입되어 묵직한 카리스마를 보여줍니다.", "제조 및 숙성": "증류소가 보유한 가장 진귀한 고연산 원액들과 함께 자사 소유의 오자크 산맥 \'디자이너 캐스크\'에서 숙성된 원액을 블렌딩했습니다. 초콜릿 맥아 특유의 쌉싸름함과 달콤함이 오랜 숙성미와 결합하여 마치 벨벳처럼 부드러운 하모니를 만들어냅니다."}, "feature": {"초콜릿 몰트의 변주": "에스프레소 로스팅 맥아를 과감하게 도입하여 기존 스페이사이드 위스키들과 완벽히 차별화되는 모카 아로마를 확보했습니다.", "디자이너 캐스크 숙성": "나무의 성장 속도까지 정밀 제어하여 특제 제작한 아메리칸 화이트 오크통을 사용해 독보적인 바닐라 향을 이끌어냈습니다.", "하이엔드 카리스마": "예술적인 보틀 디자인과 흑호박색의 짙은 비주얼로 전 세계 하이엔드 컬렉터들의 전폭적인 지지를 받습니다."}}', note = '{"note": {"향 (Nose)": "코끝을 감싸는 진한 에스프레소, 다크 초콜릿, 달콤한 브라운 슈가의 향이 직관적입니다. 뒤이어 상큼한 말린 오렌지 껍질과 진한 생강 절임, 묵직한 가죽과 시가 박스의 아로마가 겹겹이 피어오릅니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 실크나 벨벳처럼 극도로 매끄럽고 깊은 풍미가 느껴집니다. 풍부한 모카 크림과 졸인 무화과 잼의 진한 달콤함이 먼저 입안을 채우고 시나몬, 육두구의 알싸한 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 달콤한 토피 당의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 마지막에는 다크 카카오의 세련된 여운이 길게 이어집니다."}}' WHERE id = 131;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (132, '글렌모렌지 18년 디 인피니타', 'single_malt', 'Glenmorangie Whisky', 'whiskey/135091.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 18 Year Old The Infinita 70cl', 204680, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-18-year-old-the-infinita-whisky/?sku=135091', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 18년 디 인피니타(Glenmorangie 18 Year Old Azuma Makoto / The Infinita)는 증류소의 정규 고연산 라인업 중 가장 세련되고 다채로운 꽃향기를 자랑하는 프리미엄 싱글 몰트 위스키입니다. 18년이라는 오랜 세월 동안 다듬어진 화사한 하우스 스타일에 셰리의 묵직함을 정교하게 엮어내어 43% 도수 속에서 극상의 우아함을 전합니다.", "제조 및 숙성": "아메리칸 화이트 오크 버번 배럴에서 최초 15년 동안 안정적으로 장기 숙성시킨 후 원액의 30%를 추출하여 최고급 스페니시 오로로소 셰리 캐스크로 옮겨 담아 최종 3년간 추가 숙성했습니다. 이후 두 원액을 다시 정밀한 비율로 혼합하여 완성했습니다."}, "feature": {"화사한 꽃향기의 정점": "글렌모렌지 특유의 기린 목처럼 높은 증류기가 만들어낸 맑은 스피릿이 장기 숙성을 거쳐 극상의 플로럴 아로마를 뿜어냅니다.", "셰리 피니시의 밸런스": "30%의 셰리 캐스크 원액이 주는 묵직함과 70%의 버번 캐스크 원액이 주는 화사함이 완벽한 대칭과 균형을 이룹니다.", "귀족적인 세련미": "위스키 거장들과 매니아들 사이에서 단 하나의 맛도 튀지 않는 완벽한 육각형 밸런스를 지닌 명작으로 손꼽힙니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 갓 피어난 자스민, 백합 같은 화이트 플라워 아로마와 말린 무화과, 대추야자의 달콤함이 올라옵니다. 그 기저에는 꿀을 바른 구운 토스트와 따뜻한 바닐라 빈의 향이 기품 있게 받쳐줍니다.", "맛 (Palate)": "입안을 매끄럽고 맑게 감싸 안는 실키한 질감이 돋보입니다. 졸인 황도 복숭아, 자두 잼, 캐러멜 시럽의 단맛이 퍼지고 뒤이어 오크통 특유의 쌉싸름한 오렌지 제스트 스파이스와 따뜻한 계피, 구운 생강의 맛이 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 드라이한 잔향이 기분 좋게 남습니다. 바닐라의 달콤함과 셰리 와인의 잔향이 가라앉으며 입안에 기분 좋은 따뜻함과 감미로운 나무 향의 흔적을 오래도록 선사합니다."}}' WHERE id = 132;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (133, '글렌모렌지 14년 퀸타루반', 'single_malt', 'Glenmorangie Whisky', 'whiskey/89849.jpg', 46.0, 14, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 14 Year Old The Quinta Ruban 70cl', 81708, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-quinta-ruban-14-year-old-whisky/?sku=89849', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 14년 퀸타루반(Glenmorangie 14 Year Old The Quinta Ruban)은 증류소가 자랑하는 최고급 포트 와인 캐스크 피니시 제품으로, 짙고 농밀한 루비 빛깔의 자태를 뽐내는 프리미엄 싱글 몰트 위스키입니다. 포르투갈의 유서 깊은 와이너리 오크통이 가진 화려한 풍미를 입혀 46% 도수 안에서 기품 있는 달콤함을 보여줍니다.", "제조 및 숙성": "최상급 아메리칸 화이트 오크 버번 배럴에서 최초 10년 동안 안정적으로 숙성시켜 깊은 바닐라와 과일 향을 확보한 후, 포르투갈의 명품 포트 와인을 담았던 최고급 루비 포트 파이프(Ruby Port Pipes) 캐스크로 원액을 옮겨 담아 최종 4년간 집중적인 피니시 숙성을 거쳤습니다."}, "feature": {"포트 와인의 진득함": "가장 달콤하고 화려한 루비 포트 캐스크의 영향력 덕분에 말린 무화과와 토피 시럽의 깊은 맛이 압권입니다.", "46% ABV의 탄탄함": "엔트리 라인보다 한층 높은 도수 세팅 덕분에 포트 와인 캐스크 특유의 베리류 풍미와 오일감이 뭉개지지 않고 단단하게 전해집니다.", "결점 없는 단맛의 변주": "일반적인 셰리 숙성과 결이 다른, 럼에 절인 건포도와 민트 초콜릿 같은 독창적인 단 향이 드라마처럼 이어집니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 가득 차오르는 아로마입니다. 흑설탕에 졸인 자두, 건포도, 베리류 잼의 진한 단향이 먼저 코를 찌르고 뒤이어 달콤한 밀랍, 캐러멜 토피, 오래된 가죽과 은은한 다크 초콜릿의 향이 깊고 고풍스럽게 어우러집니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 오일리하게 입안 전체를 가득 코팅합니다. 다크 초콜릿 파이, 무화과 잼, 토피 당의 진한 단맛이 파도처럼 밀려오고 뒤이어 블랙페퍼, 구운 생강, 육두구의 알싸한 오크 스파이스가 포트의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 입안 가득 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 흔적이 짙게 머눕니다."}}' WHERE id = 133;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (134, '글렌모렌지 16년 더 넥타', 'single_malt', 'Glenmorangie Whisky', 'whiskey/132459.jpg', 46.0, 16, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 16 Year Old The Nectar 70cl', 117159, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-nectar-16-year-old-whisky/?sku=132459', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 16년 더 넥타(Glenmorangie 16 Year Old The Nectar)는 프랑스의 최고급 디저트 와인 캐스크 피니시를 통해 위스키가 도달할 수 있는 가장 달콤하고 고급스러운 귀족적 아우라를 표현해 낸 프리미엄 싱글 몰트 위스키입니다. 기존 12년 넥타 도르 제품의 숙성 연수를 16년으로 대폭 상향하여 46% 도수 속에서 촘촘한 밀도감을 전합니다.", "제조 및 숙성": "최상급 버번 배럴에서 최소 14년 이상 장기 숙성되어 부드러운 깊이를 획득한 고품질 원액을 기반으로 합니다. 이 진귀한 원액을 프랑스 소테른(Sauternes) 지역의 명품 주정강화 디저트 와인을 담았던 퍼스트 필 오크 캐스크로 옮겨 담아 최종 2년간 정교한 피니시 숙성 과정을 거쳤습니다."}, "feature": {"소테른 캐스크의 마술": "세계 최고급 달콤함을 자랑하는 프랑스 귀부 와인 오크통 숙성을 통해 독창적인 레몬 타르트와 벌꿀의 달콤함을 확보했습니다.", "16년 숙성으로의 진화": "숙성 연수를 늘리고 46% 도수 세팅을 채택하여 소테른 와인의 단맛 속에서도 오크통 고유의 탄닌과 구조감이 강력하게 전해집니다.", "귀족적인 디저트 스타일": "달콤한 당밀과 레몬 제스트, 시럽의 풍미가 부드럽게 감싸 안아 위스키 입문자부터 여성 애호가들까지 모두를 매료시킵니다."}}', note = '{"note": {"향 (Nose)": "화사하고 감미로운 꿀의 단향과 바닐라 아로마가 풍부하게 피어오르고, 그 뒤를 이어 오렌지 마멀레이드의 상큼함과 소테른 와인 특유의 잘 익은 살구, 구운 코코넛의 향이 우아하게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 실키한 질감이 돋보입니다. 레몬 타르트, 생강 편강, 캐러멜 시럽의 진한 단맛이 퍼지고 뒤이어 오크통 특유의 쌉싸름한 오렌지 제스트 스파이스와 계피의 알싸함이 정교한 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 긴 감미로운 여운을 남깁니다. 바닐라의 달콤함과 디저트 와인 캐스크 고유의 상큼한 과일 향이 가라앉으며 입안에 기분 좋은 드라이함과 우디한 스파이스의 흔적을 우아하게 남깁니다."}}' WHERE id = 134;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (135, '글렌모렌지 25년 디 알터스', 'single_malt', 'Glenmorangie Whisky', 'whiskey/142839.jpg', 43.0, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 25 Year Old The Altus 70cl', 829815, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-altus-25-year-old-whisky/?sku=142839', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 25년 디 알터스(Glenmorangie 25 Year Old The Altus)는 증류소가 보유한 초고연산 원액들 중 극상의 품질을 지닌 통만을 엄선하여 소량 한정 생산하는 최상위 하이엔드 마스터피스입니다. 25년이라는 장구한 시간 동안 서서히 에스테르화 과정을 거쳤으며 43% 도수 안에서 위스키가 가질 수 있는 가장 고귀하고 기품 있는 아우라를 보여줍니다.", "제조 및 숙성": "마스터 블렌더의 치밀한 설계 아래 최상급 아메리칸 화이트 오크 버번 배럴, 스페니시 오로로소 셰리 캐스크, 그리고 프랑스 부르고뉴 지역의 최고급 프리미엄 와인 오크통에서 각각 25년 이상 장기 숙성된 희귀 원액들을 황금 비율로 블렌딩했습니다."}, "feature": {"최상위 플래그십": "글렌모렌지 정규 및 한정 라인업 중 가장 높은 연산에 속하는 고귀한 마스터피스로서 소장 가치가 극도로 높습니다.", "삼중 캐스크의 하모니": "버번의 바닐라, 셰리의 묵직함, 프랑스 와인 캐스크의 베리류 풍미와 실키함이 거대한 조화를 이룹니다.", "시간이 빚은 부드러움": "25년의 기나긴 숙성 기간을 거쳐 자극적인 알코올은 완벽히 정제되고 극상의 실키한 질감과 중후한 깊이감만 남았습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 졸인 자두, 무화과 잼의 농축된 향이 깊게 퍼지고 뒤이어 고급스러운 가죽 책, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 와인의 단맛 뒤로 고급 시가 박스의 우디한 향, 에스프레소의 잔향과 마지막까지 남는 따뜻한 베이킹 스파이스의 잔향이 끝없이 지속됩니다."}}' WHERE id = 135;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (136, '글렌모렌지 X', 'single_malt', 'Glenmorangie Whisky', 'whiskey/110861.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie X 70cl', 54895, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-x-whisky/?sku=110861', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 X(X by Glenmorangie)는 전 세계 바텐더들과 홈텐딩 애호가들이 하이볼이나 칵테일을 가장 화려하고 가성비 좋게 믹싱할 수 있도록 증류소에서 파격적으로 설계하여 출시한 현대적인 뉴에이지 싱글 몰트 위스키입니다. 40% 도수로 병입되며 믹싱 시 다른 음료의 풍미를 해치지 않으면서도 글렌모렌지 고유의 화사함을 선사합니다.", "제조 및 숙성": "증류소의 전설적인 마스터 블렌더 빌 럼스던 박사가 믹싱에 최적화된 여러 연산의 원액을 정교하게 조합했습니다. 주로 퍼스트 필 버번 배럴에서 숙성된 원액과 안쪽을 강렬하게 태운 뉴 아메리칸 오크 캐스크 원액을 블렌딩하여 단맛을 극대화했습니다."}, "feature": {"칵테일 전용 싱글 몰트": "전통적인 니트 시음 방식을 넘어 하이볼이나 진저에일, 콜라 등 다양한 음료와의 가볍고 경쾌한 믹싱을 위해 기획되었습니다.", "뉴 버진 오크의 화려함": "안쪽을 깊게 그을린 새 오크통의 영향력 덕분에 짧은 연산 속에서도 캐러멜과 바닐라 본연의 직관적인 단맛을 확보했습니다.", "현대적이고 감각적인 디자인": "기존의 정형화된 보틀 레이블에서 탈피하여 감각적인 문자 디자인과 패키지로 젊은 세대의 홈파티 감성을 타겟팅했습니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 밝은 바닐라 포드와 부드러운 꿀, 구운 토스트의 고소함이 먼저 퍼집니다. 뒤이어 상큼한 레몬 제스트, 파인애플 같은 열대 과일의 아로마와 상큼한 청사과의 시트러스 향이 가볍고 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 부드러운 캐러멜 토피, 설탕 시럽을 바른 과일 타르트의 풍미가 느껴지며 뒤이어 오크통에서 배어 나온 가벼운 계피, 화이트 페퍼의 부드러운 오크 스파이스가 혀를 부드럽게 감싸 안습니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 산뜻하고 온화하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 136;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (137, '글렌모렌지 트리플 캐스크 리저브', 'single_malt', 'Glenmorangie Whisky', 'whiskey/142560.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie Triple Cask Reserve 70cl', 56266, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-triple-cask-reserve-whisky/?sku=142560', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 트리플 캐스크 리저브(Glenmorangie Triple Cask Reserve)는 세 종류의 다른 오크통 풍미를 정교하게 결합하여, 증류소 하우스 스타일의 화사함과 깊이감을 동시에 극대화해 출시한 논에이징 프리미엄 싱글 몰트 위스키입니다. 40% 도수 안에서 완벽한 육각형의 대중적인 밸런스를 자랑합니다.", "제조 및 숙성": "전통적인 버번 캐스크에서 숙성된 원액, 아메리칸 뉴 오크 캐스크 원액, 그리고 유러피안 오크 오로로소 셰리 캐스크에서 숙성된 고품질 원액들을 마스터 블렌더의 황금 비율로 결합하여 대형 오크통에서 정교한 매링 공정을 거쳐 완성했습니다."}, "feature": {"삼중 캐스크의 복합 레이어": "버번의 바닐라, 셰리의 과일 맛, 버진 오크의 강력한 탄닌과 스파이스가 완벽한 삼위일체의 균형을 이룹니다.", "진화한 엔트리 표준": "기존 정규 제품보다 오크통의 영향력이 대폭 증가하여 한층 더 묵직하고 직관적인 단맛의 타격감을 선사합니다.", "훌륭한 데일리 가성비": "부담 없는 질감 속에서 스페이사이드 전통 싱글 몰트 고유의 세련된 과수원 과일 아로마를 가성비 좋게 경험할 수 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 신선한 꿀의 달콤함이 먼저 코를 반깁니다. 그 뒤를 이어 은은하게 깔리는 바닐라 크림 고유의 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "부드럽고 가볍게 입안을 감싸 안는 질감입니다. 벌꿀 집의 달콤함과 잘 익은 노란 사과의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 따뜻한 바닐라와 가벼운 생강 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 은은한 나무의 풍미와 캐러멜의 달콤함이 서서히 가라앉으며 입안에 향긋하게 머무는 감미로운 보리의 흔적이 산뜻하게 마무리됩니다."}}' WHERE id = 137;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (138, '글렌모렌지 10년', 'single_malt', 'Glenmorangie Whisky', 'whiskey/2130.jpg', 40.0, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 10 Year Old - The Original 70cl', 68056, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-10-year-old-the-original-whisky/?sku=2130', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 10년(Glenmorangie 10 Year Old The Original)은 싱글 몰트 위스키 세계에서 스탠다드 버번 캐스크 숙성의 절대적인 기준이자 증류소 고유의 헤리티지를 대변하는 가장 핵심적이고 위대한 웰컴 보틀입니다. 스코틀랜드에서 가장 목이 긴 증류기가 선사하는 맑은 청량감을 40% 도수 안에서 가장 정석적으로 뿜어냅니다.", "제조 및 숙성": "미국 켄터키주에서 공수한 최고급 퍼스트 필 및 세컨드 필 아메리칸 화이트 오크 버번 배럴에서 최소 10년 동안 안정적으로 숙성시켰습니다. 인공 색소를 전혀 넣지 않고 오크통 내부에서 우러나온 자연스러운 밝은 레몬 빛깔의 내추럴 컬러를 자랑합니다."}, "feature": {"싱글 몰트의 입문 교과서": "화사한 꽃향기와 시트러스, 부드러운 단맛의 삼박자가 가장 모범적으로 짜여 있어 전 세계 위스키 시장의 표준으로 통합니다.", "가장 높은 구리 증류기": "성인 기린의 키와 맞먹는 독보적인 높은 증류기를 고수하여 스피릿 내부의 거칠고 무거운 성분을 완벽히 정제해 냈습니다.", "순수한 내추럴 크래프트": "색소 첨가나 냉각 여과 공정을 배제하여 밝은 빛깔 속에 숨겨진 원액 본연의 진하고 부드러운 텍스처를 완성했습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 우아한 아로마가 피어오릅니다. 향긋한 수풀 내음과 달콤한 꿀, 바닐라 포드의 향 뒤로 신선한 서양 배, 오렌지의 시트러스와 은은한 오크통의 세련된 나무 향이 기품 있게 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 매끄럽고 크리미합니다. 부드러운 캐러멜 토피, 설탕 시럽을 바른 과일 타르트의 풍미가 퍼지고 뒤이어 오크통에서 배어 나온 가벼운 계피, 시트러스 오일과 은은한 생강 스파이스가 훌륭한 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 산뜻하고 온화하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 138;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (139, '글렌모렌지 시그넷 리저브', 'single_malt', 'Glenmorangie Whisky', 'whiskey/136222.jpg', 46.0, 0, 'active', NOW(), NOW(), 'Scotland', 'Sherry', 700.0, 'Glenmorangie Signet Reserve 70cl', 569687, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-signet-reserve-whisky/?sku=136222', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 시그넷 리저브(Glenmorangie Signet Reserve)는 에스프레소 초콜릿 몰트의 신화를 이룩한 오리지널 시그넷 제품에 한층 더 귀중하고 오래된 장기 숙성 원액의 중후함을 엮어내어 소량 한정 출시한 최상위 하이엔드 익스프레션입니다. 46% 도수로 병입되어 강력하면서도 극상의 기품을 뿜어냅니다.", "제조 및 숙성": "증류소 창고 가장 깊은 곳 비밀 보관소에서 빌 럼스던 박사가 직접 선별했습니다. 초콜릿 로스팅 맥아 스피릿을 기반으로 삼고, 자사 최고급 뉴 아메리칸 오크 디자이너 캐스크와 명품 오로로소 셰리 부트에서 수십 년간 세월을 버텨온 초고연산 희귀 원액들을 황금 비율로 블렌딩했습니다."}, "feature": {"초콜릿 몰트의 진화": "오리지널 시그넷 특유의 에스프레소, 다크 초콜릿 캐릭터 기저 위에 초고연산 셰리 원액의 무화과 잼 풍미를 진하게 더했습니다.", "한정판의 독보적 희소성": "매우 한정된 오크통 세팅 안에서 극소량만 배치 형태로 생산되어 출시될 때마다 전 세계 위스키 수집가들의 표적이 됩니다.", "결점 없는 삼위일체": "로스팅 맥아의 쌉싸름함, 버번의 크리미함, 셰리의 녹진함이 완벽한 대칭과 균형을 이룬 하이엔드 마스터피스입니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 묵직한 아로마입니다. 짙은 에스프레소 샷, 말린 무화과, 건포도, 달콤한 흑설탕 시럽의 단향이 먼저 코를 감쌉니다. 뒤이어 구운 캐슈넛의 고소함, 오래된 가죽, 시가 박스의 우디함과 바닐라 빈의 향이 하모니를 이룹니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 서서히 가라앉으며 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 139;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (140, '글렌모렌지 어코드 12년', 'single_malt', 'Glenmorangie Whisky', 'whiskey/105676.jpg', 43.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenmorangie The Accord 12 Year Old 100cl', 119226, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-accord-12-year-old-whisky/?sku=105676', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 어코드 12년(Glenmorangie The Accord 12 Year Old)은 주로 면세점 시장을 타겟으로 하여, 두 가지 다른 오크통의 완벽한 조화(Accord)를 전면에 내세운 프리미엄 싱글 몰트 위스키입니다. 하우스 스타일의 화사함에 셰리의 단맛을 가미하여 43% 도수 속에서 풍성한 마우스필을 자랑합니다.", "제조 및 숙성": "증류소 마스터 블렌더의 정밀한 선별 아래 최고급 아메리칸 화이트 오크 버번 배럴에서 최소 12년 동안 숙성된 원액과 최고급 유러피안 오크 오로로소 셰리 캐스크에서 12년을 온전히 보낸 원액들을 정교한 비율로 결합하여 매링 과정을 거쳤습니다."}, "feature": {"더블 오크의 하모니": "버번의 바닐라와 셰리의 묵직한 과일 맛이 한 보틀 안에서 기적 같은 대칭과 평형의 균형을 이루도록 설계되었습니다.", "면세점 전용의 매력": "여행자들을 위해 기획된 세련된 패키지 디자인과 함께 글렌모렌지 본연의 밝고 싱그러운 아로마를 데일리로 즐기기에 최적화되었습니다.", "실키한 질감과 바디감": "43%의 탄탄한 알코올 볼륨감 덕분에 12년 숙성 셰리 원액 특유의 촘촘한 풍미 레이어가 흐트러지지 않고 직관적으로 전해집니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 가을철 과수원 아로마가 피어오릅니다. 잘 익은 서양 배, 청사과의 시트러스와 달콤한 캐러멜 토피 향이 먼저 코를 반깁니다. 뒤이어 상큼한 말린 오렌지 껍질และ 은은한 계피, 삼나무의 부드러운 나무 향이 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 훌륭한 질감이 돋보입니다. 벌꿀 집의 단맛과 다크 초콜릿, 말린 살구의 풍미가 중심을 잡고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 나무 잔향이 길게 이어집니다. 오크통에서 배어 나온 부드러운 바닐라의 흔적과 건조한 오크의 우디함, 그리고 마지막에 남는 가벼운 향신료의 여운이 기분 좋고 묵직하게 정돈해 주며 마무리됩니다."}}' WHERE id = 140;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (141, '글렌모렌지 16년 더 트리뷰트', 'single_malt', 'Glenmorangie Whisky', 'whiskey/105677.jpg', 43.0, 16, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenmorangie 16 Year Old The Tribute 100cl', 170396, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-tribute-16-year-old-whisky/?sku=105677', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 16년 더 트리뷰트(Glenmorangie 16 Year Old The Tribute)는 면세점(Travel Retail) 한정판으로 출시되어 증류소 고유의 화사함에 은은한 피트 스모크를 가미한 독창적인 싱글 몰트 위스키입니다. 과거 오크니 섬의 전통적인 제맥 방식을 오마주하여 43% 도수 속에서 기품 있는 밸런스를 자랑합니다.", "제조 및 숙성": "최상급 아메리칸 화이트 오크 버번 배럴에서 16년 동안 장기 숙성되었습니다. 스코틀랜드 하이랜드 지역의 헤더 피트 연기로 가볍게 훈연한 보리 원액을 일부 매링하여, 기존 논피트 스타일 위스키보다 한층 입체적이고 다채로운 풍미 레이어를 완성했습니다."}, "feature": {"은은한 피트의 매력": "글렌모렌지 특유의 싱그러운 과일 맛 기저 위에 은은하고 향긋한 캠프파이어 연기 향이 스치듯 자아냅니다.", "16년 숙성의 깊이감": "장기 숙성을 거쳐 날카로운 알코올의 타격감은 완전히 가라앉고 실크처럼 매끄러운 텍스처를 구현했습니다.", "면세점 전용의 희소성": "글로벌 여행자들을 위해 차별화된 피트 아로마 프로파일로 기획되어 애호가들의 소장 욕구를 자극합니다."}}', note = '{"note": {"향 (Nose)": "화사한 바닐라 크림과 부드러운 꿀 향 뒤로 싱그럽고 노란 자두, 서양 배의 시트러스가 퍼집니다. 그 밑바닥에 아주 연한 장작 연기와 흙내음 섞인 피트 스모크 향이 감미롭게 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 크리미하고 매끄럽습니다. 캐러멜 토피와 밀크 초콜릿, 졸인 황도 복숭아의 단맛이 중심을 잡고 구운 생강, 화이트 페퍼의 가벼운 오크 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "온화하고 깔끔한 우디 피날레를 보여줍니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛이 가라앉으며, 입안에 향긋하게 머무는 드라이한 스모크의 흔적이 부드럽게 마무리됩니다."}}' WHERE id = 141;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (142, '글렌모렌지 12년 라산타', 'single_malt', 'Glenmorangie Whisky', 'whiskey/37185.jpg', 43.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 12 Year Old The Lasanta 70cl', 81872, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-lasanta-12-year-old-whisky/?sku=37185', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 12년 라산타(Glenmorangie 12 Year Old Lasanta)는 게일어로 \'따뜻함과 열정\'을 뜻하는 이름에 걸맞게, 기품 있고 진득한 셰리 오크통의 풍미가 돋보이는 대표적인 정규 라인업 싱글 몰트 위스키입니다. 43% 도수 안에서 완벽한 육각형의 대중적인 밸런스를 자랑합니다.", "제조 및 숙성": "스코틀랜드에서 가장 높은 구리 증류기에서 맑게 뽑아낸 스피릿을 퍼스트 필 및 세컨드 필 버번 배럴에서 최초 10년 동안 안정적으로 숙성시켰습니다. 이후 최고급 스페니시 오로로소 셰리 캐스크와 페드로 히메네스 셰리 캐스크로 옮겨 담아 최종 2년간 정교한 더블 피니시 숙성을 거쳤습니다."}, "feature": {"더블 셰리 피니시": "올로로소의 중후한 타닌과 페드로 히메네스의 녹진한 단맛이 완벽한 평형과 대칭을 이루도록 설계되었습니다.", "따뜻하고 감미로운 성향": "글렌모렌지 고유의 화사함 위에 건포도, 무화과, 토피 당의 진한 단맛을 입혀 입문자들에게 인기가 높습니다.", "내추럴 골드 퀄리티": "오크통 나무 내부에서 우러나온 자연스러운 진한 호박색과 농밀하게 감싸 안는 탁월한 마우스필을 완성했습니다."}}', note = '{"note": {"향 (Nose)": "진한 캐러멜 토피와 럼에 절인 건포도, 말린 무화과의 단향이 묵직하게 다가옵니다. 뒤이어 상큼한 말린 오렌지 껍질과 은은한 계피 가루, 구운 아몬드의 고소한 아로마가 우아하게 어우러집니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 질감이 특징입니다. 벌꿀 집의 단맛과 다크 초콜릿, 졸인 황도 복숭아의 풍미가 전개되고 시나몬, 구운 생강의 알싸한 오크 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 길게 이어집니다. 말린 과일의 단맛과 에스프레소의 흔적이 가라앉으며, 입안 가득 기품 있는 구운 오크의 우디함과 따뜻한 베이킹 스파이스의 잔향이 남습니다."}}' WHERE id = 142;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (143, '글렌모렌지 19년 파이니스트 리버스', 'single_malt', 'Glenmorangie Whisky', 'whiskey/86654.jpg', 43.0, 19, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Glenmorangie 19 Year Old Finest Reserve 70cl', 339421, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-19-year-old-finest-reserve-whisky/?sku=86654', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 19년 파이니스트 리버스(Glenmorangie 19 Year Old Finest Reserve)는 주로 면세점 시장을 타겟으로 소량 한정 출시되어 증류소가 자랑하는 버번 캐스크 장기 숙성의 정수를 보여주는 프리미엄 싱글 몰트 위스키입니다. 43% 도수 속에서 결점 없는 세련미를 뿜어냅니다.", "제조 및 숙성": "마스터 블렌더 빌 럼스던 박사가 최고급 품질을 지닌 퍼스트 필 아메리칸 화이트 오크 버번 배럴만을 엄선했습니다. 19년이라는 장구한 시간 동안 오크통과 원액이 온전히 교감하며 나무의 성분을 정교하게 흡수하여 짙은 황금빛 자태를 완성했습니다."}, "feature": {"버번 캐스크 숙성의 정점": "셰리나 와인 캐스크의 간섭 없이 오직 최고급 아메리칸 오크통이 전하는 순수한 바닐라와 코코넛의 정수를 보여줍니다.", "시간이 공들인 부드러움": "19년의 장기 숙성 과정을 거쳐 날카로운 알코올 부즈는 완벽히 정제되고 극상의 실키한 질감만 남았습니다.", "노블 크래프트 퀄리티": "글렌모렌지 특유의 기린 목처럼 높은 증류기가 자아내는 맑은 에스테르와 장기 숙성미가 고귀한 구조감을 전합니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 갓 구운 바닐라 포드, 부드러운 꿀, 메이플 시럽 향 뒤로 신선한 청사과, 서양 배, 싱그러운 레몬 블러썸의 시트러스 아로마가 우아하고 복합적으로 피어오릅니다.", "맛 (Palate)": "실크나 벨벳처럼 부드럽고 묵직한 질감이 입안을 코팅합니다. 진한 밤꿀과 구운 마시멜로, 졸인 황도 복숭아의 단맛이 중심을 잡고 은은한 코코넛 풍미와 계피, 구운 생강의 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 오크통에서 배어 나온 부드러운 캐러멜의 단맛과 드라이한 나무 향, 그리고 마지막에 남는 미세한 오렌지 오일의 잔향이 산뜻하게 마무리됩니다."}}' WHERE id = 143;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (144, '글렌모렌지 두탁', 'single_malt', 'Glenmorangie Whisky', 'whiskey/42590.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenmorangie The Duthac 100cl', 136869, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-duthac-whisky/?sku=42590', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 두탁(Glenmorangie Duthac)은 면세점 전용으로 기획된 레전드 컬렉션(Legends Collection)의 첫 번째 명작으로, 13세기 스코틀랜드의 성인 \'성 두탁(Saint Duthac)\'의 유산과 전설에서 영감을 얻은 싱글 몰트 위스키입니다. 43% 도수로 병입되며 묵직하고 향긋한 풍미를 선사합니다.", "제조 및 숙성": "전통적인 아메리칸 오크 버번 배럴에서 숙성되어 부드러운 바닐라 향을 확보한 원액을 주축으로 삼습니다. 이후 마스터 블렌더의 정밀한 감각에 따라 최고급 페드로 히메네스 셰리 캐스크와 처녀 아메리칸 버진 오크 캐스크에서 정교하게 피니시 숙성 및 결합했습니다."}, "feature": {"레전드 컬렉션의 서막": "오크니 섬과 하이랜드 지역의 역사적 인물인 성 두탁의 영혼과 용맹함을 보틀 디자인과 풍미에 투영했습니다.", "PX 셰리와 버진 오크의 하모니": "가장 달콤한 PX 와인 오크통의 녹진함과 뉴 버진 오크 특유의 알싸한 후추 스파이스가 대담하게 결합되었습니다.", "다채로운 구조감": "단맛, 매운맛, 우디함의 레이어가 촘촘하고 단단하게 짜여 있어 매 모금마다 역동적인 타격감을 전합니다."}}', note = '{"note": {"향 (Nose)": "강렬하고 달콤한 캐러멜 토피와 진한 흑설탕, 말린 무화과의 단향이 코를 가득 채웁니다. 뒤이어 구운 마시멜로, 버진 오크 특유의 묵직한 가죽 향과 매콤한 베이킹 향신료 아로마가 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 훌륭한 텍스처입니다. 다크 초콜릿, 무화과 잼, 토피 시럽의 진한 단맛이 파도처럼 밀려오고 으깬 통후추, 시나몬 가루, 구운 생강의 알싸한 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 묵직하게 남습니다. 구운 오크의 우디한 향과 바닐라 캐러멜의 단맛이 서서히 가라앉으며, 입안에 기분 좋은 드라이함과 따뜻한 계피의 미련이 인상적인 피날레를 장식합니다."}}' WHERE id = 144;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (145, '글렌모렌지 테인', 'single_malt', 'Glenmorangie Whisky', 'whiskey/54634.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenmorangie The Tayne 100cl', 136358, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-tayne-whisky/?sku=54634', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 테인(Glenmorangie Tayne)은 주로 글로벌 면세 시장을 겨냥해 출시된 레전드 컬렉션 중 하나로, 증류소가 위치한 스코틀랜드 하이랜드의 아름다운 도스만 \'테인(Tayne)\' 만의 풍경과 해상 전설을 오마주한 싱글 몰트 위스키입니다. 43% 도수 속에서 이국적인 스파이시 밸런스를 뽐냅니다.", "제조 및 숙성": "증류소 고유의 맑은 스피릿을 버번 배럴에서 숙성시킨 후, 싱글 몰트 세계에서 흔치 않은 스페인의 진귀한 최고급 아마론티파도 셰리 캐스크(Amontillado Sherry Casks)로 원액을 옮겨 담아 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"아몬티야도 캐스크의 변주": "일반적인 올로소 숙성과 결이 다른, 견과류의 너티함과 건조하고 산뜻한 단맛을 확보하여 이색적인 스펙트럼을 넓혔습니다.", "테인 만의 정취 형상화": "해안가의 짭조름한 바닷바람 뉘앙스와 스파이시함이 와인 캐스크의 단맛과 입안에서 조화롭게 충돌합니다.", "세련된 데일리 밸런스": "부담 없는 바디감 속에서 견과류의 고소함과 시트러스 오일이 부드러운 하모니를 이루어 편안하게 즐기기 좋습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 독창적인 아로마입니다. 구운 아몬드, 피칸의 고소한 너티 향 뒤로 신선한 청사과, 오렌지 껍질의 시트러스와 은은하게 깔리는 달콤한 밤꿀, 장미 꽃잎의 아로마가 조화롭게 피어오릅니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 달콤한 토피 당과 밀크 초콜릿, 설탕 시럽을 바른 과일 타르트의 풍미가 느껴지며 아몬티야도 캐스크 특유의 쌉싸름한 오렌지 제스트와 화이트 페퍼의 가벼운 스파이스가 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 드라이 잔향을 남깁니다. 오크통에서 배어 나온 부드러운 바닐라의 단맛과 가벼운 생강 스파이스의 흔적이 입안을 산뜻하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 145;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (146, '글렌모렌지 캐드볼', 'single_malt', 'Glenmorangie Whisky', 'whiskey/76709.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Glenmorangie The Cadboll 100cl', 159323, 'https://www.masterofmalt.com/whiskies/glenmorangie/glenmorangie-the-cadboll-whisky/?sku=76709', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "글렌모렌지 캐드볼(Glenmorangie Cadboll Estate)은 증류소가 소유한 청정 캐드볼 영지(Cadboll Estate)에서 직접 재배한 보리만을 사용하여 \'떼루아(Terroir)\'의 정수를 담아낸 프리미엄 한정판 싱글 몰트 위스키입니다. 싱그러운 하우스 스타일에 대지의 깊은 영양을 입혀 43% 도수 속에서 정교한 완성도를 보여줍니다.", "제조 및 숙성": "영지에서 수확한 단일 농장 보리(Single Estate Barley)로 증류한 스피릿을 최고급 퍼스트 필 아메리칸 화이트 오크 버번 배럴에서 숙성시켰습니다. 오크통의 과한 간섭 대신 보리 고유의 크리미함과 맥아의 진한 단맛을 가장 온전하게 보존해 냈습니다."}, "feature": {"100% 싱글 에스테이트": "보리 재배부터 증류, 숙성까지 모든 과정이 단 하나의 영지와 증류소 내부 테두리 안에서 통제된 진정한 크래프트 위스키입니다.", "버번 배럴의 화사함": "최고급 버번 오크통 숙성을 통해 버터스카치, 코코넛 고유의 달콤함과 부드러운 바닐라를 극대화했습니다.", "크리미하고 리치한 바디": "일반 오리지널 제품보다 훨씬 진득하고 농밀하게 혀를 코팅하는 독보적인 마우스필과 구조감을 완성했습니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 리치한 캐러멜 토피와 바닐라 포드, 메이플 시럽의 향이 코를 가득 채웁니다. 뒤이어 상큼한 레몬 껍질, 신선한 청사과 고유의 과일 아로마와 구운 토스트의 고소함이 조화롭고 입체적으로 피어오릅니다.", "맛 (Palate)": "입안을 실크처럼 매끄럽고 크리미하게 감싸 안는 텍스처가 일품입니다. 진한 밤꿀และ 버터스카치, 달콤한 밤잼의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 부드러운 우디함과 계피, 화이트 페퍼의 가벼운 스파이스가 전개됩니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향이 길게 이어집니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소한 잔향이 입안을 산뜻하고 온화하게 정돈해 주며 온화하게 마무리됩니다."}}' WHERE id = 146;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (147, '히비키 21년', 'blended', 'Hibiki Whisky Distillery', 'whiskey/9466.jpg', 43.0, 21, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Hibiki 21 Year Old 70cl', 1279252, 'https://www.masterofmalt.com/whiskies/hibiki/hibiki-21-year-old-whisky/?sku=9466', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "히비키 21년(Hibiki 21 Year Old)은 일본 산토리 장 장인들의 블렌딩 미학이 정점에 도달한 세계 최고봉의 프리미엄 블렌디드 위스키입니다. 전 세계 유명 주류 품평회에서 \'세계 최고의 블렌디드 위스키\' 상을 수없이 휩쓸며 그 고결한 가치를 인정받았으며, 43% 도수 속에서 차원이 다른 세련미를 뿜어냅니다.", "제조 및 숙성": "야마자키와 하쿠슈 증류소의 21년 이상 장기 숙성된 희귀 싱글 몰트 원액들과, 치타 증류소의 중후한 헤비 그레인 위스키 원액들을 정밀하게 블렌딩했습니다. 특히 산토리의 시그니처인 일본산 미즈나라(Mizunara) 오크통과 최고급 셰리 캐스크 원액이 주축을 이룹니다."}, "feature": {"블렌딩의 마스터피스": "수십 가지의 진귀한 원액들이 어느 한쪽으로 치우치지 않고 완벽한 평형과 조화를 이루는 블렌딩 예술의 결정체입니다.", "미즈나라 오크의 영혼": "일본산 백참나무 캐스크 숙성을 통해 특유의 은은한 사찰 향, 백단향, 침향 고유의 오리엔탈 아우라를 선사합니다.", "24면체 디켄터의 기품": "일본의 전통 24절기를 상징하는 24면 커팅 크리스탈 디켄터 보틀에 담겨 위스키 컬렉터들 사이에서 평생의 드림 보틀로 통합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 우아한 아로마입니다. 말린 자두, 건포도, 달콤한 대추야자의 묵직한 단향 뒤로 미즈나라 오크 특유의 기품 있는 향당 향, 백단향의 오리엔탈 향이 피어오르고 잘 익은 자스민의 화사함이 어우러집니다.", "맛 (Palate)": "벨벳이나 실크를 혀에 얹은 듯 극도로 부드럽고 농밀한 질감이 압권입니다. 진한 밤꿀과 다크 초콜릿, 오렌지 마멀레이드의 달콤함이 기품 있게 전개되며 은은한 오크통의 시나몬 스파이스와 구운 피칸의 고소함이 조화를 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 감미로운 여운을 선사합니다. 농축된 와인의 단맛과 미즈나라 나무 고유의 향긋함, 에스프레소의 잔향 뒤로 가슴 속까지 따뜻해지는 우아한 스파이스의 흔적이 영원처럼 머눕니다."}}' WHERE id = 147;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (148, '히비키 30년', 'blended', 'Hibiki Whisky Distillery', 'whiskey/6660.jpg', 43.0, 30, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Hibiki 30 Year Old 70cl', 8519823, 'https://www.masterofmalt.com/whiskies/hibiki/hibiki-30-year-old-whisky/?sku=6660', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "히비키 30년(Hibiki 30 Year Old)은 산토리 위스키 가문이 보유한 가장 최고연산 원액들 중 극상의 정수만을 모아 소량 한정 생산하는 최상위 하이엔드 마스터피스 주류입니다. 거의 한 세대의 세월에 달하는 30년의 시간 동안 천천히 정제된 고귀한 영혼을 품고 있으며 43% 도수 안에서 인간이 도달할 수 있는 블렌딩 위스키의 종착점을 보여줍니다.", "제조 및 숙성": "산토리 장인들이 증류소 깊숙한 곳에서 무려 30년 이상 고독하게 세월을 버텨온 희귀한 유러피안 셰리 캐스크 몰트 원액과 미즈나라 오크통 몰트 원액, 그리고 장기 숙성된 진귀한 그레인 위스키 원액을 정밀 감별했습니다. 이를 수작업으로 정교하게 매링하여 병입했습니다."}, "feature": {"산토리 가문의 플래그십": "히비키 정규 라인업 중 가장 높은 연산에 속하는 고귀한 마스터피스로서 매년 극소량만 발매되어 천문학적인 가치를 가집니다.", "시간이 빚은 완벽함": "30년의 세월 동안 나무의 타닌과 스피릿이 만나 거칠고 매운 맛은 완전히 사라지고 극상의 실키함과 중후한 깊이감만 남았습니다.", "박물관급 소장 가치": "정교한 30면 커팅 고급 디켄터 보틀과 일본 전통 수제 종이인 에치젠 와시 레이블로 래핑되어 최고의 권위를 자랑합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 마호가니 가구, 졸인 자두, 무화과 잼의 농축된 향이 깊게 퍼지고 뒤이어 고급스러운 미즈나라 향당 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처지가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 미즈나라 나무 고유의 향긋한 풍미가 가라앉으며, 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 148;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (149, '히비키 재패니즈 하모니', 'blended', 'Hibiki Whisky Distillery', 'whiskey/43528.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Hibiki Japanese Harmony 70cl', 127925, 'https://www.masterofmalt.com/whiskies/hibiki/hibiki-japanese-harmony-whisky/?sku=43528', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "히비키 재패니즈 하모니(Hibiki Japanese Harmony)는 산토리 위스키가 지향하는 \'자연과 인간의 조화\'를 현대적이고 감각적인 아로마로 풀어낸 글로벌 시그니처 블렌디드 위스키입니다. 연산을 표기하지 않은 NAS 제품이지만 43% 도수 속에서 입안을 화사하게 가득 채우는 독보적인 대중성으로 전 세계적인 인기를 구가하고 있습니다.", "제조 및 숙성": "야마자키, 하쿠슈, 치타 증류소에서 엄선된 10종 이상의 몰트 및 그레인 위스키 원액을 정교하게 블렌딩했습니다. 원액은 아메리칸 화이트 오크 버번 캐스크를 중심으로 스페니시 오크 셰리 캐스크, 그리고 진귀한 미즈나라 오크통에서 숙성된 원액들이 절묘한 하모니를 이룹니다."}, "feature": {"자연과 인간의 조화": "산토리 특유의 부드럽고 투명한 하우스 스타일에 화사한 꽃향기를 주축으로 삼아 완벽한 육각형의 균형을 구현했습니다.", "미즈나라 터치의 대중화": "고연산 제품에서만 느낄 수 있던 일본 특산 미즈나라 오크 특유의 향당 향 레이어를 대중적인 가격대에서 기분 좋게 선사합니다.", "예술적인 24면체 디자인": "일본의 전통 24절기를 뜻하는 기하학적인 보틀 디자인 덕분에 선물용이나 홈바 디스플레이 목적으로 전 세계적인 인기를 끕니다."}}', note = '{"note": {"향 (Nose)": "화사하고 싱그럽습니다. 갓 피어난 자스민, 장미 꽃잎의 플로럴 아로마와 싱그러운 청사과, 서양 배의 시트러스가 올라옵니다. 그 기저에는 꿀을 바른 구운 토스트와 미즈나라 오크 고유의 은은한 향당 향이 받쳐줍니다.", "맛 (Palate)": "입안을 매끄럽고 맑게 감싸 안는 실키한 질감이 돋보입니다. 졸인 황도 복숭아, 오렌지 마멀레이드, 캐러멜 시럽의 단맛이 퍼지고 뒤이어 오크통 특유의 가벼운 화이트 페퍼와 따뜻한 생강의 맛이 정교한 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 긴 우아한 여운을 남깁니다. 바닐라의 달콤함과 미즈나라 나무 캐스크 고유의 상큼한 과일 향이 가라앉으며 입안에 기분 좋은 드라이함과 우디한 스파이스의 흔적을 산뜻하게 남기며 가라앉습니다."}}' WHERE id = 149;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (150, '히비키 블렌더스 초이스', 'blended', 'Hibiki Whisky Distillery', 'whiskey/118406.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Hibiki Blender\'s Choice 70cl', 426410, 'https://www.masterofmalt.com/whiskies/hibiki/hibiki-blenders-choice-whisky/?sku=118406', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "히비키 블렌더스 초이스(Hibiki Blender\'s Choice)는 산토리의 전설적인 12년 제품이 단종된 후, 마스터 블렌더의 정밀한 안목 및 창의적인 캐스크 조합을 통해 그 명성을 잇고자 출시된 프리미엄 럭셔리 블렌디드 위스키입니다. 연산을 표기하지 않는 대신 와인 캐스크 고유의 매혹적인 옷을 입혀 43% 도수 속에서 풍성한 밀도감을 전합니다.", "제조 및 숙성": "평균 15년 이상 숙성된 고품질 몰트 위스키와 그레인 위스키 원액을 베이스로 삼습니다. 블렌딩 원액의 일부를 엄선된 최고급 와인 오크 캐스크에서 피니시 숙성시켜, 기존 하모니 제품보다 훨씬 진득하고 녹진한 베리류의 단맛과 둥근 마우스필을 완성했습니다."}, "feature": {"블렌더의 영리한 선택": "숙성 연수 제한에서 벗어나 마스터 블렌더가 오직 맛과 풍미의 밀도만을 기준으로 원액을 자유롭게 선택해 결합했습니다.", "와인 캐스크의 매혹적인 옷": "산토리 가문의 와이너리 노하우가 집약된 오크통 숙성을 가미하여 독창적이고 상큼한 포도즙의 단맛을 확보했습니다.", "진해진 중후함과 레이어": "재패니즈 하모니 제품보다 훨씬 높은 연산의 원액 비율을 가져가 알코올의 튀는 맛이 없고 풀바디 텍스처가 압권입니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마입니다. 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 가득 퍼집니다. 뒤이어 구운 캐슈넛의 고소함, 미즈나라 오크 고유의 우디함, 그리고 상큼한 말린 오렌지 껍질과 바닐라 빈의 향이 훌륭한 하모니를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 단맛이 파도처럼 밀려오고 뒤이어 와인 캐스크 특유의 상큼한 베리류 풍미와 구운 생강, 육두구의 알싸한 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 달콤한 다크 프루트의 잔향과 미즈나라 나무 고유의 향긋함이 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 여운이 길게 머눕니다."}}' WHERE id = 150;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (151, '잭 다니엘스', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/2666.jpg', 40.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Tennessee Whiskey 70cl', 44251, 'https://www.masterofmalt.com/whiskies/jack-daniels-tennessee-whiskey/?sku=2666', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스(Jack Daniel\'s Old No. 7)는 미국 테네시주에서 생산되는 전 세계에서 가장 상징적이고 많이 판매되는 아메리칸 테네시 위스키의 살아있는 전설입니다. 버번 위스키와 유사한 매시빌을 공유하지만, 독창적인 단풍나무 숯 여과 공정을 거쳐 탄생한 특유의 부드러움과 화사한 바나나 풍미가 특징이며 40% 도수 속에서 변함없는 클래식 엔트리의 위상을 지킵니다.", "제조 및 숙성": "옥수수 80%, 호밀 12%, 몰트 8%의 전통적인 매시빌을 사용하여 증류한 원액을, 숙성 전 3미터 두께의 사탕단풍나무 숯 침전조에 한 방울씩 통과시키는 \'차콜 멜로잉(Charcoal Mellowing)\' 공정을 거칩니다. 이후 안쪽을 강렬하게 그을린 뉴 아메리칸 화이트 오크통에서 최소 4년 이상 장기 숙성됩니다."}, "feature": {"링컨 카운티 프로세스": "단풍나무 숯 여과 과정을 거치며 버번보다 날카로운 알코올 자극이 둥글게 깎여 나가 극상의 실키한 부드러움을 획득합니다.", "아이코닉 바나나 에스테르": "잭 다니엘스 스피릿 고유의 효모 특성 덕분에 갓 익은 바나나, 인공적인 바나나 에센스 계열의 달콤한 향이 전면에 돋보입니다.", "하이볼과 콕의 시초": "콜라와의 조합인 \'잭 콕\'이나 탄산수와 믹싱하는 \'잭 하이볼\' 베이스로서 전 세계 바와 파티 문화의 절대적인 나침반 역할을 합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 바닐라 포드 향 뒤로, 잭 다니엘스 고유의 잘 익은 바나나, 시럽을 듬뿍 바른 아세톤 계열의 시트러스 향이 직관적으로 코를 자극하며 은은한 오크통 그을음 향이 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 가볍고 매끄럽습니다. 흑설탕의 진득한 단맛과 구운 견과류의 고소함, 옥수수 시럽의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 가벼운 계피, 통후추의 스파이시함이 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 달콤한 우디 잔향이 지속됩니다. 오크통 특유의 드라이한 탄닌과 부드러운 캐러멜 흔적, 그리고 은은하게 흩어지는 단풍나무 숯의 옅은 스모키 잔향이 입안을 산뜻하게 정돈해 줍니다."}}' WHERE id = 151;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (152, '잭 다니엘스 시나트라 셀렉트', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/22725.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 1000.0, 'Jack Daniel\'s Sinatra Select', 251593, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-sinatra-select-whiskey/?sku=22725', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 시나트라 셀렉트(Jack Daniel\'s Sinatra Select)는 전설적인 보컬리스트이자 잭 다니엘스의 평생 애호가였던 프랭크 시나트라(Frank Sinatra)에게 헌정하기 위해 장인 정신을 담아 빚어낸 최고급 플래그십 프리미엄 위스키입니다. 일반 제품보다 한층 묵직하고 대담한 타격감을 위해 45% 도수로 정교하게 세팅되었습니다.", "제조 및 숙성": "오직 시나트라 셀렉트만을 위해 특제 제작된 \'시나트라 배럴(Sinatra Barrels)\'에서 숙성되었습니다. 이 오크통은 내부 안쪽에 깊은 가로 홈(Grooves)을 파서 원액과 나무의 물리적 접촉 면적을 극대화했으며, 수년간 테네시의 서늘한 창고 상층부에서 집중적인 호흡 과정을 거쳤습니다."}, "feature": {"프랭크 시나트라의 유산": "시나트라가 무대 위에서 항상 잭 다니엘스를 잔에 채워 마셨던 역사적인 유대감을 기념하여 세련된 전용 패키지와 북클릿으로 품격을 높였습니다.", "시나트라 배럴의 마술": "오크통 내부 홈을 통해 나무 본연의 성분과 천연 나무 설탕이 액체 깊숙이 배어들어 일반 라인업보다 훨씬 짙은 루비 빛깔을 띱니다.", "중후한 대담함과 복합미": "45%의 강력한 알코올 볼륨감 덕분에 농밀한 토피 단맛과 묵직한 오크통의 우디 향이 조화로운 육각형의 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "깊고 고풍스러운 아로마가 가득 퍼집니다. 진한 바닐라 빈, 꿀, 캐러멜 토피 향 뒤로 오래된 시가 박스, 마호가니 나무의 우디 향이 묵직하게 올라오고 잘 익은 바나나와 상큼한 오렌지 껍질의 아로마가 우아하게 얹어집니다.", "맛 (Palate)": "벨벳이나 실크처럼 부드럽고 묵직한 풀바디 질감이 입안을 매끄럽게 코팅합니다. 브라운 슈가, 흑설탕에 졸인 자두의 단맛이 기품 있게 전개되며 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 따뜻한 우디 피날레가 지속됩니다. 진득한 단맛이 가라앉으며 기품 있는 시가 상자의 나무 향, 에스프레소의 잔향과 마지막까지 남는 따뜻한 베이킹 스파이스의 잔향이 끝없이 이어집니다."}}' WHERE id = 152;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (153, '잭 다니엘스 싱글배럴 라이', 'rye', 'Jack Daniel\'s Whiskey', 'whiskey/62581.jpg', 45.0, 4, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Single Barrel Rye 70cl', 94971, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-single-barrel-rye-whisky/?sku=62581', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 싱글배럴 라이(Jack Daniel\'s Single Barrel Rye)는 링컨 카운티 프로세스의 부드러움과 호밀 위스키 특유의 알싸하고 매콤한 스파이시 타격감을 최고 수준으로 끌어올린 하이엔드 프리미엄 위스키입니다. 단 하나의 오크통 독립 원액만을 병입하여 47%의 강력한 도수 속에서 독보적인 복합미를 뿜어냅니다.", "제조 및 숙성": "호밀(Rye) 70%, 옥수수 18%, 몰트 12%의 고함량 호밀 매시빌을 사용하여 증류했으며, 단풍나무 숯 여과 과정을 거친 후 최고급 아메리칸 버진 오크통에 담겼습니다. 증류소 창고 가장 위층(최상단)에서 극심한 온도 변화를 견디며 숙성된 최상급 캐스크 단 한 통의 원액만 선택해 병입합니다."}, "feature": {"70% 호밀의 강력한 파워": "옥수수의 단맛을 줄이고 호밀 고유의 알싸한 풀 내음, 으깬 후추, 허브의 스파이시함을 전면에 내세운 반전 매력의 제품입니다.", "단일 오크통의 희소 가치": "블렌딩 과정이 전혀 없어 오크통 번호와 병입 날짜가 레이블에 수기 명시되며, 매 통마다 미세하게 다른 독립적인 정체성을 탐험할 수 있습니다.", "창고 최상단의 축복": "공기 순환이 가장 거친 상층부 숙성을 통해 알코올 부즈는 완벽히 휘발되고 진한 캐러멜 단맛과 우디함이 화려하게 응축되었습니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 자극하는 신선한 후추, 정향, 생강의 스파이스가 전면에 나섭니다. 이내 호밀 특유의 싱그러운 허브, 민트 향과 함께 기저에 깔리는 진한 캐러멜, 바닐라 포드, 구운 토스트의 달콤한 단 향이 묵직하게 조화를 이룹니다.", "맛 (Palate)": "입안을 진득하게 코팅하는 농밀하고 오일리한 텍스처가 특징입니다. 말린 살구, 졸인 무화과의 과일 단맛이 퍼지고 뒤이어 통후추, 육두구, 시나몬의 강력하고 알싸한 호밀 스파이시함이 혀를 정교하고 파워풀하게 타격합니다.", "여운 (Finish)": "드라이하면서도 가슴 깊은 곳까지 따뜻해지는 극도로 긴 여운입니다. 호밀 특유의 화사한 허브 잔향과 쌉싸름한 카카오, 그리고 구운 오크의 묵직한 나무 풍미가 입안 전체에 오랜 미련을 남기며 지속됩니다."}}' WHERE id = 153;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (154, '잭 다니엘스 젠틀맨 잭', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/3002.jpg', 40.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Gentleman Jack 70cl', 45275, 'https://www.masterofmalt.com/whiskies/jack-daniels/gentleman-jack-whiskey/?sku=3002', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 젠틀맨 잭(Gentleman Jack)은 증류소가 자랑하는 차콜 멜로잉 공정을 극대화하여 위스키가 가질 수 있는 극상의 부드러움과 실키함을 완성해 낸 프리미엄 테네시 위스키입니다. 이름 그대로 신사처럼 온화하고 정제된 자태를 뽐내며 40% 도수 속에서 완벽한 라운드감을 자랑합니다.", "제조 및 숙성": "전통적인 테네시 위스키 제조 방식에 따라 사탕단풍나무 숯 여과를 한 번 거친 원액을 새 오크통에서 숙성시킵니다. 이후 병입 직전 단계에서 다시 한번 거대한 단풍나무 숯 침전조에 통과시키는 이례적인 \'더블 차콜 멜로잉(Double Charcoal Mellowing)\' 공정을 거쳐 탄생합니다."}, "feature": {"더블 멜로잉의 마술": "위스키 역사상 흔치 않게 숙성 전과 숙성 후 총 두 번에 걸쳐 숯 여과를 감행하여 거친 탄닌과 알코올 자극을 완전히 도려냈습니다.", "정제된 신사의 품격": "오리지널 제품 특유의 거친 아세톤 향이나 매운 스파이스가 부드럽게 가라앉아 극상의 편안한 목 넘김을 전합니다.", "크리미한 꿀맛의 기저": "단풍나무 숯에서 배어 나온 은은한 나무 설탕 성분 덕분에 인위적이지 않은 천연 바닐라와 벌꿀 고유의 단맛이 돋보입니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 부드러운 아로마가 코를 살포시 반깁니다. 신선한 바닐라 크림, 달콤한 꿀, 캐러멜 토피 향 뒤로 은은하게 정제된 노란 사과, 청사과의 시트러스와 가벼운 맥아의 고소한 향이 조화롭게 다가옵니다.", "맛 (Palate)": "실크나 비단처럼 매끄럽고 크리미하게 입안을 감싸 안는 마우스필이 일품입니다. 벌꿀 집의 부드러운 단맛과 잘 익은 바나나 풍미가 중심을 잡고 뒤이어 오크통의 은은한 우디함과 가벼운 계피 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 단풍나무 숯 여과 특유의 감미로운 캐러멜 흔적과 부드러운 나무의 풍미가 서서히 가라앉으며 입안을 산뜻하고 깨끗하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 154;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (155, '잭 다니엘스 아메리칸 싱글몰트', 'single_malt', 'Jack Daniel\'s Whiskey', 'whiskey/132710.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 1000.0, 'Jack Daniel\'s American Single Malt 100cl', 230265, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-american-single-malt-whiskey/?sku=132710', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 아메리칸 싱글몰트(Jack Daniel\'s Twice Barreled American Single Malt)는 옥수수 중심의 아메리칸 위스키 전통을 깨부수고, 100% 보리 맥아만을 사용하여 탄생시킨 증류소 역사상 가장 파격적이고 혁신적인 스페셜 프리미엄 위스키입니다. 44% 도수로 병입되어 정교하고 탄탄한 바디감을 자랑합니다.", "제조 및 숙성": "100% 몰트 보리(Malted Barley)만을 사용하여 증류한 원액을 단풍나무 숯 여과 공정을 거쳐 부드럽게 만든 후, 최고급 퍼스트 필 아메리칸 화이트 오크 버번 배럴에서 오랜 세월 숙성시켰습니다. 이후 스페인 최고의 와이너리에서 공수한 최고급 오로로소 셰리 캐스크(Oloroso Sherry Casks)로 옮겨 최종 피니시 숙성을 거쳤습니다."}, "feature": {"아메리칸 몰트의 변주": "전통적인 옥수수 버번 스타일 기저에서 벗어나 스코틀랜드 싱글 몰트와 유사한 맥아 본연의 진하고 깊은 고소함을 이끌어냈습니다.", "트와이스 배럴의 위엄": "최고급 버번 배럴 숙성 후 퍼스트 필 오로로소 셰리통에서 정교한 피니시를 단행하여 짙은 컬러감과 녹진한 다크 크러스트 풍미를 확보했습니다.", "하우스 DNA의 계승": "싱글 몰트 스피릿임에도 잭 다니엘스 고유의 차콜 멜로잉 여과 공정을 고수하여 특유의 실키한 목 넘김과 부드러움을 고스란히 유지했습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 가득 차오르는 아로마입니다. 셰리 캐스크 특유의 말린 무화과, 건포도, 달콤한 흑설탕에 졸인 자두 잼의 단향이 먼저 가득 퍼집니다. 뒤이어 구운 견과류의 고소함, 진한 바닐라 빈, 그리고 싱그러운 애플 블러썸의 향이 훌륭한 하모니를 이룹니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 토피, 토스트한 보리의 진한 단맛이 파도처럼 밀려오고 뒤이어 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 매우 길게 이어집니다. 농축된 셰리의 단맛과 에스프레소의 쌉싸름함이 가라앉으며 입안 가득 기품 있는 시가 박스의 우디한 향과 따뜻한 베이킹 스파이스의 흔적이 짙고 감미롭게 머눕니다."}}' WHERE id = 155;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (156, '잭 다니엘스 싱글배럴', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/2665.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Single Barrel 70cl', 75035, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-single-barrel-whiskey/?sku=2665', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 싱글배럴(Jack Daniel\'s Single Barrel Select)은 증류소 창고의 최상층에서 숙성된 최고급 오크통 단 하나만을 선택하여 병입하는 하이엔드 프리미엄 위스키입니다. 일반 제품보다 높은 45%의 도수로 병입되어 테네시 위스키 고유의 부드러움 속에 강렬하고 농밀한 타격감을 품고 있습니다.", "제조 및 숙성": "수많은 오크통 중 마스터 디스틸러의 정밀한 감별을 통과한 상위 1%의 희귀 캐스크 원액만을 엄선합니다. 기온 변화가 가장 극심한 테네시 창고의 최상단에서 원액이 나무 깊숙이 호흡하며 숙성되었으며, 블렌딩 과정 없이 단일 오크통 그대로 병입됩니다."}, "feature": {"상위 1% 캐스크의 위엄": "다른 오크통과의 결합이 전혀 없어 최고급 아메리칸 버진 오크통이 품고 있는 때 묻지 않은 순수한 아로마를 선사합니다.", "독립적인 정체성": "각 보틀마다 고유의 통 번호, 배럴 위치, 병입 날짜가 명시되어 매 병마다 미세하게 다른 개성을 탐험하는 재미가 있습니다.", "응축된 풍미의 힘": "가혹한 상층부 기후 숙성을 통해 알코올 부즈는 정제되고 캐러멜, 바닐라, 오크통 고유의 깊은 터치가 화려하게 응축되었습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 진한 바닐라 빈과 달콤한 캐러멜 토피 향이 직관적으로 피어오릅니다. 뒤이어 상큼한 말린 오렌지 껍질, 잘 익은 바나나의 향과 함께 뉴 아메리칸 오크 특유의 묵직한 가죽 향이 레이어를 이룹니다.", "맛 (Palate)": "크리미하고 묵직하게 입안을 코팅하는 마우스필이 일품입니다. 브라운 슈가, 꿀을 가득 머금은 밀크 초콜릿, 졸인 황도 복숭아의 단맛이 퍼지고 알싸한 블랙페퍼와 따뜻한 생강의 우드 스파이스가 혀를 정교하게 타격합니다.", "여운 (Finish)": "온화하고 풍부한 잔향이 매우 길게 이어집니다. 버진 오크 캐스크 특유의 진한 바닐라 단맛과 시가 박스의 우디한 향, 따뜻한 계피 스파이스의 흔적이 입안을 묵직하게 채우며 마무리됩니다."}}' WHERE id = 156;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (157, '잭 다니엘스 본디드', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/118402.jpg', 50.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel’s Bonded 70cl', 68567, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-bonded-whiskey/?sku=118402', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 본디드(Jack Daniel\'s Bonded)는 1897년 제정된 미국의 엄격한 보틀드 인 본드(Bottled-in-Bond) 법을 준수하여 생산된 프리미엄 테네시 위스키입니다. 법령이 요구하는 50%의 높은 도수로 병입되어, 클래식 올드 넘버 7 제품보다 한층 묵직하고 대담하며 직관적인 버번 스타일의 힘을 뿜어냅니다.", "제조 및 숙성": "단 하나의 증류소에서 단 한 명의 마스터 디스틸러에 의해, 단 한 번의 증류 시즌(1월~6월 또는 7월~12월) 동안 증류된 원액만을 사용합니다. 미국의 연방 정부 승인 보관 창고에서 최소 4년 이상 숙성시킨 후 정확히 100프루프(50% ABV)로 병입됩니다."}, "feature": {"정부 인증의 신뢰성": "미국 위스키 황금기의 엄격한 법적 품질 규격을 100% 충족하여 높은 신뢰도와 무결한 크래프트 품질을 증명합니다.", "50% 도수의 강력한 화력": "높은 알코올 볼륨감 덕분에 잭 다니엘스 특유의 달콤한 바나나 에스테르 뒤로 묵직한 오크 탄닌의 타격감이 확실하게 전해집니다.", "진해진 다크 프로파일": "선별된 숙성 과정을 거쳐 일반 제품보다 훨씬 짙은 루비 호박색 자태와 농밀하고 꽉 찬 마우스필을 완성했습니다."}}', note = '{"note": {"향 (Nose)": "코를 자극하는 강렬하고 달콤한 브라운 슈가와 짙은 캐러멜 토피, 바닐라 아로마가 피어오릅니다. 뒤이어 잘 익은 바나나 플레이버와 오크통 특유의 그을린 나무 향, 매콤한 겨울 향신료 향이 중후하게 어우러집니다.", "맛 (Palate)": "입안을 진득하게 가득 채우는 풀바디의 오일리함이 돋보입니다. 메이플 시럽의 단맛과 옥수수의 고소함, 졸인 자두의 풍미가 중심을 잡고 으깬 통후추, 육두구, 시나몬의 알싸한 오크 스파이스가 강력하게 혀를 자극합니다.", "여운 (Finish)": "도수에 걸맞게 가슴 깊은 곳까지 따뜻해지는 긴 여운입니다. 오크통의 우디한 잔향과 에스프레소의 잔잔한 쌉싸름함, 그리고 입안 전체를 감싸는 달콤한 토피 당의 미련이 기분 좋고 드라이하게 남습니다."}}' WHERE id = 157;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (158, '잭 다니엘스 본디드 라이', 'rye', 'Jack Daniel\'s Whiskey', 'whiskey/134176.jpg', 50.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel’s Bonded Rye 70cl', 68138, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-bonded-rye-whiskey/?sku=134176', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 본디드 라이(Jack Daniel\'s Bonded Rye)는 엄격한 보틀드 인 본드 법규에 맞추어 생산된 최고급 호밀 위스키입니다. 단풍나무 숯 여과를 거친 잭 다니엘스 고유의 실키한 목 넘김 기저 위에, 호밀 특유의 와일드하고 매콤한 스파이시 타격감을 50%의 강력한 고도수 속에서 가장 이상적으로 폭발시킨 제품입니다.", "제조 및 숙성": "호밀 70%, 옥수수 18%, 몰트 12%의 고함량 호밀 매시빌 구조를 고수합니다. 단 한 번의 증류 시즌 동안 증류된 원액을 사탕단풍나무 숯 침전조에 통과시킨 후, 정부 관리 창고에서 최소 4년 이상 숙성하여 정확히 50% 도수로 가감 없이 병입했습니다."}, "feature": {"호밀과 본드법의 만남": "70% 호밀이 자아내는 화사한 허브 스파이스가 100프루프 고도수와 결합하여 폭발적인 시너지를 일으킵니다.", "정제된 스파이시 밸런스": "호밀 위스키 특유의 거칠고 매운 성향이 차콜 멜로잉 공정을 통해 부드럽게 정돈되어 극상의 세련된 밸런스를 뽐냅니다.", "크래프트 퀄리티의 정수": "단 하나의 증류소 유산만을 담아 원액의 촘촘한 풍미 밀도와 묵직한 오일감을 완벽하게 보존해 냈습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 대담한 아로마입니다. 신선한 호밀 고유의 민트, 딜 같은 허브 향과 통후추의 매콤함이 전면에 나섭니다. 이내 달콤한 바닐라 빈, 브라운 슈가, 구운 토스트의 고소한 향이 복합적으로 어우러집니다.", "맛 (Palate)": "혓바닥을 자극적으로 조여오는 진득하고 오일리한 풀바디 텍스처입니다. 말린 살구, 토피 당의 진한 단맛이 중심을 잡고 뒤이어 계피, 육두구, cracked 블랙페퍼의 알싸한 라이 스파이스가 입안 가득 파도처럼 휘몰아칩니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 데워주는 듯한 길고 드라이한 피날레입니다. 호밀 특유의 화사한 풀 잔향과 타버린 오크통의 우디함, 쌉싸름한 카카오의 흔적 뒤로 기분 좋은 바닐라의 단맛 미련이 오래도록 맴눕니다."}}' WHERE id = 158;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (159, '잭 다니엘스 트리플 매쉬', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/118403.jpg', 50.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel’s Triple Mash 70cl', 69836, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-triple-mash-whiskey/?sku=118403', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 트리플 매쉬(Jack Daniel\'s Triple Mash)는 세 종류의 보틀드 인 본드 인증 아메리칸 위스키를 정교하게 융합하여 탄생시킨 혁신적이고 파격적인 프리미엄 블렌디드 스트레이트 위스키입니다. 50% 도수 속에서 각 위스키 고유의 개성을 삼위일체로 엮어내어 압도적인 다층 구조의 풍미를 자랑합니다.", "제조 및 숙성": "정부 규격에 따라 생산된 잭 다니엘스 아메리칸 몰트 위스키 60%, 테네시 위스키 20%, 호밀 위스키 20%의 비율로 블렌딩했습니다. 각각의 스트레이트 위스키들이 버진 오크통에서 최소 4년 이상 숙성된 후 마스터 블렌더의 정밀한 감각을 통해 매링되었습니다."}, "feature": {"세 가지 매시빌의 예술": "보리 맥아의 고소함, 옥수수의 달콤함, 호밀의 스파이시함이 한 보틀 안에서 기적 같은 대칭과 평형을 구현했습니다.", "스트레이트 블렌딩의 깊이": "주정이나 기타 첨가물 없이 오직 100% 본디드 스트레이트 위스키들로만 결합하여 순수한 원액의 힘을 전합니다.", "독보적인 복합 레이어": "50%의 높은 알코올 볼륨감 덕분에 세 위스키가 자아내는 다채로운 풍미 분자가 뭉개지지 않고 단단하게 전개됩니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 몰트 위스키 고유의 향긋한 구운 보리, 시리얼의 고소함 뒤로 버번 스타일의 캐러멜 토피, 바닐라 포드의 단 향이 피어오르고 호밀 특유의 가벼운 민트 스파이스가 입체감을 더합니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 훌륭한 바디감입니다. 벌꿀 집의 단맛과 브라운 슈가, 잘 익은 살구의 풍미가 퍼지고 뒤이어 오크통에서 배어 나온 시나몬 가루, 구운 생강, 블랙페퍼의 알싸한 타격감이 정교한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 아주 길게 지속되는 피날레입니다. 농축된 단맛과 가죽 향이 가라앉으며 기품 있는 구운 오크의 우디한 풍미, 고소한 맥아 잔향과 잔잔한 라이 스파이스의 흔적이 아름다운 여운을 남깁니다."}}' WHERE id = 159;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (160, '잭 다니엘스 트래블러 볼드 앤 스파이시', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/119344.jpg', 53.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 500.0, 'Jack Daniel\'s Tennessee Travelers - Bold & Spicy 50cl', 57146, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-tennessee-travelers-bold-and-spicy-whiskey/?sku=119344', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 트래블러 볼드 앤 스파이시(Jack Daniel\'s Traveler Bold & Spicy)는 주로 글로벌 면세 시장을 겨냥하여 호밀의 함량을 높여 출시된 스페셜 에디션 위스키입니다. 이름 그대로 대담하고(Bold) 매콤한(Spicy) 캐릭터를 전면에 내세웠으며 40% 도수 안에서 경쾌하고 화사한 에너지를 뿜어냅니다.", "제조 및 숙성": "기존 올드 넘버 7 제품 라인업보다 호밀(Rye) 성분의 배치 비율을 상향 조정한 특제 매시빌 원액을 기반으로 합니다. 단풍나무 숯 여과 공정을 거친 후 안쪽을 깊게 그을린 뉴 아메리칸 화이트 오크 캐스크에서 숙성시켜 대중적이면서도 스파이시한 풍미를 구현했습니다."}, "feature": {"대담한 스파이시 프로파일": "호밀 위스키 고유의 알싸한 타격감과 풀 내음 레이어를 한층 직관적이고 생동감 있게 전개하는 반전 매력의 제품입니다.", "차콜 멜로잉의 라운드감": "대담한 호밀 스파이스 속에서도 잭 다니엘스 특유의 부드러움과 달콤한 바나나 풍미가 기저를 받쳐주어 목 넘김이 매끄럽습니다.", "면세점 전용의 매력": "여행자들을 위해 특별 기획된 세련된 보틀 디자인과 텍스처 조합으로 부담 없이 캐주얼하게 즐기기에 최적화되어 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 아로마가 가득 퍼집니다. 부드러운 바닐라 빈, 캐러멜 토피 향 뒤로 호밀 특유의 상큼한 레몬그라스, 진저, 민트 허브의 향이 잘 익은 바나나 플레이버와 가볍고 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 달콤한 벌꿀과 브라운 슈가, 과일 시럽의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 으깬 통후추, 계피의 알싸한 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 바닐라 단맛이 서서히 가라앉으며, 입안에 기분 좋은 드라이함과 호밀 특유의 산뜻하고 스파이시한 미련을 가볍게 남기며 마무리됩니다."}}' WHERE id = 160;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (161, '잭 다니엘스 스윗 앤 오키', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/119345.jpg', 53.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 500.0, 'Jack Daniel\'s Tennessee Travelers - Sweet & Oaky 50cl', 80070, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-tennessee-travelers-sweet-and-oaky-whiskey/?sku=119345', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 스윗 앤 오키(Jack Daniel\'s Sweet & Oaky)는 글로벌 면세점 및 특정 기획 라인업으로 출시되어, 아메리칸 버진 오크통이 선사할 수 있는 직관적인 달콤함과 묵직한 나무 풍미의 대비를 극대화한 테네시 위스키입니다. 40% 도수로 세팅되어 누구나 부담 없이 캐주얼하게 즐기기 좋은 이지드링킹 성향을 지니고 있습니다.", "제조 및 숙성": "증류소 고유의 사탕단풍나무 숯 여과 공정을 거친 스피릿을 기반으로 합니다. 안쪽을 강렬하게 태우고 그을리는 과정을 정밀하게 제어한 뉴 아메리칸 화이트 오크 캐스크들을 엄선하여 결합했으며, 나무 천연의 설탕 성분과 타닌이 원액 깊숙이 스며들도록 숙성시켰습니다."}, "feature": {"단맛과 우디함의 극대화": "이름 그대로 진득한 캐러멜의 달콤함(Sweet)과 강렬한 오크통 고유의 나무 캐릭터(Oaky)가 직관적으로 충돌하는 재미가 있습니다.", "차콜 멜로잉의 실키함": "진한 나무의 풍미 속에서도 잭 다니엘스 특유의 단풍나무 숯 여과 공정 덕분에 거친 알코올 자극 없이 목 넘김이 부드럽습니다.", "면세 시장의 숨은 가성비": "여행자들을 위해 특별 기획된 화려한 프로파일로, 잭 다니엘스의 개성 있는 또 다른 면모를 편안한 바디감으로 경험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "코를 가득 채우는 진한 브라운 슈가, 메이플 시럽, 버닐라 크림의 단향이 직관적입니다. 뒤이어 갓 구운 토스트의 고소함과 버진 오크 특유의 묵직한 가죽 향, 쌉싸름한 삼나무의 아로마가 감미롭게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 순간 크리미하고 진득한 달콤함이 퍼집니다. 벌꿀 집의 단맛과 잘 익은 바나나 플레이버가 중심을 잡고, 뒤이어 오크통에서 짙게 배어 나온 시나몬, 정향의 따뜻하고 알싸한 우드 스파이스가 기분 좋은 레이어를 만듭니다.", "여운 (Finish)": "온화하고 묵직한 나무 잔향을 남깁니다. 오크통 고유의 감미로운 캐러멜 흔적과 드라이한 타닌의 미련이 서서히 가라앉으며, 입안을 산뜻하고 따뜻하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 161;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (162, '잭 다니엘스 라이', 'rye', 'Jack Daniel\'s Whiskey', 'whiskey/69807.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Tennessee Rye 70cl', 54485, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-tennessee-rye-whiskey/?sku=69807', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 라이(Jack Daniel\'s Tennessee Rye)는 증류소가 고수해 온 150년 이상의 전통 크래프트 기술에 호밀 위스키의 독창적인 개성을 융합하여 탄생시킨 정규 라인업 아메리칸 위스키입니다. 45% 도수로 병입되어 호밀 특유의 와일드한 타격감과 세련된 바디감을 동시에 뽐냅니다.", "제조 및 숙성": "호밀 70%, 옥수수 18%, 몰트 12%로 구성된 자사 특제 호밀 매시빌을 사용하여 증류했습니다. 이 묵직한 원액을 숙성 전에 사탕단풍나무 숯 침전조에 통과시키는 테네시 전통의 차콜 멜로잉 공정을 거친 후, 안쪽을 태운 뉴 아메리칸 화이트 오크 배럴에서 최소 4년 이상 숙성시켰습니다."}, "feature": {"테네시 스타일 라이": "일반적인 미국 라이 위스키와 달리 잭 다니엘스 고유의 숯 여과 과정을 도입하여, 호밀의 매콤함 뒤에 숨겨진 극상의 부드러움을 완성했습니다.", "70% 호밀의 선명한 개성": "옥수수의 진득한 단맛을 다소 걷어내고, 호밀 본연의 알싸한 후추 스파이스, 싱그러운 허브와 민트 캐릭터를 전면에 내세웠습니다.", "다채로운 칵테일 믹싱": "45%의 단단한 알코올 볼륨감과 화사한 아로마 덕분에 니트로 즐겨도 훌륭하며, 맨해튼이나 사제락 같은 클래식 위스키 칵테일 베이스로 뛰어납니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 대담한 아로마가 피어오릅니다. 신선한 호밀 특유의 민트, 딜 같은 허브 향과 통후추의 매콤함이 먼저 코를 자극하고, 뒤이어 부드러운 바닐라 포드, 구운 맥아의 고소한 단 향이 조화롭게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 오일리하게 감싸 안는 마우스필이 특징입니다. 벌꿀 집의 단맛과 브라운 슈가, 잘 익은 살구의 풍미가 중심을 잡고, 뒤이어 시나몬 가루, 구운 생강, cracked 블랙페퍼의 알싸한 라이 스파이스가 혀를 정교하게 타격합니다.", "여운 (Finish)": "드라이하면서도 온화한 따뜻함이 길게 지속되는 피날레입니다. 호밀 특유의 화사한 풀 잔향과 타버린 오크통의 우디함이 가라앉으며, 입안 전체에 가벼운 향신료의 흔적과 산뜻한 여운을 기분 좋게 남깁니다."}}' WHERE id = 162;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (163, '잭 다니엘스 싱글배럴 배럴 스트렝스', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/135495.jpg', 62.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s Single Barrel - Barrel Strength 70cl', 143358, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-single-barrel-barrel-strength-62-5-whiskey/?sku=135495', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 싱글배럴 배럴 스트렝스(Jack Daniel\'s Single Barrel Barrel Strength)는 물을 단 한 방울도 섞지 않고 오크통에서 꺼낸 원액 그대로를 병입하여, 증류소 역사상 가장 폭발적이고 강력한 에너지를 날것 그대로 경험할 수 있는 최상위 하이엔드 익스프레션입니다. 배치와 배럴에 따라 보통 60%에서 67% 안팎의 압도적인 고도수를 자랑합니다.", "제조 및 숙성": "기온 변화와 공기 순환이 가장 혹독하고 거친 테네시 숙성 창고의 최상층(상단 Floors)에서만 잠들어 있던 최상위 1% 싱글 배럴을 마스터 디스틸러가 엄선합니다. 가수 공정이나 냉각 여과 없이 순수한 내추럴 컬러와 캐스크 스트렝스 형태 그대로 병입됩니다."}, "feature": {"압도적인 배럴 스트렝스": "가수 공정 없는 초고도수에서 뿜어져 나오는 폭발적인 화력과 입안을 끈적하게 코팅하는 농밀한 마우스필의 정수를 보여줍니다.", "최상위 1% 캐스크의 위엄": "단 하나의 오크통 독립 원액만을 담았기에, 오크통 번호와 배럴 위치가 레이블에 수기 명시되어 독보적인 소장 가치를 지닙니다.", "순수한 내추럴 퀄리티": "색소 첨가나 여과 가공을 거치지 않아 원액 본연의 진하고 진득한 루비 호박색 자태와 화려하게 응축된 풍미 레이어를 고스란히 보존했습니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 찌르는 강렬한 알코올 볼륨감 뒤로 진한 메이플 시럽, 브라운 슈가, 캐러멜 토피의 단향이 폭발적으로 다가옵니다. 뒤이어 잘 익은 바나나 플레이버와 묵직한 가죽, 타버린 오크통의 그을음 향이 깊게 어우러집니다.", "맛 (Palate)": "입안을 터질 듯이 가득 채우는 풀바디의 진득하고 오일리한 질감입니다. 진한 밤꿀과 다크 초콜릿, 옥수수 시럽의 묵직한 단맛이 밀려오고, 통후추, 구운 생강, 육두구, 시나몬의 알싸하고 매운 오크 스파이스가 혀를 정교하고 파워풀하게 타격합니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 뜨겁게 데워주는 극도로 길고 중후한 피날레입니다. 농축된 단맛과 가죽 향이 가라앉으며 기품 있는 마호가니 나무의 풍미, 에스프레소의 쌉싸름함과 입안 전체를 끈질기게 지배하는 숯의 잔향이 끝없이 지속됩니다."}}' WHERE id = 163;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (164, '잭 다니엘스 10년', 'etc', 'Jack Daniel\'s Whiskey', 'whiskey/135628.jpg', 48.5, 10, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jack Daniel\'s 10 Year Old Batch #2 70cl', 510002, 'https://www.masterofmalt.com/whiskies/jack-daniels/jack-daniels-10-year-old-batch-2-whiskey/?sku=135628', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "잭 다니엘스 10년(Jack Daniel\'s 10 Year Old Tennessee Whiskey)은 증류소가 무려 100년이 넘는 기나긴 세월 동안 출시하지 않았던 정밀 숙성(Age-stated) 연산 제품을 현대적으로 부활시킨 역사적인 프리미엄 싱글 몰트급 익스프레션입니다. 48%의 높은 도수로 병입되어 정교하고 탄탄한 바디감을 자랑합니다.", "제조 및 숙성": "전통적인 매시빌 원액을 사탕단풍나무 숯 여과 과정을 거치게 한 후, 최고급 아메리칸 버진 오크통에 담아 장장 10년이라는 긴 세월 동안 장기 숙성시켰습니다. 잭 다니엘스의 스피릿이 오랜 연산 숙성을 거쳤을 때 자아내는 복합미를 증명하기 위해 마스터 디스틸러가 창고 위치를 정밀 제어하여 완성했습니다."}, "feature": {"100년 만의 연산 위스키": "숙성 연수를 표기하지 않는 전통에서 벗어나 무려 10년이라는 긴 세월을 버텨온 진귀한 고연산 원액들로만 빚어낸 기념비적인 보틀입니다.", "장기 숙성이 빚은 세련미": "젊은 날의 거친 아세톤 향이나 튀는 타격감은 완벽히 가라앉고, 유러피안 오크 고연산 못지않은 중후한 가죽과 오크의 성숙함을 획득했습니다.", "48% ABV의 단단한 구조": "알코올 볼륨감을 높여 장기 숙성 원액 고유의 풍성한 마우스필과 캐러멜, 바닐라의 촘촘하게 짜인 레이어를 직관적으로 전합니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며 코끝을 스치는 아로마가 아름답습니다. 달콤한 캐러멜 토피와 메이플 시럽, 부드러운 바닐라 빈의 향이 피어오르고 뒤이어 말린 자두, 무화과와 오래된 오크, 가죽 책의 고풍스러운 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 매끄럽고 깊은 풍미가 가득 차오르는 질감입니다. 진한 브라운 슈가, 밀크 초콜릿, 졸인 황도 복숭아의 단맛이 먼저 입안을 채우고 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 가슴 깊숙이 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 잔향과 함께 머눕니다."}}' WHERE id = 164;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (165, '제임슨 18년', 'blended', 'Jameson Irish Whiskey', 'whiskey/79960.jpg', 46.0, 18, 'active', NOW(), NOW(), 'Irish Whiskey', '', 700.0, 'Jameson 18 Year Old 70cl', 254990, 'https://www.masterofmalt.com/whiskies/jameson/jameson-18-year-old-whiskey/?sku=79960', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "제임슨 18년(Jameson 18 Year Old Bow Street / Limited Reserve)은 전 세계 아이리시 위스키의 대명사인 제임슨 라인업 중 가장 귀족적이고 품격 있는 우아함을 자랑하는 플래그십 최고급 익스프레션입니다. 특유의 트리플 디스틸드(3회 증류) 공법이 선사하는 부드러움의 극치 위에 오랜 세월의 중후함을 더해 40%~46%(버전에 따라 상이) 도수 안에서 완벽한 육각형의 밸런스를 보여줍니다.", "제조 및 숙성": "아이리시 전통에 따라 피트를 사용하지 않고 제맥한 보리를 3번 증류하여 극도로 맑고 깨끗한 스피릿을 뽑아냅니다. 이 원액을 최고급 유러피안 셰리 오크통과 아메리칸 버번 캐스크에서 각각 최소 18년 동안 장기 숙성시킨 후 결합했으며, 최종 단계에서 퍼스트 필 버번 배럴로 옮겨 담아 추가 매링 과정을 거쳤습니다."}, "feature": {"아이리시 부드러움의 정점": "3회 증류 특유의 가볍고 화사한 질감과 18년 숙성이 자아내는 농밀한 복합미가 기적 같은 대칭과 평형을 이룹니다.", "정교한 더블 버번 머추어드": "마지막 단계에서 퍼스트 필 버번 배럴의 집중적인 터치를 가미하여 독보적인 크리미함과 풍부한 바닐라 토피 풍미를 확보했습니다.", "최상위 한정 수량 패키지": "증류소의 역사적인 심장부인 더블린 \'보 스트리트(Bow Street)\' 창고의 헤리티지를 담아 프리미엄 우드 케이스와 함께 소량 한정 생산됩니다."}}', note = '{"note": {"향 (Nose)": "우아하고 복합적인 아로마가 가득 퍼집니다. 향긋한 수풀 내음과 화사한 화이트 플라워 향 뒤로 구운 캐슈넛, 아몬드의 고소한 너티함 짙은 바닐라 크림, 토피 당과 셰리 캐스크 고유의 말린 무화과 향이 기품 있게 어우러집니다.", "맛 (Palate)": "벨벳이나 실크를 혀에 얹은 듯 극도로 부드럽고 매끄러운 텍스처가 압권입니다. 진한 밤꿀과 졸인 황도 복숭아, 메이플 시럽의 단맛이 기품 있게 전개되며 은은한 오크통의 시나몬 스파이스와 진저브레드의 고소함이 조화를 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 긴 감미로운 여운을 선사합니다. 농축된 와인과 바닐라의 단맛이 가라앉으며 기품 있는 구운 오크의 우디한 풍미, 에스프레소의 잔향 뒤로 가슴 속까지 온화해지는 우아한 스파이스의 잔향이 오래도록 머눕니다."}}' WHERE id = 165;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (166, '제임슨 블랙 배럴', 'blended', 'Jameson Irish Whiskey', 'whiskey/10836.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Irish Whiskey', '', 700.0, 'Jameson Black Barrel 70cl', 62939, 'https://www.masterofmalt.com/whiskies/john-jameson-and-son/jameson-black-barrel-whisky/?sku=10836', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "제임슨 블랙 배럴(Jameson Black Barrel)은 아이리시 위스키 특유의 극상의 부드러움에 버번 위스키 스타일의 진득하고 강렬한 오크통 단맛을 가미하여 반전 매력을 선사하는 프리미엄 익스프레션입니다. 냉각 여과 없이 40% 도수로 병입되며 일반 제임슨 제품보다 한층 묵직하고 농밀한 바디감을 뽐냅니다.", "제조 및 숙성": "아이리시 전통에 따라 피트를 배제하고 3회 증류하여 뽑아낸 맑은 스피릿을 기반으로 합니다. 이 원액을 안쪽을 두 번 강렬하게 태워 그을린 특제 더블 차드 아메리칸 오크 배럴(Double Charred Bourbon Barrels)과 최고급 셰리 캐스크에서 정교하게 숙성시켜 결합했습니다."}, "feature": {"더블 차드 캐스크의 터치": "오크통 내부를 두 번 태우는 공정을 통해 나무 천연의 토피 설탕 성분을 극대화하여 독보적인 진득한 단맛을 확보했습니다.", "그레인 위스키의 스몰 배치": "일년에 단 한 번만 증류되는 진귀한 스몰 배치 풍부한 타입의 그레인 위스키 원액 비율을 높여 한층 오일리한 질감을 자랑합니다.", "아이리시 단짠의 조화": "3회 증류의 깔끔한 질감 기저 위에 버번 캐스크 특유의 진한 바닐라, 캐러멜 향이 충돌하며 훌륭한 만족감을 선사합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 진한 바닐라 포드와 부드러운 밤꿀, 캐러멜 토피 향이 코를 가득 채웁니다. 뒤이어 상큼한 말린 오렌지 껍질, 신선한 복숭아 향과 함께 두 번 태운 오크통 특유의 은은하고 중후한 장작 그을음 향이 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 농밀하고 오일리하게 감싸 안는 매끄러운 텍스처가 일품입니다. 브라운 슈가, 대추야자, 졸인 황도 복숭아의 진한 단맛이 중심을 잡고, 뒤이어 시나몬 가루, 구운 생강, 화이트 페퍼의 알싸한 오크 스파이스가 기분 좋은 타격감을 선사합니다.", "여운 (Finish)": "온화하고 감미로운 우디 피날레가 길게 이어집니다. 오크통에서 배어 나온 부드러운 토피 당의 흔적과 드라이한 나무 향이 서서히 가라앉으며, 입안 전체를 산뜻하고 따뜻하게 정돈해 주며 마무리됩니다."}}' WHERE id = 166;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (167, '제임슨', 'blended', 'Jameson Irish Whiskey', 'whiskey/2696.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Irish Whiskey', '', 700.0, 'Jameson Irish Whiskey 70cl', 46912, 'https://www.masterofmalt.com/whiskies/john-jameson-and-son/jamesons-irish-whiskey/?sku=2696', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "제임슨(Jameson Irish Whiskey / 제임슨 스탠다드)은 1780년부터 이어져 온 유서 깊은 전통을 바탕으로 생산되는 전 세계 판매량 1위의 독보적인 아이코닉 아이리시 위스키입니다. 40% 도수로 병입되며 싱글 몰트 위스키나 버번 위스키 특유의 거친 자극을 완벽히 걷어내어 극상의 부드러운 목 넘김과 대중성을 전합니다.", "제조 및 숙성": "피트를 전혀 사용하지 않고 오직 열풍으로만 건조한 청정 보리를 사용하여 전통적인 대형 구리 증류기에서 총 3번 정밀 증류(Triple Distilled)합니다. 이 극도로 맑고 깨끗한 스피릿을 최고급 아메리칸 ex-버번 캐스크와 스페니시 오로로소 셰리 오크통에서 최소 4년 이상 숙성시켜 결합합니다."}, "feature": {"트리플 디스틸드의 부드러움": "3회 증류 공정을 철저히 고수하여 위스키를 처음 접하는 입문자나 알코올 자극에 민감한 이들도 누구나 편안하게 즐길 수 있습니다.", "피트 스모크 프리": "보리를 말릴 때 피트 연기를 닿지 않게 하여 탄 내나 소독약 향이 전혀 없고 순수한 보리 고유의 고소함과 과일 향만 투명하게 살아있습니다.", "최고의 하이볼 벤치마크": "탄산수나 토닉워터, 진저에일과 레몬 제스트를 곁들이는 제임슨 하이볼 베이스로서 가성비와 접근성 면에서 전 세계적인 찬사를 받습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 싱그러운 가을철 과수원 아로마가 피어오릅니다. 가벼운 수풀 내음과 신선한 꿀의 단향 뒤로 잘 익은 노란 사과, 청사과의 시트러스와 은은하게 깔리는 바닐라 크림 고유의 향이 가볍고 산뜻하게 조화롭고 어우러집니다.", "맛 (Palate)": "입안에 닿는 순간 물처럼 실크처럼 부드럽고 가볍게 굴러갑니다. 감미로운 벌꿀 집의 단맛과 잘 익은 서양 배의 풍미가 중심을 잡고 구운 견과류의 고소함과 오크통에서 배어 나온 미세한 화이트 페퍼 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 짧고 산뜻하게 남깁니다. 아메리칸 오크 특유의 가벼운 바닐라 단맛과 은은한 보리의 고소함이 입안을 부드럽게 정돈해 주며 매끄러운 목 넘김 뒤에 산뜻하게 가라앉으며 마무리됩니다."}}' WHERE id = 167;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (168, '제임슨 크레스티드', 'blended', 'Jameson Irish Whiskey', 'whiskey/52246.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Irish Whiskey', '', 700.0, 'Jameson Crested 70cl', 52029, 'https://www.masterofmalt.com/whiskies/john-jameson-and-sons/jameson-crested-whiskey/?sku=52246', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "제임슨 크레스티드(Jameson Crested)는 과거 증류소 내부가 아닌 외부 상인들이 위스키를 마음대로 병입하여 품질을 떨어뜨리던 관행을 막고, 1963년 증류소 최초로 직접 책임 병입을 단행했던 역사적인 성과를 기리기 위해 출시된 프리미엄 아바카블 에디션 위스키입니다. 40% 도수 안에서 짙은 중후함을 자랑합니다.", "제조 및 숙성": "아이리시 전통 트리플 디스틸드 원액을 기반으로 숙성시켰습니다. 스탠다드 제품과 달리 블렌딩 파이프라인에서 최고급 유러피안 오크 오로로소 셰리 캐스크(European Oak Oloroso Sherry Casks)의 숙성 원액 비율을 대폭 높여 장인 장신으로 매링했습니다."}, "feature": {"셰리 오크의 풍부한 아우라": "제임슨 고유의 깨끗하고 부드러운 질감 위에 스페니시 셰리통 특유의 진한 다크 프루트 단맛과 깊이감을 확실하게 결합했습니다.", "최초 자체 병입의 찬가": "증류소의 명예를 지키기 위해 고유의 앰블럼 문장(Crest)을 보틀 패키지에 명시하여 소장 가치와 크래프트 스토리를 전달합니다.", "촘촘하고 단단한 구조감": "엔트리 제품의 가벼움을 보완하여 입안 가득 잼을 머금은 듯 진득하고 중후한 밸런스를 가성비 좋게 경험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 진득한 말린 과일 향이 코를 감쌉니다. 건포도와 대추야자, 캐러멜 토피의 묵직한 단향이 피어오르고, 상큼한 레드 베리와 신선한 꿀, 그리고 가벼운 생강, 시나몬의 알싸한 향이 복합적인 레이어를 형성합니다.", "맛 (Palate)": "혀끝을 달콤하고 매끄럽게 코팅하는 오일리한 마우스필이 돋보입니다. 진한 밀크 초콜릿, 무화과 잼의 단맛이 퍼지고, 뒤이어 오크통에서 배어 나온 계피 가루, 육두구의 부드러운 우드 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "온화하고 감미로운 셰리 피날레가 우아하게 지속됩니다. 오크통 특유의 풍부한 나무 향과 말린 과일의 단맛 흔적이 가라앉으며, 입안에 기분 좋은 드라이함과 에스프레소의 잔향을 부드럽게 남기며 마무리됩니다."}}' WHERE id = 168;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (169, '짐빔 싱글 배럴', 'bourbon', 'Jim Beam', 'whiskey/100616.jpg', 47.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam Single Barrel 70cl', 62673, 'https://www.masterofmalt.com/whiskies/jim-beam/jim-beam-single-barrel-whiskey/?sku=100616', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 싱글 배럴(Jim Beam Single Barrel)은 전 세계 버번 위스키의 대명사인 짐빔 가문이 보유한 수많은 오크통 중, 극상의 밸런스와 품질을 지닌 통만을 엄선하여 단 한 통의 원액만 병입하는 하이엔드 프리미엄 버번 위스키입니다. 물을 섞는 공정을 최소화하여 47.5%의 강력한 도수 속에서 직관적인 파워풀함을 자랑합니다.", "제조 및 숙성": "옥수수를 주원료로 호밀과 몰트를 섞은 전통적인 짐빔 매시빌 원액을 사용합니다. 안쪽을 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크에서 숙성시키며 기온 변화가 격렬한 켄터키 라커 하우스(Rackhouse)의 가장 이상적인 명당 구역에서 온전히 세월을 버틴 단 한 통만 선택해 병입합니다."}, "feature": {"상위 1% 배럴의 위엄": "수작업으로 까다롭게 엄선되어 다른 오크통과의 블렌딩 결합이 전혀 없는 버진 오크 특유의 직관적이고 순수한 아로마를 선사합니다.", "배럴별 희소성과 개성": "각 보틀 레이블에 고유의 오크통 번호(Barrel Number)와 창고 위치가 명시되어 매 병마다 미세하게 다른 개성을 비교 시음하는 재미가 있습니다.", "47.5% ABV의 탄탄한 구조": "알코올 볼륨감을 대폭 높여 일반 데일리 제품 특유의 거친 부즈를 정제하고, 농밀한 토피 단맛과 묵직한 오크 탄닌의 타격감을 가득 채웠습니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 자극하는 강렬하고 달콤한 캐러멜 토피와 짙은 바닐라, 메이플 시럽 아로마가 피어오릅니다. 뒤이어 버진 오크 특유의 묵직한 가죽 향, 으깬 옥수수의 고소함과 호밀의 매콤한 후추 향이 묵직하게 어우러집니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 진득하고 오일리한 바디감이 일품입니다. 브라운 슈가와 꿀, 졸인 자두의 단맛이 파도처럼 밀려오고 뒤이어 통후추, 계피, 구운 생강의 알싸한 오크 스파이스가 혀를 정교하고 파워풀하게 타격합니다.", "여운 (Finish)": "도수에 걸맞게 가슴 깊은 곳까지 따뜻해지는 긴 여운입니다. 오크통의 우디한 잔향과 에스프레소의 잔잔한 쌉싸름함, 그리고 입안 전체를 기분 좋게 지배하는 달콤한 토피 당의 미련이 오래도록 남으며 마무리됩니다."}}' WHERE id = 169;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (170, '짐빔 화이트', 'bourbon', 'Jim Beam', 'whiskey/2668.jpg', 40.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam White Label 70cl', 35737, 'https://www.masterofmalt.com/whiskies/jim-beam-white-label-whiskey/?sku=2668', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 화이트(Jim Beam White / 짐빔 오리지널)는 1795년부터 7대째 이어져 온 전통 레시피를 사수하며 생산되는 아메리칸 버번 위스키의 전 세계 판매량 1위 표준 벤치마크이자 살아있는 신화입니다. 40% 도수로 병입되며 버번 위스키가 가질 수 있는 투박하고 직관적인 옥수수 단맛의 정석을 전합니다.", "제조 및 숙성": "옥수수 함량을 51% 이상 대폭 높이고 호밀과 몰트를 섞은 전통 비법 매시빌을 사용하여 증류합니다. 법적 기준인 2년을 초과하여 안쪽을 강렬하게 태운 새 아메리칸 화이트 오크 캐스크(New Charcoal Virgin Oak)에서 최소 4년 동안 켄터키 해안 기후 창고에서 숙성시킵니다."}, "feature": {"버번 위스키의 교과서": "달콤함과 강렬한 타격감, 오크통 특유의 스파이시함이 가장 대중적으로 짜여 있어 수많은 버번 브랜드의 절대적인 기준점이 됩니다.", "4년 오크 숙성의 고집": "미국 스트레이트 버번 법적 기준의 두 배에 달하는 4년의 세월을 고집하여 나무 타닌 고유의 묵직함과 아로마를 안정적으로 확보했습니다.", "최고의 믹싱 가성비": "탄산수나 토닉워터, 콜라와 결합하는 \'짐빔 하이볼\'이나 \'짐빔 콕\' 베이스로서 전 세계 대중 주류 문화와 바에서 독보적인 가성비를 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 바닐라 크림과 옥수수 시럽, 캐러멜 향이 직관적으로 코를 자극합니다. 그 투박한 달콤함 뒤로 뉴 오크통 특유의 그을린 장작 향, 향긋한 통후추와 아세톤 계열의 상큼한 과일 향이 대담하게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 느낌이 가볍고 활력 넘칩니다. 브라운 슈가의 진득한 단맛과 신선한 맥아의 고소함, 옥수수 고유의 풍미가 퍼지고, 뒤이어 오크통에서 배어 나온 알싸한 블랙페퍼, 시나몬 스파이스가 혀 위에서 화려하게 전개됩니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 나무 잔향을 남깁니다. 버진 오크 캐스크 특유의 드라이한 탄닌과 캐러멜의 달콤한 흔적이 가라앉으며, 입안에 기분 좋은 드라이함과 오크 스파이스의 여운을 산뜻하게 남기며 가라앉습니다."}}' WHERE id = 170;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (171, '짐빔 블랙 7년', 'bourbon', 'Jim Beam', 'whiskey/145294.jpg', 45.0, 7, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam Black 7 Year Old 70cl', 53728, 'https://www.masterofmalt.com/whiskies/jim-beam/jim-beam-black-7-year-old-whiskey/?sku=145294', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 블랙 7년(Jim Beam Black 7 Year Old)은 증류소의 상징적인 화이트 라인업보다 훨씬 긴 시간 동안 장인 정신으로 숙성시켜 중후함과 깊이감을 극대화한 프리미엄 스트레이트 버번 위스키입니다. 과거 연산 표기가 사라졌던 암흑기를 거쳐 7년(7 Years)이라는 명확한 숙성 연수를 달성하고 당당히 부활했으며, 43% 도수 속에서 완벽한 육각형의 프리미엄 밸런스를 자랑합니다.", "제조 및 숙성": "옥수수 비율을 대폭 높인 전통적인 짐빔 매시빌 원액을 기반으로 증류합니다. 안쪽을 강렬하게 태운 새 아메리칸 화이트 오크 캐스크에서 무려 7년이라는 오랜 세월 동안 켄터키의 변화무쌍한 기후를 견디며 숙성시켜, 오크통 내부의 천연 설탕 성분과 묵직한 타닌을 스피릿 깊숙이 화학 결합해 냈습니다."}, "feature": {"7년 숙성의 정제미": "일반 화이트 제품(4년)보다 훨씬 긴 숙성을 거쳐 거친 알코올 부즈나 자극적인 아세톤 향은 완벽히 사라지고 기품 있는 부드러움만 남았습니다.", "진해진 다크 프로파일": "장기 숙성을 통해 원액 본연의 진하고 진득한 다크 루비 호박색 자태와 입안을 촘촘하게 코팅하는 농밀한 마우스필을 완성했습니다.", "가성비 최고의 프리미엄": "부담 없는 가격대에서 고연산 버번 위스키 특유의 중후한 가죽 향과 진한 캐러멜 토피 풍미를 가장 직관적으로 맛볼 수 있습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마가 가득 퍼집니다. 진한 바닐라 빈, 메이플 시럽, 캐러멜 토피 향 뒤로 오래된 시가 박스와 묵직한 가죽의 향이 올라오고, 잘 익은 블랙베리와 상큼한 오렌지 껍질의 아로마가 우아하게 얹어집니다.", "맛 (Palate)": "입안을 진득하고 크리미하게 가득 채우는 미디엄 풀바디 텍스처입니다. 브라운 슈가와 밤꿀, 옥수수 고유의 진한 단맛이 파도처럼 밀려오고 구운 피칸의 고소함과 시나몬 가루, 육두구, 구운 생강의 알싸한 오크 스파이스가 기품 있는 타격감을 선사합니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 따뜻해지는 긴 감미로운 여운을 남깁니다. 농축된 단맛이 가라앉으며 기품 있는 구운 오크의 우디함과 에스프레소의 잔잔한 쌉싸름함, 따뜻한 계피 향의 흔적이 오래도록 머눕니다."}}' WHERE id = 171;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (172, '짐빔 라이', 'rye', 'Jim Beam', 'whiskey/13384.jpg', 40.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam Rye 70cl', 61240, 'https://www.masterofmalt.com/whiskies/jim-beam/jim-beam-rye-whiskey/?sku=13384', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 라이(Jim Beam Rye / 짐빔 그린)는 짐빔 가문이 금주법 이전 미국 위스키 시장을 풍미했던 호밀 위스키의 황금기 레시피를 사수하며 생산하는 정통 아메리칸 스트레이트 라이 위스키입니다. 40% 도수로 병입되며 호밀 특유의 알싸한 후추 스파이스 타격감과 대중적인 화사함을 동시에 전합니다.", "제조 및 숙성": "법적 기준에 따라 호밀(Rye) 성분의 배치 비율을 51% 이상 대폭 높인 특제 라이 매시빌 원액을 사용하여 증류합니다. 안쪽을 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크에서 수년간 숙성시켜, 호밀 본연의 와일드함 위에 버번 스타일의 달콤한 옷을 입혀 완성했습니다."}, "feature": {"금주법 이전 스타일 오마주": "미국 역사상 가장 거칠고 와일드했던 정통 아메리칸 라이 위스키 고유의 묵직하고 매콤한 캐릭터를 전면에 내세웠습니다.", "산뜻하고 경쾌한 개성": "옥수수의 묵직한 단맛을 과감히 걷어내고, 호밀 고유의 알싸한 풀 내음, 으깬 후추, 싱그러운 민트와 허브 레이어를 선명하게 뿜어냅니다.", "칵테일 빌딩의 대명사": "특유의 알싸한 스파이시함과 화사함 덕분에 니트로 즐겨도 훌륭하며, 올드 패션드나 올드 팰 같은 클래식 라이 위스키 칵테일 베이스로 가성비가 최고입니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 대담한 아로마가 코를 자극합니다. 신선한 호밀 특유의 민트, 딜 같은 허브 향과 통후추의 매콤함이 전면에 나섭니다. 이내 가벼운 바닐라 포드, 브라운 슈가, 신선한 보리 맥아의 고소한 단 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 굴러가는 질감입니다. 달콤한 벌꿀과 캐러멜 시럽, 과일 타르트의 풍미가 중심을 잡고, 뒤이어 계피, 육두구, cracked 블랙페퍼의 알싸한 라이 스파이스가 혀 위에서 화려하고 경쾌하게 전개됩니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 잔향을 산뜻하게 남깁니다. 호밀 특유의 화사한 풀 잔향과 오크통에서 배어 나온 부드러운 바닐라의 흔적, 가벼운 나무 스파이스의 여운이 입안을 산뜻하게 정돈해 주며 마무리됩니다."}}' WHERE id = 172;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (173, '짐빔 더블 오크', 'bourbon', 'Jim Beam', 'whiskey/52886.jpg', 43.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam Double Oak 70cl', 46892, 'https://www.masterofmalt.com/whiskies/jim-beam/jim-beam-double-oak-whiskey/?sku=52886', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 더블 오크(Jim Beam Double Oak)는 두 번의 오크통 숙성 과정을 통해 버진 오크 특유의 직관적이고 진득한 바닐라 단맛과 캐러멜 풍미를 극대화해 출시한 프리미엄 스페셜 에디션 버번 위스키입니다. 43% 도수 안에서 한층 더 중후하고 묵직한 나무의 힘을 뿜어냅니다.", "제조 및 숙성": "안쪽을 강렬하게 태운 새 아메리칸 화이트 오크통에서 최초 4년 동안 숙성되어 전통적인 짐빔 버번의 깊이를 획득한 원액을 주축으로 삼습니다. 이 원액을 다시 안쪽을 강렬하게 새로 태운 또 다른 뉴 아메리칸 화이트 오크 캐스크로 통째로 옮겨 담아 피니시 장기 숙성을 거쳤습니다."}, "feature": {"더블 버진 오크의 위엄": "리필 캐스크나 와인 캐스크가 아닌, 새 오크통만 연달아 두 번 사용하여 천연 나무 설탕 성분과 진득한 토피 향을 최고 수준으로 확보했습니다.", "진화한 단맛과 탄닌": "두 번째 오크통의 영향력이 대폭 증가하여 일반 제품보다 훨씬 진득하고 농밀하게 혀를 코팅하는 독보적인 마우스필을 전합니다.", "결점 없는 묵직함": "높아진 알코올 볼륨감과 강한 우디 터치 덕분에 에어링이 진행될수록 흑설탕에 졸인 진한 아우라가 드라마처럼 전개됩니다."}}', note = '{"note": {"향 (Nose)": "강렬하고 달콤한 캐러멜 토피와 진한 메이플 시럽, 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 구운 마시멜로, 브라운 슈가의 진한 단 향과 버진 오크 특유의 묵직한 가죽, 그을린 장작 향이 조화롭고 중후하게 피어오릅니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 진득하고 크리미한 풀바디 텍스처입니다. 진한 밤꿀과 옥수수 시럽, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고, 시나몬 가루, 구운 생강, 육두구의 알싸하고 매운 오크 스파이스가 기품 있는 타격감을 선사합니다.", "여운 (Finish)": "온화하고 묵직한 나무 잔향이 매우 길게 이어집니다. 두 번 태운 오크통 특유의 풍부한 우디 향과 캐러멜의 달콤한 흔적이 가라앉으며, 입안 가득 기분 좋은 드라이함과 스파이스의 잔향을 짙고 깊게 머금으며 마무리됩니다."}}' WHERE id = 173;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (174, '짐빔 데블스 컷', 'bourbon', 'Jim Beam', 'whiskey/15558.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Jim Beam Devil\'s Cut 70cl', 46032, 'https://www.masterofmalt.com/whiskies/jim-beam/jim-beam-devils-cut-whiskey/?sku=15558', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "짐빔 데블스 컷(Jim Beam Devil\'s Cut)은 숙성 과정 중 오크통 나무 벽면에 흡수되어 사라지는 진귀한 원액인 \'악마의 몫(Devil\'s Cut)\'을 증류소 고유의 특허 기술로 추출하여 결합한 파격적이고 대담한 프리미엄 버번 위스키입니다. 45%의 강력한 도수로 병입되어 정교하고 단단한 타격감을 자랑합니다.", "제조 및 숙성": "오랜 숙성을 마치고 비워진 최상급 오크통 나무통 내부 깊숙이 숨어있던 가장 진하고 중후한 유기 화합물 원액을 특수 추출 기법으로 이끌어냅니다. 이 진귀한 악마의 몫 원액을 장기 숙성된 6년 연산급 프리미엄 짐빔 원액과 정교한 비율로 매링하여 완성했습니다."}, "feature": {"악마의 몫의 재발견": "천사의 몫(Angel\'s Share)과 대비되는, 오크통 나무 조직 속에 갇혀 있던 가장 진득한 에센스 원액을 활용한 혁신적인 제품입니다.", "나무 풍미의 정점": "오크통 깊숙한 곳의 성분이 더해져 일반적인 버번 위스키들보다 훨씬 직관적이고 묵직한 구운 오크와 진한 탄닌의 파워를 전합니다.", "45% ABV의 단단한 구조": "알코올 볼륨감을 높여 진득한 옥수수 단맛 속에서도 나무 고유의 거친 가죽 향과 후추 스파이스가 강력한 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 자극하는 강렬하고 묵직한 아로마입니다. 짙은 캐러멜 토피와 바닐라 빈의 향 뒤로 오래된 가죽 책, 시가 박스의 진한 우디 향이 피어오르고, 잘 익은 살구와 옥수수 시럽 고유의 단 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "혀끝을 자극적으로 조여오는 진득하고 오일리한 풀바디 질감입니다. 브라운 슈가, 꿀을 가득 머금은 다크 초콜릿의 단맛이 먼저 입안을 채우고, 뒤이어 cracked 블랙페퍼, 계피, 구운 생강의 알싸한 오크 스파이스가 혀를 정교하게 타격합니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 데워주는 듯한 길고 드라이한 피날레입니다. 나무 벽면에서 추출한 묵직한 오크의 우디 향과 에스프레소의 잔향 뒤로, 입안 전체를 끈질기게 지배하는 따뜻한 베이킹 스파이스의 여운이 길게 지속됩니다."}}' WHERE id = 174;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (175, '메이커스 마크 46', 'bourbon', 'Maker\'s Mark Whiskey', 'whiskey/5098.jpg', 47.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Maker\'s Mark 46 70cl', 64402, 'https://www.masterofmalt.com/whiskies/makers-mark/makers-mark-46-whisky/?sku=5098', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "메이커스 마크 46(Maker\'s Mark 46)은 증류소의 장인 정신과 창의적인 오크통 실험이 집약된 최상위 정규 프리미엄 버번 위스키입니다. 호밀 대신 밀을 사용하여 극상의 부드러움을 자랑하는 메이커스 마크 고유의 하우스 스타일에 한층 더 다채롭고 화사한 풍미 레이어를 입혀 47%의 높은 도수 안에서 완벽한 명품의 품격을 뿜어냅니다.", "제조 및 숙성": "전통적인 붉은 겨울 밀(Wheated Bourbon) 원액을 버진 오크통에서 온전히 숙성시킨 후 원액을 비워냅니다. 그 오크통 내부에 프랑스산 최고급 리무쟁 오크 스태브(French Oak Staves) 10장을 결합하여 원액을 다시 채워 넣고 서늘한 석회암 지하 창고에서 추가 피니시 숙성을 거쳤습니다."}, "feature": {"프렌치 오크 스태브 46번": "수많은 실험 번호 중 가장 경이로운 맛을 선사했던 46번째 프랑스산 오크 스태브 레시피를 전면에 내세운 마스터피스입니다.", "위티드 버번의 우아함": "호밀 특유의 매운맛 대신 밀 고유의 부드럽고 크리미한 단맛을 극대화하여 벨벳처럼 매끄러운 텍스처를 구현했습니다.", "지하 창고의 미학": "온도 변화가 차단된 서늘한 석회암 동굴 창고 숙성을 통해 거친 알코올 부즈 없이 풍성한 오일감과 깊은 단맛을 가득 채웠습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 갓 피어난 자스민 같은 화사한 플로럴 아로마와 진한 바닐라 크림, 메이플 시럽의 향이 피어오릅니다. 뒤이어 상큼한 말린 오렌지 껍질과 프랑스산 오크 특유의 세련된 삼나무, 토스트의 고소함이 조화롭게 다가옵니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 매끄럽고 깊은 풍미가 가득 차오르는 마우스필입니다. 감미로운 캐러멜 토피와 밀크 초콜릿, 졸인 황도 복숭아의 진한 단맛이 먼저 입안을 채우고 시나몬 가루, 육두구의 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 프렌치 오크 특유의 상큼한 단맛 흔적과 베이킹 스파이스의 잔향이 가라앉으며, 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 잔향과 함께 머눕니다."}}' WHERE id = 175;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (176, '메이커스 마크', 'bourbon', 'Maker\'s Mark Whiskey', 'whiskey/2671.jpg', 45.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Maker\'s Mark 70cl', 48312, 'https://www.masterofmalt.com/whiskies/makers-mark-whiskey/?sku=2671', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "메이커스 마크(Maker\'s Mark)는 미국 켄터키주에서 생산되는 프리미엄 스트레이트 버번 위스키로, 전형적인 빨간 왁스 밀봉 바틀 디자인으로 전 세계적인 사랑을 받는 아이코닉 제품입니다. 버번 위스키가 가질 수 있는 극상의 부드러움을 표현하기 위해 호밀 대신 밀을 선택한 대표적인 주류이며, 45% 도수 안에서 한결같은 완성도를 전합니다.", "제조 및 숙성": "옥수수 70%, 붉은 겨울 밀(Wheated) 16%, 몰트 14%의 독창적인 매시빌 레시피를 고수하여 증류합니다. 안쪽을 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크에서 숙성되며, 창고 내부의 상층부와 하층부 캐스크 위치를 수작업으로 직접 순환시키는 엄격한 로테이션 숙성 방식을 거쳐 균일한 품질을 확보합니다."}, "feature": {"위티드 버번의 정석": "호밀 고유의 거칠고 매운맛 대신 밀 특유의 크리미하고 달콤한 맥아 맛을 극대화하여 벨벳처럼 매끄러운 텍스처를 구현했습니다.", "수작업 왁스 실링": "모든 보틀의 상단 부분을 장인들이 직접 뜨거운 붉은 왁스에 담가 밀봉하기 때문에, 전 세계 단 한 병도 똑같은 왁스 눈물 자국이 없습니다.", "장인 정신의 아이콘": "기계식 대량 생산을 배제하고 전통 방식을 고수하는 소량 생산(Small Batch) 크래프트 위스키의 위대한 선구자로 통합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 바닐라 크림과 풍부한 캐러멜 토피, 구운 맥아의 고소한 향이 먼저 코를 반깁니다. 뒤이어 상큼한 노란 사과, 서양 배의 시트러스 아로마와 은은한 오크통 특유의 그을린 나무 향이 조화롭게 다가옵니다.", "맛 (Palate)": "입안에 닿는 느낌이 매끄럽고 실크처럼 가볍게 굴러갑니다. 벌꿀 집의 단맛과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 중심을 잡고, 뒤이어 오크통에서 배어 나온 가벼운 계피, 시나몬의 부드러운 우드 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 산뜻하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 176;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (177, '메이커스 마크 셀러 에이지드', 'bourbon', 'Maker\'s Mark Whiskey', 'whiskey/142813.jpg', 56.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Maker\'s Mark Cellar Aged 2025 Release 70cl', 245792, 'https://www.masterofmalt.com/whiskies/makers-mark/makers-mark-cellar-aged-2025-release-whisky/?sku=142813', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "메이커스 마크 셀러 에이지드(Maker\'s Mark Cellar Aged)는 증류소 역사상 최초로 공식 숙성 연수를 대폭 상향하여 출시한 하이엔드 울트라 프리미엄 버번 위스키입니다. 브랜드가 고집해 온 부드러운 밀 버번의 캐릭터에 반세기에 가까운 세월의 깊이를 입혀 배치별로 약 57% 안팎의 강력한 캐스크 스트렝스로 병입해 낸 마스터피스입니다.", "제조 및 숙성": "전통적인 붉은 겨울 밀 원액을 일반 버번 배럴 창고에서 약 6년 동안 기본 숙성시킵니다. 이후 온도 변화가 철저히 통제되는 증류소 고유의 지하 석회암 셀러(Limestone Cellar)로 통째로 옮겨 담아 최종 5~6년을 추가로 장기 장착하여 총 11~12년 동안 장기 숙성시켰습니다."}, "feature": {"역사적인 고연산 라인": "위스키가 너무 오래 숙성되면 나무의 떫은 타닌이 과해진다는 편견을 깨기 위해 서늘한 지하 동굴 창고 숙성을 최초로 시도한 혁신적인 보틀입니다.", "무여과 캐스크 스트렝스": "물을 섞지 않고 오크통 원액 그대로 추출하여 병입했기 때문에, 장기 숙성 밀 버번 특유의 촘촘한 풍미 밀도와 묵직한 오일감을 고스란히 간직하고 있습니다.", "귀족적인 밸런스": "11년이 넘는 기나긴 세월 속에서도 거칠거나 매운 스파이스는 완벽히 정제되었고, 극상의 중후함과 우아함의 정점을 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 오래된 가죽 책, 말린 자두, 무화과 잼의 농축된 향이 깊게 퍼지고, 뒤이어 고급스러운 샌달우드 향, 정제된 밀랍, 서양란의 화사함과 흑설탕에 졸인 오렌지 껍질의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 자두의 단맛이 기품 있게 전개되며, 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 와인의 단맛 뒤로 고급 시가 박스의 우디한 향, 에스프레소의 잔향과 마지막까지 남는 따뜻한 베이킹 스파이스의 잔향이 끝없이 지속됩니다."}}' WHERE id = 177;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (178, '메이커스 마크 CS', 'bourbon', 'Maker\'s Mark Whiskey', 'whiskey/103084.jpg', 55.1, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Maker\'s Mark Cask Strength 70cl', 119509, 'https://www.masterofmalt.com/whiskies/makers-mark/makers-mark-cask-strength-55-05-whiskey/?sku=103084', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "메이커스 마크 캐스크 스트렝스(Maker\'s Mark Cask Strength)는 가수 공정 없이 오크통 속 원액 그대로를 다이렉트로 병입하여, 증류소 고유의 크리미한 부드러움을 가장 파워풀하고 진득한 텍스처로 느낄 수 있는 하이엔드 익스프레션입니다. 배치별로 보통 54%에서 57% 안팎의 폭발적인 도수를 자랑합니다.", "제조 및 숙성": "자사 특제의 밀 버번 매시빌 원액을 안쪽을 강렬하게 차링한 뉴 아메리칸 화이트 오크 캐스크에서 수년간 숙성시킵니다. 장인들이 까다롭게 선별한 최상위 소량의 배럴 묶음 원액을 물 단 한 방울도 섞지 않고, 냉각 여과 공정 없이 내추럴 컬러 그대로 병입해 완성합니다."}, "feature": {"순수한 캐스크 스트렝스": "가수 공정이 없는 고도수에서 뿜어져 나오는 폭발적인 타격감과 입안을 끈적하게 코팅하는 농밀한 마우스필의 진수를 보여줍니다.", "위티드 버번의 정수": "높은 알코올 볼륨감 덕분에 호밀 ex-버번들과 차별화되는 밀 특유의 진한 버터스카치, 브라운 슈가, 맥아 단맛이 압도적인 밀도로 전해집니다.", "내추럴 무여과 구성": "색소 첨가나 인위적인 필터 가공을 거치지 않아 원액 본연의 진하고 진득한 호박색 자태와 화려한 복합 레이어를 완벽히 보존했습니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 자극하는 강렬하고 달콤한 캐러멜 토피와 짙은 바닐라 빈, 메이플 시럽 아로마가 폭발적입니다. 뒤이어 구운 마시멜로, 브라운 슈가의 진한 단향과 버진 오크 특유의 묵직한 가죽, 그을린 장작 향이 조화롭게 어우러집니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 진득하고 오일리한 풀바디 바디감이 일품입니다. 진한 밤꿀과 옥수수 시럽, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고, 시나몬 가루, 구운 생강, 육두구의 알싸하고 매운 오크 스파이스가 기품 있는 타격감을 선사합니다.", "여운 (Finish)": "도수에 걸맞게 가슴 깊은 곳까지 따뜻해지는 극도로 길고 중후한 피날레입니다. 오크통 특유의 풍부한 우디 향과 캐러멜의 달콤한 흔적이 가라앉으며, 입안 가득 기분 좋은 드라이함과 스파이스의 잔향을 깊고 중후하게 머금으며 마무리됩니다."}}' WHERE id = 178;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (179, '메이커스 마크 101 Proof', 'bourbon', 'Maker\'s Mark Whiskey', 'whiskey/110836.jpg', 50.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 1000.0, 'Maker\'s Mark 101 Proof 100cl', 107039, 'https://www.masterofmalt.com/whiskies/makers-mark/makers-mark-101-proof-whiskey/?sku=110836', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "메이커스 마크 101 프루프(Maker\'s Mark 101 Proof)는 주로 글로벌 면세 시장이나 스페셜 에디션으로 제한 출시되어 위스키 매니아들의 뜨거운 갈증을 해소해 준 프리미엄 버번 위스키입니다. 정확히 50.5%의 높은 도수로 결합되어, 오리지널 제품 특유의 화사함에 단단한 타격감과 구조감을 입혀 완성한 작품입니다.", "제조 및 숙성": "붉은 겨울 밀을 주축으로 삼은 자사 고유의 위티드 매시빌 스피릿을 기반으로 증류합니다. 안쪽을 헤비 차링한 새 화이트 오크 캐스크에서 장인들의 철저한 수작업 로테이션 방식을 통해 최소 4년 이상 온전히 숙성시킨 후, 정확히 101프루프 규격에 맞추어 병입했습니다."}, "feature": {"101 프루프의 황금 비율": "가수 공정을 정밀하게 제한하여 메이커스 마크 고유의 실키함과 높은 알코올 파워가 가장 이상적인 균형을 이루도록 설계되었습니다.", "밀 버번 고유의 진득함": "일반 데일리 라인업의 가벼운 바디감을 보완하여, 입안 전체를 꽉 차게 조여오는 듯한 농밀한 토피 단맛과 중후함을 선사합니다.", "컬렉터를 위한 가치": "과거 패밀리 및 VIP 증류소 방문객들에게만 소량 제공되던 전통 배합 규격을 그대로 이식하여 소장 및 선물용으로 인기가 높습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 진득한 아로마가 가득 피어오릅니다. 구운 오크와 향긋한 바닐라 크림, 메이플 시럽의 향 뒤로 말린 살구, 건포도, 그리고 상큼한 말린 오렌지 껍질의 시트러스 아로마가 우아하고 복합적으로 피어오릅니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 매끄럽고 깊은 풍미가 가득 차오르는 질감입니다. 진한 브라운 슈가, 밀크 초콜릿, 졸인 황도 복숭아의 단맛이 먼저 입안을 채우고 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 잔향과 함께 머눕니다."}}' WHERE id = 179;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (180, '닛카 위스키 프롬 더 배럴', 'blended', 'Nikka Whisky', 'whiskey/2697.jpg', 51.4, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 500.0, 'Nikka Whisky From The Barrel 50cl', 71034, 'https://www.masterofmalt.com/whiskies/nikka/nikka-whisky-from-the-barrel-whisky/?sku=2697', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 위스키 프롬 더 배럴(Nikka From The Barrel)은 일본 위스키의 아버지 타케츠루 마사타카의 유산을 이어받은 닛카(Nikka) 가문이 자랑하는 세계적인 명성의 고도수 블렌디드 위스키입니다. 물을 최소한으로 섞어 오크통 내부의 에너지를 그대로 보존했으며 사각형 보틀 디자인과 함께 51.4% 도수 속에서 폭발적인 화력을 선사합니다.", "제조 및 숙성": "닛카 가문이 보유한 요이치 증류소의 묵직한 헤비 피트 몰트 원액과 미야기쿄 증류소의 화사한 논피트 몰트 원액, 그리고 특제 코프 스틸(Coffey Still)에서 뽑아낸 밀도 높은 그레인 위스키 원액 등 100종 이상의 캐스크를 결합했습니다. 블렌딩 후 서로 다른 오크통에 다시 채워 넣어 수개월간 재숙성(Marriage) 과정을 거쳤습니다."}, "feature": {"51.4%의 강력한 파워": "재패니즈 블렌디드 중 이례적인 고도수 세팅 덕분에 몰트 고유의 묵직함과 그레인의 실키함이 파워풀하게 충돌합니다.", "독창적인 재매링 공정": "서로 다른 성향의 원액들을 단순히 섞는 것을 넘어, 오크통에서 다시 함께 숨 쉬게 하여 깊고 세련된 복합미를 완성했습니다.", "미학적 사각 보틀": "세계적인 그래픽 디자이너 사토 타쿠가 디자인한 미니멀하고 기하학적인 사각형 보틀 패키지로 시각적 압도감을 자랑합니다."}}', note = '{"note": {"향 (Nose)": "화려하고 복합적인 아로마가 가득 퍼집니다. 짙은 바닐라 빈과 캐러멜 토피 향 뒤로 신선한 배, 오렌지 껍질의 시트러스가 퍼지고 요이치 몰트 특유의 은은한 가죽 향과 옅은 석탄 연기 같은 피트 스모크가 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 진득하고 오일리하게 가득 채우는 풀바디 마우스필입니다. 진한 밤꿀과 다크 초콜릿, 졸인 자두의 단맛이 파도처럼 밀려오고, 뒤이어 cracked 블랙페퍼, 구운 생강, 시나몬의 알싸한 오크 스파이스가 혀 위에서 역동적으로 전개됩니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 매우 길게 이어집니다. 오크통의 우디한 잔향과 에스프레소의 쌉싸름함이 가라앉으며, 입안 전체를 감싸는 은은하고 향긋한 캠프파이어의 재 잔향이 짙은 여운을 선사합니다."}}' WHERE id = 180;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (181, '닛카 코피 그레인', 'etc', 'Nikka Whisky', 'whiskey/32316.jpg', 45.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Nikka Coffey Grain Whisky 70cl', 93207, 'https://www.masterofmalt.com/whiskies/nikka/nikka-coffey-grain-whisky-70cl/?sku=32316', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 코피 그레인(Nikka Coffey Grain)은 닛카 위스키 가문의 전설적인 기술력과 헤리티지를 대변하는 프리미엄 그레인 위스키입니다. 일반적인 그레인 위스키는 블렌딩용 기저 원액으로만 취급받던 고정관념을 깨부수고, 단독 제품으로서 전 세계 위스키 평론가들에게 극상의 실키한 부드러움과 바닐라 단맛을 인정받아 45% 도수 안에서 확실한 독창성을 자랑합니다.", "제조 및 숙성": "1963년 일본 위스키의 아버지 타케츠루 마사타카가 스코틀랜드에서 직접 도입한 유서 깊은 전통 연속식 증류기인 \'코피 스틸(Coffey Still)\'을 사용하여 증류합니다. 옥수수를 주원료로 증류한 스피릿을 최고급 아메리칸 리필 버번 캐스크에서 수년간 안정적으로 숙성시켜 완성했습니다."}, "feature": {"전통 코피 스틸의 미학": "현대적인 다단식 증류기보다 효율은 낮지만, 원액 내부 고유의 묵직하고 리치한 오일리함과 곡물 본연의 달콤한 에스테르를 고스란히 남겨둡니다.", "그레인 위스키의 재발견": "가볍고 단조로운 저가형 그레인 위스키들과 완전히 결이 다른, 촘촘한 질감과 진득한 캐러멜 토피 풍미의 레이어를 전면에 내세웠습니다.", "실키한 목 넘김의 표준": "알코올의 날카로운 타격감이 전혀 없이 부드럽게 넘어가 니트로 즐겨도 훌륭하며, 올드 패션드 등 칵테일 베이스로 뛰어난 존재감을 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 시럽과 바닐라 빈, 메이플 시럽의 단향이 직관적으로 코를 자극합니다. 뒤이어 상큼한 바나나, 망고 같은 열대 과일 아로마와 구운 토스트의 고소함이 조화롭고 산뜻하게 피어오릅니다.", "맛 (Palate)": "입안을 실크나 밤꿀처럼 매끄럽고 크리미하게 감싸 안는 마우스필이 일품입니다. 브라운 슈가의 달콤함과 버터스카치, 멜론의 과일 풍미가 중심을 잡고 뒤이어 오크통의 은은한 우디함과 가벼운 생강, 시나몬 스파이스가 부드러운 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 고유의 감미로운 바닐라 흔적과 은은한 옥수수 특유의 고소한 단맛이 서서히 가라앉으며 입안을 산뜻하게 정돈해 줍니다."}}' WHERE id = 181;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (182, '닛카 코피 몰트', 'single_malt', 'Nikka Whisky', 'whiskey/36723.jpg', 45.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Nikka Coffey Malt Whisky 70cl', 103317, 'https://www.masterofmalt.com/whiskies/nikka/nikka-coffey-malt-whisky/?sku=36723', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 코피 몰트(Nikka Coffey Malt)는 싱글 몰트 위스키의 주원료인 100% 보리 맥아만을 사용하면서도, 스코틀랜드 전통 단식 증류기가 아닌 연속식 증류기를 사용하여 완성시킨 위스키 세계의 가장 독창적이고 파격적인 익스프레션입니다. 45% 도수로 병입되며 몰트 위스키가 가질 수 있는 극상의 부드러운 단맛과 풍성한 볼륨감을 뽐냅니다.", "제조 및 숙성": "100% 몰트(Malted Barley) 보리만을 사용하여 자사의 보물인 전통 연속식 \'코피 스틸\' 증류기를 통해 증류해 냈습니다. 일반적인 싱글 몰트보다 정밀하고 맑게 걸러진 스피릿을 최고급 아메리칸 화이트 오크 캐스크에서 수년간 숙성시켜 블렌딩조에서 완성했습니다."}, "feature": {"몰트와 코피 스틸의 도킹": "법적 규제상 싱글 몰트로 표기할 수는 없으나, 100% 보리 맥아를 연속식으로 증류하여 부드러운 텍스처와 몰트 고유의 고소함을 동시에 획득한 혁신작입니다.", "크리미한 디저트 프로파일": "새로운 시도를 통해 기존 스페이사이드 위스키들과 차별화되는 리치한 바닐라 케이크, 구운 코코넛 본연의 이국적인 달콤함을 확보했습니다.", "완벽한 육각형 밸런스": "높은 알코올 볼륨감 속에서도 자극적인 부즈를 완벽하게 정제하여, 부드러운 단맛과 우디함이 완벽한 대칭과 균형을 이룹니다."}}', note = '{"note": {"향 (Nose)": "향긋하고 진득한 아로마가 퍼집니다. 부드러운 바닐라 포드, 밀크 초콜릿, 캐러멜 토피 향 뒤로 상큼한 레몬 제스트, 신선한 바나나, 서양 배의 시트러스 아로마와 구운 견과류의 고소한 아로마가 감미롭게 어우러집니다.", "맛 (Palate)": "혀끝을 실크처럼 매끄럽고 크리미하게 코팅하는 훌륭한 질감이 돋보입니다. 벌꿀 집의 단맛과 브라운 슈가, 졸인 황도 복숭아의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 시나몬 가루, 구운 생강의 알싸한 우드 스파이스가 기분 좋은 레이어를 만듭니다.", "여운 (Finish)": "온화하고 긴 감미로운 여운을 선사합니다. 오크통의 우디한 향과 바닐라 캐러멜의 달콤한 흔적이 가라앉으며 입안에 기분 좋은 드라이함과 스파이스의 잔향을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 182;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (183, '닛카 데이즈', 'blended', 'Nikka Whisky', 'whiskey/87186.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Nikka Days 70cl', 64402, 'https://www.masterofmalt.com/whiskies/nikka/nikka-days-whisky/?sku=87186', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 데이즈(Nikka Days)는 일상 속에서(Days) 언제 어디서나 위스키를 가볍고 경쾌하게 즐기고자 하는 현대인들의 캐주얼한 라이프스타일을 타겟으로 출시된 뉴에이지 블렌디드 위스키입니다. 40% 도수로 가볍게 세팅되어 부담 없이 즐길 수 있으면서도 닛카 고유의 화사함과 은은한 복합미를 전합니다.", "제조 및 숙성": "자사 특제의 미야기쿄 증류소 화사한 논피트 몰트 원액과 맑은 그레인 위스키 원액을 주축으로 삼고, 요이치 증류소의 묵직한 피트 원액을 아주 미량 결합했습니다. 주로 리필 아메리칸 오크 배럴에서 숙성되어 오크통의 간섭을 줄이고 원액 본연의 밝은 생동감을 살렸습니다."}, "feature": {"일상 속의 이지드링킹": "투명하고 밝은 보틀 디자인과 함께 니트, 하이볼, 온더락 등 어떤 방식으로 즐겨도 편안하고 상쾌하게 다듬어진 대중적인 위스키입니다.", "미야기쿄와 요이치의 조화": "미야기쿄의 싱그러운 과일 단맛 기저 위에 요이치 특유의 은은한 스모키 아로마를 아주 미풍처럼 가미하여 숨겨진 깊이를 더했습니다.", "독보적인 가성비": "부담 없는 가격대에서 일본 위스키 장인들의 정교한 블렌딩 노하우와 화사하고 산뜻한 마우스필을 캐주얼하게 경험하기에 최적화되어 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 꽃향기가 가득 퍼집니다. 갓 피어난 화이트 플라워, 신선한 청사과, 레몬 시트러스 아로마 뒤로 부드러운 꿀, 바닐라 크림 고유의 단 향과 미세하게 깔리는 은은한 모닥불 연기 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 가볍고 부드럽게 굴러가는 질감입니다. 달콤한 벌꿀과 캐러멜 시럽, 잘 익은 서양 배의 풍미가 느껴지며 뒤이어 구운 보리의 고소함과 오크통에서 배어 나온 가벼운 화이트 페퍼 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 가벼운 나무 스파이스의 따뜻함과 바닐라 캐러멜의 달콤함, 그리고 은은하게 흩어지는 마른 피트의 연기 흔적이 입안을 산뜻하게 정돈해 주며 산뜻하게 마무리됩니다."}}' WHERE id = 183;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (184, '닛카 타케츠루 퓨어 몰트', 'blended', 'Nikka Whisky', 'whiskey/104826.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Nikka Taketsuru Pure Malt 70cl', 101689, 'https://www.masterofmalt.com/whiskies/nikka/nikka-taketsuru-pure-malt-2020-release-whisky/?sku=104826', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 타케츠루 퓨어 몰트(Nikka Taketsuru Pure Malt)는 일본 위스키의 전설적인 개척자 타케츠루 마사타카의 이름을 전면에 내세운 닛카 가문의 시그니처 프리미엄 블렌디드 몰트 위스키입니다. 그레인 위스키를 일절 섞지 않고 100% 몰트 원액들로만 구성되어 43% 도수 속에서 독보적인 기품과 강렬한 깊이감을 자랑합니다.", "제조 및 숙성": "서로 다른 극명한 성향을 지닌 두 증류소의 합작품입니다. 대서양 해풍을 맞으며 전통 석탄 직화 증류 방식을 고수하는 요이치(Yoichi) 증류소의 묵직한 헤비 피트 몰트 원액과, 스페이사이드 스타일의 목이 긴 증류기를 사용하는 미야기쿄(Miyagikyo) 증류소의 화사한 논피트 셰리 몰트 원액을 마스터 블렌더가 정교하게 블렌딩했습니다."}, "feature": {"100% 퓨어 몰트의 위엄": "그레인 위스키의 간섭 없이 오직 최고급 몰트 스피릿 고유의 진한 고소함과 묵직한 바디감을 최고 수준으로 이끌어냈습니다.", "요이치와 미야기쿄의 오케스트라": "요이치의 투박한 석탄 타르 피트 스모크와 미야기쿄의 화사한 사과, 건포도 셰리 풍미가 완벽한 대칭과 황금 균형을 이룹니다.", "일본 위스키 거장의 헤리티지": "타케츠루의 위대한 유산과 블렌딩 미학을 계승하는 아이코닉 보틀로서 전 세계 위스키 평론가들에게 한결같은 극찬을 받습니다."}}', note = '{"note": {"향 (Nose)": "풍부하고 묵직한 아로마가 가득 퍼집니다. 진한 건포도, 말린 무화과, 셰리 캐스크 특유의 달콤한 토피 향 뒤로 오래된 가죽, 시가 박스의 우디함과 요이치 몰트 고유의 향긋한 바닷바람 섞인 피트 스모크 향이 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 진득하고 오일리하게 가득 채우는 풀바디 마우스필입니다. 다크 초콜릿, 졸인 황도 복숭아, 벌꿀 집의 진한 단맛이 파도처럼 밀려오고 구운 피칸의 고소함과 cracked 블랙페퍼, 구운 생강의 알싸한 오크 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 이어집니다. 농축된 셰리의 단맛과 고급 나무 풍미가 가라앉으며 입안 가득 맴도는 건조하고 향긋한 캠프파이어의 연기 잔향이 묵직하고 따뜻하게 인상적인 피날레를 장식합니다."}}' WHERE id = 184;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (185, '슈퍼 닛카', 'blended', 'Nikka Whisky', 'whiskey/10011.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Super Nikka 70cl', 80941, 'https://www.masterofmalt.com/whiskies/nikka/super-nikka-whisky/?sku=10011', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "슈퍼 닛카(Super Nikka)는 1962년 창립자 타케츠루 마사타카가 사별한 스코틀랜드인 아내 리타(Rita)를 향한 불멸의 사랑과 깊은 그리움을 담아 빚어낸 역사적이고 애틋한 유산을 지닌 클래식 프리미엄 블렌디드 위스키입니다. 43% 도수로 병입되며 전통적인 재패니즈 블렌디드의 클래식하고 묵직한 매력을 선사합니다.", "제조 및 숙성": "타케츠루 마사타카가 아내를 기리며 증류소 내부의 가장 진귀한 올드 올로로소 셰리 오크통 몰트 원액과 장기 숙성된 ex-버번 배럴 원액, 그리고 실키한 그레인 위스키 원액을 직접 심혈을 기울여 황금 비율로 블렌딩했습니다. 전통적인 매링조에서 오랜 시간 조율 과정을 거쳐 탄생합니다."}, "feature": {"불멸의 사랑에 대한 헌정": "타케츠루 마사타카의 개인적인 스토리텔링과 슬픔이 집약된 위스키로, 아름답고 기하학적인 프리미엄 디켄터 모양 보틀에 담겨 깊은 역사를 전달합니다.", "전통적인 셰리 버번 밸런스": "최고급 셰리의 진한 건포도 단맛에 버번 배럴 특유의 풍부한 바닐라 향이 결합되어 어느 한쪽으로 치우치지 않는 대칭을 이룹니다.", "정제된 라운드감": "오랜 숙성 세월의 블렌딩 노하우 덕분에 알코올의 거친 부즈는 완벽히 정제되었고, 실크처럼 부드러운 목 넘김과 은은한 피트 힌트를 전합니다."}}', note = '{"note": {"향 (Nose)": "깊고 온화한 아로마가 가득 피어오릅니다. 달콤한 캐러멜 토피와 바닐라 포드, 밤꿀 향 뒤로 말린 살구, 건포도와 함께 은은하게 기저에 깔리는 부드러운 오래된 오크의 나무 향과 미세한 스모키 뉘앙스가 조화롭게 다가옵니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳처럼 매끄럽고 크리미한 바디감을 줍니다. 브라운 슈가의 진한 단맛과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 중심을 잡고 구운 견과류의 고소함과 가벼운 시나몬, 생강의 부드러운 우드 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "깔끔하면서도 긴 온화한 잔향을 남깁니다. 오크통에서 배어 나온 감미로운 캐러멜 단맛과 우디함이 서서히 가라앉으며 입안 전체를 따뜻하고 산뜻하게 정돈해 주며 매끄럽게 마무리됩니다."}}' WHERE id = 185;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (186, '닛카 테일러드', 'blended', 'Nikka Whisky', 'whiskey/104266.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'The Nikka Tailored 70cl', 178847, 'https://www.masterofmalt.com/whiskies/nikka/the-nikka-tailored-whisky/?sku=104266', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 테일러드(Nikka Tailored)는 닛카 위스키 가문의 유서 깊은 블렌딩 기술과 장인 정신을 집약하여 탄생시킨 프리미엄 재패니즈 블렌디드 위스키입니다. 과거 증류소의 상징이었던 \'닛카 12년\' 제품의 단종 이후 그 명맥을 잇기 위해 출시되었으며, 43% 도수 속에서 극상의 부드러움과 우아한 중후함을 뽐냅니다.", "제조 및 숙성": "요이치 증류소의 묵직한 석탄 직화 피트 몰트 원액과 미야기쿄 증류소의 화사한 셰리 몰트 원액을 베이스로 삼습니다. 여기에 닛카의 시그니처인 전통 \'코피 스틸\' 연속식 증류기에서 뽑아낸 밀도 높은 그레인 위스키 원액을 정교하게 결합하여 매링 과정을 거쳤습니다."}, "feature": {"재단된 듯한 완벽한 밸런스": "이름 그대로 최고급 수트처럼 마스터 블렌더가 원액의 성향을 정밀하게 재단(Tailored)하여 한 치의 오차도 없는 조화를 구현했습니다.", "코피 그레인의 실키함": "닛카의 보물인 코피 그레인 원액 비율을 높여, 입안에 닿는 감각이 실크처럼 매끄럽고 고급스러운 질감을 자랑합니다.", "닛카 플래그십의 유산": "고급스러운 비대칭형 비주얼 보틀 패키지와 내추럴 골드 빛깔로 닛카 가문의 정통 프리미엄 블렌디드 계보를 증명합니다."}}', note = '{"note": {"향 (Nose)": "화사하고 진득한 아로마가 피어오릅니다. 달콤한 캐러멜 토피와 바닐라 포드, 밤꿀 향 뒤로 말린 살구, 건포도의 진한 과일 향과 은은한 오래된 오크의 고풍스러운 나무 향이 조화롭게 다가옵니다.", "맛 (Palate)": "혀끝에 닿는 느낌이 벨벳처럼 매끄럽고 크리미한 바디감을 줍니다. 브라운 슈가의 진한 단맛과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 중심을 잡고 구운 견과류의 고소함과 시나몬의 부드러운 우드 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "깔끔하면서도 긴 온화한 잔향을 남깁니다. 오크통에서 배어 나온 감미로운 캐러멜 단맛과 우디함이 서서히 가라앉으며 입안 전체를 따뜻하고 산뜻하게 정돈해 주며 매끄럽게 마무리됩니다."}}' WHERE id = 186;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (187, '닛카 세션', 'single_malt', 'Nikka Whisky', 'whiskey/133106.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Nikka Session 70cl', 169489, 'https://www.masterofmalt.com/whiskies/nikka/nikka-session-whisky/?sku=133106', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "닛카 세션(Nikka Session)은 일본 위스키의 거장 닛카와 스코틀랜드 하이랜드의 명문 증류소 원액을 정교하게 엮어낸 혁신적인 크로스오버 프리미엄 블렌디드 몰트 위스키입니다. 그레인 위스키를 일절 섞지 않고 100% 보리 맥아 원액들로만 구성되었으며 43% 도수 속에서 현대적이고 감각적인 음악적 하모니를 분출합니다.", "제조 및 숙성": "닛카 가문이 소유한 요이치 증류소의 강력한 피트 몰트와 미야기쿄 증류소의 화사한 논피트 몰트를 주축으로 삼습니다. 여기에 스코틀랜드 하이랜드 지역의 전설적인 벤 Nevis(Ben Nevis) 증류소에서 공수한 장기 숙성 프리미엄 몰트 원액을 마스터 블렌더의 황금 비율로 결합하여 매링했습니다."}, "feature": {"대륙을 넘은 크로스오버": "스코틀랜드 스피릿의 묵직한 오일리함과 일본 스피릿의 섬세한 터치가 한 보틀 안에서 기적 같은 하모니 세션을 펼칩니다.", "100% 몰트의 음악적 해석": "음악의 협주곡(Session)을 모티브로 삼아 대담한 피트 스모크와 화사한 과일 단맛이 독창적인 리듬감으로 충돌하도록 설계했습니다.", "감각적인 블루 바틀": "기존의 클래식한 호박색 유리병에서 탈피하여 청량하고 감각적인 프리미엄 블루 보틀 디자인으로 젊은 위스키 매니아들의 취향을 저격합니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 갓 피어난 자스민 같은 플로럴 아로마와 오렌지 껍질, 청사과의 시트러스가 퍼지고 그 기저에는 꿀을 바른 구운 토스트와 요이치 몰트 특유의 은은한 석탄 피트 스모크 향이 감미롭게 받쳐줍니다.", "맛 (Palate)": "입안을 매끄럽고 오일리하게 감싸 안는 실키한 질감이 돋보입니다. 졸인 황도 복숭아, 자두 잼, 캐러멜 시럽의 단맛이 퍼지고 뒤이어 벤네비스 원액 특유의 묵직한 몰트 고소함과 화이트 페퍼, 구운 생강의 알싸한 스파이스가 정교한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 매우 길게 이어집니다. 오크통의 우디한 잔향과 에스프레소의 쌉싸름함이 가라앉으며 입안 전체를 계속 감싸는 은은하고 향긋한 캠프파이어의 연기 잔향이 짙은 여운을 선사합니다."}}' WHERE id = 187;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (188, '야마자키 12년', 'single_malt', 'Yamazaki Whisky', 'whiskey/2713.jpg', 43.0, 12, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Yamazaki 12 Year Old 70cl', 237228, 'https://www.masterofmalt.com/whiskies/yamazaki-japanese/yamazaki-12-year-old-whisky/?sku=2713', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "야마자키 12년(Yamazaki 12 Year Old)은 일본 최초의 싱글 몰트 위스키 증류소인 야마자키의 독보적인 아이콘이자 전 세계 재패니즈 위스키 열풍의 중심에 선 위대한 클래식 교과서입니다. 국제 품평회에서 수많은 금메달을 휩쓸며 품질을 증명했으며, 43% 도수 속에서 차원이 다른 정교하고 고결한 아우라를 전합니다.", "제조 및 숙성": "일본 교토 외곽의 청정 수질을 자랑하는 야마자키 지역에서 증류한 원액을 베이스로 합니다. 아메리칸 화이트 오크 버번 배럴과 스페니시 오로로소 셰리 캐스크, 그리고 산토리 가문의 보물인 일본 특산 미즈나라(Mizunara) 오크통에서 최소 12년 동안 숙성된 원액들을 정밀하게 블렌딩했습니다."}, "feature": {"재패니즈 위스키의 나침반": "전 세계 싱글 몰트 시장에서 재패니즈 위스키 고유의 정체성과 가치를 명징하게 정립한 기념비적인 오리지널 보틀입니다.", "미즈나라 오크의 영혼": "진귀한 일본 백참나무 오크통 숙성을 통해 특유의 은은한 동양적인 침향, 사찰의 부드러운 향당 향 레이어를 선사합니다.", "독보적인 프리미엄 가치": "전 세계적인 극도의 원액 부족 현상으로 인해 현재 오픈런과 추첨제로만 구할 수 있는 소장 및 자산 가치가 극도로 높은 진귀한 명주입니다."}}', note = '{"note": {"향 (Nose)": "우아하고 복합적인 아로마가 가득 퍼집니다. 신선한 서양 배, 노란 사과의 시트러스 뒤로 미즈나라 오크 특유의 기품 있는 백단향, 오리엔탈 향이 피어오르고 감미로운 바닐라 크림과 꿀의 단향이 레이어를 형성합니다.", "맛 (Palate)": "실크나 벨벳을 혀에 얹은 듯 극도로 부드럽고 매끄러운 텍스처가 압권입니다. 벌꿀 집의 단맛과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 중심을 잡고 구운 아몬드의 고소함과 은은한 계피, 시나몬의 부드러운 우드 스파이스가 조화를 이룹니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 우아하며 감미로운 여운을 선사합니다. 농축된 과일의 단맛과 미즈나라 나무 고유의 향긋한 풍미가 가라앉으며 입안 가득 기품 있는 나무 잔향과 따뜻한 베이킹 스파이스의 흔적이 오래도록 머눕니다."}}' WHERE id = 188;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (189, '야마자키 25년', 'single_malt', 'Yamazaki Whisky', 'whiskey/24432.jpg', 43.0, 25, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Yamazaki 25 Year Old 70cl', 10002613, 'https://www.masterofmalt.com/whiskies/yamazaki/yamazaki-25-year-old-whisky/?sku=24432', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "야마자키 25년(Yamazaki 25 Year Old)은 산토리 위스키 가문이 보유한 초고연산 싱글 몰트 원액들 중 극상의 정수만을 엄선하여 소량 한정 생산하는 최상위 하이엔드 울트라 프리미엄 마스터피스입니다. 4분의 1세기가 넘는 기나긴 세월 동안 다듬어졌으며 43% 도수 안에서 인간이 도달할 수 있는 재패니즈 싱글 몰트의 절대적인 정점을 보여줍니다.", "제조 및 숙성": "과거 셰리 캐스크 중심의 설계에서 진화하여, 현재는 장기 숙성된 최상급 미즈나라 오크통 원액을 기저에 두고 유러피안 셰리 캐스크 원액과 아메리칸 버번 배럴 원액을 치밀하게 결합했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 병입했습니다."}, "feature": {"궁극의 울트라 프리미엄": "야마자키 정규 라인업 중 최고봉에 속하는 고귀한 마스터피스로서 매년 극소량만 발매되어 천문학적인 프리미엄 가치를 지닙니다.", "미즈나라와 셰리의 대서사시": "최고급 미즈나라 오크 고유의 중후한 침향과 유러피안 셰리의 녹진한 다크 프루트 단맛이 완벽한 대칭과 구도를 이룹니다.", "일본 장인 예술의 결정체": "정교한 커팅 디켄터 보틀과 일본 전통 수제 종이인 에치젠 와시 레이블, 그리고 전통 자색 매듭 끈으로 특제 패킹되어 독보적인 위엄을 자랑합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 깊은 아로마입니다. 오래된 마호가니 가구, 졸인 무화과, 말린 자두의 농축된 향이 깊게 퍼지고 뒤이어 미즈나라 오크 특유의 기품 있는 향당 향, 정제된 밀랍, 오래된 가죽 책의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "비단이나 밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 졸인 체리, 자두의 단맛이 기품 있게 전개되며 오래된 오크에서 배어 나온 시나몬, 육두구, 부드러운 오렌지 오일 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 여운입니다. 농축된 셰리와 미즈나라 나무 고유의 향긋한 풍미가 가라앉으며, 입안 전체를 계속 감싸는 감미로운 흔적과 잔잔한 에스프레소의 잔향이 끝없이 지속됩니다."}}' WHERE id = 189;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (190, '야마자키 디스틸러리 리저브', 'single_malt', 'Yamazaki Whisky', 'whiskey/31204.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Yamazaki Distiller’s Reserve 70cl', 127056, 'https://www.masterofmalt.com/whiskies/yamazaki/the-yamazaki-single-malt-whisky-distillers-reserve-whisky/?sku=31204', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "야마자키 디스틸러리 리저브(Yamazaki Distiller\'s Reserve)는 증류소의 고유한 정체성과 크래프트 노하우를 한층 더 젊고 생동감 넘치는 아로마로 풀어내어 대중적인 접근성을 넓힌 글로벌 시그니처 싱글 몰트 위스키입니다. 연산을 표기하지 않은 NAS 제품이지만 43% 도수 속에서 입안을 화사하게 가득 채우는 독보적인 하모니를 자랑합니다.", "제조 및 숙성": "마스터 블렌더의 정밀한 안목에 따라 선별된 다양한 오크통 원액들을 블렌딩했습니다. 상큼한 과일 향을 내는 와인 캐스크(Wine Casks) 숙성 원액과 녹진한 셰리 캐스크 원액, 그리고 젊고 활력 넘치는 미즈나라 오크통 원액을 유기적으로 결합하여 완성했습니다."}, "feature": {"와인 캐스크의 화려한 변주": "산토리 가문의 와이너리 노하우가 집약된 특제 와인 오크통 숙성 원액을 터치하여 독창적이고 상큼한 딸기, 체리 고유의 붉은 과수원 풍미를 확보했습니다.", "미즈나라 터치의 대중화": "고연산 제품에서만 느낄 수 있던 야마자키 시그니처 미즈나라 특유의 향당 향 레이어를 산뜻하게 주입하여 밸런스를 잡았습니다.", "상쾌하고 경쾌한 마우스필": "장기 숙성의 무거움을 덜어내고, 생기 넘치는 시트러스 과일 단맛과 부드러움이 공존하여 부담 없이 즐기기에 최적화되어 있습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 싱그러운 붉은 베리류 아로마가 가득 퍼집니다. 신선한 딸기, 체리, 말린 복숭아 향 뒤로 부드러운 캐러멜 토피, 바닐라 포드의 단 향과 함께 미즈나라 오크 고유의 은은한 향당 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 감싸 안는 실키한 질감이 돋보입니다. 벌꿀 집의 단맛과 달콤한 오렌지 마멀레이드, 과일 시럽의 단맛이 중심을 잡고 뒤이어 오크통에서 배어 나온 가벼운 시나몬, 화이트 페퍼의 부드러운 우드 스파이스가 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 아메리칸 오크 특유의 바닐라 단맛과 와인 캐스크 고유의 상큼한 과일 향이 가라앉으며 입안에 기분 좋은 드라이함과 우디한 스파이스의 흔적을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 190;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (191, '야마자키 18년', 'single_malt', 'Yamazaki Whisky', 'whiskey/2712.jpg', 43.0, 18, 'active', NOW(), NOW(), 'Japanese Whisky', '', 700.0, 'Yamazaki 18 Year Old 70cl', 998448, 'https://www.masterofmalt.com/whiskies/yamazaki-18-year-old-whisky/?sku=2712', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "야마자키 18년(Yamazaki 18 Year Old)은 전 세계 위스키 시장에서 재패니즈 싱글 몰트의 정수이자 독보적인 최고급 명품으로 통하는 거장급 익스프레션입니다. 18년이라는 기나긴 세월 동안 다듬어진 기품 있는 하우스 스타일에 셰리와 미즈나라 오크의 깊은 밀도를 정교하게 도킹하여, 43% 도수 속에서 완벽에 가까운 귀족적 아우라를 펼쳐 보입니다.", "제조 및 숙성": "교토 외곽의 서늘하고 축축한 야마자키 증류소 창고에서 최소 18년 이상 장기 숙성된 원액만을 엄선합니다. 마스터 블렌더의 치밀한 설계 아래 최고급 유러피안 오크 오로로소 셰리 캐스크 원액의 비율을 대폭 높이고, 산토리 가문의 유산인 일본 특산 미즈나라 오크통 원액을 황금 비율로 매링하여 완성했습니다."}, "feature": {"글로벌 셰리 피트의 거장": "국제 주류 품평회에서 \'세계 최고의 싱글 몰트\' 위상을 차지하며 전 세계 컬렉터들과 전문가들에게 독보적인 품질을 검증받았습니다.", "미즈나라와 셰리의 하모니": "유러피안 셰리통 고유의 묵직한 건포도 단맛과 미즈나라 오크 특유의 동양적인 백단향, 오리엔탈 향이 한 보틀 안에서 완벽한 평형을 이룹니다.", "희소성과 자산 가치": "전 세계적인 원액 고갈 현상으로 인해 현재는 구하기가 극도로 어려운 진귀한 올드 보틀이며, 위스키 재테크 시장에서 가장 뜨거운 상징물입니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 묵직한 아로마입니다. 흑설탕에 졸인 자두, 말린 무화과, 건포도의 짙은 셰리 향이 지배적으로 퍼지고 뒤이어 오래된 가죽, 시가 박스의 우디함과 미즈나라 오크 고유의 은은한 향당 향이 고결하게 피어오릅니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 벨벳처럼 매끄러운 풀바디 텍스처가 혀를 감쌉니다. 진한 다크 초콜릿, 구운 피칸의 고소함과 토피 당의 진한 단맛이 파도처럼 밀려오고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 우아한 피날레를 선사합니다. 농축된 셰리의 단맛과 미즈나라 나무 고유의 향긋함, 에스프레소의 잔향 뒤로 가슴 속 깊은 곳까지 데워주는 듯한 중후한 베이킹 스파이스의 잔향이 끝없이 지속됩니다."}}' WHERE id = 191;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (192, '와일드 터키 레어브리드', 'bourbon', 'Wild Turkey', 'whiskey/83741.jpg', 58.4, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Wild Turkey Rare Breed Bourbon (58.4%) 70cl', 92841, 'https://www.masterofmalt.com/whiskies/wild-turkey/wild-turkey-rare-breed-bourbon-58-4-percent-whiskey/?sku=83741', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "와일드 터키 레어브리드(Wild Turkey Rare Breed)는 물을 단 한 방울도 섞지 않고 오크통에서 꺼낸 원액 그대로를 병입하여, 버번 위스키 고유의 거칠고 파워풀한 타격감을 가장 순수하게 느낄 수 있는 배럴 스트렝스(Barrel Proof)의 바이블입니다. 배치별로 보통 58%에서 58.4% 안팎의 강력한 도수를 자랑하며 냉각 여과 없이 병입되어 묵직한 카리스마를 분출합니다.", "제조 및 숙성": "옥수수 75%, 호밀 13%, 몰트 12%로 구성된 자사 특제의 호밀 함량이 높은 매시빌을 사용하여 증류합니다. 안쪽을 가장 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크 \'알리게이터 차(Alligator Char)\' 등급에서 각각 6년, 8년, 12년 동안 숙성된 최상급 스트레이트 버번 원액들을 마스터 디스틸러가 정교하게 결합했습니다."}, "feature": {"타합 없는 배럴 프루프": "인위적인 가수 공정이 없는 고도수에서 뿜어져 나오는 폭발적인 타격감과 입안을 끈적하게 코팅하는 농밀한 마우스필의 진수를 보여줍니다.", "6, 8, 12년 원액의 오케스트라": "젊은 원액의 역동적인 생동감과 장기 숙성 원액 고유의 중후한 가죽, 오크 탄닌 풍미가 한 병 안에서 기적 같은 대칭과 균형을 이룹니다.", "버번 매니아들의 종교적 우상": "냉각 여과(Non-chill filtered) 과정을 과감히 배제하여 원액 본연의 진하고 진득한 호박색 자태와 화려하게 응축된 풍미 레이어를 고스란히 보존했습니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 자극하는 강렬하고 달콤한 캐러멜 토피와 짙은 바닐라 빈, 메이플 시럽 아로마가 폭발적입니다. 뒤이어 구운 마시멜로, 브라운 슈가의 진한 단향과 버진 오크 특유의 묵직한 가죽, 그을린 장작 향이 조화롭게 어우러집니다.", "맛 (Palate)": "입안 전체를 폭발적으로 자극하는 묵직하고 오일리한 풀바디 마우스필입니다. 진한 밤꿀과 옥수수 시럽, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고, 호밀 특유의 통후추 스파이스와 계피, 구운 생강의 매운 오크 스파이스가 혀를 정교하고 파워풀하게 타격합니다.", "여운 (Finish)": "도수에 걸맞게 가슴 깊은 곳까지 뜨겁게 데워주는 극도로 길고 중후한 피날레입니다. 오크통 특유의 풍부한 우디 향과 캐러멜의 달콤한 흔적이 가라앉으며, 입안 가득 기분 좋은 드라이함과 스파이스의 잔향을 깊고 중후하게 머금으며 마무리됩니다."}}' WHERE id = 192;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (193, '와일드 터키 101', 'bourbon', 'Wild Turkey', 'whiskey/2676.jpg', 50.5, 8, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Wild Turkey 101 70cl', 57547, 'https://www.masterofmalt.com/whiskies/wild-turkey-101-whiskey/?sku=2676', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "와일드 터키 101(Wild Turkey 101 Bourbon)은 전 세계 버번 위스키 시장에서 대담하고 투박한 미국 개척 시대 버번 본연의 정석을 가장 완벽하게 보여주는 영원한 베스트셀러이자 살아있는 전설입니다. 정확히 101프루프(50.5% ABV)의 높은 도수로 병입되어, 부담 없는 가성비 속에서도 타 브랜드를 압도하는 강력한 존재감과 화력을 뿜어냅니다.", "제조 및 숙성": "옥수수 75%를 주원료로 호밀과 몰트를 결합한 고유의 매시빌을 사용하여 낮은 도수로 증류해 냅니다. 원액을 오크통에 담을 때부터 도수를 낮게 세팅하여 안쪽을 악어 가죽처럼 강렬하게 태운 \'넘버 4 알리게이터 차\' 뉴 아메리칸 화이트 오크 캐스크에서 최소 6년에서 8년 동안 켄터키 기후 창고에서 숙성시킵니다."}, "feature": {"버번 위스키의 표준 나침반": "달콤함과 강렬한 타격감, 오크통 특유의 스파이시함이 가장 대중적으로 짜여 있어 수많은 버번 매니아들의 교과서이자 기준점으로 통합니다.", "낮은 증류 및 통입 도수": "증류 및 숙성 시 물을 많이 섞지 않는 전통 방식을 사수하여, 오크통 내부의 캐러멜과 바닐라 성분을 가감 없이 순수하게 액체 깊숙이 뽑아냈습니다.", "최고의 하이볼과 칵테일 벤치마크": "50.5%의 높은 도수 덕분에 탄산수나 콜라, 혹은 올드 패션드나 부도카레 같은 클래식 버번 칵테일 베이스로 활용해도 위스키 고유의 묵직한 캐릭터가 절대 묻히지 않습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 바닐라 크림과 옥수수 시럽, 진한 캐러멜 향이 직관적으로 코를 자극합니다. 그 투박한 달콤함 뒤로 뉴 오크통 특유의 그을린 장작 향, 호밀 특유의 향긋한 통후추와 민트 허브의 아로마가 대담하게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 순간 오일리하면서도 파워풀한 타격감을 줍니다. 브양이 진득한 흑설탕의 단맛과 구운 피칸의 고소함, 메이플 시럽의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 알싸한 블랙페퍼, 시나몬 스파이스가 혀 위에서 화려하게 전개됩니다.", "여운 (Finish)": "깔끔하면서도 가슴 속까지 온화해지는 묵직한 나무 잔향을 남깁니다. 버진 오크 캐스크 특유의 드라이한 탄닌과 캐러멜의 달콤한 흔적이 가라앉으며, 입안에 기분 좋은 드라이함과 오크 스파이스의 여운을 산뜻하게 남기며 가라앉습니다."}}' WHERE id = 193;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (194, '와일드 터키 81', 'bourbon', 'Wild Turkey', 'whiskey/13567.jpg', 40.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Wild Turkey 81 Proof 70cl', 43064, 'https://www.masterofmalt.com/whiskies/wild-turkey/wild-turkey-81-proof-whiskey/?sku=13567', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "와일드 터키 81(Wild Turkey 81 Bourbon)은 부드럽고 가벼운 이지드링킹 캐릭터를 지향하며, 버번 위스키 고유의 풍미는 잃지 않으면서도 대중적인 접근성을 극대화하기 위해 기획된 데일리 스트레이트 버번 위스키입니다. 정확히 81프루프(40.5% ABV) 도수로 세팅되어 부담 없이 캐주얼하게 즐기기 최적화되어 있습니다.", "제조 및 숙성": "101 제품과 동일한 고품질의 옥수수 및 호밀 매시빌 스피릿을 기반으로 증류합니다. 전설적인 마스터 디스틸러 에디 러셀이 직접 주도하여, 안쪽을 강렬하게 태운 새 아메리칸 화이트 오크 캐스크에서 최소 6년에서 8년 동안 안정적으로 숙성된 원액들을 한층 더 부드러운 텍스처로 블렌딩해 완성했습니다."}, "feature": {"신사를 위한 버번": "와일드 터키 가문 특유의 직관적이고 거친 타격감을 온화하게 정돈하여, 목 넘김이 실크처럼 부드럽고 편안한 라운드감을 선사합니다.", "데일리 밸런스의 정석": "바닐라의 달콤함과 은은한 나무 향이 과하지 않게 조화를 이루어, 피로감 없이 매일 밤 가볍게 니트나 온더락으로 마시기 좋습니다.", "하이볼을 위한 완벽한 파트너": "부담 없는 알코올 볼륨감 덕분에 위스키 입문자나 여성 애호가들이 레몬 제스트를 곁들인 청량한 버번 하이볼 베이스로 즐기기에 독보적인 만족감을 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 온화한 아로마가 코를 살포시 반깁니다. 신선한 바닐라 크림, 달콤한 꿀, 캐러멜 토피 향 뒤로 은은하게 정제된 노란 사과의 시트러스와 가벼운 호밀 특유의 민트, 구운 호두의 고소한 아로마가 조화롭게 다가옵니다.", "맛 (Palate)": "입안에서 매끄럽고 부드럽게 감싸 안는 마우스필이 일품입니다. 벌꿀 집의 부드러운 단맛과 메이플 시럽의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 가벼운 우디함과 계피, 화이트 페퍼의 부드러운 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 산뜻한 잔향을 남깁니다. 버진 오크 캐스크 고유의 감미로운 캐러멜 흔적과 부드러운 나무의 풍미가 서서히 가라앉으며 입안을 산뜻하고 깨끗하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 194;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (195, '와일드 터키 라이', 'rye', 'Wild Turkey', 'whiskey/41661.jpg', 40.5, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Wild Turkey Straight Rye (40.5%) 70cl', 54150, 'https://www.masterofmalt.com/whiskies/wild-turkey/wild-turkey-straight-rye-40-5-percent-whiskey/?sku=41661', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "와일드 터키 라이(Wild Turkey 101 Rye)는 금주법 이전 미국 위스키 시장의 주류였던 정통 아메리칸 스트레이트 라이 위스키의 대담하고 와일드한 화력을 고스란히 복원해 낸 크래프트 위스키입니다. 정확히 101프루프(50.5% ABV)의 강력한 고도수 구조를 채택하여 호밀 특유의 알싸한 후추 스파이스 타격감의 극치를 보여줍니다.", "제조 및 숙성": "법적 기준에 따라 호밀(Rye) 성분의 배치 비율을 51% 이상 높이고 옥수수와 몰트를 섞은 특제 라이 매시빌을 고수하여 증류합니다. 안쪽을 악어 가죽처럼 강렬하게 그을린 뉴 아메리칸 화이트 오크 캐스크에서 수년간 켄터키의 혹독한 기후 속에서 숙성시켜 원액 본연의 밀도를 높였습니다."}, "feature": {"101 라이의 압도적 파워": "옥수수의 진득한 단맛을 대폭 걷어내고, 호밀 고유의 알싸한 풀 내음, 민트, 허브, 으깬 통후추의 스파이시 타격감을 전면에 매섭게 내세웠습니다.", "차콜 멜로잉을 뛰어넘는 화력": "일반적인 테네시 스타일 라이와 달리 여과 공정 없이 버진 오크통에서 뿜어져 나오는 강력한 탄닌과 호밀 본연의 거친 에너지를 날것 그대로 전합니다.", "바텐더들의 클래식 드림": "50.5%의 탄탄한 알코올 볼륨감과 폭발적인 스파이스 덕분에 니트로 즐겨도 훌륭하며, 맨해튼이나 뉴올리언스 사제락 같은 정통 라이 위스키 칵테일 빌딩 시 독보적인 존재감을 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 대담한 아로마가 코를 직관적으로 자극합니다. 신선한 호밀 특유의 민트, 딜 같은 허브 향과 통후추의 매콤함이 전면에 나섭니다. 이내 가벼운 바닐라 포드, 브라운 슈가, 신선한 보리 맥아의 고소한 단 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "혓바닥을 자극적으로 조여오는 진득하고 오일리한 풀바디 텍스처입니다. 말린 살구, 토피 당의 진한 단맛이 중심을 잡고 뒤이어 계피, 육두구, cracked 블랙페퍼의 알싸한 라이 스파이스가 입안 가득 파도처럼 휘몰아칩니다.", "여운 (Finish)": "가슴 속 깊은 곳까지 데워주는 듯한 길고 드라이한 피날레입니다. 호밀 특유의 화사한 풀 잔향과 타버린 오크통의 우디함, 쌉싸름한 카카오의 흔적 뒤로 기분 좋은 바닐라의 단맛 미련이 오래도록 남으며 복합적으로 마무리됩니다."}}' WHERE id = 195;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (196, '와일드 터키 롱브랜치', 'bourbon', 'Wild Turkey', 'whiskey/92555.jpg', 43.0, 0, 'active', NOW(), NOW(), 'American Whiskey', '', 700.0, 'Wild Turkey Longbranch 70cl', 73312, 'https://www.masterofmalt.com/whiskies/wild-turkey/wild-turkey-longbranch-whiskey/?sku=92555', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "와일드 터키 롱브랜치(Wild Turkey Longbranch)는 전설적인 마스터 디스틸러 에디 러셀과 유명 배우 매튜 맥커너히(Matthew McConaughey)의 예술적인 협업으로 탄생한 프리미엄 스트레이트 버번 위스키입니다. 와일드 터키 특유의 대담하고 강렬한 캐릭터를 텍사스 감성의 독창적인 숯 여과 공법으로 감싸 안아, 43% 도수 속에서 극상의 부드러움과 온화함을 자랑합니다.", "제조 및 숙성": "안쪽을 가장 강렬하게 태운 뉴 아메리칸 화이트 오크 캐스크에서 최소 8년 동안 숙성된 최상급 와일드 터키 원액을 기반으로 합니다. 이 원액을 텍사스산 메스키트(Mesquite) 나무 숯과 켄터키산 사탕단풍나무 숯으로 구성된 독창적인 이중 정제 공정을 거쳐 완성했습니다."}, "feature": {"메스키트 숯의 마술": "텍사스를 상징하는 메스키트 나무 숯 여과를 통해 일반 버번 위스키에서 느낄 수 없는 독특하고 향긋한 스모키 풍미를 주입했습니다.", "8년 숙성의 세련미": "최소 8년 이상 오랜 세월 동안 다듬어진 원액을 사용하여, 와일드 터키 특유의 거친 타격감 대신 실크처럼 매끄러운 질감을 구현했습니다.", "이지드링킹 버번의 기준": "부담 없는 43% 도수와 감미로운 단맛 덕분에 위스키 입문자부터 부드러운 아메리칸 스타일을 선호하는 매니아까지 편안하게 매료시킵니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 바닐라 포드 향 뒤로, 상큼한 오렌지 제스트와 부드러운 꿀의 향이 피어오릅니다. 그 기저에는 메스키트 숯에서 기인한 은은하고 향긋한 나무 연기 향이 부드럽게 감쌉니다.", "맛 (Palate)": "입안에 닿는 느낌이 매끄럽고 크리미합니다. 브라운 슈가와 메이플 시럽, 졸인 황도 복숭아의 진한 단맛이 중심을 잡고, 뒤이어 오크통에서 배어 나온 가벼운 시나몬, 화이트 페퍼의 부드러운 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 나무 잔향이 지속됩니다. 버진 오크 특유의 드라이한 탄닌과 캐러멜의 달콤한 흔적이 가라앉으며, 입안 전체를 산뜻하고 따뜻하게 정돈해 주며 매끄럽게 마무리됩니다."}}' WHERE id = 196;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (197, '조니워커 블루 라벨', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/2423.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Blue Label', 255882, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-blue-label-whisky/?sku=2423', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블루 라벨(Johnnie Walker Blue Label)은 전 세계 프리미엄 블렌디드 위스키 시장에서 범접할 수 없는 최고봉의 지위를 누리는 아이코닉 마스터피스입니다. 1867년 창립자 존 워커의 아들 알렉산더 워커가 완성했던 전설적인 \'올드 하이랜드 위스키\'의 풍미를 현대적으로 재해석했으며, 40% 도수 속에서 타의 추종을 불허하는 벨벳 같은 부드러움과 거대한 복합미를 분출합니다.", "제조 및 숙성": "증류소가 보유한 수백만 개의 오크통 중 오직 1만 개의 통당 단 한 통(1만 분의 1) 꼴로만 발굴되는 극도로 진귀한 원액들만을 엄선합니다. 현재는 가동이 중단된 이른바 \'유령 증류소(Ghost Distillery)\'의 희귀 고연산 원액들이 대거 포함되어 장인 정신으로 블렌딩됩니다."}, "feature": {"1만 분의 1의 희소성": "철저한 품질 관리를 통과한 극소수의 진귀한 캐스크 원액만을 사용하여 블렌딩되므로 소장 및 선물용으로 독보적인 위엄을 자랑합니다.", "유령 증류소의 유산": "포트 앨런이나 브로라 등 전설 속으로 사라진 증류소의 장기 숙성 원액이 기저를 이루어, 수십 년의 세월만이 빚어낼 수 있는 깊이를 품고 있습니다.", "결점 없는 하모니": "수많은 싱글 몰트와 그레인 위스키가 어느 한쪽으로 치우치지 않고 단맛, 짠맛, 스모키함의 완벽한 6각형 오케스트라 하모니를 구현합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 화려하고 묵직한 아로마입니다. 감미로운 바닐라 빈과 신선한 꿀, 캐러멜 토피 향 뒤로 말린 무화과, 말린 오렌지 껍질의 시트러스가 피어오르고, 은은하게 깔리는 고급 가죽과 잔잔한 서부 하이랜드 스타일의 피트 스모크 향이 기품 있게 어우러집니다.", "맛 (Palate)": "벨벳이나 실크를 입에 머금은 듯 극도로 부드럽고 농밀한 텍스처가 압권입니다. 진한 밤꿀과 다크 초콜릿, 졸인 자두의 단맛이 기품 있게 전개되며, 구운 호두의 고소함과 시나몬 가루, 정향의 오크 스파이스가 혀 위에서 화려하고 정교하게 전개됩니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 피날레를 선사합니다. 농축된 말린 과일의 단맛과 고급 시가 박스의 우디한 향이 가라앉으며, 입안 전체를 끈질기게 감싸 안는 온화하고 드라이한 캠프파이어의 연기 잔향이 끝없이 지속됩니다."}}' WHERE id = 197;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (198, '조니워커 블랙 라벨 12년', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/2422.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Black Label 12 Year Old 70cl', 44833, 'https://www.masterofmalt.com/whiskies/johnnie-walker-black-label-12-year-old-whisky/?sku=2422', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블랙 라벨 12년(Johnnie Walker Black Label 12 Year Old)은 전 세계 위스키 역사상 가장 성공적이고 전설적인 프리미엄 블렌디드 위스키의 절대적인 표준이자 교과서입니다. 12년이라는 명확한 숙성 연수와 40% 도수 안에서 단맛, 과일 향, 해풍의 미네랄, 그리고 스모키함이 완벽한 6각형의 균형을 이루어 전 세계 바텐더들과 매니아들의 영원한 나침반 역할을 수행합니다.", "제조 및 숙성": "스코틀랜드 전역(하이랜드, 로우랜드, 아일라, 스페이사이드)을 대표하는 40여 가지 이상의 최상급 싱글 몰트와 그레인 위스키 원액을 결합했습니다. 블렌딩에 사용되는 모든 원액은 오크통 속에서 최소 12년 이상 장기 숙성된 상태를 철저히 고수합니다."}, "feature": {"블렌디드 위스키의 바이블": "풍미의 촘촘한 밀도와 구조감이 완벽한 대칭을 이루어, 수많은 블렌디드 위스키 품질의 절대적인 기준점으로 통합니다.", "스모키와 과일의 충돌": "스페이사이드의 화사한 과일 단맛과 아일라 섬 특유의 거친 피트 스모크, 요오드 향이 한 보틀 안에서 기적 같은 평형을 이룹니다.", "독보적인 올라운더": "부담 없는 가성비 속에서도 니트, 온더락, 하이볼 베이스 등 어떤 방식으로 즐겨도 위스키 본연의 묵직한 캐릭터를 명징하게 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 먼저 피어오릅니다. 뒤이어 잘 익은 붉은 사과, 청사과의 시트러스 아로마와 함께 조니워커 시그니처인 은은하고 향긋한 모닥불 연기, 마른 피트의 스모크 향이 조화롭게 다가옵니다.", "맛 (Palate)": "입안을 매끄럽고 크리미하게 감싸 안는 오일리한 질감이 돋보입니다. 벌꿀 집의 단맛과 졸인 건포도, 설탕 시럽을 바른 과일 타르트의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 시나몬 가루, 블랙페퍼의 알싸한 스파이스와 바다 소금의 짠맛이 레이어를 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 훈연 잔향이 묵직하게 오래 지속됩니다. 오크통 특유의 풍부한 나무 향과 캐러멜의 단맛이 서서히 가라앉으며, 입안 가득 감미롭고 드라이한 캠프파이어의 재 잔향을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 198;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (199, '조니워커 그린 라벨 15년', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/2428.jpg', 43.0, 15, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Green Label 15 Year Old 70cl', 77116, 'https://www.masterofmalt.com/whiskies/johnnie-walker-green-label-15-year-old-whisky/?sku=2428', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 그린 라벨 15년(Johnnie Walker Green Label 15 Year Old)은 조니워커 정규 코어 라인업 중 유일하게 그레인 위스키를 일절 섞지 않고 오직 싱글 몰트 위스키들로만 구성되어 독보적인 깊이감을 자랑하는 블렌디드 몰트(Blended Malt) 위스키입니다. 15년의 장기 숙성이 주는 중후함과 43% 도수 세팅에서 나오는 탄탄한 타격감으로 애호가들 사이에서 숨겨진 가성비 최고의 명작으로 통합니다.", "제조 및 숙성": "스코틀랜드의 사대천왕이라 불리는 네 곳의 핵심 싱글 몰트 원액을 주축으로 삼습니다. 화사한 탈리스커(Talisker), 녹진한 링크우드(Linkwood), 부드러운 크래간모어(Cragganmore), 강력한 쿠일라(Caol Ila) 증류소에서 최소 15년 이상 숙성된 명품 원액들을 장인 정신으로 블렌딩했습니다."}, "feature": {"100% 블렌디드 몰트": "부드럽고 가벼운 그레인 위스키의 간섭이 전혀 없어, 싱글 몰트 위스키 특유의 진한 고소함과 묵직한 바디감을 최고 수준으로 경험할 수 있습니다.", "사대천왕의 골든 하모니": "탈리스커의 바다 소금 짠맛, 쿠일라의 타르 피트, 링크우드와 크래간모어의 싱그러운 과일 단맛이 완벽한 평형과 대칭을 구현했습니다.", "43% ABV의 단단함": "엔트리 라인보다 한층 높은 알코올 볼륨감 덕분에 원액 고유의 풍성한 마우스필과 촘촘하게 짜인 풍미 레이어가 흐트러지지 않고 직관적으로 전해집니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 화사한 아로마가 가득 퍼집니다. 갓 피어난 화이트 플라워, 신선한 수풀 내음 뒤로 잘 익은 서양 배, 청사과의 시트러스가 퍼지고 달콤한 밤꿀, 바닐라 포드의 향과 함께 은은한 해안가 특유의 피트 스모크 향이 우아하게 어우러집니다.", "맛 (Palate)": "입안을 오일리하고 매끄럽게 감싸 안는 실키한 질감이 압권입니다. 감미로운 캐러멜 토피와 다크 초콜릿, 졸인 황도 복숭아의 진한 단맛이 중심을 잡고, 뒤이어 블랙페퍼, 구운 생강, 육두구의 알싸한 오크 스파이스와 바다 소금의 짭조름한 단짠이 정교한 레이어를 만듭니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 매우 길게 이어지는 피날레입니다. 오크통의 우디한 잔향과 에스프레소의 쌉싸름함이 가라앉으며, 입안 전체를 계속 감싸 안는 드라이하고 향긋한 캠프파이어의 연기 잔향이 짙은 여운을 선사합니다."}}' WHERE id = 199;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (200, '조니워커 18년', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/62837.jpg', 40.0, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker 18 Year Old 70cl', 152219, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-18-year-old-whisky/?sku=62837', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 18년(Johnnie Walker 18 Year Old / 과거 플래티넘 라벨)은 마스터 블렌더가 프라이빗 블렌딩의 전통을 이어받아, 오랜 세월 숙성된 고연산 원액들의 세련된 기품과 우아함을 전면에 내세운 프리미엄 싱글 몰트급 블렌디드 위스키입니다. 18년이라는 오랜 시간 동안 다듬어진 원액을 사용하여 40% 도수 속에서 극상의 온화함을 선사합니다.", "제조 및 숙성": "스코틀랜드 전역에서 엄선하여 최소 18년 이상 장기 숙성되어 완벽한 부드러움과 깊이를 획득한 18가지의 진귀한 싱글 몰트와 그레인 위스키 원액을 기반으로 합니다. 특히 스페이사이드 지역의 화사한 단맛을 품은 캐스크 비율을 대폭 높여 정교한 매링 공정을 거쳐 완성했습니다."}, "feature": {"프라이빗 블렌드의 부활": "과거 워커 가문의 마스터 블렌더들이 사적인 모임이나 VIP 고객들만을 위해 특별히 제조했던 최고급 접대용 레시피를 현대적으로 재해석했습니다.", "시간이 공들인 세련미": "18년의 기나긴 세월을 거치며 젊은 날의 거친 부즈나 날카로운 스파이스는 완벽히 정제되었고, 실크처럼 매끄러운 마우스필과 둥근 단맛만 남았습니다.", "스페이사이드 중심의 달콤함": "조니워커 특유의 묵직한 스모키함의 강도를 한 단계 낮추고, 꿀에 절인 살구, 바닐라 크림의 고급스러운 달콤함을 극대화했습니다."}}', note = '{"note": {"향 (Nose)": "깊고 정제되어 있으며 코끝을 스치는 아로마가 아름답습니다. 달콤한 캐러멜 토피와 메이플 시럽, 부드러운 바닐라 빈의 향이 피어오르고 뒤이어 말린 살구, 건포도와 상큼한 말린 오렌지 껍질, 은은한 오크통의 고풍스러운 삼나무 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크나 꿀을 머금은 듯 매끄럽고 깊은 풍미가 가득 차오르는 질감입니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 단맛이 먼저 입안을 채우고 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 잔향과 함께 가슴 속 깊은 곳까지 머눕니다."}}' WHERE id = 200;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (201, '조니워커 블랙 루비', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/141211.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Black Ruby 70cl', 56795, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-black-ruby-whisky/?sku=141211', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블랙 루비(Johnnie Walker Black Ruby)는 조니워커 가문이 트렌디한 감각과 달콤함을 극대화하여 출시한 프리미엄 블렌디드 위스키입니다. 기존 블랙 라벨의 캐릭터를 기반으로 하면서도 붉은 베리류의 달콤하고 화사한 과일 풍미를 전면에 내세웠으며, 40% 도수 속에서 매혹적이고 부드러운 목 넘김을 선사합니다.", "제조 및 숙성": "달콤하고 화사한 과일 에스테르를 풍부하게 품은 스코틀랜드 스페이사이드 및 하이랜드 지역의 싱글 몰트 원액들을 엄선했습니다. 특히 달콤한 와인 오크 캐스크와 최고급 셰리 캐스크에서 숙성된 희귀 원액들을 마스터 블렌더의 감각적인 터치로 결합해 냈습니다."}, "feature": {"베리류 달콤함의 극대화": "기존 블랙 라벨 특유의 중후함 대신, 신선한 딸기, 라즈베리 같은 달콤하고 상큼한 다크 프루트의 매력을 전면에 뿜어냅니다.", "화사한 뉴에이지 스타일": "젊은 세대와 여성 애호가들의 취향을 겨냥하여 떫은 타닌이나 거친 스파이스를 부드럽게 깎아내고 실크 같은 질감을 구현했습니다.", "최적의 하이볼 파트너": "토닉워터나 진저에일, 혹은 베리류 가니시를 곁들이는 하이볼 베이스로 활용했을 때 칵테일의 풍미를 한층 싱그럽게 살려줍니다."}}', note = '{"note": {"향 (Nose)": "화사하고 매혹적인 아로마가 가득 퍼집니다. 갓 피어난 자스민 향과 함께 신선한 딸기, 크랜베리, 복숭아 잼의 진한 단향이 올라오고 그 기저에는 부드러운 바닐라 포드와 캐러멜 토피 향이 조화롭게 받쳐줍니다.", "맛 (Palate)": "입안을 부드럽고 가볍게 감싸 안는 실키한 질감이 돋보입니다. 벌꿀 집의 단맛과 시럽을 바른 과일 타르트, 마시멜로의 풍미가 중심을 잡고 가벼운 오크통의 은은한 우디함과 화이트 페퍼 스파이스가 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 따뜻한 과일 잔향을 남깁니다. 아메리칸 오크 고유의 바닐라 단맛과 와인 캐스크 특유의 상큼한 과일 향이 가라앉으며, 입안에 기분 좋은 드라이함을 남기며 매끄럽게 마무리됩니다."}}' WHERE id = 201;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (202, '조니워커 골드 라벨 리저브', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/14376.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Gold Label Reserve 70cl', 83829, 'https://www.masterofmalt.com/whiskies/johnnie-walker-gold-label-reserve-blended-whisky/?sku=14376', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 골드 라벨 리저브(Johnnie Walker Gold Label Reserve)는 축제와 환희의 순간을 빛내기 위해 마스터 블렌더가 장인 정신으로 완성한 하이엔드 스타일 프리미엄 블렌디드 위스키입니다. 과거 증류소의 유서 깊은 골드 라벨 18년의 명성을 이어받았으며, 40% 도수 속에서 꿀을 머금은 듯한 극상의 부드러움과 화려한 크리미함을 뽐냅니다.", "제조 및 숙성": "과거 금광이 발견되었던 청정 수원의 물로 위스키를 빚는 클라이넬리시(Clynelish) 증류소의 진귀한 싱글 몰트 원액을 핵심 기저로 삼습니다. 여기에 스페이사이드와 하이랜드의 엄선된 장기 숙성 버번 배럴 원액들을 마스터 블렌더가 정교하게 혼합했습니다."}, "feature": {"클라이넬리시의 왁시함": "핵심 원액 특유의 꿀을 머금은 듯 진득하고 오일리한 \'왁시(Waxy)\' 질감이 살아있어 입안을 벨벳처럼 고급스럽게 코팅합니다.", "골드 메달 밸런스": "수많은 국제 주류 대회에서 금메달을 수상하며 명성을 떨쳤으며 단 하나의 튀는 맛도 없이 우아하고 크리미한 과일 단맛의 대칭을 보여줍니다.", "프로즌 골드의 미학": "보틀 통째로 냉동실에 얼려 걸쭉하게 만든 후 차갑게 샷으로 즐기는 \'프로즌 골드(Frozen Gold)\' 시음 방식으로 전 세계 매니아들을 매료시켰습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그러운 아로마가 가득 피어오릅니다. 잘 익은 노란 사과, 청사과의 시트러스 뒤로 감미로운 바닐라 크림, 밤꿀, 메이플 시럽의 진한 단향이 퍼지고 은은한 구운 아몬드의 고소함이 조화롭게 다가옵니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 매끄럽고 리치한 바디감이 일품입니다. 벌꿀 집의 부드러운 단맛과 졸인 황도 복숭아, 밀크 초콜릿의 풍미가 중심을 잡고 뒤이어 오크통에서 배어 나온 가벼운 계피, 시나몬의 우드 스파이스가 훌륭한 레이어를 만듭니다.", "여운 (Finish)": "온화하고 우아한 여운이 기분 좋게 지속됩니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소한 잔향이 서서히 가라앉으며, 입안 가득 맴도는 미세하고 향긋한 스모크 힌트가 산뜻하게 마무리됩니다."}}' WHERE id = 202;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (203, '조니워커 더블 블랙', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/11104.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Double Black 70cl', 62551, 'https://www.masterofmalt.com/whiskies/johnnie-walker-double-black-whisky/?sku=11104', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 더블 블랙(Johnnie Walker Double Black)은 전설적인 클래식 블랙 라벨의 성공적인 DNA를 기반으로, 피트 스모크의 화력과 우디한 타격감을 대담하게 두 배로 증폭시켜 출시한 강렬한 캐릭터의 프리미엄 블렌디드 위스키입니다. 40% 도수로 병입되며 헤비 피티드 스타일을 선호하는 애호가들 사이에서 독보적인 지지를 받습니다.", "제조 및 숙성": "스코틀랜드 서부 해안과 아일라(Islay) 섬을 대표하는 쿠일라, 탈리스커 등 강렬한 피트 싱글 몰트 원액의 블렌딩 비중을 과감하게 늘렸습니다. 이 스피릿들을 안쪽을 탄화가 일어날 때까지 강렬하게 태운 헤비 차드 오크 캐스크(Deep Charred Oak Casks)에서 숙성시켜 결합했습니다."}, "feature": {"블랙 라벨의 강렬한 변주": "기존 블랙 라벨 고유의 육각형 균형미 위에 깊고 어두운 캠프파이어 연기와 타르, 해풍의 소금기 레이어를 묵직하게 얹어냈습니다.", "헤비 차드 캐스크의 매력": "강하게 태운 새 오크통 내부 벽면에서 흘러나온 묵직한 오크 캐러멜 단맛과 탄닌 성분이 스모키함과 멋진 대조를 이룹니다.", "압도적인 타격감": "가볍고 부드러운 성향의 위스키들과 완전히 결이 다른, 직관적이고 거친 사나이의 강인한 텍스처를 가성비 좋게 경험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 자극하는 강렬한 타오르는 장작 연기, 그을음과 훈제 베이컨의 피트 향이 압도합니다. 그 뒤로 진한 캐러멜 토피, 바닐라 포드의 단 향과 신선한 바닷바람의 짭조름한 바다 내음이 묵직하게 엉켜 듭니다.", "맛 (Palate)": "입안을 진득하고 오일리하게 가득 채우는 풀바디 텍스처입니다. 다크 초콜릿, 흑설탕에 졸인 자두의 진한 단맛이 중심을 잡고 뒤이어 cracked 블랙페퍼, 구운 생강의 알싸한 오크 스파이스와 바다 소금의 짠맛이 피트 스모크와 충돌하며 폭발적인 풍미를 냅니다.", "여운 (Finish)": "드라이하면서도 스모키한 화력이 가슴 깊은 곳까지 묵직하게 남는 긴 여운입니다. 입안 전체를 끈질기게 지배하는 드라이한 석탄 연기와 담배 연기 잔향 뒤로 부드러운 오크통의 흔적이 짙은 미련을 남기며 지속됩니다."}}' WHERE id = 203;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (204, '조니워커 레드 라벨', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/2427.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Red Label 70cl', 37266, 'https://www.masterofmalt.com/whiskies/johnnie-walker-red-label-whisky/?sku=2427', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 레드 라벨(Johnnie Walker Red Label)은 전 세계 싱글 몰트 및 블렌디드 위스키 시장을 통틀어 가장 널리 알려지고 대량 판매되는 조니워커 가문의 위대한 개척자이자 스탠다드 엔트리 위스키입니다. 1909년 탄생한 이래 40% 도수 속에서 버번과 몰트 고유의 직관적이고 역동적인 타격감을 전면에 내세우며 전 세계 바 문화의 기준점이 되었습니다.", "제조 및 숙성": "스코틀랜드 동해안의 화사한 싱글 몰트 원액들과 서해안의 대담하고 스모키한 원액들을 주축으로 하여, 약 35가지 이상의 몰트 및 그레인 위스키 원액을 정교하게 결합했습니다. 젊은 연산 특유의 활력 넘치는 스피릿을 전통 오크통에서 숙성시켜 완성합니다."}, "feature": {"하이볼 문화의 선구자": "탄산수, 진저에일, 콜라 등 다양한 음료와 혼합했을 때 위스키 고유의 향이 죽지 않고 살아나 전 세계 바텐더들의 고정 픽으로 통합니다.", "직관적인 타격감의 힘": "고연산 제품들 특유의 묵직한 묵은 향 대신, 생기 넘치는 시트러스 과일 단맛과 알싸한 후추 스파이시의 대담한 퍼포먼스를 전합니다.", "독보적인 글로벌 가성비": "가장 합리적이고 부담 없는 가격대에서 조니워커 가문 특유의 화사함과 잔잔한 피트 스모크 캐릭터를 가장 온전하게 맛볼 수 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 활력 넘치는 아로마가 코를 자극합니다. 신선한 바닐라 크림, 구운 토스트의 고소함 뒤로 상큼한 레몬 제스트, 청사과의 시트러스와 함께 조니워커 특유의 은은하고 향긋한 모닥불 연기 향이 대담하게 피어오릅니다.", "맛 (Palate)": "입안에 닿는 느낌이 가볍고 생동감 넘칩니다. 브라운 슈가의 직관적인 단맛과 옥수수 시럽의 풍미가 퍼지고, 뒤이어 오크통에서 배어 나온 알싸한 블랙페퍼, 계피 가루의 부드러운 스파이스가 혀 위에서 화려하고 경쾌하게 전개됩니다.", "여운 (Finish)": "깔끔하면서도 온화한 나무 잔향을 산뜻하게 남깁니다. 가벼운 나무 스파이스의 따뜻함과 캐러멜의 달콤한 흔적이 가라앉으며, 입안에 기분 좋은 드라이함과 가벼운 피트 smoke의 잔향을 산뜻하게 남기며 마무리됩니다."}}' WHERE id = 204;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (205, '조니워커 블랙 트리플 캐스크', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/97636.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Johnnie Walker Black Triple Cask 100cl', 93146, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-black-triple-cask-whisky/?sku=97636', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블랙 트리플 캐스크(Johnnie Walker Black Triple Cask)는 주로 글로벌 면세 시장을 타겟으로 기획된 스페셜 익스프레션으로, 세 가지 서로 다른 오크통의 영향력을 정교하게 엮어내어 풍미의 스펙트럼을 넓힌 싱글 몰트급 블렌디드 위스키입니다. 40% 도수로 병입되며 풍성하고 다채로운 과일 단맛을 뽐냅니다.", "제조 및 숙성": "최상급 아메리칸 화이트 오크 버번 배럴에서 숙성되어 바닐라 향을 확보한 원액을 주축으로 삼습니다. 이후 마스터 블렌더의 정밀한 비율 설계에 따라 최고급 유러피안 오크 오로로소 셰리 캐스크와 스카치 위스키 숙성 오크 캐스크까지 총 세 종류의 상이한 오크통에서 매링 과정을 거쳤습니다."}, "feature": {"삼중 캐스크의 복합 레이어": "버번의 바닐라, 셰리의 과일 맛, 전통 오크통의 은은한 맥아 고소함이 어느 한쪽으로 치우치지 않고 완벽한 하모니를 이룹니다.", "진화한 블랙 라벨 표준": "기존의 정규 블랙 라벨 제품보다 오크통의 영향력이 대폭 증가하여 한층 더 묵직하고 직관적인 달콤함의 타격감을 선사합니다.", "면세점 전용의 매력": "여행자들을 위해 특별 기획된 세련된 골드 앤 블랙 패키지 디자인과 함께 가성비 좋게 경험할 수 있는 프리미엄 컬렉션입니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 진한 바닐라 크림 향이 코를 가득 채웁니다. 뒤이어 상큼한 말린 오렌지 껍질, 신선한 꿀의 단 향과 함께 셰리 오크통에서 기인한 말린 무화과, 베이킹 스파이스 아로마가 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 부드럽고 크리미하게 감싸 안는 오일리한 질감이 돋보입니다. 진한 밤꿀과 다크 초콜릿, 졸인 황도 복숭아의 단맛이 파도처럼 밀려오고 시나몬 가루, 구운 생강, 육두구의 알싸한 오크 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "온화하고 묵직한 나무 잔향이 기분 좋게 지속됩니다. 오크통에서 배어 나온 부드러운 바닐라 풍미와 캐러멜의 단맛, 그리고 따뜻한 계피 스파이스의 흔적이 입안을 산뜻하게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 205;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (206, '조니워커 아일랜드 그린', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/64251.jpg', 43.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 1000.0, 'Johnnie Walker Island Green 100cl', 121889, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-island-green-whisky/?sku=64251', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 아일랜드 그린(Johnnie Walker Island Green)은 글로벌 면세 시장을 겨냥해 출시된 프리미엄 블렌디드 몰트 위스키입니다. 일반 그린 라벨과 마찬가지로 그레인 위스키를 일절 섞지 않고 100% 싱글 몰트 원액들로만 구성되었으나, 아일라 섬 특유의 강렬한 스모키 캐릭터를 한층 더 전면에 내세워 43% 도수 속에서 파워풀한 타격감을 선사합니다.", "제조 및 숙성": "스코틀랜드 전역의 장기 숙성 싱글 몰트 원액들을 엄선하여 블렌딩했습니다. 특히 일반 그린 라벨에서 밸런스를 잡던 스페이사이드 몰트의 비중을 다소 낮추고, 아일라 섬을 대표하는 쿠일라(Caol Ila) 증류소의 헤비 피티드 원액 비율을 과감하게 늘려 전통 오크통에서 매링했습니다."}, "feature": {"진화한 스모키 그린": "기존 그린 라벨 고유의 화사한 과일 단맛 기저 위에 대담한 석탄 타르와 묵직한 캠프파이어 연기 향을 짙게 얹어냈습니다.", "100% 몰트의 강인함": "부드럽고 가벼운 그레인 위스키의 간섭이 전혀 없어, 싱글 몰트 위스키 특유의 진한 고소함하고 묵직한 오일리 바디감을 최고 수준으로 경험할 수 있습니다.", "면세 시장의 독보적 가성비": "여행자들을 위해 특별 기획된 화려한 프로파일로, 아일라 피트의 제왕적 면모와 대중적인 밸런스를 동시에 탐험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 자극하는 강렬한 타오르는 장작 연기, 소독약 향과 훈제 베이컨의 피트 향이 전면에 나섭니다. 이내 신선한 밤꿀, 바닐라 포드의 단 향과 상큼한 청사과, 서양 배의 시트러스 아로마가 짭조름한 해풍의 뉘앙스와 조화롭게 피어오릅니다.", "맛 (Palate)": "입안을 가득 채우는 진득하고 오일리한 풀바디 텍스처입니다. 다크 초콜릿, 캐러멜 시럽, 말린 살구의 진한 단맛이 중심을 잡고, 뒤이어 블랙페퍼, 구운 생강의 알싸한 오크 스파이스와 바다 소금의 짭조름한 단짠이 피트 스모크와 충돌하며 폭발적인 풍미를 냅니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 가슴 깊은 곳까지 매우 길게 이어집니다. 입안 전체를 끈질기게 지배하는 드라이한 석탄 연기와 시가 박스의 우디 향 뒤로, 감미로운 꿀맛의 흔적이 짙는 미련을 남기며 지속됩니다."}}' WHERE id = 206;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (207, '조니워커 XR 21년', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/35089.jpg', 40.0, 21, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker XR 21 Year Old 70cl', 254275, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-xr-21-year-old-whisky/?sku=35089', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 XR 21년(Johnnie Walker XR 21 Year Old)은 조니워커 가문의 마스터 블렌더였던 경(Sir) 알렉산더 워커 2세의 기사 작위 수임을 기념하여 탄생한 최고급 럭셔리 고연산 블렌디드 스카치 위스키입니다. 왕실의 품격과 유산을 담아 40% 도수 속에서 극상의 실키한 부드러움과 우아한 복합미를 분출합니다.", "제조 및 숙성": "창립자 가문의 마스터 블렌더들이 남긴 수기 레시피 노트를 기반으로 하여, 최소 21년 이상 오랜 세월 동안 고독하게 숙성된 진귀한 원액들을 엄선했습니다. 특히 현재는 가동이 중단된 희귀한 유령 증류소들의 올드 그레인 및 싱글 몰트 원액들을 장인 정신으로 정교하게 결합했습니다."}, "feature": {"기사 작위 기념의 유산": "알렉산더 워커 2세의 명예로운 리더십을 기리기 위해 기하학적이고 장엄한 디켄터 보틀 패키지로 완성되어 격식 있는 선물용으로 최고의 위엄을 자랑합니다.", "시간이 빚은 완벽함": "21년의 기나긴 세월을 거치며 젊은 날의 거친 부즈나 날카로운 스파이스는 완벽히 정제되었고, 실크처럼 매끄러운 마우스필과 단맛의 정점만 남았습니다.", "희귀 유령 원액의 깊이": "사라진 증류소의 장기 숙성 원액이 기저를 이루어, 일반 프리미엄 위스키들과 완벽히 차별화되는 중후한 가죽 향과 천연 목재의 깊이를 품고 있습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 화려하고 묵직한 아로마입니다. 달콤한 캐러멜 토피와 메이플 시럽, 부드러운 바닐라 빈의 단향이 가득 피어오르고 뒤이어 말린 살구, 건포도와 상큼한 말린 오렌지 껍질, 오래된 오크의 고풍스러운 삼나무 향이 겹겹이 층을 이룹니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 매끄럽고 깊은 풍미가 가득 차오르는 극상의 질감입니다. 풍부한 바닐라 크림, 구운 마시멜로, 졸인 황도 복숭아의 진한 단맛이 먼저 입안을 채우고 뒤이어 구운 피칸의 고소함과 시나몬, 넛멕의 부드러운 오크 스파이스가 훌륭한 밸런스를 이룹니다.", "여운 (Finish)": "놀라울 정도로 길고 우아하며 따뜻함이 오래 지속됩니다. 꿀을 머금은 오크 향과 베이킹 스파이스의 흔적이 가라앉으며 마지막에는 다크 카카오와 에스프레소의 세련되고 쌉싸름한 여운이 긴 잔향과 함께 머눕니다."}}' WHERE id = 207;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (208, '조니워커 스윙', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/9383.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Swing 70cl', 115970, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-swing-whisky/?sku=9383', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 스윙(Johnnie Walker Swing)은 1930년대 대서양을 횡단하던 호화 여객선 승객들을 위해 마스터 블렌더 알렉산더 워커가 직접 디자인하여 출시한 역사적이고 낭만적인 헤리티지를 지닌 프리미엄 블렌디드 위스키입니다. 40% 도수로 병입되며 흔들리는 배 위에서도 넘어지지 않는 특유의 바닥 구조와 화사한 풍미를 선사합니다.", "제조 및 숙성": "당시 부유한 여객선 승객들의 고급스러운 취향을 맞추기 위해 스페이사이드와 하이랜드 지역의 화사하고 달콤한 캐스크 원액 비중을 대폭 높여 블렌딩했습니다. 전통적인 오크 혼합조에서 오랜 시간 마리잉 과정을 거쳐 거친 알코올 자극을 부드럽게 정돈해 냈습니다."}, "feature": {"오뚝이 보틀 디자인": "배의 흔들림에 맞추어 유연하게 앞뒤로 요동치도록 하단부가 둥글게 볼록 구부러진 특제 스윙 비주얼 보틀로 독보적인 시각적 재미를 자랑합니다.", "낭만적인 항해의 유산": "스카치 위스키 황금기 시절 여객선 바 문화를 지배했던 정통 럭셔리 레시피를 오마주하여, 클래식하면서도 우아한 감성을 그대로 전달합니다.", "부드러운 올라운더 밸런스": "조니워커 특유의 묵직한 피트 연기 향을 대폭 낮추고, 꿀에 절인 건포도와 바닐라 크림의 고급스러운 달콤함을 극대화하여 목 넘김이 실크처럼 감미롭습니다."}}', note = '{"note": {"향 (Nose)": "화사하고 달콤한 캐러멜 토피와 풍부한 꿀, 바닐라 아로마가 풍부하게 피어오릅니다. 뒤이어 상큼한 빨간 사과, 잘 익은 배의 시트러스와 함께 셰리 오크통에서 기인한 은은한 시나몬, 말린 과일 향이 조화롭게 어우러집니다.", "맛 (Palate)": "입안에 닿는 느낌이 부드럽고 크리미합니다. 벌꿀 집의 단맛과 밀크 초콜릿, 시럽을 바른 과일 타르트의 달콤함이 퍼지고 오크통에서 배어 나온 가벼운 나무 스파이스와 말린 오렌지 껍질의 풍미가 전개됩니다.", "여운 (Finish)": "온화하고 산뜻한 잔향을 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 풍미와 가벼운 생강 스파이스의 흔적이 입안을 기분 좋게 정돈해 주며 부드럽게 마무리됩니다."}}' WHERE id = 208;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (209, '조니워커 블론드', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/110834.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Johnnie Blonde 70cl', 45749, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-johnnie-blonde-whisky/?sku=110834', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블론드(Johnnie Walker Blonde)는 전 세계 하이볼 트렌드와 젊은 세대의 이지드링킹 취향을 겨냥하여 조니워커 가문이 파격적으로 설계하여 출시한 현대적이고 캐주얼한 뉴에이지 블렌디드 위스키입니다. 40% 도수로 병입되며 기존 위스키의 무거운 캐릭터를 걷어내고 산뜻한 생동감을 전면에 뽐냅니다.", "제조 및 숙성": "믹싱 시 다른 탄산음료나 주스와의 가벼운 하모니를 극대화하기 위해 마스터 블렌더가 원액을 정밀 조율했습니다. 화사한 스페이사이드 몰트 원액과 함께, 안쪽을 깊게 그을리지 않고 부드러운 단맛을 내는 최상급 퍼스트 필 아메리칸 화이트 오크 캐스크에서 숙성된 그레인 위스키 원액 비율을 높여 완성했습니다."}, "feature": {"하이볼 특화 뉴에이지": "전통적인 니트 시음 방식에서 벗어나 칵테일이나 진저에일, 토닉워터 등과 화려하고 청량하게 믹싱되는 것에 초점을 맞춰 기획되었습니다.", "화사한 황금빛 아이콘": "이름에 걸맞게 밝고 투명한 노란 블론드 자태와 캐주얼한 비주얼 패키지 디자인으로 젊은 세대의 파티 홈텐딩 감성을 타겟팅했습니다.", "피트 스모크 제로 지향": "기존 조니워커 특유의 탄 내나 거친 요오드 스모키함을 과감하게 완벽히 배제하고, 오직 순수한 바닐라와 달콤한 과일 단맛으로 승부합니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 밝은 바닐라 포드와 부드러운 꿀, 메이플 시럽의 단향이 직관적으로 코를 자극합니다. 뒤이어 상큼한 자몽, 레몬 제스트, 파인애플 같은 열대 과일의 아로마와 파릇파릇한 청사과의 시트러스 향이 가볍고 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 가볍고 매끄럽게 굴러가는 질감입니다. 부드러운 캐러멜 토피, 설탕 시럽을 바른 과일 타르트의 풍미가 느껴지며 뒤이어 오크통에서 배어 나온 가벼운 계피, 화이트 페퍼의 부드러운 스파이스가 혀 위에서 경쾌하게 전개됩니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 산뜻하게 남깁니다. 아메리칸 오크 고유의 달콤한 바닐라 단맛과 은은한 보리의 고소함이 입안을 부드럽게 정돈해 주며 감미롭고 가볍게 마무리됩니다."}}' WHERE id = 209;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (210, '조니워커 블랙 라벨 12년 셰리 피니시', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/119346.jpg', 40.0, 12, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Johnnie Walker Black Label 12 Year Old Sherry Finish 70cl', 62694, 'https://www.masterofmalt.com/whiskies/johnnie-walker/johnnie-walker-black-label-12-year-old-sherry-finish-whisky/?sku=119346', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 블랙 라벨 12년 셰리 피니시(Johnnie Walker Black Label 12 Year Old Sherry Finish)는 전 세계 베스트셀러인 클래식 블랙 라벨의 완벽한 6각형 균형미 위에 최고급 셰리 캐스크의 진득한 달콤함을 정교하게 주입한 스페셜 에디션 위스키입니다. 12년의 명확한 숙성 연수와 40% 도수 안에서 독창적인 단짠과 스모키의 하모니를 뿜어냅니다.", "제조 및 숙성": "스코틀랜드 전역에서 엄선되어 최소 12년 동안 장기 숙성되어 블랙 라벨 본연의 중후함을 완성한 싱글 몰트 및 그레인 위스키 원액들을 주축으로 삼습니다. 이 명품 원액들을 스페인 헤레스 지역에서 공수한 최고급 퍼스트 필 유러피안 오크 오로로소 셰리 캐스크로 옮겨 담아 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"오로로소 셰리의 마술": "블랙 라벨 특유의 잔잔한 모닥불 피트 연기 향이 셰리 오크통 고유의 말린 무화과, 건포도, 다크 초콜릿 풍미를 만나 한층 온화하게 다듬어졌습니다.", "진해진 다크 크러스트": "퍼스트 필 유러피안 셰리통 숙성을 주축으로 가미하여 일반 블랙 라벨 제품보다 훨씬 짙은 루비 호박색 빛깔과 진득한 과일 단맛의 밀도를 확보했습니다.", "입문 애호가들의 종착지": "전통적인 스모키함에 진득한 달콤함이 촘촘하고 단단하게 짜여 있어 셰리 피트 위스키 스타일을 가성비 좋게 경험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 깊은 셰리 아로마가 코를 자극합니다. 진한 건포도, 말린 무화과, 흑설탕에 졸인 자두 잼의 단향이 지배적으로 피어오르고 뒤이어 조니워커 고유의 은은하고 향긋한 모닥불 연기 향과 시나몬, 진저 스파이스가 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 매끄럽고 진득하게 가득 채우는 훌륭한 미디엄 바디의 질감입니다. 달콤한 토피 당과 밀크 초콜릿, 말린 과일의 진한 풍미가 전개되고 뒤이어 유러피안 오크 특유의 쌉싸름한 오렌지 마멀레이드와 계피, 블랙페퍼의 알싸한 스파이스가 멋진 레이어를 만듭니다.", "여운 (Finish)": "중후하고 따뜻한 여운이 묵직하게 오래 지속됩니다. 말린 과일의 단맛과 에스프레소의 흔적이 서서히 가라앉으며, 입안 가득 기품 있는 구운 오크의 우디함과 따뜻한 캠프파이어의 재 잔향이 짙은 여운을 선사합니다."}}' WHERE id = 210;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (211, '조니워커 더 존 워커', 'blended', 'Johnnie Walker Scotch Whisky Distillery', 'whiskey/19120.jpg', 40.0, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'The John Walker 70cl', 3390348, 'https://www.masterofmalt.com/whiskies/johnnie-walker-the-john-walker-whisky/?sku=19120', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "조니워커 더 존 워커(The John Walker)는 조니워커 브랜드 라인업의 최정점에 위치한 울트라 프리미엄 플래그십 블렌디드 스카치 위스키입니다. 창립자 존 워커의 선구적인 업적을 기리기 위해 40% 도수 속에서 가장 품격 있고 호화로운 오케스트라 하모니를 구현해 냈으며, 예술적인 바틀 디자인과 함께 최상위 자산가들의 컬렉션 표적이 되는 마스터피스입니다.", "제조 및 숙성": "존 워커가 살았던 19세기 당시에 운영되던 유서 깊은 증류소들의 초고연산 원액들만을 엄선하여 결합했습니다. 현재는 가동이 중단된 전설적인 유령 증류소인 글렌 얼비(Glen Albyn), 캄부스(Cambus) 등의 희귀 원액과 최상급 퍼스트 필 오크통 원액들을 혼합하여 오랜 시간 매링 창고에서 완벽하게 숙성시켰습니다."}, "feature": {"브랜드 최고 정점의 희소성": "수백만 개의 캐스크 중 극소수로 선별된 진귀한 유산 원액들로만 블렌딩되어 생산량이 극도로 한정된 최고급 프리미엄 익스프레션입니다.", "유령 증류소의 고결한 깊이": "사라진 증류소의 수십 년 장기 숙성 원액이 기저를 이루어, 일반 럭셔리 라인업을 상회하는 중후한 가죽 향과 침향의 깊이를 품고 있습니다.", "수작업 바카라 디켄터": "프랑스의 명품 크리스탈 가문 바카라(Baccarat)가 빚어낸 핸드메이드 디켄터 보틀과 24K 금박 장식 패키지로 감싸여 박물관급 소장 가치를 자랑합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 화려하고 묵직한 아로마입니다. 감미로운 파푸아뉴기니 바닐라 빈과 진한 밤꿀, 메이플 시럽 향 뒤로 오래된 가죽 책의 고풍스러운 삼나무 향이 피어오르고, 잘 익은 블랙커런트와 상큼한 오렌지 껍질의 풍미가 은은한 시가 박스 향과 완벽하게 어우러집니다.", "맛 (Palate)": "벨벳이나 실크를 입안 가득 머금은 듯 극도로 부드럽고 농밀하게 감싸 안는 마우스필이 압권입니다. 진한 다크 초콜릿, 졸인 무화과 잼, 토피 당의 진한 달콤함이 먼저 입안을 채우고 시나몬 가루, 구운 피칸의 고소함과 정향의 오크 스파이스가 정교하게 타격합니다.", "여운 (Finish)": "끝을 알 수 없을 정도로 깊고 우아한 피날레를 선사합니다. 농축된 말린 과일의 단맛과 에스프레소의 잔잔한 쌉싸름함이 가라앉으며, 입안 전체를 계속 감싸 안는 따뜻한 베이킹 스파이스의 잔향과 드라이하고 향긋한 캠프파이어 연기의 흔적이 영원처럼 지속됩니다."}}' WHERE id = 211;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (212, '탈리스커 포트 리', 'single_malt', 'Talisker', 'whiskey/23253.jpg', 45.8, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker Port Ruighe 70cl', 94834, 'https://www.masterofmalt.com/whiskies/talisker/talisker-port-ruighe-whisky/?sku=23253', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 포트 리(Talisker Port Ruighe)는 스카이 섬의 야생마라 불리는 탈리스커 증류소 고유의 강렬한 폭풍우 피트 캐릭터에 최고급 포트 와인의 화려한 달콤함을 정교하게 입힌 프리미엄 싱글 몰트 위스키입니다. 45.8%의 상징적인 도수로 병입되며, 이색적인 단짠의 충돌이 자아내는 폭발적인 퍼포먼스를 자랑합니다.", "제조 및 숙성": "안쪽을 강렬하게 태운 아메리칸 오크 및 유러피안 오크 캐스크에서 기본 숙성되어 탈리스커 특유의 후추 타격감을 획득한 원액을 주축으로 삼습니다. 이 원액을 포르투갈의 유서 깊은 와이너리에서 공수한 최고급 루비 포트 와인 캐스크(Ruby Port Pipes)로 옮겨 담아 최종 피니시 숙성 과정을 거쳤습니다."}, "feature": {"루비 포트의 화려한 옷": "탈리스커의 날카로운 칠리 페퍼 스파이스와 거친 요오드 스모크가 포트 와인 특유의 녹진한 베리류 단맛을 만나 온화하고 입체적으로 다듬어졌습니다.", "45.8% ABV의 단단한 화력": "탈리스커 고유의 정교한 통입 도수 설정을 고수하여, 와인 캐스크의 진한 단맛 속에서도 스피릿 고유의 묵직한 오일 바디감이 뭉개지지 않고 단단하게 전해집니다.", "이색적인 단짠 밸런스": "대서양 거친 해풍의 짭조름한 바다 소금기와 포트 와인의 흑설탕 단맛이 입안에서 조화롭게 충돌하며 독보적인 육각형의 매력을 뿜어냅니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 자극하는 타오르는 장작 연기와 훈제 베이컨의 피트 향이 퍼집니다. 뒤이어 루비 포트 와인 특유의 졸인 무화과, 건포도, 블랙커런트의 진한 단향이 상큼한 만다린 오렌지 시트러스와 짭조름한 바닷바람 내음 속에 겹겹이 레이어를 형성합니다.", "맛 (Palate)": "입안을 진득하고 오일리하게 가득 채우는 훌륭한 미디엄 풀바디 텍스처입니다. 다크 초콜릿, 무화과 잼, 토피 당의 진한 달콤함이 전면에 전개되고 뒤이어 탈리스커 특유의 알싸한 칠리 페퍼, cracked 블랙페퍼의 오크 스파이스와 바다 소금의 짠맛이 피트 스모크와 어우러집니다.", "여운 (Finish)": "중후하고 깊은 따뜻함이 가슴 깊은 곳까지 오래 지속되는 피날레입니다. 와인 캐스크 고유의 상큼한 과일 단맛이 가라앉으며, 입안 가득 기품 있는 시가 박스의 우디한 향과 드라이하고 향긋한 캠프파이어의 재 잔향이 짙은 여운을 선사합니다."}}' WHERE id = 212;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (213, '탈리스커 10년', 'single_malt', 'Talisker', 'whiskey/2604.jpg', 45.8, 10, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker 10 Year Old 70cl', 73150, 'https://www.masterofmalt.com/whiskies/talisker/talisker-10-year-old-whisky/?sku=2604', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 10년(Talisker 10 Year Old)은 전 세계 피트 위스키 시장에서 대중적인 표준이자 싱글 몰트 애호가들 사이에서 \'바다의 맛\'을 대변하는 영원한 베스트셀러이자 아이코닉 명작입니다. 스코틀랜드 스카치 위스키 중에서도 45.8% 도수 속에서 뿜어져 나오는 직관적인 칠리 페퍼 타격감과 해풍의 소금기로 독보적인 위상을 자랑합니다.", "제조 및 숙성": "대서양의 거친 폭풍우를 정면으로 마주하는 스카이(Sky) 섬의 유일한 증류소 헤리티지를 담았습니다. 구부러진 유자형 웜 텁(Worm Tub) 냉각기를 고수하여 묵직하고 황 화합물이 가득 찬 스피릿을 증류해 내며, 최고급 아메리칸 ex-버번 캐스크에서 최소 10년 동안 아일라 해안 창고에서 온전히 숙성시킵니다."}, "feature": {"폭풍우가 빚은 바다의 맛": "병원 소독약 중심의 아일라 피트 위스키와 완전히 결이 다른, 짭조름한 굴 껍데기와 대서양 해풍, 미네랄 캐릭터를 전면에 내세웁니다.", "시그니처 칠리 페퍼 스파이스": "탈리스커 특유의 목 넘김 시점에서 혀와 목구멍을 짜릿하게 쪼아주는 독보적인 후추 스파이스 타격감을 선사하여 매니아들을 열광시킵니다.", "가성비 최고의 하이볼 치트키": "부담 없는 가격대에서 진한 피트 스모키를 맛볼 수 있으며, 탄산수에 통후추 가루를 쳐서 마시는 \'탈리스커 탈 하이볼\' 베이스로서 글로벌 독점 인기를 구가합니다."}}', note = '{"note": {"향 (Nose)": "코를 찌르는 강렬한 소독약, 크레오소트, 타르와 그을린 장작의 헤비 피트 향이 직관적입니다. 그 거친 스모키함 뒤로 상큼한 레몬 제스트, 신선한 청사과의 시트러스와 싱그러운 바닷바람의 짭조름한 소금기가 은은하게 캐러멜 단 향과 조화를 이룹니다.", "맛 (Palate)": "입안에 닿는 순간 오일리하면서도 파워풀한 타격감을 줍니다. 구운 보리의 고소한 단맛과 밀크 초콜릿의 풍미가 중심을 잡고, 뒤이어 탈리스커의 정석인 알싸한 칠리 페퍼, cracked 블랙페퍼 스파이스와 바다 소금의 단짠 풍미가 입안 전체를 역동적으로 지배합니다.", "여운 (Finish)": "깔끔하면서도 묵직한 훈연 향이 가슴 속 깊은 곳까지 길게 지속됩니다. 입안을 드라이하게 정돈해 주는 오크의 우디함, 쌉싸름한 에스프레소, 그리고 마지막까지 맴도는 건조하고 향긋한 캠프파이어의 재와 같은 피트 스모크의 여운이 길고 짙게 남습니다."}}' WHERE id = 213;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (214, '탈리스커 스카이', 'single_malt', 'Talisker', 'whiskey/39170.jpg', 45.8, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker Skye 70cl', 77137, 'https://www.masterofmalt.com/whiskies/talisker/talisker-skye-whisky/?sku=39170', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 스카이(Talisker Skye)는 증류소의 고향인 스카이 섬의 축복받은 청정 대자연과 시시각각 변하는 아름다운 하늘(Skye) 풍경을 오마주하여 탄생한 논에이징(NAS) 싱글 몰트 위스키입니다. 오리지널 10년 제품의 거친 피트 강도를 한 단계 온화하게 정돈하여 45.8% 도수 속에서 세련되고 둥근 대중성을 선보입니다.", "제조 및 숙성": "마스터 블렌더의 정밀한 선별 아래 주로 아메리칸 오크 버번 캐스크에서 숙성된 다양한 연산의 원액을 블렌딩했습니다. 특히 안쪽을 가볍게 한 번 더 태운 토스트한 재생 캐스크(Toasted Rejuvenated Casks) 원액 비율을 높여, 나무 고유의 캐러멜 단맛을 스피릿 깊숙이 이식했습니다."}, "feature": {"온화하게 정돈된 탈리스커": "특유의 칠리 페퍼 스파이스 타격감은 사수하되, 자극적인 요오드 향을 오크통의 달콤한 바닐라 풍미로 부드럽게 감싸 안아 입문자들에게 적합합니다.", "스카이 섬의 떼루아 형상화": "해안가 특유의 짭조름한 해풍 뉘앙스와 상큼한 과일 시트러스가 은은한 장작 연기와 잔잔한 육각형의 균형을 이룹니다.", "산뜻하고 캐주얼한 접근성": "가볍고 부드러운 질감 덕분에 피로감 없이 매일 밤 데일리 위스키나 온더락, 하이볼 베이스로 청량하게 즐기기에 최적화되어 있습니다."}}', note = '{"note": {"향 (Nose)": "싱그럽고 부드러운 아로마가 코를 자극합니다. 향긋하고 밝은 바닐라 포드와 부드러운 꿀 믹스 향 뒤로, 상큼한 오렌지, 청사과의 시트러스 과수원 풍미와 함께 은은하게 기저에 깔리는 향긋한 모닥불 연기 향이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안에서 매끄럽고 가볍게 감싸 안는 오일리한 질감입니다. 달콤한 벌꿀과 캐러멜 토피, 잘 익은 살구의 단맛이 중심을 잡고 뒤이어 구운 생강, 화이트 페퍼의 알싸한 오크 스파이스와 미세한 바다 소금의 짭조름함이 훌륭한 라운드감을 만듭니다.", "여운 (Finish)": "깔끔하면서도 온화한 잔향을 남깁니다. 오크통 특유의 바닐라 단맛과 나무 향이 서서히 가라앉으며, 입안에 산뜻하게 머무는 드라이하고 가벼운 피트 스모크의 흔적이 매력적으로 가라앉으며 마무리됩니다."}}' WHERE id = 214;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (215, '탈리스커 스톰', 'single_malt', 'Talisker', 'whiskey/21337.jpg', 45.8, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker Storm 70cl', 80513, 'https://www.masterofmalt.com/whiskies/talisker/talisker-storm-whisky/?sku=21337', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 스톰(Talisker Storm)은 이름 그대로 스카이 섬 해안가에 몰아치는 격렬한 폭풍우(Storm)와 성난 파도의 파괴력을 직관적인 풍미 레이어로 형상화해 낸 대담한 캐릭터의 논에이징(NAS) 싱글 몰트 위스키입니다. 45.8%의 단단한 도수 안에서 오리지널 제품을 능가하는 와일드한 화력과 강렬함을 분출합니다.", "제조 및 숙성": "마스터 블렌더가 증류소 창고 내부에서 가장 파워풀하고 길들여지지 않은 야생마 같은 캐릭터를 품은 젊은 캐스크 원액들을 주축으로 엄선했습니다. 안쪽을 강렬하게 태운 헤비 차드 아메리칸 오크 캐스크의 원액 비율을 대폭 높여 블렌딩조에서 정교하게 매링했습니다."}, "feature": {"폭풍우 치는 바다의 파괴력": "10년 제품 고유의 칠리 페퍼 타격감과 해풍의 소금기를 두 배로 증폭시켜, 입안 전체를 매섭게 타격하는 와일드함을 완성했습니다.", "헤비 차드 캐스크의 구조감": "강하게 태운 새 오크통의 영향력 덕분에 거친 스모키함 속에서도 묵직한 오크 탄닌과 캐러멜 단맛의 단단한 구조감이 돋보입니다.", "피트 매니아들을 위한 반전": "가볍고 부드러운 성향의 위스키들과 완전히 결이 다른, 날것 그대로의 타르, 장작 그을음, 요오드 스모크를 짜릿하게 경험하기에 훌륭합니다."}}', note = '{"note": {"향 (Nose)": "코를 직관적으로 쪼아주는 강력한 아로마입니다. 갓 그을린 타르, 요오드, 메디컬한 소독약 향과 타오르는 장작 연기 향이 폭발적입니다. 그 거친 스모키함 뒤로 상큼한 자몽, 레몬 제스트의 시트러스와 브라운 슈가의 진한 단 향이 묵직하게 어우러집니다.", "맛 (Palate)": "혓바닥을 자극적으로 조여오는 진득하고 오일리한 풀바디 텍스처입니다. 구운 보리의 고소한 단맛과 메이플 시럽의 풍미가 기저에 깔리고 뒤이어 cracked 블랙페퍼, 알싸한 칠리 페퍼의 오크 스파이스와 강렬한 바다 소금의 짭조름한 단짠이 파도처럼 휘몰아칩니다.", "여운 (Finish)": "도수에 걸맞게 온몸을 데워주는 듯한 드라이하고 긴 피날레입니다. 입안 전체를 끈질기게 지배하는 짙은 시가 박스의 우디 향, 석탄 재와 담배 연기 같은 스모키 잔향 뒤로 쌉싸름한 카카오의 여운이 깊은 인상을 남기며 지속됩니다."}}' WHERE id = 215;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (216, '탈리스커 디스틸러스 에디션', 'single_malt', 'Talisker', 'whiskey/125041.jpg', 45.8, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker Distillers Edition 70cl', 124595, 'https://www.masterofmalt.com/whiskies/talisker/talisker-distillers-edition-whisky/?sku=125041', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 디스틸러스 에디션(Talisker Distillers Edition)은 증류소가 매년 단 한 번 출시하는 하이엔드 연간 한정판 시리즈로, 탈리스커 고유의 강렬한 칠리 페퍼 타격감과 해풍의 소금기에 최고급 와인의 달콤함을 집중적으로 입혀낸 마스터클래스 익스프레션입니다. 45.8%의 상징적인 도수로 병입되며 피트 위스키가 도달할 수 있는 가장 화려하고 농밀한 단짠의 극치를 뽐냅니다.", "제조 및 숙성": "전통적인 버번 캐스크에서 숙성되어 탈리스커 본연의 폭풍우 같은 피트 깊이를 획득한 원액을 주축으로 삼습니다. 이 원액을 스페인의 최고급 아모로소 셰리 캐스크(Amoroso Sherry Casks)로 옮겨 담아 수개월간 정교한 더블 머추어드(Double Matured) 피니시 과정을 거쳐 완성됩니다."}, "feature": {"아모로소 캐스크의 마술": "일반적인 올로로소 숙성과 결이 다른, 한층 더 달콤하고 부드러운 아모로소 셰리 와인의 영향력 덕분에 말린 무화과와 토피의 깊은 단맛이 압권입니다.", "연간 한정판의 희소성": "매년 병입 연도(Bottled Year)와 고유 넘버를 새겨 한정 수량만 발매하므로 위스키 수집가들 사이에서 프리미엄이 보장되는 보틀입니다.", "경이로운 단짠 하모니": "탈리스커 특유의 묵직하고 거친 석탄 타르 스모크와 해풍의 짠맛이 셰리의 진득한 단맛과 충돌하며 경이로운 하모니를 이룹니다."}}', note = '{"note": {"향 (Nose)": "농밀하고 가득 차오르는 아로마입니다. 코를 감싸는 짙은 피트 연기와 요오드 향 뒤로 흑설탕에 졸인 자두, 진한 건포도, 말린 무화과의 녹진한 단향이 파도처럼 밀려오고 오래된 가죽과 시나몬의 아로마가 고풍스럽게 어우러집니다.", "맛 (Palate)": "밤꿀을 머금은 듯 진득하고 오일리하게 입안 전체를 풀바디 텍스처로 코팅합니다. 다크 초콜릿 파이, 무화과 잼, 토피 당의 진한 단맛이 전면에 나서고 뒤이어 cracked 블랙페퍼, 구운 생강, 그리고 강렬한 바다 소금의 짭조름함이 셰리의 단맛을 정교하게 타격합니다.", "여운 (Finish)": "중후하고 깊은 우아한 여운이 끝없이 지속됩니다. 달콤한 다크 프루트의 잔향과 에스프레소의 쌉싸름함이 가라앉으며 기품 있는 시가 박스의 우디한 향과 입안 전체를 묵직하게 채우는 드라이한 캠프파이어의 잔향이 긴 흔적을 남깁니다."}}' WHERE id = 216;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (217, '탈리스커 18년', 'single_malt', 'Talisker', 'whiskey/2810.jpg', 45.8, 18, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker 18 Year Old 70cl', 352507, 'https://www.masterofmalt.com/whiskies/talisker/talisker-18-year-old-whisky/?sku=2810', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 18년(Talisker 18 Year Old)은 전 세계 싱글 몰트 시장에서 피트 위스키의 중후함과 장기 숙성미가 자아내는 완벽한 평형을 정교하게 증명해 낸 전설적인 명작입니다. 2007년 월드 위스키 어워드(WWA)에서 \'세계 최고의 싱글 몰트\' 위상을 차지하며 품질을 공인받았으며, 45.8% 도수 속에서 극상의 우아함을 전합니다.", "제조 및 숙성": "마스터 블렌더의 치밀한 설계 아래 최고급 아메리칸 화이트 오크 버번 배럴과 유러피안 오크 셰리 캐스크에서 무려 18년이라는 기나긴 세월 동안 스카이 섬의 해풍을 맞으며 숙성된 원액만을 결합했습니다. 오랜 숙성을 통해 스피릿 고유의 날카로움이 기적적인 과일 에스테르로 부드럽게 고쳐졌습니다."}, "feature": {"시간이 공들인 정제미": "젊은 날의 투박하고 날카로웠던 칠리 페퍼의 강도는 중후하고 은은한 우드 스파이스와 풍성한 과일 단맛으로 완벽히 에스테르화되었습니다.", "어워드가 입증한 품질": "위스키 평론가들과 애호가들 사이에서 단 하나의 맛도 과하거나 모자라지 않은 가장 교과서적인 밸런스를 지닌 명작으로 손꼽힙니다.", "독보적인 구조감": "높은 알코올 볼륨감 덕분에 장기 숙성 원액 고유의 묵직한 오일감과 바다 소금의 짭조름한 단짠이 뭉개지지 않고 단단하게 짜여 있습니다."}}', note = '{"note": {"향 (Nose)": "화려하고 싱그럽습니다. 갓 피어난 자스민 향과 달콤한 바닐라 빈, 밤꿀 향 뒤로 말린 살구, 건포도, 상큼한 오렌지 껍질의 시트러스 아로마가 은은하게 깔리는 고급 가죽과 향긋한 모닥불 연기 향 속에 기품 있게 어우러집니다.", "맛 (Palate)": "입안을 실크나 꿀처럼 매끄럽고 크리미하게 감싸 안는 마우스필이 돋보입니다. 브라운 슈가의 진한 단맛과 밀크 초콜릿, 졸인 황도 복숭아의 풍미가 중심을 잡고, 뒤이어 탈리스커 특유의 알싸한 칠리 페퍼와 따뜻한 생강 스파이스가 기품 있는 레이어를 만듭니다.", "여운 (Finish)": "귀족적인 우아함이 돋보이는 매우 긴 여운입니다. 오크통에서 배어 나온 부드러운 캐러멜의 단맛과 따뜻한 나무 향이 서서히 가라앉으며, 입안 전체를 감싸 안는 감미롭고 드라이한 헤더 피트 연기의 잔향이 끝없이 지속됩니다."}}' WHERE id = 217;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (218, '탈리스커 서지', 'single_malt', 'Talisker', 'whiskey/121779.jpg', 45.8, 0, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker Surge 70cl', 114851, 'https://www.masterofmalt.com/whiskies/talisker/talisker-surge-whisky/?sku=121779', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 서지(Talisker Surge)는 글로벌 면세 시장(Travel Retail) 한정판으로 출시되어 증류소 고유의 와일드함과 대서양 거친 해풍의 역동적인 개성을 전면에 내세운 프리미엄 논에이징(NAS) 싱글 몰트 위스키입니다. 45.8%의 탄탄한 도수 세팅 안에서 솟구치는(Surge) 화력과 확실한 존재감을 자랑합니다.", "제조 및 숙성": "증류소 장인들이 엄선한 100% 최고급 퍼스트 필 아메리칸 화이트 오크 버번 배럴(First-fill Bourbon Barrels)에서 숙성된 원액만을 블렌딩했습니다. 새 버번 오크통의 영향력을 극대화하여 스피릿 본연의 피트 연기 위에 화사하고 강력한 캐러멜 단맛을 이식했습니다."}, "feature": {"퍼스트 필 버번의 위엄": "리필 캐스크를 배제하고 퍼스트 필 버번 배럴 특유의 진한 바닐라 크림과 코코넛 고유의 직관적인 단맛을 최고 수준으로 확보했습니다.", "솟구치는 피트의 에너지": "장기 숙성 제품들보다 훨씬 생기 넘치고 활력 있는 칠리 페퍼 타격감과 향긋한 장작 연기, 요오드 스모크를 전면에 내세웠습니다.", "면세점 전용의 매력": "여행자들을 위해 특별 기획된 세련된 네이비 테마 보틀 디자인과 함께, 글렌모렌지나 맥캘란 등 버번 배럴 스타일의 화사함을 선호하는 이들에게도 좋은 반전을 선사합니다."}}', note = '{"note": {"향 (Nose)": "코를 짜릿하게 자극하는 타오르는 장작 연기, 소독약 향 뒤로 향긋한 바닐라 빈과 캐러멜 토피, 메이플 시럽의 단향이 가득 퍼집니다. 이내 신선한 자몽, 청사과의 시트러스와 함께 짭조름한 바닷바람 내음이 산뜻하게 어우러집니다.", "맛 (Palate)": "입안을 꽉 차게 코팅하는 농밀하고 오일리한 마우스필입니다. 진한 벌꿀과 브라운 슈가, 졸인 살구의 달콤한 풍미가 중심을 잡고, 뒤이어 통후추, 계피의 알싸한 오크 스파이스와 바다 소금의 짭조름함이 피트 스모크와 함께 혀를 부드럽게 타격합니다.", "여운 (Finish)": "드라이하면서도 스모키한 화력이 묵직하게 남는 긴 여운입니다. 퍼스트 필 캐스크 고유의 풍부한 바닐라 캐러멜 단맛과 나무 향이 서서히 가라앉으며, 입안 전체를 산뜻하게 정돈해 주는 드라이한 캠프파이어의 재 연기 잔향이 지속됩니다."}}' WHERE id = 218;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (219, '탈리스커 25년', 'single_malt', 'Talisker', 'whiskey/42954.jpg', 45.8, 25, 'active', NOW(), NOW(), 'Scotland', '', 700.0, 'Talisker 25 Year Old (2021 Release) 70cl', 845883, 'https://www.masterofmalt.com/whiskies/talisker/talisker-25-year-old-whisky/?sku=42954', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 25년(Talisker 25 Year Old)은 증류소가 보유한 초고연산 원액들 중 극상의 품질을 지닌 통만을 엄선하여 출시하는 울트라 프리미엄 싱글 몰트 위스키입니다. 한 세기의 4분의 1에 달하는 장구한 세월 동안 숨을 쉬며 나무 고유의 성분과 피트 스피릿이 만나 기적적인 화학 결합을 이루어 냈으며, 45.8% 도수 속에서 범접할 수 없는 품격을 보여줍니다.", "제조 및 숙성": "최상급 아메리칸 화이트 오크 리필 배럴과 유러피안 오크 캐스크에서 무려 25년 이상 오랜 시간 고독하게 숙성된 진귀한 원액들을 마스터 블렌더의 정교한 비율로 결합했습니다. 오랜 숙성을 거쳤기에 물을 섞어 도수를 맞추는 공정을 대폭 줄이고 내추럴 컬러에 가까운 품격으로 완성했습니다."}, "feature": {"초고연산 피트의 미학": "젊은 날의 날카롭고 폭발적이었던 폭풍우 캐릭터는 뒤안길로 가라앉고, 대신 고급 시가 smoke와 오래된 마호가니 가구 같은 세련되고 정제된 아로마로 진화했습니다.", "미네랄리티와 우디의 하모니": "대서양 해풍이 남긴 바다 소금의 짠맛과 리필 오크통에서 배어 나온 고풍스러운 우디함, 은은한 과일 단맛이 완벽한 구도와 대칭을 이룹니다.", "역사적 귀족성의 희소 가치": "출시될 때마다 전 세계 위스키 컬렉터 및 글로벌 자산가들 사이에서 수집 프리미엄이 보장되는 최고급 하이엔드 드림 보틀로 통합니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스러운 향입니다. 은은하고 정제된 피트 스모크 뒤로 말린 무화과, 건포도, 진한 밤꿀의 단향이 깊게 퍼지고, 이내 고급스러운 오래된 가죽 책, 시가 박스의 우디함과 정제된 미네랄 해풍의 뉘앙스가 고결하게 피어오릅니다.", "맛 (Palate)": "실크나 밤꿀을 머금은 듯 농밀하고 벨벳처럼 매끄러운 텍스처지가 혀를 감쌉니다. 진한 다크 초콜릿, 졸인 프루트 잼, 토피 당의 진한 단맛이 기품 있게 전개되며, 시나몬 가루와 구운 생강, 육두구, 그리고 은은한 바다 소금의 맛이 조화를 이룹니다.", "여운 (Finish)": "영원에 가까울 정도로 깊고 우아한 피날레입니다. 농축된 단맛과 기품 있는 시가 상자의 나무 향, 에스프레소의 흔적이 가라앉으며, 입안 전체를 계속 감싸 안는 감미롭고 드라이한 헤더 피트 연기의 잔향이 끝없이 지속됩니다."}}' WHERE id = 219;
INSERT INTO whiskeys (id, name, type, brand, image_url, abv, age_years, status, created_at, updated_at, country, cask, volume, name_eng, price, cost_url, cost_url_source) VALUES (220, '탈리스커 30년', 'single_malt', 'Talisker', 'whiskey/34507.jpg', 48.5, 30, 'active', NOW(), NOW(), 'Island 30 Whisky', '', 700.0, 'Talisker 30 Year Old 70cl', 1406896, 'https://www.masterofmalt.com/whiskies/talisker/talisker-30-year-old-whisky/?sku=34507', 'Master Of Malts');
UPDATE whiskeys SET description = '{"introduction": {"제품 소개": "탈리스커 30년(Talisker 30 Year Old)은 산토리 야마자키나 맥캘란 초고연산 라인업과 어깨를 나란히 하는 증류소 최고 정점의 울트라 럭셔리 하이엔드 싱글 몰트 위스키입니다. 30년이라는 장구한 숙성 연수 속에서 자극적인 알코올은 완전히 정제되고, 위스키가 도달할 수 있는 가장 고귀하고 기품 있는 유산을 45.8%의 상징적인 도수 세팅 안에서 명징하게 증명합니다.", "제조 및 숙성": "증류소 창고 깊숙한 곳에서 무려 30년 이상 고독하게 세월을 버텨온 희귀한 전통 아메리칸 오크 및 유러피안 오크 리필 캐스크 원액만을 엄선했습니다. 오랜 숙성으로 인해 원액의 상당량이 증발하는 천사의 몫을 감내하고 남은 진귀한 정수만을 장인 정신으로 혼합하여 소량 한정 생산했습니다."}, "feature": {"최상위 플래그십의 위엄": "탈리스커 코어 라인업 중 가장 높은 숙성 연수를 자랑하는 고귀한 마스터피스로서 매년 극소량만 발매되어 천문학적인 가치를 가집니다.", "세월이 공들인 부드러움": "30년의 세월 동안 나무의 타닌과 스피릿이 만나 거칠고 매운 맛은 완전히 사라지고 극상의 실키함과 중후한 깊이감만 남았습니다.", "결점 없는 예술적 조화": "강렬했던 바다의 폭풍우는 잔잔한 안개처럼 다듬어졌고, 꿀에 절인 살구와 오크통 특유의 고급스러운 침향 레이어가 경이로운 드라마를 완성했습니다."}}', note = '{"note": {"향 (Nose)": "경외감이 드는 고풍스럽고 묵직한 아로마입니다. 오래된 마호가니 가구, 구운 코코넛, 망고와 파인애플 같은 극도로 숙성된 열대 과일의 향이 가득 퍼집니다. 뒤이어 부드러운 바닐라 포드, 토피 당, 오래된 가죽 책의 아로마가 고결하게 피어오릅니다.", "맛 (Palate)": "벨벳이나 실크처럼 부드럽고 가득 차오르는 극상의 풀바디 텍스처입니다. 진한 밤꿀과 다크 초콜릿, 럼에 절인 건포도의 단맛이 기품 있게 전개되며, 은은한 오크통의 시나몬 스파이스와 구운 피칸의 고소함, 미세한 바다 소금의 단짠 풍미가 완벽한 대칭을 이룹니다.", "여운 (Finish)": "가슴 깊은 곳까지 따뜻해지는 극도로 길고 우아한 여운입니다. 농축된 단맛 뒤로 부드러운 오크의 풍미, 에스프레소의 잔향, 그리고 마지막에 남는 쌉싸름한 다크 카카오와 대서양 해풍이 남긴 미세한 소금기의 흔적이 영원처럼 머뭅니다."}}' WHERE id = 220;